prompt
prompt Creating trigger TB_ASISTENCIA_HT580
prompt ====================================
prompt
CREATE OR REPLACE TRIGGER CANTABRIA.tb_asistencia_ht580
  before insert on asistencia_ht580
  for each row
declare
  -- local variables here
  ln_ult_nro         num_asistencia_ht580.ult_nro%TYPE;
  ls_reckey          asistencia_ht580.reckey%TYPE;
  ln_count           number;
begin

  select count(*)
    into ln_count
    from num_asistencia_ht580
   where cod_origen = :new.cod_origen;

  if ln_count = 0 then
     insert into num_asistencia_ht580(cod_origen, ult_nro)
     values(:new.cod_origen, 1);
  end if;

  select ult_nro
    into ln_ult_nro
    from num_asistencia_ht580
   where cod_origen = :new.cod_origen for update;

  ls_reckey := trim(:new.cod_origen) || trim(to_char(ln_ult_nro, '0000000000'));

  :new.reckey := ls_reckey;

  ln_ult_nro := ln_ult_nro + 1;

  update num_asistencia_ht580
     set ult_nro = ln_ult_nro
   where cod_origen = :new.cod_origen;
end tb_asistencia_ht580;
/

prompt
prompt Creating trigger TDA_AP_GUIA_RECEPCION_DET
prompt ==========================================
prompt
CREATE OR REPLACE TRIGGER CANTABRIA.TDA_AP_GUIA_RECEPCION_DET
  after delete on  AP_GUIA_RECEPCION_DET
  for each row
declare
  -- local variables here
  ls_nro_vale        vale_mov.nro_vale%TYPE;
  ls_nro_guia        ap_guia_recepcion.cod_guia_rec%Type;
  ls_origen_oc       ap_guia_recepcion.origen_oc%Type;
  ls_nro_oc          ap_guia_recepcion.nro_oc%Type;
  ls_doc_oc          logparam.doc_oc%TYPE;
  ls_org_amp_oc      articulo_mov_proy.cod_origen%TYPE;
  ln_nro_amp_oc      articulo_mov_proy.nro_mov%TYPE;
  ln_monto_total     orden_compra.monto_total%Type;
  ls_doc_grmp        ap_param.doc_guia_mp%TYPE;
  ln_count           number;
  ls_docs            varchar2(10000);

  cursor c_cp_grmp is
    select cp.tipo_doc, cp.nro_doc
      from cntas_pagar cp,
           cntas_pagar_det cpd
     where cp.cod_relacion = cpd.cod_relacion
       and cp.tipo_doc     = cpd.tipo_doc
       and cp.nro_doc      = cpd.nro_doc
       and cpd.tipo_ref    = ls_doc_grmp
       and cpd.nro_ref     = :old.cod_guia_rec
       and cpd.item_ref    = :old.item
       and cp.flag_estado  <> '0';

begin

  -- Primero valido si la GRMP no se encuentra en Cntas x pagar
  select count(*)
    into ln_count
    from ap_param t
   where t.origen = 'XX';

  if ln_count = 0 then
     RAISE_APPLICATION_ERROR(-20000, 'No existen paramatros generales en AP_PARAM, por favor verficar');
  end if;

  select doc_guia_mp
    into ls_doc_grmp
    from ap_param t
   where t.origen = 'XX';

  -- ahora busco si hay referencia en cntas_pagar_det
  select count(*)
    into ln_count
    from cntas_pagar     cp,
         cntas_pagar_det cpd
     where cp.cod_relacion = cpd.cod_relacion
       and cp.tipo_doc     = cpd.tipo_doc
       and cp.nro_doc      = cpd.nro_doc
       and cpd.tipo_ref    = ls_doc_grmp
       and cpd.nro_ref     = :old.cod_guia_rec
       and cpd.item_ref    = :old.item
       and cp.flag_estado  <> '0';

  if ln_count > 0 then
     -- Busco el primer registro y lo muestro
     ls_docs := '';
     for lc_reg in c_cp_grmp loop
         ls_docs := lc_reg.tipo_doc || '-' || lc_reg.nro_doc || ', ';
     end loop;
     RAISE_APPLICATION_ERROR(-20000, 'No se puede eliminar el item ' || to_char(:old.item)
                                     || ' de la Guia Nro: ' || :old.cod_guia_rec
                                     || ' porque ha generado los siguientes documentos x pagar: ' || ls_docs);
  end if;

  -- Ahora vemos el amarre con la OC
  select doc_oc
    into ls_doc_oc
    from logparam
   where reckey = '1';

   -- Se obtiene el amarre entre el AMP_OC y el Articulo_Mov
   SELECT am.nro_mov_proy, am.origen_mov_proy
    INTO ln_nro_amp_oc, ls_org_amp_oc
   FROM   articulo_mov am
   WHERE nro_mov    = :old.nro_mov
    AND cod_origen = :old.origen_mov;

  -- Obtengo el numero del movimiento de almacen
  select nro_Vale
    into ls_nro_Vale
    from articulo_mov
   where nro_mov    = :old.nro_mov
     and cod_origen = :old.origen_mov;

  -- Si elimino el detalle de la Guia de Recepcion
  -- debo anular el mov de almacen
  Update articulo_mov
     set flag_estado = '0',
         cant_procesada = 0,
         precio_unit = 0
   where nro_mov    = :old.nro_mov
     and cod_origen = :old.origen_mov;

  -- Ahora actualizo la cabecera
  Update vale_mov
     set flag_estado = '0'
   where nro_Vale = ls_nro_vale;

  -- Anular los AMP_OC y la Orden de Compra
  -- Obtenemos el nro de la OC
  ls_nro_guia := :old.cod_guia_rec;

  -- Obtengo los amarres entre el amp_oc y articulo_mov
  SELECT COUNT(*)
    INTO ln_count
  FROM  AP_GUIA_RECEPCION
  WHERE COD_GUIA_REC = ls_nro_guia
    AND ORIGEN_OC IS NOT NULL
    AND NRO_OC IS NOT NULL;

  IF ln_count = 1 THEN  -- Si la Guia esta amarrada a una OC
     -- Obtenemos el nro de la OC de la cabecera de la Guia
     SELECT ORIGEN_OC, NRO_OC
       INTO ls_origen_oc, ls_nro_oc
     FROM   AP_GUIA_RECEPCION
     WHERE  COD_GUIA_REC = ls_nro_guia;

     -- Anulamos los registros del AMP_OC
     UPDATE Articulo_Mov_Proy
      SET  flag_estado  = '0',
           cant_proyect = 0
     WHERE cod_origen = ls_org_amp_oc
       and nro_mov    = ln_nro_amp_oc;

     -- Actualiza la cabecera de la OC
     SELECT count(*)
       INTO ln_count
     FROM articulo_mov_proy
     WHERE tipo_doc = ls_doc_oc
       AND nro_doc  = ls_nro_oc
       AND flag_estado <> '0';

     IF ln_count = '0' THEN
        UPDATE ORDEN_COMPRA
           SET FLAG_ESTADO = '0',
               MONTO_TOTAL = 0
         WHERE COD_ORIGEN = ls_origen_oc
           AND NRO_OC     = ls_nro_oc;
     ELSE
       -- Se vuelve a calcular el monto total de la OC
        SELECT SUM(AMP.PRECIO_UNIT * AMP.CANT_PROYECT + AMP.IMPUESTO)
         INTO  ln_monto_total
        FROM   ARTICULO_MOV_PROY AMP
        WHERE  AMP.COD_ORIGEN = ls_origen_oc
         AND   AMP.TIPO_DOC   = ls_doc_oc
         AND   AMP.NRO_DOC    = ls_nro_oc;

        -- Actualizamos el monto total de la Orden de compra
        UPDATE ORDEN_COMPRA
          SET MONTO_TOTAL = ln_monto_total
        WHERE COD_ORIGEN  = ls_origen_oc
          AND NRO_OC      = ls_nro_oc;
          null;
        END IF;
   END IF;

END TDA_AP_GUIA_RECEPCION_DET;
/

prompt
prompt Creating trigger TDA_ARTICULO_ALMACEN
prompt =====================================
prompt
CREATE OR REPLACE TRIGGER CANTABRIA.TDA_ARTICULO_ALMACEN
  after delete on articulo_almacen
  for each row
declare
  -- Articulo
  ln_saldo_total         articulo.sldo_total%TYPE;
  ln_saldo_total_und2    articulo.sldo_total_und2%TYPE;
  ln_saldo_llegar        articulo.sldo_por_llegar%TYPE;
  ln_saldo_solicitado    articulo.sldo_solicitado%TYPE;
  ln_saldo_devuelto      articulo.sldo_devuelto%TYPE;
  ln_saldo_prestamo      articulo.sldo_prestamo%TYPE;
  ln_saldo_consig        articulo.sldo_consignacion%TYPE;
  ln_saldo_reservado     articulo.sldo_reservado%TYPE;
  ln_saldo_warranteado   articulo.sldo_warranteado%TYPE;
  ln_saldo_transportado  articulo.sldo_transportado%TYPE;
  ln_costo_prom_dol      articulo.costo_prom_dol%TYPE;
  ln_costo_prom_sol      articulo.costo_prom_sol%TYPE;

begin
  --===============================================
  -- Lectura de Articulo
  --===============================================
  select NVL(sldo_total,0)       , NVL(sldo_total_und2,0), NVL(sldo_por_llegar,0),
         NVL(sldo_solicitado,0)  , NVL(sldo_devuelto,0)  , NVL(sldo_prestamo,0),
         NVL(sldo_consignacion,0), NVL(sldo_reservado,0) , NVL(costo_prom_dol,0),
         NVL(costo_prom_sol,0),    NVL(sldo_warranteado,0),
         NVL(sldo_transportado, 0)
    into ln_saldo_total          , ln_saldo_total_und2   , ln_saldo_llegar,
         ln_saldo_solicitado     , ln_saldo_devuelto     , ln_saldo_prestamo,
         ln_saldo_consig         , ln_saldo_reservado    , ln_costo_prom_dol,
         ln_costo_prom_sol       , ln_saldo_warranteado  ,
         ln_saldo_transportado
    from articulo
   where cod_art = :old.cod_art for update;

  --===============================================
  -- Calculando Precio Unitario del Articulo
  --===============================================
  if ln_saldo_total - :old.sldo_total > 0 then
      ln_costo_prom_sol := (ln_costo_prom_sol * ln_saldo_total
                - :old.sldo_total * :old.costo_prom_sol) / (ln_saldo_total - :old.sldo_total);

      ln_costo_prom_dol := (ln_costo_prom_dol * ln_saldo_total
                - :old.sldo_total * :old.costo_prom_dol) / (ln_saldo_total - :old.sldo_total);
  end if;

  if ln_costo_prom_dol is null or ln_costo_prom_sol is null then
     RAISE_APPLICATION_ERROR(-20000, 'ERROR CALCULANDO EL PRECIO PROMEDIO, NO DEBE SER NULO'
                         || CHR(13) || 'PROM SOL: '        || ln_costo_prom_sol
                         || CHR(13) || 'PROM DOL: '        || ln_costo_prom_dol
                         || CHR(13) || 'SALDO_TOTAL: '     || ln_saldo_total
                         || CHR(13) || 'Cantidad :  '      || :old.sldo_total
                         || CHR(13) || 'Cod Articulo:'     || :old.cod_art
                         || CHR(13) || 'Precio unit sol: ' || :old.costo_prom_sol
                         || CHR(13) || 'Precio unit dol: ' || :old.costo_prom_dol);
  end if;

  --===============================================
  -- Actualizando Saldos
  --===============================================
  ln_saldo_total      := ln_saldo_total       - :old.sldo_total;
  if ln_saldo_total < 0 then
     RAISE_APPLICATION_ERROR(-20000, 'El saldo Total en Articulo no debe ser negativo'
            || chr(13) || 'Cod Art: ' || :old.cod_art
            || chr(13) || 'Saldo: ' || to_char(ln_saldo_total + :old.sldo_total)
            || chr(13) || 'Cantidad: ' || to_char(:old.sldo_total));
  end if ;

  ln_saldo_total_und2 := ln_saldo_total_und2  - :old.sldo_total_und2;
  if ln_saldo_total_und2 < 0 then
     RAISE_APPLICATION_ERROR(-20000, 'El saldo Total (Und2)en Articulo no debe ser negativo'
            || chr(13) || 'Cod Art: ' || :old.cod_art
            || chr(13) || 'Saldo: ' || to_char(ln_saldo_total_und2 + :old.sldo_total_und2)
            || chr(13) || 'Cantidad: ' || to_char(:old.sldo_total_und2));
  end if ;

  ln_saldo_llegar     := ln_saldo_llegar      - :old.sldo_por_llegar;
  if ln_saldo_llegar < 0 then
     RAISE_APPLICATION_ERROR(-20000, 'El saldo x llegar en Articulo no debe ser negativo'
            || chr(13) || 'Cod Art: ' || :old.cod_art
            || chr(13) || 'Saldo: ' || to_char(ln_saldo_llegar + :old.sldo_por_llegar)
            || chr(13) || 'Cantidad: ' || to_char(:old.sldo_por_llegar));
  end if ;

  ln_saldo_solicitado := ln_saldo_solicitado  - :old.sldo_solicitado;
  if ln_saldo_solicitado < 0 then
     RAISE_APPLICATION_ERROR(-20000, 'El saldo Solicitado en Articulo no debe ser negativo'
            || chr(13) || 'Cod Art: ' || :old.cod_art
            || chr(13) || 'Saldo: ' || to_char(ln_saldo_solicitado + :old.sldo_solicitado)
            || chr(13) || 'Cantidad: ' || to_char(:old.sldo_solicitado));
  end if ;

  ln_saldo_devuelto   := ln_saldo_devuelto    - :old.sldo_devuelto;
  if ln_saldo_devuelto < 0 then
     RAISE_APPLICATION_ERROR(-20000, 'El saldo Devuelto en Articulo no debe ser negativo'
            || chr(13) || 'Cod Art: ' || :old.cod_art
            || chr(13) || 'Saldo: ' || to_char(ln_saldo_devuelto + :old.sldo_devuelto)
            || chr(13) || 'Cantidad: ' || to_char(:old.sldo_devuelto));
  end if ;

  ln_saldo_prestamo   := ln_saldo_prestamo    - :old.sldo_prestamo;
  if ln_saldo_prestamo < 0 then
     RAISE_APPLICATION_ERROR(-20000, 'El saldo Prestamo en Articulo no debe ser negativo'
            || chr(13) || 'Cod Art: ' || :old.cod_art
            || chr(13) || 'Saldo: ' || to_char(ln_saldo_prestamo + :old.sldo_prestamo)
            || chr(13) || 'Cantidad: ' || to_char(:old.sldo_prestamo));
  end if ;

  ln_saldo_consig     := ln_saldo_consig      - :old.sldo_consignacion;
  if ln_saldo_consig < 0 then
     RAISE_APPLICATION_ERROR(-20000, 'El saldo Consignacion en Articulo no debe ser negativo'
            || chr(13) || 'Cod Art: ' || :old.cod_art
            || chr(13) || 'Saldo: ' || to_char(ln_saldo_prestamo + :old.sldo_consignacion)
            || chr(13) || 'Cantidad: ' || to_char(:old.sldo_consignacion));
  end if ;

  ln_saldo_reservado  := ln_saldo_reservado   - :old.sldo_reservado;
  if ln_saldo_reservado < 0 then
     RAISE_APPLICATION_ERROR(-20000, 'El saldo Reservado en Articulo no debe ser negativo'
            || chr(13) || 'Cod Art: ' || :old.cod_art
            || chr(13) || 'Saldo Total: ' || to_char(ln_saldo_reservado + :old.sldo_reservado)
            || chr(13) || 'Cantidad: ' || to_char(:old.sldo_reservado));
  end if ;

  ln_saldo_warranteado  := ln_saldo_warranteado   - :old.sldo_warranteado;
  if ln_saldo_warranteado < 0 then
     RAISE_APPLICATION_ERROR(-20000, 'El saldo Warranteado en Articulo no debe ser negativo'
            || chr(13) || 'Cod Art: ' || :old.cod_art
            || chr(13) || 'Saldo Total: ' || to_char(ln_saldo_warranteado + :old.sldo_warranteado)
            || chr(13) || 'Cantidad: ' || to_char(:old.sldo_warranteado));
  end if ;

  ln_saldo_transportado  := ln_saldo_transportado  - :old.sldo_transportado;
  if ln_saldo_transportado < 0 then
     RAISE_APPLICATION_ERROR(-20000, 'El saldo Warranteado en Articulo no debe ser negativo'
            || chr(13) || 'Cod Art: ' || :old.cod_art
            || chr(13) || 'Saldo Total: ' || to_char(ln_saldo_transportado + :old.sldo_transportado)
            || chr(13) || 'Cantidad: ' || to_char(:old.sldo_transportado));
  end if ;

  --===============================================
  -- Grabar Datos en Articulo
  --===============================================
  update articulo a
     set a.sldo_total        = ln_saldo_total,
         a.sldo_total_und2   = ln_saldo_Total_und2,
         a.sldo_por_llegar   = ln_saldo_llegar,
         a.sldo_solicitado   = ln_saldo_solicitado,
         a.sldo_devuelto     = ln_saldo_devuelto,
         a.sldo_prestamo     = ln_saldo_prestamo,
         a.sldo_consignacion = ln_saldo_consig,
         a.sldo_reservado    = ln_saldo_reservado,
         a.sldo_warranteado  = ln_saldo_warranteado,
         a.sldo_transportado = ln_saldo_transportado,
         a.costo_prom_sol    = ln_costo_prom_sol,
         a.costo_prom_dol    = ln_costo_prom_dol,
         a.flag_replicacion  = '0'
   where a.cod_art = :old.cod_art;

end TDA_ARTICULO_ALMACEN;
/

prompt
prompt Creating trigger TDA_ARTICULO_MOV
prompt =================================
prompt
CREATE OR REPLACE TRIGGER CANTABRIA.TDA_ARTICULO_MOV
  AFTER DELETE on articulo_mov
  for each row

DECLARE
  -- Logparam
  ls_cod_soles         logparam.cod_soles%TYPE;
  ls_cod_dolares       logparam.cod_dolares%TYPE;
  ls_oper_ing_oc       logparam.oper_ing_oc%type;       -- Ingreso x OC
  ls_oper_ing_prod     logparam.oper_ing_prod%type;     -- Ingreso x produccion
  ls_oper_ing_cdir     logparam.oper_ing_cdir%TYPE;     -- Ingreso x Compra Directa
  ls_oper_ing_otr      logparam.oper_ing_otr%TYPE;      -- Ingreso x Orden Traslado
  ls_oper_sal_otr      logparam.oper_sal_otr%TYPE;      -- Salida x Orden de Traslado
  ls_oper_cons_int     logparam.oper_cons_interno%TYPE; -- Salida por consumo interno
  ls_doc_mov_alm       logparam.doc_mov_almacen%type;   -- Documento Mov Almacen
  ls_doc_sc            logparam.doc_sc%type;            -- Documento Solicitud de Compra
  ls_doc_otr           logparam.doc_otr%TYPE;           -- Documento Orden de Traslado
  ls_doc_oc            logparam.doc_oc%TYPE;            -- Documento Orden de Compra
  ls_doc_ot            logparam.doc_ot%TYPE;            -- Documento Orden de Trabajo
  ls_doc_ov            logparam.doc_ov%TYPE;            -- Documento Orden de Venta
  ls_doc_prog          logparam.tipo_doc_prog_cmp%TYPE; -- Documento Programa de Compras

  -- Presup_param
  ls_flag_prsp_prev    presup_param.flag_presup_prevent%TYPE;

  -- Articulo_Mov_Tipo
  ls_tipo_mov          articulo_mov_tipo.tipo_mov%type;
  ln_fac_total         articulo_mov_tipo.factor_sldo_total%type;
  ln_fac_xllegar       articulo_mov_tipo.factor_sldo_x_llegar%type;
  ln_fac_sol           articulo_mov_tipo.factor_sldo_sol%type;
  ln_fac_dev           articulo_mov_tipo.factor_sldo_dev%type;
  ln_fac_presup        articulo_mov_tipo.factor_presup%type;
  ln_fac_templa        articulo_mov_tipo.factor_ctrl_templa%type;
  ls_ajuste_valoriz    articulo_mov_tipo.flag_ajuste_valorizacion%type;
  ls_flag_contab       articulo_mov_tipo.flag_contabiliza%TYPE;
  ls_sol_precio        articulo_mov_tipo.flag_solicita_precio%TYPE;
  ls_tipo_mov_dev      articulo_mov_tipo.tipo_mov_dev%TYPE;
  ln_fac_total_dev     articulo_mov_tipo.factor_sldo_total%TYPE;
  ls_flag_amp          articulo_mov_tipo.flag_amp%TYPE;
  ln_factor_mov_amp    articulo_mov_tipo.factor_sldo_total%TYPE;

  -- Vale_Mov
  ld_fec_registro      vale_mov.fec_registro%type;
  ls_tipo_ref          vale_mov.tipo_refer%type;
  ls_nro_ref           vale_mov.nro_refer%type;
  ls_origen_ref        vale_mov.origen_refer%type;
  ls_proveedor         vale_mov.proveedor%type;
  ls_cod_usr           vale_mov.cod_usr%type;

  -- Articulo
  ls_flag_estado       articulo.flag_estado%TYPE;
  ls_flag_invent       articulo.flag_inventariable%TYPE;
  ls_und               articulo.und%type;
  ls_nom_art           articulo.nom_articulo%type;
  ls_cntrl_lote_art    articulo.flag_cntrl_lote%TYPE;
  ls_flag_und2         articulo.flag_und2%TYPE;

  -- Articulo_almacen
  ln_saldo_total       articulo_almacen.sldo_total%TYPE;
  ln_saldo_total_und2  articulo_almacen.sldo_total_und2%TYPE;
  ln_saldo_llegar      articulo_almacen.sldo_por_llegar%TYPE;
  ln_saldo_solicit     articulo_almacen.sldo_solicitado%TYPE;
  ln_costo_prom_sol    articulo_almacen.costo_prom_sol%TYPE;
  ln_costo_prom_dol    articulo_almacen.costo_prom_dol%TYPE;

  -- Articulo_mov
  ln_pre_unit_sol      articulo_mov.precio_unit%TYPE;
  ln_pre_unit_dol      articulo_mov.precio_unit%TYPE;


  -- Almacen
  ls_cntrl_lote_alm    almacen.flag_cntrl_lote%TYPE;
  ls_almacen           almacen.almacen%type;

  -- Reservacion
  ln_cant_proc_reserv  reservacion_det.cant_procesada%TYPE;
  ln_cant_libre_ot     NUMBER;

  -- Articulo_Mov_Proy
  ln_cant_proyect      articulo_mov_proy.cant_proyect%type;
  ln_cant_procesada    articulo_mov_proy.cant_procesada%type;
  ln_cant_facturada    articulo_mov_proy.cant_facturada%TYPE;
  ln_cant_reservado    articulo_mov_proy.cant_reservado%TYPE;
  ln_cant_transport    articulo_mov_proy.cant_transportada%TYPE;
  ln_flag_crg_inm_prsp articulo_mov_proy.flag_crg_inm_prsp%TYPE;
  ld_fec_proyect       articulo_mov_proy.fec_proyect%TYPE;
  ls_org_amp_ot        articulo_mov_proy.cod_origen%TYPE;
  ln_nro_amp_ot        articulo_mov_proy.nro_mov%TYPE;
  ls_tipo_mov_amp      articulo_mov_proy.tipo_mov%TYPE;

  -- Varios
  ln_ano               number;
  ln_mes               Number(2);
  ln_pre_unit_mov      articulo_mov_proy.precio_unit%TYPE;
  ls_estado_oc         orden_compra.flag_estado%TYPE;
  ls_estado_ov         orden_venta.flag_estado%TYPE;
  ln_count             number;

  -- Templa_saldo
  ln_cant_work         templa_saldo.cantidad_total%TYPE;
  ln_cant_work2        templa_saldo.cant_total_und2%TYPE;

  -- Presupuesto_partida
  ls_flag_ctrl      presupuesto_partida.flag_ctrl%TYPE;


BEGIN
  --=================================================
  -- Si el movimiento esta anulado no debo hacer nada
  --=================================================
  if :old.flag_estado = '0' then return; end if;

  --=================================================
  -- Lectura de Parametros LogParam
  --=================================================
  SELECT cod_soles       , cod_dolares     , oper_ing_oc         , oper_ing_prod ,
         doc_mov_almacen , doc_sc          , oper_ing_cdir ,
         doc_otr         , oper_ing_otr    , oper_sal_otr        ,
         doc_ot          , oper_cons_interno, l.tipo_doc_prog_cmp
    INTO ls_cod_soles    , ls_cod_dolares  , ls_oper_ing_oc      , ls_oper_ing_prod,
         ls_doc_mov_alm  , ls_doc_sc       , ls_oper_ing_cdir,
         ls_doc_otr      , ls_oper_ing_otr , ls_oper_sal_otr     ,
         ls_doc_ot      , ls_oper_cons_int , ls_doc_prog
    FROM logparam l
   WHERE reckey = '1' ;

  --=================================================
  -- Lectura de Parametros - Presup_param
  --=================================================
   SELECT NVL(p.flag_presup_prevent, '0')
     INTO ls_flag_prsp_prev
     FROM presup_param p
    WHERE llave = '1' ;

  --=================================================
  -- Vale_mov
  --=================================================
  SELECT to_number(to_char(fec_registro,'YYYY')), to_number(to_char(fec_registro,'MM')),
         almacen     , fec_registro   , tipo_mov     , origen_refer,
         tipo_refer  , nro_refer      , proveedor    , cod_usr
    INTO ln_ano, ln_mes,
         ls_almacen  ,ld_fec_registro , ls_tipo_mov   , ls_origen_ref,
         ls_tipo_ref , ls_nro_ref     , ls_proveedor  , ls_cod_usr
    FROM vale_mov
   WHERE nro_vale   = :old.nro_vale ;

  --=================================================
  -- tipo de Movimiento
  --=================================================
  SELECT Nvl(factor_sldo_total,0),  Nvl(factor_sldo_x_llegar,0),
         Nvl(factor_sldo_sol,0),    NVL(factor_presup, 0),
         NVL(factor_ctrl_templa,0), NVL(flag_ajuste_valorizacion,'0'),
         NVL(flag_contabiliza, '0'), NVL(factor_sldo_dev,0),
         Nvl(flag_solicita_precio, '0'), tipo_mov_dev,
         NVL(FLAG_AMP, '1')
    INTO ln_fac_total,              ln_fac_xllegar,
         ln_fac_sol,                ln_fac_presup,
         ln_fac_templa,             ls_ajuste_valoriz,
         ls_flag_contab,            ln_fac_dev,
         ls_sol_precio,             ls_tipo_mov_dev,
         ls_flag_amp
    FROM articulo_mov_tipo
   WHERE tipo_mov = ls_tipo_mov ;

  --=====================================================
  -- Si tiene tipo_mov_dev, verificar que no sea el mismo
  -- Que el tipo de movimiento original
  --=====================================================
  if ls_tipo_mov_dev is not null then
     if ls_tipo_mov_dev = ls_tipo_mov then
        RAISE_APPLICATION_ERROR(-20000, 'El tipo de movimiento no puede ser '
                || 'devolucion de si mismo'
                || chr(13) || 'tipo_mov: ' || ls_tipo_mov
                || chr(13) || 'tipo_mov_dev: ' || ls_tipo_mov_dev );
     end if;
    --=====================================================
    -- Verifico si los flag de sldo_total son distintos
    --=====================================================
    SELECT Nvl(factor_sldo_total,0)
      INTO ln_fac_total_dev
      FROM articulo_mov_tipo
     WHERE tipo_mov = ls_tipo_mov_dev ;

    if ln_fac_total_dev = 0 then
        RAISE_APPLICATION_ERROR(-20000, 'Tipo de movimiento de devolucion '
                || 'no tiene definido flag_sldo_total'
                || chr(13) || 'tipo_mov_dev: ' || ls_tipo_mov_dev );
    end if;

    if ln_fac_total_dev = ln_fac_total then
        RAISE_APPLICATION_ERROR(-20000, 'Tipo de movimiento de devolucion '
                || 'no puede tener el mismo flag_sldo_total que el movimiento'
                || 'original'
                || chr(13) || 'tipo_mov: ' || ls_tipo_mov
                || chr(13) || 'tipo_mov_dev: ' || ls_tipo_mov_dev );
    end if;
  end if;

  --=================================================
  -- Flag Cntrl Lote de Almacen
  --=================================================
   SELECT Flag_cntrl_lote
     INTO ls_cntrl_lote_alm
     FROM almacen
    WHERE almacen = ls_almacen;

  --=================================================
  -- Lectura de Articulo
  --=================================================
  SELECT NVL(flag_estado, '0'), NVL(flag_inventariable, '0'),
         und, nom_articulo, NVL(flag_und2,'0'), NVL(flag_cntrl_lote, '0')
    INTO ls_flag_estado, ls_flag_invent,
         ls_und, ls_nom_art, ls_flag_und2, ls_cntrl_lote_art
    FROM articulo
   WHERE cod_art = :old.cod_art FOR UPDATE;

  --=================================================
  -- Lectura de Articulo_almacen
  --=================================================
  select count(*)
    into ln_count
    from articulo_almacen
   where cod_art = :old.cod_art
     and almacen = ls_almacen;

  if ln_count > 0 then
      SELECT NVL(sldo_total,0), NVL(sldo_por_llegar,0), NVL(sldo_solicitado,0),
             NVL(costo_prom_sol,0), NVL(costo_prom_dol,0), NVL(sldo_total_und2, 0)
        INTO ln_saldo_total, ln_saldo_llegar, ln_saldo_solicit,
             ln_costo_prom_sol, ln_costo_prom_dol, ln_saldo_total_und2
        FROM articulo_almacen
       WHERE cod_art = :old.cod_art
         and almacen = ls_almacen FOR UPDATE;
  else
       ln_saldo_total      := 0;
       ln_saldo_llegar     := 0;
       ln_saldo_solicit    := 0;
       ln_costo_prom_sol   := 0;
       ln_costo_prom_dol   := 0;
       ln_saldo_total_und2 := 0;
  end if;

  --==================================================
  -- Valida Segunda Unidad
  --==================================================
  if ls_flag_und2 = '0' and NVL(:old.cant_proc_und2,0) <> 0 then
     RAISE_APPLICATION_ERROR(-20000, 'La cantidad procesada de la segunda unidad '
                    || 'es diferente de cero y el articulo no maneja una segunda unidad');
     return;
  end if;

  --==================================================
  -- Valido Nro de Lote cuando es necesario
  --==================================================
  IF usf_alm_cntrl_lote(ls_cntrl_lote_alm, ls_cntrl_lote_art) = 1
       AND :old.nro_lote IS NULL THEN

     RAISE_APPLICATION_ERROR(-20000, 'El tipo de movimiento mueve lotes pero no ha ingresado nro_lote'
            || chr(13) || 'Flag Cntrl Lote Almacen : ' || ls_cntrl_lote_alm
            || chr(13) || 'Flag Cntrl Lote Articulo: ' || ls_cntrl_lote_art
            || chr(13) || 'Nro Lote (:old)         : ' || :old.nro_lote);

  end if;

  --==================================================
  -- Valido el Factor templa si es necesario el lote
  --==================================================
  IF usf_alm_cntrl_lote(ls_cntrl_lote_alm, ls_cntrl_lote_art) = 1
     AND ln_fac_templa = 0 THEN

    RAISE_APPLICATION_ERROR(-20000, 'El tipo de movimiento mueve lotes pero su factor es cero'
              || chr(13) || 'Flag Cntrl Lote Almacen : ' || ls_cntrl_lote_alm
              || chr(13) || 'Flag Cntrl Lote Articulo: ' || ls_cntrl_lote_art
              || chr(13) || 'Factor Templa  (:old)   : ' || ln_fac_templa   );

  end if;

  --==================================================
  -- Lectura de Articulo_Mov_Proy
  --==================================================
  IF :old.nro_mov_proy IS NOT NULL and ls_tipo_mov_dev is null THEN

     SELECT NVL(cant_proyect, 0), NVL(cant_procesada, 0), NVL(cant_reservado, 0),
            NVL(flag_crg_inm_prsp, '0'), NVL(cant_facturada, 0), NVL(cant_transportada, 0),
            fec_proyect, amp.tipo_mov
       INTO ln_cant_proyect, ln_cant_procesada, ln_cant_reservado,
            ln_flag_crg_inm_prsp, ln_cant_facturada, ln_cant_transport,
            ld_fec_proyect, ls_tipo_mov_amp
       FROM articulo_mov_proy amp
      WHERE cod_origen = :old.origen_mov_proy
        AND nro_mov    = :old.nro_mov_proy FOR UPDATE;

     select amt.factor_sldo_x_llegar
       into ln_factor_mov_amp
       from articulo_mov_tipo amt
      where amt.tipo_mov = ls_tipo_mov_amp;

     -- ================================================================
     -- Valido, No debo permitir eliminar el movimiento de almacen si es
     -- que tiene cantidad facturada
     -- ================================================================
     if ln_cant_facturada > 0 then
        if ls_tipo_ref = ls_doc_oc or ls_tipo_ref = ls_doc_ov then
           -- ================================================================
           -- En caso de una Orden de Compra o de Una Orden de Venta no puedo
           -- eliminar el movimiento si tiene cantidad facturada
           -- ================================================================
           RAISE_APPLICATION_ERROR(-20000, 'No se puede eliminar el movimiento, Item ya ha sido facturado'
                     || chr(13) || 'Tipo Doc           : ' || ls_tipo_ref
                     || chr(13) || 'Nro Doc            : ' || ls_nro_ref
                     || chr(13) || 'Tipo Mov           : ' || ls_tipo_mov
                     || chr(13) || 'Nro Mov Proy       : ' || :old.nro_mov_proy
                     || chr(13) || 'Origen Mov Proy    : ' || :old.origen_mov_proy
                     || chr(13) || 'Codigo Articulo    : ' || :old.cod_art
                     || chr(13) || 'Cantidad Facturada : ' || ln_cant_facturada   );
        elsif ls_tipo_ref = ls_doc_otr and ln_fac_total = -1 then
           -- ========================================================================
           -- En caso de una salida x Orden de Traslado no deberia eliminar la salida
           -- Si ya tiene ingreso
           -- ========================================================================
           if ln_cant_procesada - ln_Cant_facturada < :old.cant_procesada then
               RAISE_APPLICATION_ERROR(-20000, 'No se puede eliminar el movimiento, Item ya tiene Ingreso x almacen'
                         || chr(13) || 'Docum. : ' || ls_tipo_ref || '-' || ls_nro_ref
                         || chr(13) || 'Tipo Mov : ' || ls_tipo_mov
                         || chr(13) || 'Mov Proy : ' || :old.origen_mov_proy || to_char(:old.nro_mov_proy)
                         || chr(13) || 'Cod Art: ' || :old.cod_art
                         || chr(13) || 'Cant Sal: ' || ln_cant_procesada
                         || chr(13) || 'Cant Ing: ' || ln_cant_facturada
                         || chr(13) || :old.cant_procesada   );
           end if;
        end if;
     end if;
  ELSE
     ln_cant_proyect      := 0;
     ln_cant_procesada    := 0;
     ln_flag_crg_inm_prsp := '0';
  END IF;

  --==================================================
  -- Cantidad Valida
  --==================================================
  IF :old.nro_mov_proy IS NOT NULL AND ls_tipo_mov_dev is null AND :old.vale_trans IS NULL
     AND :OLD.item_trans IS NULL THEN

     if ln_fac_total = 1 and ls_tipo_ref = ls_doc_otr then
        -- =====================================================================
        -- Si es un ingreso por Orden de Traslado, debo verificar si la cantidad
        -- que ingresa no es mayor que la que ingreso el usuario
        -- Cant_facturada <= cant_proyect
        -- =====================================================================
        if ln_cant_proyect < ln_cant_facturada - :old.cant_procesada then
           RAISE_APPLICATION_ERROR( -20000, 'la Cantidad Salida Sobre Pasa a la Orden de Traslado'
                          || chr(13) || 'Cant Traslado: ' || to_char(ln_cant_proyect)
                          || chr(13) || 'Cant Ingreso : ' || to_char(ln_cant_procesada)
                          || chr(13) || 'Cant Salida  : ' || to_char(ln_cant_facturada - :old.cant_procesada)
                          || chr(13) || 'Tipo Mov     : ' || ls_tipo_mov
                          || chr(13) || 'Cod. Art     : ' || :old.cod_art) ;
        end if;
     else
        -- =====================================================================
        -- La Validacion sobre si sobrepasa o no la cant_proyect de AMP
        -- debe darse solamente cuando el FLAG_AMP = '1'
        -- =====================================================================

        if ln_cant_proyect < ln_cant_procesada - :old.cant_procesada and ls_flag_amp = '1' then
           RAISE_APPLICATION_ERROR( -20000, 'la Cantidad Procesada Sobre Pasa la Proyectada'
                          || chr(13) || 'Tipo Mov: ' || ls_tipo_mov
                          || chr(13) || 'Cant Proyectada: ' || to_char(ln_cant_proyect)
                          || chr(13) || 'Cant Procesada : ' ||  to_char(ln_cant_procesada - :old.cant_procesada)
                          || chr(13) || 'Cod. Art       : ' || :old.cod_art) ;
       end if;
     end if;
  END IF;

  --=============================================================
  -- Si es Ingreso por compra y esta amarrada a un vale de
  -- Transporte debo verificar que la cantidad transportada
  -- no sea mayor a la cant_procesada
  --=============================================================
  /*
  IF ls_tipo_mov = ls_oper_ing_oc AND :OLD.vale_trans IS NOT NULL AND
     :OLD.item_trans IS NOT NULL THEN

       if ln_cant_transport + :OLD.cant_procesada > ln_cant_procesada then
           RAISE_APPLICATION_ERROR( -20005, 'la Cantidad Transportada no puede ser mayor a la cantidad Procesada'
                          || chr(13) || 'Tipo Mov: ' || ls_tipo_mov
                          || chr(13) || 'Cant Transportada: ' || to_char(ln_cant_transport)
                          || chr(13) || 'Cant Procesada : ' || to_char(:OLD.cant_procesada)
                          || chr(13) || 'Cod. Art     : ' || :OLD.cod_art) ;
       end if;
  END IF;
  */

  --==================================================
  -- Precio Unitario en Soles y Dolares
  --==================================================
  ln_pre_unit_mov := :old.precio_unit - (:old.precio_unit * NVL(:old.decuento,0))/100 ;
  ln_pre_unit_sol := usf_fl_conv_mon(ln_pre_unit_mov, :old.cod_moneda, ls_cod_soles, ld_fec_registro);
  ln_pre_unit_dol := usf_fl_conv_mon(ln_pre_unit_mov, :old.cod_moneda, ls_cod_dolares, ld_fec_registro);

  --==================================================
  -- Precio Promedio Cuando es Ajuste
  --==================================================
  IF ls_ajuste_valoriz = '1' THEN
     if ln_saldo_Total > 0 then
       ln_costo_prom_sol := (ln_costo_prom_sol - ln_pre_unit_sol * ln_fac_total)/ln_saldo_total;
       ln_costo_prom_dol := (ln_costo_prom_dol - ln_pre_unit_dol * ln_fac_total)/ln_saldo_total;
     end if;
     GOTO Grabacion_Articulo;
  END IF;

  --=======================================================
  -- Calculo el Precio Promedio Cuando es INGRESO X OC
  -- o INGRESO X COMPRA DIRECTA (SIN OC),
  -- INGRESO X PRODUCCION o que FLAG_SOLICITA_PRECIO = '1'
  --=======================================================
  IF ls_oper_ing_oc = ls_tipo_mov or ls_oper_ing_cdir = ls_tipo_mov
     or ls_sol_precio = '1' or ls_oper_ing_prod = ls_tipo_mov THEN

     if (ln_saldo_total - :old.cant_procesada) = 0 then
        ln_costo_prom_dol := 0;
        ln_costo_prom_sol := 0;
     else
        ln_costo_prom_sol := ((ln_saldo_total * ln_costo_prom_sol) - (:old.cant_procesada * ln_pre_unit_sol))/(ln_saldo_total - :old.cant_procesada);
        ln_costo_prom_dol := ((ln_saldo_total * ln_costo_prom_dol) - (:old.cant_procesada * ln_pre_unit_dol))/(ln_saldo_total - :old.cant_procesada);
     end if;

     if ln_costo_prom_dol is null or ln_costo_prom_sol is null then
         RAISE_APPLICATION_ERROR(-20000, 'ERROR CALCULANDO EL PRECIO PROMEDIO, NO DEBE SER NULO'
                          || CHR(13) || 'PROM SOL:  '            || ln_costo_prom_sol
                          || CHR(13) || 'PROM DOL:  '            || ln_costo_prom_dol
                          || CHR(13) || 'SALDO_TOTAL:  '         || ln_saldo_total
                          || CHR(13) || ':old.cant_procesada:  ' || :old.cant_procesada
                          || chr(13) || 'Cod. Art       : '      || :old.cod_art
                          || CHR(13) || 'Precio unit sol:  '     || ln_pre_unit_sol
                          || CHR(13) || 'Precio unit dol:  '     || ln_pre_unit_dol);
     end if;
  END IF;

  --==================================================
  -- Saldos en Articulo_almacen
  --==================================================
  IF ls_flag_invent = '1' THEN
     ln_saldo_total      := ln_saldo_total - :old.cant_procesada * ln_fac_total;
     if ln_saldo_total < 0 then
        RAISE_APPLICATION_ERROR(-20000, 'El saldo total no puede ser negativo'
                          || chr(13) || 'Saldo Total : ' || to_char(ln_saldo_total + :old.cant_procesada * ln_fac_total)
                          || chr(13) || 'Cantidad    : ' || to_char(:old.cant_procesada * ln_fac_total)
                          || chr(13) || 'Cod. Art    : ' || :old.cod_art);
        return;
     end if;

     ln_saldo_total_und2 := ln_saldo_total_und2 - NVL(:old.cant_proc_und2,0) * ln_fac_total;
     if ln_saldo_total_und2 < 0 then
        RAISE_APPLICATION_ERROR(-20000, 'El saldo total (und2) no puede ser negativo'
                          || chr(13) || 'Saldo Total : ' || to_char(ln_saldo_total_und2 + :old.cant_procesada * ln_fac_total)
                          || chr(13) || 'Cantidad    : ' || to_char(:old.cant_procesada * ln_fac_total)
                          || chr(13) || 'Cod. Art    : ' || :old.cod_art);
        return;
     end if;
  END IF;

  --==================================================
  -- Actualizacion Articulo_Mov_Proy
  --==================================================
  IF :old.nro_mov_proy IS NOT NULL THEN
     IF ls_tipo_mov_dev is null then
        -- ===========================================================================
        -- Si el tipo de movimiento es un ingreso, debo actualizar en la segunda linea
        -- de la orden de traslado, la cant_facturada, correspondiente a la salida
        -- por Traslado.
        -- ===========================================================================
        if ln_fac_total = 1 and ls_tipo_ref = ls_doc_otr then
           /*****************************************************
           REPLICACION
           *****************************************************/
           -- Primera Linea de detalle de la Orden de Traslado
           UPDATE articulo_mov_proy
              SET cant_facturada = Nvl(cant_facturada,0) - :old.cant_procesada,
                  flag_replicacion = '0'
            WHERE nro_mov    = :old.nro_mov_proy
              AND cod_origen = :old.origen_mov_proy;

           -- Segunda linea de detalle de la Orden de Traslado
           UPDATE articulo_mov_proy
              SET cant_procesada = Nvl(cant_procesada,0) - :old.cant_procesada,
                  flag_replicacion = '0'
            WHERE tipo_doc   = ls_tipo_ref
              AND nro_doc    = ls_nro_ref
              AND cod_art    = :old.cod_art
              AND tipo_mov   = ls_oper_ing_otr;
           --******************************************************
       ELSIF ls_tipo_ref = ls_doc_oc THEN
             IF :OLD.vale_trans IS NULL AND :OLD.item_trans IS NULL THEN
                /*****************************************************
                -- Si es un ingreso por Compra, debo asegurarme de no modificar la cantidad
                -- procesada si esta amarrado a un movimiento de transporte, porque la cantidad
                -- procesada de la OC ya fue actualizada desde el ingreso por transporte
                *****************************************************/
                UPDATE articulo_mov_proy
                   SET cant_procesada = Nvl(cant_procesada,0) - :OLD.cant_procesada,
                       flag_replicacion = '0'
                 WHERE nro_mov        = :OLD.nro_mov_proy
                   AND cod_origen     = :OLD.origen_mov_proy;
             END IF;
       else
           /*****************************************************
           REPLICACION
           *****************************************************/
           --if ln_fac_total = ln_factor_mov_amp then
              -- De lo contrario actualizo la cantidad procesada de la manera normal
              UPDATE articulo_mov_proy
                 SET cant_procesada = Nvl(cant_procesada,0) - :old.cant_procesada,
                     flag_replicacion = '0'
               WHERE nro_mov    = :old.nro_mov_proy
                 AND cod_origen = :old.origen_mov_proy;
           --else
           --   UPDATE articulo_mov_proy
           --      SET cant_procesada = Nvl(cant_procesada,0) + :old.cant_procesada,
           --          flag_replicacion = '0'
           --    WHERE nro_mov    = :old.nro_mov_proy
           --      AND cod_origen = :old.origen_mov_proy;
           --end if;
           --******************************************************
       end if;
     else  --Devoluciones al almacen

       -- ===========================================================================
       -- Si el tipo de movimiento es un ingreso, debo actualizar en la segunda linea
       -- de la orden de traslado, la cant_facturada, correspondiente a la salida
       -- por Traslado.
       -- ===========================================================================

       if ln_fac_total = -1 and ls_tipo_ref = ls_doc_otr then
          /*****************************************************
          REPLICACION
          *****************************************************/
          -- Primera Linea de detalle de la Orden de Traslado
          UPDATE articulo_mov_proy
             SET cant_facturada = Nvl(cant_facturada,0) + :old.cant_procesada,
                 flag_replicacion = '0'
           WHERE nro_mov    = :old.nro_mov_proy
             AND cod_origen = :old.origen_mov_proy;

          -- Segunda linea de detalle de la Orden de Traslado
          UPDATE articulo_mov_proy
             SET cant_procesada = Nvl(cant_procesada,0) + :old.cant_procesada,
                 flag_replicacion = '0'
           WHERE tipo_doc   = ls_tipo_ref
             AND nro_doc    = ls_nro_ref
             AND cod_art    = :old.cod_art
             AND tipo_mov   = ls_oper_ing_otr;
          --******************************************************
       else
          /*****************************************************
          REPLICACION
          *****************************************************/
          -- De lo contrario actualizo la cantidad procesada de la manera normal
          UPDATE articulo_mov_proy
              SET cant_procesada = Nvl(cant_procesada,0) + :old.cant_procesada,
                 flag_replicacion = '0'
           WHERE nro_mov    = :old.nro_mov_proy
             AND cod_origen = :old.origen_mov_proy;
          --******************************************************
       end if;

     end if;
  END IF;

  --=============================================================
  -- Actualizo en Articulo_mov_proy la cantidad transportada
  -- disminuyendola
  --=============================================================
  IF ls_tipo_mov = ls_oper_ing_oc AND :OLD.vale_trans IS NOT NULL AND
     :OLD.item_trans IS NOT NULL THEN

     -- Actualizo la cant_transportada en AMP_OC
     UPDATE articulo_mov_proy
        SET cant_transportada = cant_transportada + :OLD.cant_procesada,
            flag_replicacion = '0'
      WHERE nro_mov        = :OLD.nro_mov_proy
        AND cod_origen     = :OLD.origen_mov_proy;

     -- Ahora tambien actualizo la cant_proc_am del movimiento de transporte
     UPDATE vale_mov_trans_det t
        SET t.cant_proc_am = NVL(t.cant_proc_am, 0) - :OLD.cant_procesada,
            flag_replicacion = '0'
      WHERE nro_vale     = :OLD.vale_trans
        AND nro_item     = :OLD.item_trans;

  END IF;


  --==================================================
  -- Actualizacion Presupuesto_Ejec
  --==================================================
  IF ln_fac_presup <> 0 THEN

     if ls_tipo_mov = ls_oper_cons_int and ls_tipo_ref = ls_doc_ot and
        ln_fac_presup = -1 and ls_flag_prsp_prev = '1' then

        select count(*)
          into ln_count
          from presupuesto_partida
         where ano        = ln_ano
           and cencos    = :old.cencos
           and cnta_prsp = :old.cnta_prsp;

        if ln_count = 0 then
           RAISE_APPLICATION_ERROR(-20000, 'No existe la Partida Presupuestal '
                              || chr(13) || 'A?o:'       || to_char(ln_ano)
                              || chr(13) || 'Cencos:'    || :old.cencos
                              || chr(13) || 'Cnta Prsp:' || :old.cnta_prsp);
        end if;

        select flag_ctrl
          into ls_flag_ctrl
          from presupuesto_partida
         where ano       = ln_ano
           and cencos    = :old.cencos
           and cnta_prsp = :old.cnta_prsp for update;

        update presupuesto_partida
           set flag_ctrl = '0'
         where ano       = ln_ano
           and cencos    = :old.cencos
           and cnta_prsp = :old.cnta_prsp;

     end if;

     DELETE PRESUPUESTO_EJEC PE
      WHERE PE.tipo_doc_ref = ls_doc_mov_alm
        AND PE.Nro_Doc_Ref  = :old.nro_vale
        AND PE.Item_Ref     = :old.nro_mov
        AND PE.Origen_Ref   = :old.cod_origen;

     if ls_tipo_mov = ls_oper_cons_int and ls_tipo_ref = ls_doc_ot and
        ln_fac_presup = -1 and ls_flag_prsp_prev = '1' then

        update presupuesto_partida
           set flag_ctrl = ls_flag_ctrl
         where ano       = ln_ano
           and cencos    = :old.cencos
           and cnta_prsp = :old.cnta_prsp;

     end if;


  END IF;


  --==================================================
  -- Cambiar el Flag de Estado de la Orden de Compra
  --==================================================
  /*
         0 = Anulado
         1 = Generado
         2 = Cerrado
  */

  if ls_tipo_ref = ls_doc_oc and ls_nro_ref is not null then
     select flag_estado
       into ls_estado_oc
       from orden_compra oc
      where oc.cod_origen = ls_origen_ref
        and oc.nro_oc     = ls_nro_ref for update;

     if ls_estado_oc = '0' then
        RAISE_APPLICATION_ERROR(-20000, 'La Orden de Compra ' || ls_nro_ref || ' esta anulada');
        return;
     end if;

     select count(*)
       into ln_count
       from articulo_mov_proy amp
      where amp.tipo_doc    = ls_tipo_ref
        and amp.nro_doc     = ls_nro_ref
        and amp.flag_estado = '1';

     if ln_count = 0 then
        ls_Estado_oc := '2';  --Cerrado
     else
        ls_estado_oc := '1';  --Abierto
     end if;

     /*****************************************************
     **** REPLICACION
     *****************************************************/
     update orden_compra
        set flag_estado = ls_estado_oc,
            flag_replicacion = '0'
      where cod_origen = ls_origen_ref
        and nro_oc     = ls_nro_ref;
     /*****************************************************/

  end if;

  --==================================================
  -- Cambiar el Flag de Estado de la Orden de Venta
  --==================================================
  /*
         0 = Anulado
         1 = Generado
         2 = Cerrado
  */

  if ls_tipo_ref = ls_doc_ov and ls_nro_ref is not null then
     select flag_estado
       into ls_estado_ov
       from orden_venta ov
      where ov.nro_ov     = ls_nro_ref for update;

     -- Si la Orden de Venta esta anulada no debo hacer nada
     if ls_estado_ov = '0' then
        RAISE_APPLICATION_ERROR(-20000, 'La Orden de Venta ' || ls_nro_ref || ' esta anulada');
        return;
     end if;

     select count(*)
       into ln_count
       from articulo_mov_proy amp
      where amp.tipo_doc    = ls_tipo_ref
        and amp.nro_doc     = ls_nro_ref
        and amp.flag_estado = '1';

     if ln_count = 0 then
        ls_Estado_ov := '2';  --Cerrado
     else
        ls_estado_ov := '1';  --Abierto
     end if;

    /*****************************************************
    **** REPLICACION
    *****************************************************/
    update orden_venta
       set flag_estado = ls_estado_ov,
           flag_replicacion = '0'
     where cod_origen = ls_origen_ref
       and nro_ov     = ls_nro_ref;
    /*****************************************************/
  end if;

  --===========================================================
  -- Modificado el 20/04/2007 x Jhonny Ramirez Chiroque
  -- Si es un Ingreso x Compra debo dismunir la cantidad
  -- reservada de reservacion_det, de esta manera disminuye la
  -- cantidad reservada en el requerimiento de la OT
  --==========================================================
  if ls_tipo_mov = ls_oper_ing_oc and :old.nro_reservacion is not null AND
     :old.item_reservacion IS NOT NULL then

     -- Obtengo los datos de reservacion_det que necesito para utilizarlos
     select NVL(cant_procesada,0), flag_estado, cantidad
       into ln_cant_proc_reserv , ls_flag_estado, ln_cant_reservado
       from reservacion_det t
      where t.nro_reservacion = :old.nro_reservacion
        and t.nro_item        = :old.item_reservacion FOR UPDATE;

     if ls_flag_estado <> '1' then
        RAISE_APPLICATION_ERROR(-20000, 'Item de Reservacion no se encuentra activo '
                                || chr(13) || 'Reservacion: ' || :old.nro_reservacion
                                || chr(13) || 'Item: ' || :old.item_reservacion);
     end if;

     if ln_cant_reservado - :old.cant_procesada < ln_cant_proc_reserv then
        RAISE_APPLICATION_ERROR(-20000, 'La cantidad reservada no puede ser menor que la cantidad que ya se retiro'
                                || chr(13) || 'Reservacion: ' || :old.nro_reservacion
                                || chr(13) || 'Item: ' || :old.item_reservacion
                                || chr(13) || 'Pendiente x retirar: ' || to_char(ln_cant_reservado - ln_cant_proc_reserv)
                                || chr(13) || 'Cant a devolver: ' || to_char(:old.cant_procesada));
     end if;

     if ln_cant_reservado - :old.cant_procesada < 0 then
        RAISE_APPLICATION_ERROR(-20000, 'Se genera Cantidad reservada en negativo '
                                || chr(13) || 'Reservacion: ' || :old.nro_reservacion
                                || chr(13) || 'Item: ' || :old.item_reservacion
                                || chr(13) || 'Cant reservada: ' || to_char(ln_cant_reservado)
                                || chr(13) || 'Cant a devolver: ' || to_char(:old.cant_procesada));
     end if;

     -- Actualizo la cantidad reservada disminuyendola
     ln_cant_reservado := ln_cant_reservado - :old.cant_procesada;

     update reservacion_det
        set cantidad = ln_cant_reservado
      where nro_reservacion  = :old.nro_reservacion
        and nro_item         = :old.item_reservacion;
  end if;

  --=================================================================
  -- Modificado el 20/04/2007 x Jhonny Ramirez Chiroque
  -- Si es una devolucion a almacen de una salida x consumo interno
  -- y esta amarrado a una reservacion_det, entonces debo incrementar
  -- la cant_procesada para disminuir la cantidad reservada del
  -- requerimiento de la OT
  --=================================================================
  if ls_tipo_mov_dev = ls_oper_cons_int  and :OLD.nro_reservacion IS NOT NULL AND
     :OLD.item_reservacion IS NOT NULL AND ls_tipo_ref = ls_doc_ot then

     -- Obtengo los datos de reservacion_det que necesito para utilizarlos
     select NVL(cant_procesada,0), flag_estado, cantidad
       into ln_cant_proc_reserv , ls_flag_estado, ln_cant_reservado
       from reservacion_det t
      where t.nro_reservacion = :OLD.nro_reservacion
        and t.nro_item        = :OLD.item_reservacion FOR UPDATE;

     if ls_flag_estado <> '1' then
        RAISE_APPLICATION_ERROR(-20000, 'Item de Reservacion no se encuentra activo '
                                || chr(13) || 'Reservacion: ' || :OLD.nro_reservacion
                                || chr(13) || 'Item: ' || :OLD.item_reservacion);
     end if;

     if ln_cant_proc_reserv + :OLD.cant_procesada > ln_cant_reservado then
        RAISE_APPLICATION_ERROR(-20000, 'La cantidad a retirar no puede superar a la cantidad reservada pendiente'
                                || chr(13) || 'Reservacion: ' || :OLD.nro_reservacion
                                || chr(13) || 'Item: ' || :OLD.item_reservacion
                                || chr(13) || 'Pendiente x retirar: ' || to_char(ln_cant_reservado - ln_cant_proc_reserv)
                                || chr(13) || 'Cant a retirar: ' || to_char(:OLD.cant_procesada));
     end if;

     -- Actualizo la cantidad procesada de reservacion_det incrementadola
     ln_cant_proc_reserv := ln_cant_proc_reserv + :OLD.cant_procesada;

     update reservacion_det
        set cant_procesada = ln_cant_proc_reserv
      WHERE nro_reservacion  = :OLD.nro_reservacion
        and nro_item         = :OLD.item_reservacion;

  end if;

  --==================================================
  -- Actualizacion Articulo
  --==================================================
  <<Grabacion_Articulo>>
  IF ln_fac_total <> 0 and :old.cant_procesada > 0 THEN
      /*****************************************************
        REPLICACION
      *****************************************************/
      UPDATE Articulo_almacen
         SET sldo_total      = ln_saldo_total,
             sldo_total_und2 = ln_saldo_total_und2,
             costo_prom_sol  = ln_costo_prom_sol,
             costo_prom_dol  = ln_costo_prom_dol,
             flag_Replicacion = '0'
       WHERE COD_ART = :old.cod_art
         and almacen = ls_almacen;
      --******************************************************

      IF SQL%NOTFOUND THEN
         RAISE_APPLICATION_ERROR( -20000, 'El Articulo ' || :old.cod_art ||
                         ' no existe en el Almacen ' || ls_almacen) ;
      END IF ;

  END IF;

  --====================================================================================
  -- Modificado el 20/04/2007 x Jhonny Ramirez Chiroque
  -- Si es un Devolucion de un Ingreso x Compra debo incrementar la cantidad reservada
  -- en reservacion_det, de esa manera se incrementa el saldo reservado, teniendo cuidado
  -- de no pasar la cantidad libre de la OT
  --====================================================================================
  if ls_tipo_mov_dev = ls_oper_ing_oc and :old.nro_reservacion is not null AND
     :old.item_reservacion IS NOT NULL THEN

     -- Obtengo el Nro_mov_proy de la OT para luego obtener la cant_libre de la OT
     select org_amp_ref    , nro_amp_ref
       into ls_org_amp_ot  , ln_nro_amp_ot
       from articulo_mov_proy amp
      where amp.cod_origen = :OLD.origen_mov_proy
        and amp.nro_mov    = :OLD.nro_mov_proy FOR UPDATE;

     -- Valido que si esta amarrado a una reservacion_det, entonces la OC debe estar
     -- referenciada obligatoriamente a una OT, sino de lo contrario es un error
     IF ls_org_amp_ot IS NULL OR ln_nro_amp_ot IS NULL THEN
        RAISE_APPLICATION_ERROR(-20000, 'La OC a la que esta amarrada este Mov de Almacen '
                                     || 'no esta amarrada a una OT, verifique por favor'
                                     || chr(13) || 'Reservacion: ' || :OLD.nro_reservacion
                                     || chr(13) || 'Item: ' || :OLD.item_reservacion);
     END IF;

     -- Obtengo la cantidad libre la OT, esto es muy importante, ya que no deberia reservar
     -- mas de esta cantidad
     ln_cant_libre_ot := usf_alm_cant_libre_ot(ls_org_amp_ot, ln_nro_amp_ot);

     -- Verifico el total reservado
     if :OLD.cant_procesada > ln_cant_libre_ot then
        RAISE_APPLICATION_ERROR(-20000, 'A ocurrido un error el item ' || :OLD.cod_origen || to_char(:OLD.nro_mov) || ', se esta reservando mas de la cantidad libre de la OT '
                     || chr(13) || 'Cant Ingr.: ' || to_Char(:OLD.cant_procesada)
                     || chr(13) || 'Cant Libe: '  || to_Char(ln_cant_libre_ot)
                     || chr(13) || 'Cod Art: '    || :OLD.cod_art
                     || chr(13) || 'Nro Req.:'    || ls_org_amp_ot || to_char(ln_nro_amp_ot));
     end if;

     -- Obtengo los datos de reservacion_det que necesito para utilizarlos
     select NVL(cant_procesada,0), flag_estado, cantidad
       into ln_cant_proc_reserv , ls_flag_estado, ln_cant_reservado
       from reservacion_det t
      where t.nro_reservacion = :old.nro_reservacion
        and t.nro_item        = :old.item_reservacion FOR UPDATE;

     if ls_flag_estado NOT IN ('1', '2') then
        RAISE_APPLICATION_ERROR(-20000, 'El Item de la reservacion esta en un estado inadecuado, por favor verifique'
                                || chr(13) || 'Reservacion: ' || :old.nro_reservacion
                                || chr(13) || 'Item: ' || :old.item_reservacion);
     end if;

     -- Actualizo la cantidad reservada disminuyendola
     ln_cant_reservado := ln_cant_reservado + :OLD.cant_procesada;

     update reservacion_det
        set cantidad = ln_cant_reservado
      where nro_reservacion  = :OLD.nro_reservacion
        and nro_item         = :OLD.item_reservacion;

  end if;

  --======================================================================================
  -- Modificado el 20/04/2007 x Jhonny Ramirez Chiroque
  -- Si es una salida x consumo interno y ademas esta amarrado al detalle
  -- de una reservacion_det, entonces debo disminuir la cantidad procesada
  -- de la reservacion_det, esto incrementara la cantidad reservada
  -- Ojo primero debo actualizar articulo_almacen para luego actualizar el saldo reservado
  --======================================================================================
  if :old.nro_reservacion is not null  and :OLD.item_reservacion IS NOT NULL and
     ls_tipo_mov = ls_oper_cons_int AND ls_tipo_ref = ls_doc_ot then

     -- Obtengo los datos de reservacion_det que necesito para utilizarlos
     select NVL(cant_procesada,0), flag_estado, cantidad
       into ln_cant_proc_reserv , ls_flag_estado, ln_cant_reservado
       from reservacion_det t
      where t.nro_reservacion = :OLD.nro_reservacion
        and t.nro_item        = :OLD.item_reservacion FOR UPDATE;

     -- Verifico el total reservado
     if ls_flag_estado NOT IN ('1', '2') THEN
        RAISE_APPLICATION_ERROR(-20000, 'El Item de la reservacion esta en un estado inadecuado, por favor verifique'
                               || chr(13) || 'Reservacion: ' || :old.nro_reservacion
                               || chr(13) || 'Nro Item: ' || :old.item_reservacion );
     END IF;

     if ln_cant_proc_reserv - :OLD.cant_procesada < 0 then
        RAISE_APPLICATION_ERROR(-20000, 'La cantidad a retirar no puede ser negativa'
                                || chr(13) || 'Reservacion: ' || :OLD.nro_reservacion
                                || chr(13) || 'Item: ' || :OLD.item_reservacion
                                || chr(13) || 'Cantidad Retirada: ' || to_char(ln_cant_proc_reserv)
                                || chr(13) || 'Cant a devolver: ' || to_char(:OLD.cant_procesada));
     end if;

     ln_cant_proc_reserv := ln_cant_proc_reserv - :OLD.cant_procesada;

     update reservacion_det
        set cant_procesada = ln_cant_proc_reserv
      where nro_reservacion  = :OLD.nro_reservacion
        and nro_item         = :OLD.item_reservacion;
  end if;

  --==================================================
  -- Actualizacion Templa_Saldo
  --==================================================
  IF usf_alm_cntrl_lote(ls_cntrl_lote_alm, ls_cntrl_lote_art) = 1
     AND :old.nro_lote IS NOT NULL and :old.cant_procesada > 0
     and ln_fac_templa <> 0 THEN

     IF ls_tipo_mov = ls_oper_ing_prod or ls_tipo_ref = ls_doc_otr THEN
        ln_cant_work  := :old.cant_procesada * ln_fac_templa;
        ln_cant_work2 := :old.cant_proc_und2 * ln_fac_templa;
     ELSE
        ln_cant_work  := 0;
        ln_cant_work2 := 0;
     END IF;
     /*****************************************************
       REPLICACION
     *****************************************************/
     Update templa_saldo t
        set t.cantidad_total  = NVL( t.cantidad_total,0 ) - ln_cant_work,
            t.cant_total_und2 = NVL( t.cant_total_und2,0 ) - ln_cant_work2,
            t.saldo           = NVL( t.saldo,0 ) - :old.cant_procesada * ln_fac_templa,
            t.saldo_und2      = NVL( t.saldo_und2,0 ) - NVL(:old.cant_proc_und2,0) * ln_fac_templa,
            t.flag_replicacion = '0'
      Where TRIM(cod_templa)  = TRIM(:old.nro_lote)
        and t.cod_art         = :old.cod_Art
        and t.almacen         = ls_almacen ;
     --******************************************************

      IF SQL%NOTFOUND THEN
         RAISE_APPLICATION_ERROR( -20000, 'La Templa ' || Trim(:old.nro_lote) || ' no Existe') ;
      END IF ;
  END IF;

  --=============================================================
  -- Actualizo la Tabla PRESUP_PRODUCCION_UND
  -- Siempre y cuando el movimiento sea de ingreso por produccion
  --=============================================================
  if ls_tipo_mov = ls_oper_ing_prod then

     if :old.cencos is null then return; end if;

     UPDATE PRESUP_PRODUCCION_UND P
        SET P.Ejec_Ene = P.Ejec_Ene + decode(to_char(ld_fec_registro, 'mm'),'01', nvl(:old.cant_procesada,0), 0),
            P.Ejec_Feb = P.Ejec_Feb + decode(to_char(ld_fec_registro, 'mm'),'02', nvl(:old.cant_procesada,0), 0),
            P.Ejec_Mar = P.Ejec_Mar + decode(to_char(ld_fec_registro, 'mm'),'03', nvl(:old.cant_procesada,0), 0),
            P.Ejec_Abr = P.Ejec_Abr + decode(to_char(ld_fec_registro, 'mm'),'04', nvl(:old.cant_procesada,0), 0),
            P.Ejec_May = P.Ejec_May + decode(to_char(ld_fec_registro, 'mm'),'05', nvl(:old.cant_procesada,0), 0),
            P.Ejec_Jun = P.Ejec_Jun + decode(to_char(ld_fec_registro, 'mm'),'06', nvl(:old.cant_procesada,0), 0),
            P.Ejec_Jul = P.Ejec_Jul + decode(to_char(ld_fec_registro, 'mm'),'07', nvl(:old.cant_procesada,0), 0),
            P.Ejec_Ago = P.Ejec_Ago + decode(to_char(ld_fec_registro, 'mm'),'08', nvl(:old.cant_procesada,0), 0),
            P.Ejec_Set = P.Ejec_Set + decode(to_char(ld_fec_registro, 'mm'),'09', nvl(:old.cant_procesada,0), 0),
            P.Ejec_Oct = P.Ejec_Oct + decode(to_char(ld_fec_registro, 'mm'),'10', nvl(:old.cant_procesada,0), 0),
            P.Ejec_Nov = P.Ejec_Nov + decode(to_char(ld_fec_registro, 'mm'),'11', nvl(:old.cant_procesada,0), 0),
            P.Ejec_Dic = P.Ejec_Dic + decode(to_char(ld_fec_registro, 'mm'),'12', nvl(:old.cant_procesada,0), 0)
      WHERE p.ano       = to_number(to_char(ld_fec_registro,'yyyy'))
        and p.cencos    = :old.cencos
        and p.cod_art   = :old.cod_art;

  elsif ls_tipo_mov_dev = ls_oper_ing_prod then

     if :old.cencos is null then return; end if;

     UPDATE PRESUP_PRODUCCION_UND P
        SET P.Ejec_Ene = P.Ejec_Ene - decode(to_char(ld_fec_registro, 'mm'),'01', nvl(:old.cant_procesada,0), 0),
            P.Ejec_Feb = P.Ejec_Feb - decode(to_char(ld_fec_registro, 'mm'),'02', nvl(:old.cant_procesada,0), 0),
            P.Ejec_Mar = P.Ejec_Mar - decode(to_char(ld_fec_registro, 'mm'),'03', nvl(:old.cant_procesada,0), 0),
            P.Ejec_Abr = P.Ejec_Abr - decode(to_char(ld_fec_registro, 'mm'),'04', nvl(:old.cant_procesada,0), 0),
            P.Ejec_May = P.Ejec_May - decode(to_char(ld_fec_registro, 'mm'),'05', nvl(:old.cant_procesada,0), 0),
            P.Ejec_Jun = P.Ejec_Jun - decode(to_char(ld_fec_registro, 'mm'),'06', nvl(:old.cant_procesada,0), 0),
            P.Ejec_Jul = P.Ejec_Jul - decode(to_char(ld_fec_registro, 'mm'),'07', nvl(:old.cant_procesada,0), 0),
            P.Ejec_Ago = P.Ejec_Ago - decode(to_char(ld_fec_registro, 'mm'),'08', nvl(:old.cant_procesada,0), 0),
            P.Ejec_Set = P.Ejec_Set - decode(to_char(ld_fec_registro, 'mm'),'09', nvl(:old.cant_procesada,0), 0),
            P.Ejec_Oct = P.Ejec_Oct - decode(to_char(ld_fec_registro, 'mm'),'10', nvl(:old.cant_procesada,0), 0),
            P.Ejec_Nov = P.Ejec_Nov - decode(to_char(ld_fec_registro, 'mm'),'11', nvl(:old.cant_procesada,0), 0),
            P.Ejec_Dic = P.Ejec_Dic - decode(to_char(ld_fec_registro, 'mm'),'12', nvl(:old.cant_procesada,0), 0)
      WHERE p.ano       = to_number(to_char(ld_fec_registro,'yyyy'))
        and p.cencos    = :old.cencos
        and p.cod_art   = :old.cod_art;
  end if;

  --=============================================================
  -- Actualizo la Tabla PRESUP_INGRESOS_UND
  -- Siempre y cuando el movimiento este amarrado a una OV
  --=============================================================
  if ls_tipo_ref = ls_doc_ov then

     if :old.cencos is null then return; end if;

     if ls_tipo_mov_dev is null then
         UPDATE PRESUP_INGRESOS_UND P
            SET P.Ejec_Ene = P.Ejec_Ene + decode(to_char(ld_fec_registro, 'mm'),'01', nvl(:old.cant_procesada,0), 0),
                P.Ejec_Feb = P.Ejec_Feb + decode(to_char(ld_fec_registro, 'mm'),'02', nvl(:old.cant_procesada,0), 0),
                P.Ejec_Mar = P.Ejec_Mar + decode(to_char(ld_fec_registro, 'mm'),'03', nvl(:old.cant_procesada,0), 0),
                P.Ejec_Abr = P.Ejec_Abr + decode(to_char(ld_fec_registro, 'mm'),'04', nvl(:old.cant_procesada,0), 0),
                P.Ejec_May = P.Ejec_May + decode(to_char(ld_fec_registro, 'mm'),'05', nvl(:old.cant_procesada,0), 0),
                P.Ejec_Jun = P.Ejec_Jun + decode(to_char(ld_fec_registro, 'mm'),'06', nvl(:old.cant_procesada,0), 0),
                P.Ejec_Jul = P.Ejec_Jul + decode(to_char(ld_fec_registro, 'mm'),'07', nvl(:old.cant_procesada,0), 0),
                P.Ejec_Ago = P.Ejec_Ago + decode(to_char(ld_fec_registro, 'mm'),'08', nvl(:old.cant_procesada,0), 0),
                P.Ejec_Set = P.Ejec_Set + decode(to_char(ld_fec_registro, 'mm'),'09', nvl(:old.cant_procesada,0), 0),
                P.Ejec_Oct = P.Ejec_Oct + decode(to_char(ld_fec_registro, 'mm'),'10', nvl(:old.cant_procesada,0), 0),
                P.Ejec_Nov = P.Ejec_Nov + decode(to_char(ld_fec_registro, 'mm'),'11', nvl(:old.cant_procesada,0), 0),
                P.Ejec_Dic = P.Ejec_Dic + decode(to_char(ld_fec_registro, 'mm'),'12', nvl(:old.cant_procesada,0), 0)
          WHERE p.ano       = to_number(to_char(ld_fec_registro,'yyyy'))
            and p.cencos    = :old.cencos
            and p.cod_art   = :old.cod_art;

     else

         UPDATE PRESUP_INGRESOS_UND P
            SET P.Ejec_Ene = P.Ejec_Ene - decode(to_char(ld_fec_registro, 'mm'),'01', nvl(:old.cant_procesada,0), 0),
                P.Ejec_Feb = P.Ejec_Feb - decode(to_char(ld_fec_registro, 'mm'),'02', nvl(:old.cant_procesada,0), 0),
                P.Ejec_Mar = P.Ejec_Mar - decode(to_char(ld_fec_registro, 'mm'),'03', nvl(:old.cant_procesada,0), 0),
                P.Ejec_Abr = P.Ejec_Abr - decode(to_char(ld_fec_registro, 'mm'),'04', nvl(:old.cant_procesada,0), 0),
                P.Ejec_May = P.Ejec_May - decode(to_char(ld_fec_registro, 'mm'),'05', nvl(:old.cant_procesada,0), 0),
                P.Ejec_Jun = P.Ejec_Jun - decode(to_char(ld_fec_registro, 'mm'),'06', nvl(:old.cant_procesada,0), 0),
                P.Ejec_Jul = P.Ejec_Jul - decode(to_char(ld_fec_registro, 'mm'),'07', nvl(:old.cant_procesada,0), 0),
                P.Ejec_Ago = P.Ejec_Ago - decode(to_char(ld_fec_registro, 'mm'),'08', nvl(:old.cant_procesada,0), 0),
                P.Ejec_Set = P.Ejec_Set - decode(to_char(ld_fec_registro, 'mm'),'09', nvl(:old.cant_procesada,0), 0),
                P.Ejec_Oct = P.Ejec_Oct - decode(to_char(ld_fec_registro, 'mm'),'10', nvl(:old.cant_procesada,0), 0),
                P.Ejec_Nov = P.Ejec_Nov - decode(to_char(ld_fec_registro, 'mm'),'11', nvl(:old.cant_procesada,0), 0),
                P.Ejec_Dic = P.Ejec_Dic - decode(to_char(ld_fec_registro, 'mm'),'12', nvl(:old.cant_procesada,0), 0)
          WHERE p.ano       = to_number(to_char(ld_fec_registro,'yyyy'))
            and p.cencos    = :old.cencos
            and p.cod_art   = :old.cod_art;

     end if;
  end if;

end TDA_ARTICULO_MOV;
/

prompt
prompt Creating trigger TDA_ARTICULO_MOV_PROY
prompt ======================================
prompt
CREATE OR REPLACE TRIGGER CANTABRIA.TDA_ARTICULO_MOV_PROY
  AFTER DELETE on articulo_mov_proy
  for each row

DECLARE
  -- LogParam
  ls_doc_otr           logparam.doc_otr%TYPE;
  ls_oper_ing_otr      logparam.oper_ing_otr%TYPE;
  ls_oper_sal_otr      logparam.oper_sal_otr%TYPE;
  ls_doc_sc            logparam.doc_sc%TYPE;
  ls_doc_prog          logparam.tipo_doc_prog_cmp%TYPE;
  ls_doc_oc            logparam.doc_oc%TYPE;
  ls_doc_ot            logparam.doc_ot%TYPE;

  -- Articulo_Mov_Tipo
  ln_fac_xllegar       articulo_mov_tipo.factor_sldo_x_llegar%type;
  ln_fac_sol           articulo_mov_tipo.factor_sldo_sol%type;
  ln_fac_reservado     articulo_mov_tipo.factor_sldo_reservado%TYPE;

  -- Articulo
  ls_flag_estado       articulo.flag_estado%TYPE;
  ls_flag_invent       articulo.flag_inventariable%TYPE;

  -- Articulo_almacen
  ln_saldo_llegar      articulo_almacen.sldo_por_llegar%type;
  ln_saldo_solicit     articulo_almacen.sldo_solicitado%type;
  ln_saldo_reserv      articulo_almacen.sldo_reservado%TYPE;
  ln_saldo_transport   articulo_almacen.sldo_transportado%TYPE;

  -- Varios
  ls_flag_Articulo     char(1);
  ln_count             number;

  -- Programa de Compras
  ln_cant_proc_prog    prog_compras_det.cant_procesada%TYPE;
  ln_cant_proy_prog    prog_compras_det.cant_proyect%TYPE;
  ls_estado_prog       prog_compras_det.flag_estado%TYPE;

  -- Parametros Origen
  ls_flag_prsp_igv     origen.flag_prsp_igv%TYPE;

begin

  --==============================================================
  -- Si el movimiento esta anulado o pendiente simplemente retorno
  --==============================================================
  if :old.flag_estado in ('0', '3') then return; end if;

  --===============================================
  -- Lectura de parametros de logparam
  --===============================================
  select doc_sc, doc_otr, oper_sal_otr, oper_ing_otr, tipo_doc_prog_cmp,
         doc_oc, doc_ot
    into ls_doc_sc, ls_doc_otr, ls_oper_sal_otr, ls_oper_ing_otr, ls_doc_prog,
         ls_doc_oc, ls_doc_ot
  from logparam
  where reckey = '1';

  --===============================================
  -- Parametros por Origen
  --===============================================
  Select NVL(o.flag_prsp_igv,'0')
    into ls_flag_prsp_igv
    from origen o
   where o.cod_origen = :old.cod_origen;

  --===============================================
  -- Verificacion de parametros
  --===============================================
  if ls_doc_otr is null then
     RAISE_APPLICATION_ERROR(-20000, 'No ha definido Documento de Orden de traslado en LogParam');
  end if;

  if ls_doc_prog is null then
     RAISE_APPLICATION_ERROR(-20000, 'No ha definido Documento PROGRAMA DE COMPRAS en LogParam');
  end if;

  --==========================================================================
  -- Verifico que no pueda eliminar un amp que ya tenga movimiento de almacen
  --==========================================================================
  if :old.tipo_doc = ls_doc_otr then
     if :old.tipo_mov = ls_oper_sal_otr then
       if :old.cant_procesada > 0 then
          RAISE_APPLICATION_ERROR( -20000, 'NO SE PUEDE ELIMINAR REGISTRO, TIENE SALIDAS DE ALMACEN');
          return;
       end if;
       if :old.cant_facturada > 0 then
          RAISE_APPLICATION_ERROR( -20000, 'NO SE PUEDE ELIMINAR REGISTRO, TIENE INGRESOS A ALMACEN');
          return;
       end if;
     end if;
  else
     if :old.cant_procesada > 0 then
        RAISE_APPLICATION_ERROR( -20000, 'NO SE PUEDE ELIMINAR REGISTRO, TIENE CANTIDAD PROCESADA');
        return;
     end if;
     if :old.cant_facturada > 0 then
        RAISE_APPLICATION_ERROR( -20000, 'NO SE PUEDE ELIMINAR REGISTRO, TIENE CANTIDAD FACTURADA');
        return;
     end if;
     if :old.cant_reservado > 0 then
        RAISE_APPLICATION_ERROR( -20000, 'NO PUEDE ELIMINAR REGISTRO, TIENE CANTIDAD RESERVADA');
        return;
     end if;
  end if;

  --===============================================
  -- Actualiza costo estimado de orden de trabajo
  --===============================================
  IF :old.tipo_doc = ls_doc_ot THEN

     UPDATE orden_trabajo ot
        SET ot.costo_estimado = NVL(costo_estimado,0) -
                                NVL(:old.cant_proyect,0) * NVL(:old.precio_unit,0)
      WHERE ot.nro_orden = :old.nro_doc ;

  END IF ;

  --===============================================
  -- Lectura de los Factores x tipo de Movimiento
  --===============================================
  SELECT Nvl(factor_sldo_x_llegar,0), Nvl(factor_sldo_sol,0), NVL(factor_sldo_reservado, 0)
    INTO ln_fac_xllegar, ln_fac_sol, ln_fac_reservado
    FROM articulo_mov_tipo
  WHERE  tipo_mov  = :old.tipo_mov ;

  --===============================================
  -- Lectura de Articulo
  --===============================================
  SELECT NVL(flag_estado, '0'), NVL(flag_inventariable,0)
    INTO ls_flag_estado, ls_flag_invent
    FROM articulo
   WHERE cod_art = :old.cod_art FOR UPDATE;

  --===============================================
  -- Lectura de ARTICULO_ALMACEN
  --===============================================
  select count(*)
    into ln_count
    from articulo_almacen
   where cod_art = :old.cod_art
     and almacen = :old.almacen;

  if ln_count > 0 then
     SELECT NVL(sldo_por_llegar,0), NVL(sldo_solicitado,0),
            NVL(sldo_reservado, 0), NVL(sldo_transportado, 0)
       INTO ln_saldo_llegar, ln_saldo_solicit,
            ln_saldo_reserv, ln_saldo_transport
       FROM articulo_almacen
      WHERE cod_art = :old.cod_art
        and almacen = :old.almacen FOR UPDATE;
  else
     ln_saldo_llegar    := 0;
     ln_saldo_solicit   := 0;
     ln_saldo_reserv    := 0;
     ln_saldo_transport := 0;
  end if;

  --===============================================
  -- Actualizar Saldos Proyectados Articulo
  --===============================================
  IF ls_flag_invent = '1' THEN
     ls_flag_articulo   := 'S';
     ln_saldo_llegar    := ln_saldo_llegar  + (NVL(:old.cant_proyect,0) - NVL(:old.cant_procesada,0)) * ln_fac_xllegar;
     ln_saldo_solicit   := ln_saldo_solicit + (NVL(:old.cant_proyect,0) - NVL(:old.cant_procesada,0)) * ln_fac_sol;
     ln_saldo_reserv    := ln_saldo_reserv + NVL(:old.cant_reservado,0) * ln_fac_reservado;
     ln_saldo_transport := ln_saldo_transport - :OLD.cant_transportada;

     if ln_saldo_llegar < 0 then
        RAISE_APPLICATION_ERROR(-20000, 'El Saldo x llegar no puede ser negativo: '
                              || to_char(ln_saldo_llegar)
                              || chr(13) || 'Factor Saldo x llegar: ' || to_Char(ln_fac_xllegar)
                              || chr(13) || 'Tipo de movimiento: ' || :old.tipo_mov
                              || chr(13) || 'Codigo Articulo: ' || :old.cod_Art);

        return;
     end if;

     if ln_saldo_solicit < 0 then
        RAISE_APPLICATION_ERROR(-20000, 'El Saldo Solicitado no puede ser negativo: '
                                       || to_char(ln_saldo_solicit)
                                       || chr(13) || 'Factor Saldo solicitado: ' || to_Char(ln_fac_sol)
                                       || chr(13) || 'Tipo de movimiento: ' || :old.tipo_mov
                                       || chr(13) || 'Codigo Articulo   : ' || :old.cod_art);
        return;
     end if;

     if ln_saldo_reserv < 0 then
        RAISE_APPLICATION_ERROR(-20000, 'El Saldo Reservado no puede ser negativo: '
                                       || to_char(ln_saldo_reserv)
                                       || chr(13) || 'Factor Saldo solicitado: ' || to_Char(ln_fac_reservado)
                                       || chr(13) || 'Tipo de movimiento: ' || :old.tipo_mov
                                       || chr(13) || 'Codigo Articulo   : ' || :old.cod_art);
        return;
     end if;

     if ln_saldo_transport < 0 then
        RAISE_APPLICATION_ERROR(-20000, 'El Saldo Transportado no puede ser negativo: '
                                       || to_char(ln_saldo_transport)
                                       || chr(13) || 'Cant Transportada: ' || to_Char(:OLD.cant_transportada)
                                       || chr(13) || 'Tipo de movimiento: ' || :old.tipo_mov
                                       || chr(13) || 'Codigo Articulo   : ' || :old.cod_art);
        return;
     end if;

  END IF;

  --===============================================
  -- Actualizar Datos de Presupuesto_Ejec
  --===============================================
  IF NVL(:old.flag_crg_inm_prsp, '0') = '1' or (ls_flag_prsp_igv = '1' and :old.tipo_doc = ls_doc_oc) THEN
     DELETE presupuesto_ejec
      WHERE origen_ref   = :old.cod_origen
        AND tipo_doc_ref = :old.tipo_doc
        AND nro_doc_ref  = :old.nro_doc
        AND item_ref     = :old.nro_mov  ;
  END IF;

  --===============================================
  -- Grabacion Articulos
  --===============================================
  IF ls_flag_articulo = 'S' THEN

     /*****************************************************
     **** REPLICACION
     *****************************************************/
     UPDATE Articulo_Almacen
        SET sldo_por_llegar  = ln_saldo_llegar,
            sldo_solicitado  = ln_saldo_solicit,
            sldo_reservado   = ln_saldo_reserv,
            sldo_transportado= ln_saldo_transport,
            flag_replicacion = '0'
       WHERE COD_ART = :old.cod_art
         and almacen = :old.almacen ;
     /*****************************************************/
  END IF;

  --===============================================
  -- Eliminar el enlace con la Solicitud de Compra
  --===============================================
  IF :old.tipo_doc = ls_doc_oc and :old.tipo_ref = ls_doc_sc THEN
     /*****************************************************
     **** REPLICACION
     *****************************************************/
      UPDATE sol_comp_det sc
         set sc.nro_mov         = null,
             sc.origen_mov_proy = null,
             sc.cant_procesada  = Nvl(sc.cant_procesada,0) - (NVL(:old.cant_proyect,0) - NVL(:old.cant_procesada,0)),
             flag_replicacion   = '0'
       where nro_sol_comp = :old.referencia
         and cod_art      = :old.cod_art;
     /*****************************************************/
  END IF;

  -- ====================================================================================
  -- Si es una Orden de Compras amarrada con un programa de Compra debo disminuir la
  -- cantidad Procesada
  -- ====================================================================================
  IF :old.tipo_doc = ls_doc_oc and :old.tipo_ref = ls_doc_prog and
     :old.flag_estado = '1' THEN

     select count(*)
       into ln_count
       from prog_compras_det
      where nro_programa = :old.referencia
        and nro_item     = :old.item_ref;

     if ln_count = 0 then
        RAISE_APPLICATION_ERROR(-20000, 'No existe Item en Programa de Compras: '
                    || chr(13) || chr(10) || 'Nro Programa: ' || :old.referencia
                    || chr(13) || chr(10) || 'Nro Item: ' || to_char(:old.item_ref));
        return;
     end if;

     select nvl(cant_procesada,0), nvl(cant_proyect,0), flag_estado
       into ln_cant_proc_prog, ln_cant_proy_prog, ls_estado_prog
       from prog_compras_det
      where nro_programa = :old.referencia
        and nro_item     = :old.item_ref for update;

     ln_cant_proc_prog := ln_cant_proc_prog - NVL(:old.cant_proyect,0);

     if ln_cant_proc_prog >= ln_cant_proy_prog then
        ls_estado_prog := '2';
     else
        ls_estado_prog := '1';
     end if;

     update prog_compras_det
        set cant_procesada = ln_cant_proc_prog,
            flag_estado    = ls_estado_prog,
            flag_replicacion = '0'
      where nro_programa = :old.referencia
        and nro_item     = :old.item_ref;

  END IF;

end TDA_ARTICULO_MOV_PROY;
/

prompt
prompt Creating trigger TDA_CNTBL_ASIENTO_DET
prompt ======================================
prompt
CREATE OR REPLACE TRIGGER CANTABRIA.TDA_CNTBL_ASIENTO_DET
  after delete on cntbl_asiento_det
  for each row

declare
  -- local variables here
  ln_n1              cntblparam.nivel1%type  ;
  ln_n2              cntblparam.nivel2%type  ;
  ln_n3              cntblparam.nivel3%type  ;
  ln_n4              cntblparam.nivel4%type  ;
  ln_n5              cntblparam.nivel5%type  ;
  ln_n6              cntblparam.nivel6%type  ;
  ln_n7              cntblparam.nivel7%type  ;
  ln_n8              cntblparam.nivel8%type  ;
  ln_n9              cntblparam.nivel9%type  ;
  ln_n10             cntblparam.nivel10%type  ;
  ls_cuenta          VARCHAR2(10);


begin

-- Edgar Morante Miercoles 10Jul2002, replicacion
If (dbms_reputil.from_remote=true or dbms_snapshot.i_am_a_refresh=true) then
   return;
end if;

-- Lectura de tama?o de niveles
SELECT nivel1, nivel2, nivel3, nivel4, nivel5, nivel6,
       nivel7, nivel8, nivel9, nivel10
  INTO ln_n1, ln_n2, ln_n3, ln_n4, ln_n5, ln_n6,
       ln_n7, ln_n8, ln_n9, ln_n10
  FROM cntblparam
 WHERE reckey = '1' ;

-- Sumar Saldos a Tabla CNTBL_CNTA_SDO
ls_cuenta    := :old.cnta_ctbl ;
SELECT rtrim(ls_cuenta, ' ')
  INTO ls_cuenta
  FROM dual ;


end TDA_CNTBL_ASIENTO_DET;
/

prompt
prompt Creating trigger TDA_FIN_CAJA_BANCOS_DET
prompt ========================================
prompt
CREATE OR REPLACE TRIGGER CANTABRIA.TDA_FIN_CAJA_BANCOS_DET
  after delete on caja_bancos_det
  for each row
declare

-- local variables here
lc_flag_tiptran     caja_bancos.flag_tiptran%type ;
ln_Tasa_cambio      caja_bancos.tasa_cambio%type  ;
lc_origen           caja_bancos.origen%type       ;
ln_ano              caja_bancos.ano%type          ;
ln_mes              caja_bancos.mes%type          ;
ln_nro_libro        caja_bancos.nro_libro%type    ;
ln_nro_asiento      caja_bancos.nro_asiento%type  ;
ln_monto_total      caja_bancos.imp_total%type    ;
ln_saldo_sol        caja_bancos.imp_total%type    ;
ln_saldo_dol        caja_bancos.imp_total%type    ;
ln_imp_dol_old      caja_bancos.imp_total%type    ;
ln_imp_sol_old      caja_bancos.imp_total%type    ;
ln_saldo_sol_old    caja_bancos.imp_total%type    ;
ln_saldo_dol_old    caja_bancos.imp_total%type    ;
ln_Tasa_cambio_old      caja_bancos.tasa_cambio%type  ;
ls_soles            moneda.cod_moneda%type        ;
ls_dolares          moneda.cod_moneda%type        ;
lc_flag_estado      caja_bancos.flag_estado%type  ;
lc_flag_estado_og   caja_bancos.flag_estado%type  ;
ln_count            number                        ;
lc_flag_debhab_esp  doc_pendientes_cta_cte.flag_debhab%type   ;
ln_factor_esp       doc_pendientes_cta_cte.factor%type        ;
lc_flag_ctrl_reg    cntas_cobrar.flag_control_reg%type        ;
lc_flag_caja_bancos cntas_pagar.flag_caja_bancos%type         ;
lc_cnta_ctbl        doc_pendientes_cta_cte.cnta_ctbl%type     ;
lc_cta_ctbl_gan     doc_pendientes_cta_cte.cnta_ctbl%type     ;
lc_cta_ctbl_per     doc_pendientes_cta_cte.cnta_ctbl%type     ;
lc_nro_sol_cred     rrhh_credito_solicitud.nro_solicitud%type ;
ln_existe_cnta_crrte integer                                  ;
lb_control           Boolean ;

-- Presupuesto_caja
ls_moneda_prsp       prsp_caja_det.cod_moneda%TYPE;
ln_imp_ejecutado     prsp_caja_det.imp_ejecutado%TYPE;

-- Comprobante de retencion
ls_doc_cri           finparam.doc_ret_igv_crt%TYPE;
ls_flag_tiptran      caja_bancos.flag_tiptran%TYPE;
ln_imp_soles         retencion_igv_crt.saldo_sol%TYPE;
ln_imp_dolar         retencion_igv_crt.saldo_dol%TYPE;
ln_imp_retencion     retencion_igv_crt.importe_doc%TYPE;
ln_tcambio_cri       retencion_igv_crt.tasa_cambio%TYPE;


--  Inicio de modificacion realizada por JORGE. FARFAN LINEA 486

begin

  /*******************************************************
   REPLICACION
  ********************************************************/
  IF ORA_LOGIN_USER = 'REPP5' THEN
     RETURN ;
  END IF;

  --INICIALIZACION DE VARIABLES
  lb_control := FALSE ;

  --tabla de parametros
  select l.cod_soles,l.cod_dolares
    into ls_soles,ls_dolares
    from logparam l
   where l.reckey = '1';

  select f.doc_ret_igv_crt
    into ls_doc_cri
    from finparam f
   where f.reckey = '1';

  --cabecera de caja bancos
  select cb.flag_tiptran ,cb.tasa_cambio, cb.origen       ,cb.ano        ,
         cb.mes          ,cb.nro_libro  , cb.nro_asiento  ,cb.flag_tiptran
    into lc_flag_tiptran ,ln_Tasa_cambio  ,lc_origen       ,ln_ano      ,
         ln_mes          ,ln_nro_libro    ,ln_nro_asiento  ,ls_flag_tiptran
    from caja_bancos cb
   where cb.origen       = :old.origen
     and cb.nro_registro = :old.nro_registro ;

  -- Los cri solo pueden pagarse por cartera de pagos, al ser un documento exclusivo de pago para retenciones
  if :old.tipo_doc = ls_doc_cri then


     if ls_flag_tiptran <> '2' then
        RAISE_APPLICATION_ERROR(-20000, 'Los comprobantes de Retencion solo pueden estar en cartera de pagos, por favor verifique!'
                                   || chr(13) || 'Cod Relacion: ' || :old.cod_relacion
                                   || chr(13) || 'Tipo Doc: ' || :old.tipo_doc
                                   || chr(13) || 'Nro Doc: ' || :old.nro_doc);
     end if;

     -- Si es cartera de pagos entonces simplemente obtengo los datos que necesito
     -- Obtengo los datos del comprobante de retencion
     select count(*)
       into ln_count
       from retencion_igv_crt t
      where t.nro_certificado = :old.nro_doc;

     if ln_count = 0 then
        RAISE_APPLICATION_ERROR(-20000, 'El Comprobante de retencion no existe, por favor verifique!'
                                   || chr(13) || 'Cod Relacion: ' || :old.cod_relacion
                                   || chr(13) || 'Tipo Doc: ' || :old.tipo_doc
                                   || chr(13) || 'Nro Doc: ' || :old.nro_doc);
     end if;

     if :old.cod_moneda = ls_soles then
        ln_imp_soles := :old.importe;
        ln_imp_dolar := :old.importe / ln_tasa_cambio;
     else
        ln_imp_soles := :old.importe * ln_tasa_cambio;
        ln_imp_dolar := :old.importe;
     end if;

     select saldo_sol, saldo_dol, t.tasa_cambio
       into ln_saldo_sol, ln_saldo_dol, ln_tcambio_cri
       from retencion_igv_crt t
      where t.nro_certificado = :old.nro_doc for update;

     if ln_saldo_sol + ln_imp_soles >= ln_imp_retencion then
        ln_saldo_sol := ln_imp_retencion;
        ln_saldo_dol := ln_saldo_sol / ln_tcambio_cri;
        /*RAISE_APPLICATION_ERROR(-20000, 'Importe por Pagado excede al saldo del Comprobante de Retencion, por favor verifique!'
                                   || chr(13) || 'Cod Relacion: ' || :old.cod_relacion
                                   || chr(13) || 'Tipo Doc: ' || :old.tipo_doc
                                   || chr(13) || 'Nro Doc: ' || :old.nro_doc
                                   || chr(13) || 'Saldo S/.: ' || to_Char(ln_saldo_sol, '999,990.00')
                                   || chr(13) || 'Importe a Pagar: ' || to_Char(ln_imp_soles, '999,990.00'));*/

     else
     	  ln_saldo_sol := ln_saldo_sol + ln_imp_soles;
        ln_saldo_dol := ln_saldo_dol + ln_imp_dolar;
     end if;

     if ln_saldo_dol > ln_imp_retencion / ln_tcambio_cri then
        ln_saldo_dol := ln_saldo_sol / ln_tcambio_cri;
     end if;

     update retencion_igv_crt r
        set r.saldo_sol = ln_saldo_sol,
            r.saldo_dol = ln_saldo_dol
      where r.nro_certificado = :old.nro_doc;

  end if;

  --Este cambio corresponde a la ejecucion del presupuesto de Caja
  if :old.nro_prsp is not null and :old.item_prsp is not null then
     -- Obtengo la moneda de la cabecera del presupuesto de caja
     select cod_moneda, nvl(pd.imp_ejecutado, 0)
       into ls_moneda_prsp, ln_imp_ejecutado
       from prsp_caja_det pd
      where pd.nro_presupuesto  = :old.nro_prsp
        and pd.nro_item         = :old.item_prsp for update;

     if :old.cod_moneda = ls_moneda_prsp then
        ln_imp_ejecutado := ln_imp_ejecutado - :old.importe;
     elsif :old.cod_moneda = ls_soles then
        ln_imp_ejecutado := ln_imp_ejecutado - :old.importe * ln_tasa_cambio;
     elsif :old.cod_moneda = ls_dolares then
        ln_imp_ejecutado := ln_imp_ejecutado - :old.importe / ln_tasa_cambio;
     end if;

     if ln_imp_ejecutado < 0 then ln_imp_ejecutado := 0; end if;

     -- Actualizo el importe ejecutado
     update prsp_caja_det pd
        set pd.imp_ejecutado = ln_imp_ejecutado
      where pd.nro_presupuesto  = :old.nro_prsp
        and pd.nro_item         = :old.item_prsp;

  end if;



IF  (lc_flag_tiptran = '2' OR lc_flag_tiptran = '3' OR lc_flag_tiptran = '4') THEN
    --CARTERA DE PAGOS ,CARTERA DE COBROS ,APLICACION DE DOCUEMNTOS

    if :old.flab_tabor = '1' then --cuentas por cobrar

       select count(*)
         into ln_count
         from cntas_cobrar cc
        where cc.tipo_doc     = :old.tipo_doc
          and cc.nro_doc      = :old.nro_doc ;

       if ln_count = 0 then
          RAISE_APPLICATION_ERROR(-20000, 'Error, no existe el documento en Cntas x Cobrar, por favor verifique!'
                               || chr(13) || 'Tipo Doc : ' || :old.tipo_doc
                               || chr(13) || 'Nro Doc : ' || :old.nro_doc ) ;
       end if;

       select cc.flag_estado,cc.flag_caja_bancos,cc.flag_control_reg,cc.nro_sol_cred_rrhh
         into lc_flag_estado,lc_flag_caja_bancos,lc_flag_ctrl_reg,lc_nro_sol_cred
         from cntas_cobrar cc
        where cc.tipo_doc     = :old.tipo_doc
          and cc.nro_doc      = :old.nro_doc      ;

       /*verificaicon de asignacion en grupo de doc tipo cta cte*/
       select count(*)
         into ln_count
         from doc_grupo_relacion dg
        where dg.grupo    = 'C1'
          and dg.tipo_doc = :old.tipo_doc ;

    elsif :old.flab_tabor = '3' then --cuentas por pagar
       select count(*)
         into ln_count
         from cntas_pagar cp
        where cp.cod_relacion = :old.cod_relacion
          and cp.tipo_doc     = :old.tipo_doc
          and cp.nro_doc      = :old.nro_doc;

       if ln_count = 0 then
          return;
       end if;


        select cp.flag_estado,cp.flag_caja_bancos,cp.flag_control_reg,cp.nro_sol_cred_rrhh
          into lc_flag_estado,lc_flag_caja_bancos,lc_flag_ctrl_reg,lc_nro_sol_cred
          from cntas_pagar cp
         where (cp.cod_relacion = :old.cod_relacion ) and
               (cp.tipo_doc     = :old.tipo_doc     ) and
               (cp.nro_doc      = :old.nro_doc      ) ;

        /*verificaicon de asignaci?n en grupo de doc tipo cta cte*/
        select count(*)
          into ln_count
          from doc_grupo_relacion dg
         where (trim(dg.grupo)  = 'C2') and (dg.tipo_doc =:old.tipo_doc );

    end if ;


    if lc_flag_ctrl_reg = '1' and lc_flag_caja_bancos = '1' then --documento por cobrar verifico si es cuenta corriente
       if ln_count = 0 then
          raise_application_error(-20000,'Verifique Documento '||:old.tipo_doc||' no esta Considerado en Grupo de Cta Cte') ;
       end if ;


       if lc_flag_tiptran = '2' or lc_flag_tiptran = '4' then --cartera de pagos y aplicacion de documentos
          if :old.factor = -1  and :old.flab_tabor = '1' then --primer cobro de cntas cobrar
             --datos de cta cte
             USP_FIN_DATOS_PEND_CTA_CTE(:old.cod_relacion,:old.tipo_doc,:old.nro_doc,lc_flag_debhab_esp,ln_factor_esp);

             if lc_flag_debhab_esp = 'H' then
               lc_flag_debhab_esp := 'D' ;
             else
               --verifique flag_debhab de documento
               raise_application_error(-20000,'Verifque Flag Deb_Haber del documento ...'||:old.cod_relacion ||' '||:old.tipo_doc||' '||:old.nro_doc);
             end if ;

             if ln_factor_esp = '-1' then
                ln_factor_esp := '1' ;
             else
                --verifique factor del documento
                raise_application_error(-20000,'Verifque Flag Deb_Haber del documento .... '||:old.cod_relacion ||' '||:old.tipo_doc||' '||:old.nro_doc);
             end if ;

             --enciende control de cta cte
             lb_control := TRUE ;

          elsif :old.factor = 1  and :old.flab_tabor = '3' then --primer pago de cntas pagar
             --datos de cta cte
             USP_FIN_DATOS_PEND_CTA_CTE(:old.cod_relacion,:old.tipo_doc,:old.nro_doc,lc_flag_debhab_esp,ln_factor_esp);

             if lc_flag_debhab_esp = 'D' or lc_flag_debhab_esp is null then
                lc_flag_debhab_esp := 'H' ;
             else
                lc_flag_debhab_esp := 'D';
             --else
               --verifique flag_debhab de documento
             --  raise_application_error(-20000,'Verifque Flag Deb_Haber del documento .'||:old.cod_relacion ||' '||:old.tipo_doc||' '||:old.nro_doc);
             end if ;



             if ln_factor_esp = 1 or ln_factor_esp is null then
                ln_factor_esp := -1 ;
             else
                ln_factor_esp := 1;
                --verifique factor del documento
                --raise_application_error(-20000,'Verifque Factor del documento '||:old.cod_relacion ||' '||:old.tipo_doc||' '||:old.nro_doc);
             end if ;




             --enciende control de cta cte
             lb_control := TRUE ;

          end if ;

        elsif lc_flag_tiptran = '3' then --cartera de cobros

           if :old.factor = 1  and :old.flab_tabor = '1' then --primer cobro de cntas cobrar
             --datos de cta cte
             USP_FIN_DATOS_PEND_CTA_CTE(:old.cod_relacion,:old.tipo_doc,:old.nro_doc,lc_flag_debhab_esp,ln_factor_esp);

              if lc_flag_debhab_esp = 'H' then
                 lc_flag_debhab_esp := 'D' ;
              else
                 --verifique flag_debhab de documento
                 raise_application_error(-20000,'Verifque Flag Deb_Haber del documento '||:old.cod_relacion ||' '||:old.tipo_doc||' '||:old.nro_doc);
              end if ;


             if ln_factor_esp = '-1' then
                ln_factor_esp := '1' ;
             else
                --verifique factor del documento
                raise_application_error(-20000,'Verifque Flag Deb_Haber del documento '||:old.cod_relacion ||' '||:old.tipo_doc||' '||:old.nro_doc);
             end if ;

             --enciende control de cta cte
             lb_control := TRUE ;


          elsif :old.factor = -1  and :old.flab_tabor = '3' then --primer pago de cntas pagar
             --datos de cta cte
             USP_FIN_DATOS_PEND_CTA_CTE(:old.cod_relacion,:old.tipo_doc,:old.nro_doc,lc_flag_debhab_esp,ln_factor_esp);

             if lc_flag_debhab_esp = 'D' then
                lc_flag_debhab_esp := 'H' ;
             else
               --verifique flag_debhab de documento
               raise_application_error(-20000,'Verifque Flag Deb_Haber del documento '||:old.cod_relacion ||' '||:old.tipo_doc||' '||:old.nro_doc);
             end if ;


             if ln_factor_esp = '1' then
                ln_factor_esp := '-1' ;
             else
                --verifique factor del documento
                raise_application_error(-20000,'Verifque Flag Deb_Haber del documento '||:old.cod_relacion ||' '||:old.tipo_doc||' '||:old.nro_doc);
             end if ;

             --enciende control de cta cte
             lb_control := TRUE ;

          end if ;
        end if ;

        IF lb_control = TRUE THEN
           if lc_flag_estado <> '1' then
              raise_application_error(-20000,'Verifique Documento'||:old.cod_relacion||' '||:old.tipo_doc||' '||:old.nro_doc ||' ya ha sido Aplicado') ;

           end if ;

           if :old.flab_tabor = '3' then --ACTUALIZA CUENTAS POR PAGAR
              If (lc_nro_sol_cred is not null) OR trim(lc_nro_sol_cred) <> '' then
                 select count(*) into ln_existe_cnta_crrte from cnta_crrte_detalle
                  where ((cod_trabajador = :old.cod_relacion ) and (tipo_doc = :old.tipo_doc) and
                         (nro_doc        = :old.nro_doc      ));

                 If ln_existe_cnta_crrte > 0 then
                    Raise_application_error(-20001, ' No se Puede eliminar el  Registro '||:old.nro_registro||'  porque ya se realizo el descuento al Trabajador');
                 else
                    delete from cnta_crrte
                     where ((cod_trabajador = :old.cod_relacion ) and (tipo_doc = :old.tipo_doc) and
                            (nro_doc        = :old.nro_doc      ));

                    update rrhh_credito_solicitud set flag_estado = '4'
                     where (nro_solicitud = lc_nro_sol_cred);
                 End If;
              End If;

              ----------------
              update cntas_pagar cp set cp.flag_caja_bancos = '0' ,cp.flag_replicacion ='1'
               where (cp.cod_relacion = :old.cod_relacion ) and
                     (cp.tipo_doc     = :old.tipo_doc     ) and
                     (cp.nro_doc      = :old.nro_doc      ) ;
           elsif :old.flab_tabor = '1' then
              update cntas_cobrar cc set cc.flag_caja_bancos = '0' ,cc.flag_replicacion ='1'
               where (cc.cod_relacion = :old.cod_relacion ) and
                     (cc.tipo_doc     = :old.tipo_doc     ) and
                     (cc.nro_doc      = :old.nro_doc      ) ;

           end if ;

           update doc_pendientes_cta_cte dp set dp.flag_debhab = lc_flag_debhab_esp ,
                                                dp.factor      = ln_factor_esp      ,
                                                dp.cnta_ctbl   = null               ,
                                                dp.flag_replicacion = '1'
            where (dp.cod_relacion = :old.cod_relacion ) and
                  (dp.tipo_doc     = :old.tipo_doc     ) and
                  (dp.nro_doc      = :old.nro_doc      ) ;


           RETURN ;

        END IF ;

    end if ;




    lc_flag_estado := null ;






    IF (:old.flag_provisionado = 'R' OR :old.flag_provisionado = 'D' OR :old.flag_provisionado= 'O') THEN --REFERENCIA / DIRECTO...



        if :old.flab_tabor = '1' then  /*Cuentas x Cobrar*/

           select count(*)
             into ln_count
             from cntas_cobrar
            where tipo_doc     = :old.tipo_doc
              AND nro_doc      = :old.nro_doc  ;

           if ln_count = 0 then
              RAISE_APPLICATION_ERROR(-20000, 'No existe documento por Cobrar Directo, por favor verifique!'
                                        || chr(13) || 'Tipo Doc: ' || :old.tipo_doc
                                        || chr(13) || 'Nro Doc: ' || :old.nro_doc);
           end if;

           select NVL(importe_doc,0),Nvl(saldo_sol,0),Nvl(saldo_dol,0),flag_caja_bancos
             into ln_monto_total,ln_saldo_sol,ln_saldo_dol,lc_flag_caja_bancos
             from cntas_cobrar
            where tipo_doc     = :old.tipo_doc
              AND nro_doc      = :old.nro_doc  ;

           ln_imp_dol_old := ln_saldo_dol ;
           ln_imp_sol_old := ln_saldo_sol ;

           --hallar t.cambio old
           select count(*)
             into ln_count
             from tt_fin_tasa_cambio_cb
            where (origen       = :old.origen      ) and
                  (nro_registro = :old.nro_registro ) ;

           if ln_count > 0 then
              select tasa_cambio
                into ln_Tasa_cambio_old
                from tt_fin_tasa_cambio_cb
               where (origen       = :old.origen      ) and
                     (nro_registro = :old.nro_registro ) ;
           else
               select tasa_cambio
                into ln_Tasa_cambio_old
                from caja_bancos
               where (origen       = :old.origen      ) and
                     (nro_registro = :old.nro_registro ) ;
           end if;


             if :old.cod_moneda = ls_soles then
                ln_saldo_sol := (ln_saldo_sol + Nvl(:old.importe,0)) ;
                ln_saldo_dol := (ln_saldo_dol  + Round(Nvl(:old.importe,0) /ln_Tasa_cambio_old,2))  ;

                if ln_saldo_sol < 0 then ln_saldo_sol := 0; end if;
                if ln_saldo_dol < 0 then ln_saldo_dol := 0; end if;

                if ln_saldo_sol = 0 then --cobrado totalmente
                   lc_flag_estado := '3' ;
                elsif ln_monto_total = ln_saldo_sol then --generado
                   lc_flag_estado := '1';
                elsif ln_saldo_sol > 0 then    --cobrado parcialmente
                   lc_flag_estado := '2';
                else
                   RAISE_APPLICATION_ERROR( -20000,'Error para generar flag de estado en documento: ' || :old.nro_doc||' '||:old.tipo_doc
                                                 || chr(13) || 'Saldo Sol: ' || to_char(ln_saldo_sol, '999,990.00')
                                                 || chr(13) || 'Saldo Dol: ' || to_char(ln_saldo_dol, '999,990.00'))  ;
                end if ;

             elsif :old.cod_moneda = ls_dolares then
                --monto anterior a transaci?n x diferencia en cambio
                usp_fin_monto_asiento_x_doc(lc_origen,ln_ano,ln_mes,ln_nro_libro,ln_nro_asiento,:old.cod_relacion,:old.tipo_doc,:old.nro_doc,ln_saldo_sol_old,ln_saldo_dol_old);

                ln_saldo_sol_old := Nvl(ln_saldo_sol_old,0) + Nvl(ln_imp_sol_old,0) ;
                ln_saldo_dol_old := Nvl(ln_saldo_dol_old,0) + Nvl(ln_imp_dol_old,0) ;

                ln_saldo_sol_old := Round(ln_saldo_dol_old * ln_Tasa_cambio_old,2) -ln_saldo_sol_old ;

                ---termina diferencia en cambio
                ln_saldo_dol := ((ln_saldo_dol + Nvl(:old.importe,0)) )  ;
                ln_saldo_sol := (ln_saldo_sol  + (Round(Nvl(:old.importe,0) * ln_Tasa_cambio_old,2) - ln_saldo_sol_old) ) ;

                if ln_saldo_dol = 0 then --pagado totalmente
                   lc_flag_estado := '3' ;
                elsif ln_monto_total = ln_saldo_dol then --generado
                   lc_flag_estado := '1';
                elsif ln_saldo_dol > 0 then    --pagado parcialmente
                   lc_flag_estado := '2';
                end if ;

             end if ;

             /**/
             /**************************************************************************
              REPLICACION (replicar informacion)
             ***************************************************************************/
             UPDATE cntas_cobrar
                SET flag_estado = lc_flag_estado ,
                    saldo_sol   = ln_saldo_sol,
                    saldo_dol   =ln_saldo_dol,
                    flag_replicacion = '1'
              WHERE tipo_doc     = :old.tipo_doc
                AND nro_doc      = :old.nro_doc     ;


           /*Actualizar Doc_Pendientes_cta_cte*/
           if lc_flag_caja_bancos = '1' THEN  --cta cte ha sido cancelada
              --buscar cta ctble de ultima transacion
              select min(cnta_ctbl)
                into lc_cnta_ctbl
                from cntbl_asiento_det
               where (cod_relacion = :old.cod_relacion )
                 and (tipo_docref1 = :old.tipo_doc)
                 and (nro_docref1  = :old.nro_doc      ) ;

              /*REPLICACION*/
              update doc_pendientes_cta_cte
                 set cnta_ctbl = lc_cnta_ctbl,flag_replicacion = '1'
               where (cod_relacion = :old.cod_relacion ) and
                     (tipo_doc     = :old.tipo_doc     ) and
                     (nro_doc       = :old.nro_doc     ) ;

           end if ;


        elsif :old.flab_tabor = '6' then  /*Solicitud de Giro*/


           select importe_doc,Nvl(saldo_sol,0),Nvl(saldo_dol,0),flag_estado
             into ln_monto_total,ln_saldo_sol,ln_saldo_dol,lc_flag_estado_og
             from solicitud_giro
            where (( origen        = :old.origen_doc ) AND
                   ( nro_solicitud = :old.nro_doc    ));



           --contador de og..
           if lc_flag_estado_og = '3' then --pagada
              lc_flag_estado := '2' ;--aprobada

              /**Actualiza Contador de Solicitudes Pendientes **/
             /**************************************************************************
              REPLICACION (replicar informacion)
             ***************************************************************************/


              UPDATE maestro_param_autoriz
                 SET nro_solicitudes_pend = Nvl(nro_solicitudes_pend,0) - 1,flag_replicacion= '1'
               WHERE (cod_relacion = :old.cod_relacion) ;

              --

             /**Actualiza Estado **/
             /**************************************************************************
              REPLICACION (replicar informacion)
             ***************************************************************************/
             UPDATE solicitud_giro sg
                SET sg.nro_reg_caja_banco = null,
                    sg.origen_caja_banc0  = null,
                    sg.flag_replicacion   = '1'
             WHERE ((origen        = :old.origen_doc ) AND
                    (nro_solicitud = :old.nro_doc   )) ;

           else
              lc_flag_estado := lc_flag_estado_og ;--mantener estado
           end if ;


           ln_imp_dol_old := ln_saldo_dol ;
           ln_imp_sol_old := ln_saldo_sol ;


           --hallar t.cambio old
           select tasa_cambio into ln_Tasa_cambio_old from tt_fin_tasa_cambio_cb
            where (origen       = :old.origen       ) and
                  (nro_registro = :old.nro_registro ) ;


          ln_saldo_sol := abs(ln_saldo_sol) ;
          ln_saldo_dol := abs(ln_saldo_dol) ;



           if :old.cod_moneda = ls_soles then
              ln_saldo_sol := (ln_saldo_sol + Nvl(:old.importe,0)) ;
              ln_saldo_dol := (ln_saldo_dol + Round(Nvl(:old.importe,0) / ln_Tasa_cambio_old,2));

           elsif :old.cod_moneda = ls_dolares then
              --monto anterior a transaci?n x diferencia en cambio
              usp_fin_monto_asiento_x_doc(lc_origen,ln_ano,ln_mes,ln_nro_libro,ln_nro_asiento,:old.cod_relacion,:old.tipo_doc,:old.nro_doc,ln_saldo_sol_old,ln_saldo_dol_old);

              ln_saldo_sol_old := Nvl(ln_saldo_sol_old,0) + Nvl(ln_imp_sol_old,0) ;
              ln_saldo_dol_old := Nvl(ln_saldo_dol_old,0) + Nvl(ln_imp_dol_old,0) ;

              ln_saldo_sol_old := Round(ln_saldo_dol_old * ln_Tasa_cambio_old,2)-ln_saldo_sol_old ;
              ---termina diferencia en cambio
              ln_saldo_dol := ((ln_saldo_dol + Nvl(:old.importe,0)) )  ;
              ln_saldo_sol := (ln_saldo_sol  + (Round(Nvl(:old.importe,0) * ln_Tasa_cambio_old,2)- ln_saldo_sol_old) ) ;

           end if ;

           --revertir devolucion
           if lc_flag_estado = '5' then
              --parametros
              select cnta_ctbl_liq_HABER ,cnta_ctbl_liq_debe
                into lc_cta_ctbl_gan,lc_cta_ctbl_per
                from finparam where reckey = '1' ;
              --
              select count(*) into ln_count from solicitud_giro_liq_det where nro_solicitud= :old.nro_doc ;




              if ln_count = 0 then
                 ln_saldo_dol := ln_saldo_dol * -1 ;
                 ln_saldo_sol := ln_saldo_sol * -1 ;
              else--revertir devoluciones o excedencia
                 --
                 select Count(*) into ln_count from cntbl_asiento_det cad
                   where (TRIM(cad.cod_relacion) = TRIM(:old.cod_relacion) ) and
                         (TRIM(cad.tipo_docref1) = TRIM(:old.tipo_doc)     ) and
                         (TRIM(cad.nro_docref1)  = TRIM(:old.nro_doc)      ) and
                         (TRIM(cad.cnta_ctbl)    = TRIM(lc_cta_ctbl_gan)   ) and
                         (cad.origen||trim(to_char(cad.ano))||trim(to_char(cad.mes))||trim(to_char(cad.nro_libro))||trim(to_char(cad.nro_asiento)))= (select sg.cnt_origen||trim(to_char(sg.ano))||trim(to_char(sg.mes))||trim(to_char(sg.nro_libro))||trim(to_char(sg.nro_asiento))
                                                                                                                                                        from solicitud_giro sg
                                                                                                                                                       where sg.nro_solicitud = :old.nro_doc  ) ;

--

                 IF ln_count > 0 THEN
                    ln_saldo_dol := ABS(ln_saldo_dol) * 1 ;
                    ln_saldo_sol := ABS(ln_saldo_sol) * 1 ;
                 ELSE
                    select Count(*) into ln_count from cntbl_asiento_det cad
                     where (cad.cod_relacion = :old.cod_relacion ) and
                           (cad.tipo_docref1 = :old.tipo_doc     ) and
                           (cad.nro_docref1  = :old.nro_doc      ) and
                           (cad.cnta_ctbl    = lc_cta_ctbl_per   ) and
                           (cad.origen||trim(to_char(cad.ano))||trim(to_char(cad.mes))||trim(to_char(cad.nro_libro))||trim(to_char(cad.nro_asiento)))= (select sg.cnt_origen||trim(to_char(sg.ano))||trim(to_char(sg.mes))||trim(to_char(sg.nro_libro))||trim(to_char(sg.nro_asiento))
                                                                                                                                                          from solicitud_giro sg
                                                                                                                                                         where sg.nro_solicitud = :old.nro_doc  ) ;


                    IF ln_count > 0 THEN
                       ln_saldo_dol := ABS(ln_saldo_dol) * -1 ;
                       ln_saldo_sol := ABS(ln_saldo_sol) * -1 ;
                    END IF ;
                 END IF;

--                 RAISE_APPLICATION_ERROR(-20000,to_char(ln_count)||' '||TO_CHAR(ln_saldo_dol));

              end if;

           end if ;
           /**/
           /**************************************************************************
              REPLICACION (replicar informacion)
            ***************************************************************************/
           UPDATE solicitud_giro
              SET saldo_sol = ln_saldo_sol,saldo_dol = ln_saldo_dol,flag_estado=lc_flag_estado,
                  flag_replicacion = '1'
            WHERE ((origen        = :old.origen_doc ) AND
                   (nro_solicitud = :old.nro_doc    )) ;

        elsif :old.flab_tabor = '3' then  /*Cuentas x Pagar*/



           select cp.importe_doc,Nvl(cp.saldo_sol,0),Nvl(cp.saldo_dol,0),cp.flag_caja_bancos
             into ln_monto_total,ln_saldo_sol,ln_saldo_dol,lc_flag_caja_bancos
             from cntas_pagar cp,doc_tipo dt
            where  ( cp.tipo_doc     = dt.tipo_doc       ) AND
                  (( cp.origen       = :old.origen_doc   ) AND
                   ( cp.cod_relacion = :old.cod_relacion ) AND
                   ( cp.tipo_doc     = :old.tipo_doc     ) AND
                   ( cp.nro_doc      = :old.nro_doc      ));

           ln_imp_dol_old := ln_saldo_dol ;
           ln_imp_sol_old := ln_saldo_sol ;


           --hallar t.cambio old
           select count(*)
             into ln_count
             from tt_fin_tasa_cambio_cb
            where (origen       = :old.origen       ) and
                  (nro_registro = :old.nro_registro ) ;

           if ln_count > 0 then
              select tasa_cambio
                into ln_Tasa_cambio_old from tt_fin_tasa_cambio_cb
                where (origen       = :old.origen       ) and
                      (nro_registro = :old.nro_registro ) ;
           else
              select cb.tasa_cambio
                into ln_Tasa_cambio_old
                from caja_bancos cb
               where origen       = :old.origen
                 and nro_registro = :old.nro_registro;

           end if;



           if :old.cod_moneda = ls_soles then
              ln_saldo_sol := (ln_saldo_sol + Nvl(:old.importe,0)) ;
              ln_saldo_dol := (ln_saldo_dol  + Round(Nvl(:old.importe,0) / ln_Tasa_cambio_old,2)
)
;

              if ln_saldo_sol = 0 then --pagado totalmente
                 lc_flag_estado := '3' ;
              elsif ln_monto_total = ln_saldo_sol then --generado
                 lc_flag_estado := '1';
              elsif ln_saldo_sol > 0 then    --pagado parcialmente
                 lc_flag_estado := '2';
              end if ;

           elsif :old.cod_moneda = ls_dolares then
              --monto anterior a transaci?n x diferencia en cambio
              usp_fin_monto_asiento_x_doc(lc_origen,ln_ano,ln_mes,ln_nro_libro,ln_nro_asiento,:old.cod_relacion,:old.tipo_doc,:old.nro_doc,ln_saldo_sol_old,ln_saldo_dol_old);

              ln_saldo_sol_old := Nvl(ln_saldo_sol_old,0) + Nvl(ln_imp_sol_old,0) ;
              ln_saldo_dol_old := Nvl(ln_saldo_dol_old,0) + Nvl(ln_imp_dol_old,0) ;

              ln_saldo_sol_old := Round(ln_saldo_dol_old * ln_Tasa_cambio_old,2) - ln_saldo_sol_old ;
              ---termina diferencia en cambio
              ln_saldo_dol := ((ln_saldo_dol + Nvl(:old.importe,0)) )  ;
              ln_saldo_sol := (ln_saldo_sol  + (Round(Nvl(:old.importe,0) * ln_Tasa_cambio_old,2) - ln_saldo_sol_old) ) ;

              if ln_saldo_dol = 0 then --pagado totalmente
                 lc_flag_estado := '3' ;
              elsif ln_monto_total = ln_saldo_dol then --generado
                 lc_flag_estado := '1';
              elsif ln_saldo_dol > 0 then    --pagado parcialmente
                 lc_flag_estado := '2';
              elsif ln_saldo_dol < 0 then
                 --RAISE_APPLICATION_ERROR(-20000, 'Saldo del Documento en negativo: ' || to_char(ln_saldo_dol));
                 lc_flag_estado := '1';
              end if ;

           end if ;
           /**/
           /***************************************************************************
              REPLICACION (replicar informacion)
            ***************************************************************************/
           UPDATE cntas_pagar
              SET flag_estado = lc_flag_estado , saldo_sol = ln_saldo_sol,saldo_dol =
ln_saldo_dol,
                  flag_replicacion = '1'
            WHERE (( origen       = :old.origen_doc   ) AND
                   ( cod_relacion = :old.cod_relacion ) AND
                   ( tipo_doc     = :old.tipo_doc     ) AND
                   ( nro_doc      = :old.nro_doc      ));

           /*Actualizar Doc_Pendientes_cta_cte*/
           if lc_flag_caja_bancos = '1' THEN  --cta cte ha sido cancelada
              --buscar cta ctble de ultima transacion
              select min(cnta_ctbl) into lc_cnta_ctbl from cntbl_asiento_det
               where (cod_relacion = :old.cod_relacion ) and (tipo_docref1 = :old.tipo_doc) and
                     (nro_docref1  = :old.nro_doc      ) ;

              /*REPLICACION*/
              update doc_pendientes_cta_cte
                 set cnta_ctbl = lc_cnta_ctbl,flag_replicacion = '1'
               where (cod_relacion = :old.cod_relacion ) and
                     (tipo_doc     = :old.tipo_doc     ) and
                     (nro_doc       = :old.nro_doc     ) ;

           end if ;

        END IF ;

     ELSIF (:old.flag_provisionado = 'N' AND lc_flag_tiptran = '2') THEN   --INDIRECTO/CARTERA DE PAGOS
        --ELIMINAR DE CNTAS PAGAR DETALLE
        delete from cntas_pagar_det where ((cod_relacion = :old.cod_relacion ) and
                                           (tipo_doc     = :old.tipo_doc     ) and
                                           (nro_doc      = :old.nro_doc      )) ;

        --ELIMINAR DE CNTAS PAGAR CABECERA
        delete from cntas_pagar where ((cod_relacion = :old.cod_relacion ) and
                                       (tipo_doc     = :old.tipo_doc     ) and
                                       (nro_doc      = :old.nro_doc      )) ;

     ELSIF (:old.flag_provisionado = 'N' AND lc_flag_tiptran = '3') THEN   --INDIRECTO/CARTERA DE COBROS
        --ELIMINAR DE CNTAS COBRAR DETALLE
        delete from cntas_cobrar_det where ((tipo_doc     = :old.tipo_doc     ) and
                                            (nro_doc      = :old.nro_doc      )) ;

        --ELIMINAR DE CNTAS COBRAR CABECERA
        delete from cntas_cobrar where ((cod_relacion = :old.cod_relacion ) and
                                        (tipo_doc     = :old.tipo_doc     ) and
                                        (nro_doc      = :old.nro_doc      )) ;

    END IF ;

END IF ;


end TDA_FIN_CAJA_BANCOS_DET;
/

prompt
prompt Creating trigger TDA_FIN_CNTAS_COBRAR
prompt =====================================
prompt
CREATE OR REPLACE TRIGGER CANTABRIA.tda_fin_cntas_cobrar
  after delete on cntas_cobrar
  for each row

declare

ln_existe integer ;
ln_existe_cnta_crrte  integer ;
  -- local variables here

begin
  If (dbms_reputil.from_remote=true or dbms_snapshot.i_am_a_refresh=true) then
     return;
  end if;

  --  Inicio de modificacion realizada por JORGE. FARFAN LINEA 40
--documento provisionado
IF :old.flag_provisionado = 'R' THEN
   --llena tabla temporal
   insert into tt_fin_cp_asiento
   (origen,ano,mes,nro_libro,nro_asiento,cod_relacion,tipo_doc,nro_doc)
   values
   (:old.origen,:old.ano,:old.mes,:old.nro_libro,:old.nro_asiento,:old.cod_relacion,:old.tipo_doc,:old.nro_doc) ;
   --
   --se ingresa informacion en tabla temporal
   insert into tt_fin_tasa_cambio
   (cod_relacion,tipo_doc,nro_doc,tasa_cambio)
   values
   (:old.cod_relacion,:old.tipo_doc,:old.nro_doc,:old.tasa_cambio) ;


END IF;

delete from doc_pendientes_cta_cte
 where (cod_relacion = :old.cod_relacion ) and
       (tipo_doc     = :old.tipo_doc     ) and
       (nro_doc      = :old.nro_doc      ) ;

--- ******************************************************************************************
--- Eliminacion de registro de una Factura y/o Boleta procesada en Cta. Cte. Trabajador
--- ******************************************************************************************

    select count(*) into ln_existe  from cnta_crrte_detalle
     where (cod_trabajador = :old.cod_relacion ) and
           (tipo_doc       = :old.tipo_doc     ) and
           (nro_doc        = :old.nro_doc      ) ;

    If ln_existe > 0 then
       Raise_application_error(-20001, ' No se Puede eliminar el  Documento ' ||:old.nro_doc||'  porque ya se realizo el descuento al Trabajador');
    ElSE

     select count(*) into ln_existe_cnta_crrte  from cnta_crrte
      where (cod_trabajador = :old.cod_relacion ) and
            (tipo_doc       = :old.tipo_doc     ) and
            (nro_doc        = :old.nro_doc      ) ;

       If ln_existe_cnta_crrte > 0 then
          delete cnta_crrte
           where (cod_trabajador = :old.cod_relacion ) and
                 (tipo_doc       = :old.tipo_doc     ) and
                 (nro_doc        = :old.nro_doc      ) ;
          update rrhh_credito_solicitud
             set flag_estado = '2'
           where (cod_trabajador = :old.cod_relacion ) and
                 (nro_solicitud  = :old.nro_sol_cred_rrhh) ;
       End If;
    End If;

end tia_fin_cntas_cobrar;
/

prompt
prompt Creating trigger TDA_FIN_CNTAS_COBRAR_DET
prompt =========================================
prompt
CREATE OR REPLACE TRIGGER CANTABRIA.TDA_FIN_CNTAS_COBRAR_DET
  after delete on cntas_cobrar_det
  for each row



declare
  -- local variables here
  lc_bol_cobrar  doc_tipo.tipo_doc%type  ;
  lc_fac_cobrar  doc_tipo.tipo_doc%type  ;
  lc_doc_ov      doc_tipo.tipo_doc%type  ;
  lc_cod_art     articulo.cod_art%type ;
  lc_orden_venta orden_venta.nro_ov%type ;
  lc_flag_estado orden_venta.flag_estado%type ;
  ln_cant_dif    cntas_cobrar_det.cantidad%type ;
  ln_cant_ov     cntas_cobrar_det.cantidad%type ;
  lc_grupo_ventas finparam.doc_ventas%type ;
  ln_count        number  ;

  Cursor c_art_mov  is /*Articulo Movimiento Proyectado*/
  SELECT cant_procesada ,
         cant_facturada ,
         cant_proyect
    FROM articulo_mov_proy
   WHERE (tipo_doc = lc_doc_ov      ) AND
         (nro_doc  = lc_orden_venta ) ;

  Cursor c_articulo(as_tipo_doc      doc_tipo.tipo_doc%type,
                    as_nro_doc      orden_venta.nro_ov%type,
                    as_cod_art      articulo.cod_art%type)  is /*Articulo facturarado a modificar*/
  SELECT a.cod_origen, a.nro_mov,
         cant_proyect   ,
         cant_procesada ,
         cant_facturada ,
         ( nvl(cant_proyect,0) - nvl(cant_facturada,0) ) as cant_x_fact
    FROM articulo_mov_proy a
   WHERE tipo_doc = as_tipo_doc       AND
         nro_doc  = as_nro_doc  AND
         cod_art  = as_cod_art    AND
         flag_estado <>'0'
    ORDER BY ( nvl(cant_proyect,0) - nvl(cant_facturada,0) ) desc ;


begin
  -- Edgar Morante Miercoles 10Jul2002, replicacion
  If (dbms_reputil.from_remote=true or dbms_snapshot.i_am_a_refresh=true) then
     return;
  end if;


  SELECT doc_fact_cobrar,doc_bol_cobrar,doc_ventas INTO lc_fac_cobrar, lc_bol_cobrar, lc_grupo_ventas from finparam  WHERE (reckey = '1') ;


  select count(*) into ln_count from doc_grupo_relacion dgr where dgr.grupo = lc_grupo_ventas and TRIM(dgr.tipo_doc) = TRIM(:old.tipo_doc) ;


   IF (ln_count > 0 ) then


       lc_doc_ov      := :old.tipo_ref   ;
       lc_orden_venta := :old.nro_ref    ;
       lc_cod_art     := :old.cod_art    ;

       ln_cant_dif := :old.cantidad ;

       FOR rc_art in c_articulo(lc_doc_ov, lc_orden_venta, lc_cod_art ) LOOP

         /*Actualiza Articulo Movimiento Proyectado, si referencia es una orden de venta*/
         IF ln_cant_dif > 0 THEN

             IF rc_art.cant_facturada > ln_cant_dif THEN
                ln_cant_ov := ln_cant_dif ;
             ELSE
                ln_cant_ov := rc_art.cant_facturada  ;
             END IF ;

             /**************************************************
               REPLICACION
             *****************************************************/
             UPDATE articulo_mov_proy a
                SET cant_facturada = Nvl(cant_facturada,0) - Nvl(ln_cant_ov,0) ,flag_replicacion = '0'
              WHERE (a.cod_origen = rc_art.cod_origen) AND
                    (a.nro_mov    = rc_art.nro_mov   ) ;

             ln_cant_dif := ln_cant_dif - Nvl(ln_cant_ov,0) ;

         ELSIF ln_cant_dif > 0 THEN
             IF (rc_art.cant_proyect - rc_art.cant_facturada) > abs(ln_cant_dif) THEN
                ln_cant_ov := abs(ln_cant_dif) ;
             ELSE
                ln_cant_ov := (rc_art.cant_proyect - rc_art.cant_facturada)  ;
             END IF ;

             /**************************************************
               REPLICACION
             *****************************************************/
             UPDATE articulo_mov_proy a
                SET cant_facturada = Nvl(cant_facturada,0) + Nvl(ln_cant_ov,0) ,flag_replicacion = '0'
              WHERE (a.cod_origen = rc_art.cod_origen) AND
                    (a.nro_mov    = rc_art.nro_mov   ) ;

             ln_cant_dif := ln_cant_dif + Nvl(ln_cant_ov,0) ;
         ELSE
             exit ;
         END IF ;
      END LOOP ;

       /*
      --Actualiza Articulo Movimiento Proyectado
      UPDATE articulo_mov_proy
         SET cant_facturada = (Nvl(cant_facturada,0) -  Nvl(:old.cantidad,0)  )
       WHERE (cod_art  = :old.cod_art   ) AND
             (tipo_doc = lc_doc_ov      ) AND
             (nro_doc  = lc_orden_venta ) ;
      */
--     Modificado el 27/12/2004  Feliz Navidad y Prospero A?o Nuevo
--      lc_flag_estado := '5' ; /*Facturacion Total*/
      /*Verifica Estado de Orden de Venta en Articulo Movimiento Proyectado*/
--      For rc_art_mov in c_art_mov  Loop
--          If Nvl(rc_art_mov.cant_facturada,0) = 0 then
--             If rc_art_mov.cant_proyect > rc_art_mov.cant_procesada  AND  rc_art_mov.cant_procesada > 0  then /*Despachado Parcial*/
--                lc_flag_estado := '2' ; /*Despachado Parcial*/
--             Elsif rc_art_mov.cant_proyect <= rc_art_mov.cant_procesada  AND  rc_art_mov.cant_procesada > 0 then /*Despachado Total  */
--                lc_flag_estado := '3' ; /*Despachado Total*/
--             Elsif Nvl(rc_art_mov.cant_procesada,0) = 0 then
--                lc_flag_estado := '1' ; /*Generado*/
--             End if ;
--          Elsif Nvl(rc_art_mov.cant_facturada,0) > 0 then /*Cantidad Facturada*/
--             If rc_art_mov.cant_proyect > rc_art_mov.cant_facturada  then
--                lc_flag_estado := '4' ;  /*Facturacion Parcial*/
--                Exit ;
--             End if ;
--          End if ;
--       End Loop ;

       /**************************************************
         REPLICACION
       *****************************************************/
--       UPDATE orden_venta
--          SET flag_estado = lc_flag_estado,flag_replicacion = '0'
--        WHERE (nro_ov     = lc_orden_venta );

   End if;

end TDA_FIN_CNTAS_COBRAR_DET;
/

prompt
prompt Creating trigger TDA_FIN_CNTAS_PAGAR
prompt ====================================
prompt
CREATE OR REPLACE TRIGGER CANTABRIA.tda_fin_cntas_pagar
  after delete on cntas_pagar
  for each row

declare
  -- local variables here
  ln_count number ;
begin
  If (dbms_reputil.from_remote=true or dbms_snapshot.i_am_a_refresh=true) then
     return;
  end if;

--documento provisionado
IF :old.flag_provisionado = 'R' THEN
   --llena tabla temporal
   insert into tt_fin_cp_asiento
   (origen,ano,mes,nro_libro,nro_asiento,cod_relacion,tipo_doc,nro_doc)
   values
   (:old.origen,:old.ano,:old.mes,:old.nro_libro,:old.nro_asiento,:old.cod_relacion,:old.tipo_doc,:old.nro_doc) ;
   --
   --se ingresa informacion en tabla temporal
   insert into tt_fin_tasa_cambio
   (cod_relacion,tipo_doc,nro_doc,tasa_cambio)
   values
   (:old.cod_relacion,:old.tipo_doc,:old.nro_doc,:old.tasa_cambio) ;

END IF;


delete from doc_pendientes_cta_cte
where (cod_relacion = :old.cod_relacion ) and
      (tipo_doc     = :old.tipo_doc     ) and
      (nro_doc      = :old.nro_doc      ) ;

IF (:old.cod_relacion is not null AND
    :old.tipo_doc is not null AND
    :old.nro_doc is not null) THEN

    -- Verifica si existe en tabla de control documentario
    SELECT count(*)
      INTO ln_count
      FROM cd_doc_recibido c
     WHERE c.cod_relacion = :old.cod_relacion
       AND c.tipo_doc     = :old.tipo_doc
       AND c.nro_doc      = :old.nro_doc ;

    -- Actualiza en caso lo encuentre
    UPDATE cd_doc_recibido c
       SET c.flag_provisionado = '0'
     WHERE c.cod_relacion = :old.cod_relacion
       AND c.tipo_doc     = :old.tipo_doc
       AND SUBSTR(c.nro_doc,1,10)  = :old.nro_doc ;
END IF ;

END tda_fin_cntas_pagar;
/

