prompt
prompt Creating trigger TDA_FIN_DOC_REFERENCIAS
prompt ========================================
prompt
CREATE OR REPLACE TRIGGER CANTABRIA.tda_fin_doc_referencias
  after delete on doc_referencias
  for each row




declare
  -- local variables here
  /*****************/
  lc_flag_estado     Char(1) ;
  ls_tipo_ref_gr     logparam.doc_gr%type           ;
  lc_fact_cobrar     finparam.doc_fact_cobrar%type  ;
  lc_letra_pagar     finparam.doc_letra_pagar%type  ;
  lc_letra_cobrar    finparam.doc_letra_cobrar%type ;
  lc_cod_moneda      moneda.cod_moneda%type          ;
  lc_soles           moneda.cod_moneda%type          ;
  lc_dolares         moneda.cod_moneda%type          ;
  ln_monto_total     orden_servicio.monto_total%type         ;
  ln_monto_fact      orden_servicio.monto_total%type         ;

  ls_doc_oc          logparam.doc_oc%type;
  ls_doc_os          logparam.doc_os%type;
  lc_doc_chq_dif     doc_tipo.tipo_doc%type          ;

 --nuevas variables
ln_saldo_sol     cntas_pagar.saldo_sol%type   ;
ln_saldo_dol     cntas_pagar.saldo_dol%type   ;
ln_imp_sol_old   cntas_pagar.saldo_sol%type   ;
ln_imp_dol_old   cntas_pagar.saldo_dol%type   ;
ln_saldo_sol_old cntas_pagar.saldo_sol%type   ;
ln_saldo_dol_old cntas_pagar.saldo_dol%type   ;
ln_tcambio_old   cntas_pagar.tasa_cambio%type ;
lc_origen        cntas_pagar.origen%type      ;
ln_ano           cntas_pagar.ano%type         ;
ln_mes           cntas_pagar.mes%type         ;
ln_nro_libro     cntas_pagar.nro_libro%type   ;
ln_nro_asiento   cntas_pagar.nro_asiento%type ;
ln_count         Number ;

begin
  -- Edgar Morante Miercoles 10Jul2002, replicacion
  If (dbms_reputil.from_remote=true or dbms_snapshot.i_am_a_refresh=true) then
     return;
  end if;

  /*******************************************************
   REPLICACION
  ********************************************************/
  IF ORA_LOGIN_USER = 'REPP5' THEN
     RETURN ;
  END IF;

 /**Selecione tipo de doc Guia de Remision**/
   SELECT doc_gr,         doc_oc   , doc_os, cod_soles, cod_dolares
     INTO ls_tipo_ref_gr, ls_doc_oc, ls_doc_os, lc_soles, lc_dolares
     FROM logparam
    WHERE reckey = '1' ;
 /*****************************************/
 /***Selecione tipo de Facturas x Cobrar***/
   SELECT doc_fact_cobrar,doc_letra_pagar,doc_letra_cobrar,doc_cheque_dif
     INTO lc_fact_cobrar,lc_letra_pagar,lc_letra_cobrar,lc_doc_chq_dif
     FROM finparam f
    WHERE reckey = '1' ;

 /*****************************************/
 /*Actualizacion de Guias a              */
 /*Pendiente en Caso sea Ctas x Cobrar */
    IF :old.tipo_mov = 'C' AND :old.tipo_ref  = ls_tipo_ref_gr THEN
       /****************************************************************
         REPLICACION (replicar informaci?n)
        *****************************************************************/
          UPDATE guia
             SET flag_estado = '1' ,
                 tipo_doc    = Null,
                 nro_doc     = Null,
                 flag_replicacion = '1'
           WHERE cod_origen = :old.origen_ref AND
                 nro_guia   = :old.nro_ref    ;

    /*Cuentas x Pagar*/
    ELSIF :old.tipo_mov = 'P' AND :old.tipo_ref = ls_doc_oc        THEN /*Orden de Compra*/
       /*Actualizacion de Monto de Orden de Comnpra*/
       /***********************************************************************
        REPLICACION (replicar informacion)
       ************************************************************************/
          UPDATE orden_compra
             SET monto_facturado = Nvl(monto_facturado,0) - :old.importe ,
                 flag_replicacion = '1'
           WHERE ((cod_origen = :old.origen_ref )  AND
                  (nro_oc     = :old.nro_ref    )) ;

    ELSIF :old.tipo_mov = 'P' AND :old.tipo_ref = ls_doc_os        THEN /*Orden de Servicio*/
          /*Actualizacion de Monto de Orden de Servicio*/
          UPDATE orden_servicio
             SET monto_facturado = (Nvl(monto_facturado,0) - :old.importe),
                 flag_replicacion = '1'
           WHERE ((cod_origen = :old.origen_ref )  AND
                  (nro_os     = :old.nro_ref    )) ;

          SELECT nvl(monto_total,0) ,nvl(monto_facturado,0)
            INTO ln_monto_total , ln_monto_fact
            FROM orden_servicio
           WHERE ((cod_origen = :old.origen_ref )  AND
                  (nro_os     = :old.nro_ref    )) ;

          lc_flag_estado := '1' ;

          IF ln_monto_fact >=  ln_monto_total THEN
             lc_flag_estado := '2' ;          /*Facturado Total  */
          ELSIF (ln_monto_fact > 0 or ln_monto_fact = 0) THEN
             lc_flag_estado := '1' ;
          END IF ;

          /************************************************************************
           REPLICACION (replicar informacion)
           ************************************************************************/
          UPDATE orden_servicio
             SET flag_estado = lc_flag_estado,
                 flag_replicacion = '1'
           WHERE ((cod_origen = :old.origen_ref )  AND
               (nro_os     = :old.nro_ref    )) ;

    ELSIF :old.tipo_mov = 'C' AND (:old.tipo_doc = lc_letra_cobrar or :old.tipo_doc = lc_doc_chq_dif) THEN /*Elimina Letra X Cobrar Canje Renovacion*/

       --verificar si documento no ha sido eliminado
       select count(*) into ln_count
         from cntas_cobrar
        where (cod_relacion = :old.cod_relacion ) and
              (tipo_doc     = :old.tipo_doc     ) and
              (nro_doc      = :old.nro_doc      ) ;

       if ln_count > 0 then  --documento esta vigente
          select origen,ano,mes,nro_libro,nro_asiento
            into lc_origen,ln_ano,ln_mes,ln_nro_libro,ln_nro_asiento
            from cntas_cobrar
           where (cod_relacion = :old.cod_relacion ) and
                 (tipo_doc     = :old.tipo_doc     ) and
                 (nro_doc      = :old.nro_doc      ) ;

       else --buscar en temporal por que documento ha sido anulado
           select origen,ano,mes,nro_libro,nro_asiento
             into lc_origen,ln_ano,ln_mes,ln_nro_libro,ln_nro_asiento
             from tt_fin_cp_asiento
            where (cod_relacion = :old.cod_relacion ) and
                  (tipo_doc     = :old.tipo_doc     ) and
                  (nro_doc      = :old.nro_doc      ) ;
       end if ;


          if :old.flab_tabor = '1' then  /*Cuentas x Cobrar*/
             select importe_doc,Nvl(saldo_sol,0),Nvl(saldo_dol,0),cod_moneda
               into ln_monto_total,ln_saldo_sol,ln_saldo_dol,lc_cod_moneda
               from cntas_cobrar
              where (( origen       = :old.origen_ref   ) AND
                     ( cod_relacion = :old.proveedor_ref ) AND
                     ( tipo_doc     = :old.tipo_ref     ) AND
                     ( nro_doc      = :old.nro_ref      ));

             ln_imp_dol_old := ln_saldo_dol ;
             ln_imp_sol_old := ln_saldo_sol ;

             --hallar t.cambio old
             select tasa_cambio into ln_tcambio_old from tt_fin_tasa_cambio
              where (cod_relacion = :old.cod_relacion) and
                    (tipo_doc     = :old.tipo_doc    ) and
                    (nro_doc      = :old.nro_doc     ) ;



             if lc_cod_moneda = lc_soles then
                ln_saldo_sol := (ln_saldo_sol + Nvl(:old.importe,0)) ;
                ln_saldo_dol := (ln_saldo_dol  + Round(Nvl(:old.importe,0) / ln_tcambio_old,2) )  ;

             if ln_saldo_sol = 0 then --cobrado totalmente
                lc_flag_estado := '3' ;
             elsif ln_monto_total = ln_saldo_sol then --generado
                lc_flag_estado := '1';
             elsif ln_saldo_sol > 0 then    --cobrado parcialmente
                lc_flag_estado := '2';
             end if ;

          elsif lc_cod_moneda = lc_dolares then
             --monto anterior a transaci?n x diferencia en cambio
             usp_fin_monto_asiento_x_doc(lc_origen,ln_ano,ln_mes,ln_nro_libro,ln_nro_asiento,:old.cod_relacion,:old.tipo_ref,:old.nro_ref,ln_saldo_sol_old,ln_saldo_dol_old);

             ln_saldo_sol_old := Nvl(ln_saldo_sol_old,0) + Nvl(ln_imp_sol_old,0) ;
             ln_saldo_dol_old := Nvl(ln_saldo_dol_old,0) + Nvl(ln_imp_dol_old,0) ;

             ln_saldo_sol_old := Round(ln_saldo_dol_old * ln_tcambio_old,2) - ln_saldo_sol_old ;
             ---termina diferencia en cambio
             ln_saldo_dol := ((ln_saldo_dol + Nvl(:old.importe,0)) )  ;
             ln_saldo_sol := (ln_saldo_sol  + (Round(Nvl(:old.importe,0) * ln_tcambio_old,2 ) - ln_saldo_sol_old) ) ;

             if ln_saldo_dol = 0 then --pagado totalmente
                lc_flag_estado := '3' ;
             elsif ln_monto_total = ln_saldo_dol then --generado
                lc_flag_estado := '1';
             elsif ln_saldo_dol > 0 then    --pagado parcialmente
                lc_flag_estado := '2';
             end if ;

          end if ;

          /**/
          /************************************************************************
           REPLICACION (replicar informacion)
          ************************************************************************/
          UPDATE cntas_cobrar
             SET flag_estado = lc_flag_estado , saldo_sol = ln_saldo_sol,saldo_dol = ln_saldo_dol,
                 flag_replicacion = '1'
           WHERE (( origen       = :old.origen_ref   ) AND
                  ( cod_relacion = :old.proveedor_ref ) AND
                  ( tipo_doc     = :old.tipo_ref     ) AND
                  ( nro_doc      = :old.nro_ref      ));

       ELSIF :old.flab_tabor = '3' then  /*Cuentas x Pagar*/

             select importe_doc,Nvl(saldo_sol,0),Nvl(saldo_dol,0),cod_moneda
               into ln_monto_total,ln_saldo_sol,ln_saldo_dol,lc_cod_moneda
               from cntas_pagar
              where (( origen       = :old.origen_ref   ) AND
                     ( cod_relacion = :old.proveedor_ref ) AND
                     ( tipo_doc     = :old.tipo_ref     ) AND
                     ( nro_doc      = :old.nro_ref      ));

             ln_imp_dol_old := ln_saldo_dol ;
             ln_imp_sol_old := ln_saldo_sol ;

             --hallar t.cambio old
             select tasa_cambio into ln_tcambio_old from tt_fin_tasa_cambio
              where (cod_relacion = :old.cod_relacion) and
                    (tipo_doc     = :old.tipo_doc    ) and
                    (nro_doc      = :old.nro_doc     ) ;



             if lc_cod_moneda = lc_soles then
                ln_saldo_sol := (ln_saldo_sol + Nvl(:old.importe,0)) ;
                ln_saldo_dol := (ln_saldo_dol  + Round(Nvl(:old.importe,0) / ln_tcambio_old,2) )  ;

             if ln_saldo_sol = 0 then --pagado totalmente
                lc_flag_estado := '3' ;
             elsif ln_monto_total = ln_saldo_sol then --generado
                lc_flag_estado := '1';
             elsif ln_saldo_sol > 0 then    --pagado parcialmente
                lc_flag_estado := '2';
             end if ;

          elsif lc_cod_moneda = lc_dolares then
             --monto anterior a transaci?n x diferencia en cambio
             usp_fin_monto_asiento_x_doc(lc_origen,ln_ano,ln_mes,ln_nro_libro,ln_nro_asiento,:old.cod_relacion,:old.tipo_ref,:old.nro_ref,ln_saldo_sol_old,ln_saldo_dol_old);

             ln_saldo_sol_old := Nvl(ln_saldo_sol_old,0) + Nvl(ln_imp_sol_old,0) ;
             ln_saldo_dol_old := Nvl(ln_saldo_dol_old,0) + Nvl(ln_imp_dol_old,0) ;

             ln_saldo_sol_old := Round(ln_saldo_dol_old * ln_tcambio_old,2) - ln_saldo_sol_old ;
             ---termina diferencia en cambio
             ln_saldo_dol := ((ln_saldo_dol + Nvl(:old.importe,0)) - Nvl(:new.importe,0))  ;
             ln_saldo_sol := (ln_saldo_sol  + (Round(Nvl(:old.importe,0) * ln_tcambio_old,2 ) - ln_saldo_sol_old) ) ;

             if ln_saldo_dol = 0 then --pagado totalmente
                lc_flag_estado := '3' ;
             elsif ln_monto_total = ln_saldo_dol then --generado
                lc_flag_estado := '1';
             elsif ln_saldo_dol > 0 then    --pagado parcialmente
                lc_flag_estado := '2';
             end if ;

          end if ;

          /**/
          /************************************************************************
           REPLICACION (replicar informacion)
          ************************************************************************/
          UPDATE cntas_pagar
             SET flag_estado = lc_flag_estado , saldo_sol = ln_saldo_sol,saldo_dol = ln_saldo_dol,
                 flag_replicacion = '1'
           WHERE (( origen       = :old.origen_ref   ) AND
                  ( cod_relacion = :old.proveedor_ref ) AND
                  ( tipo_doc     = :old.tipo_ref     ) AND
                  ( nro_doc      = :old.nro_ref      ));


       END IF ;

    ELSIF :old.tipo_mov = 'P' AND :old.tipo_doc  = lc_letra_pagar THEN /*Elimina Letra X Pagar Canje Renovacion*/
       --verificar si documento no ha sido eliminado
       select count(*) into ln_count
         from cntas_pagar
        where (cod_relacion = :old.cod_relacion ) and
              (tipo_doc     = :old.tipo_doc     ) and
              (nro_doc      = :old.nro_doc      ) ;

       if ln_count > 0 then  --documento esta vigente
          select origen,ano,mes,nro_libro,nro_asiento
            into lc_origen,ln_ano,ln_mes,ln_nro_libro,ln_nro_asiento
            from cntas_pagar
           where (cod_relacion = :old.cod_relacion ) and
                 (tipo_doc     = :old.tipo_doc     ) and
                 (nro_doc      = :old.nro_doc      ) ;

       else --buscar en temporal por que documento ha sido anulado
           select origen,ano,mes,nro_libro,nro_asiento
             into lc_origen,ln_ano,ln_mes,ln_nro_libro,ln_nro_asiento
             from tt_fin_cp_asiento
            where (cod_relacion = :old.cod_relacion ) and
                  (tipo_doc     = :old.tipo_doc     ) and
                  (nro_doc      = :old.nro_doc      ) ;
       end if ;

          if :old.flab_tabor = '3' then  /*Cuentas x Pagar*/
             select importe_doc,Nvl(saldo_sol,0),Nvl(saldo_dol,0),cod_moneda
               into ln_monto_total,ln_saldo_sol,ln_saldo_dol,lc_cod_moneda
               from cntas_pagar
              where (( origen       = :old.origen_ref   ) AND
                     ( cod_relacion = :old.proveedor_ref ) AND
                     ( tipo_doc     = :old.tipo_ref     ) AND
                     ( nro_doc      = :old.nro_ref      ));

             ln_imp_dol_old := ln_saldo_dol ;
             ln_imp_sol_old := ln_saldo_sol ;

             --hallar t.cambio old
             select tasa_cambio into ln_tcambio_old from tt_fin_tasa_cambio
              where (cod_relacion = :old.cod_relacion) and
                    (tipo_doc     = :old.tipo_doc    ) and
                    (nro_doc      = :old.nro_doc     ) ;



             if lc_cod_moneda = lc_soles then
                ln_saldo_sol := (ln_saldo_sol + Nvl(:old.importe,0)) ;
                ln_saldo_dol := (ln_saldo_dol  + Round(Nvl(:old.importe,0) / ln_tcambio_old,2) )  ;

             if ln_saldo_sol = 0 then --pagado totalmente
                lc_flag_estado := '3' ;
             elsif ln_monto_total = ln_saldo_sol then --generado
                lc_flag_estado := '1';
             elsif ln_saldo_sol > 0 then    --pagado parcialmente
                lc_flag_estado := '2';
             end if ;

          elsif lc_cod_moneda = lc_dolares then
             --monto anterior a transaci?n x diferencia en cambio
             usp_fin_monto_asiento_x_doc(lc_origen,ln_ano,ln_mes,ln_nro_libro,ln_nro_asiento,:old.cod_relacion,:old.tipo_ref,:old.nro_ref,ln_saldo_sol_old,ln_saldo_dol_old);

             ln_saldo_sol_old := Nvl(ln_saldo_sol_old,0) + Nvl(ln_imp_sol_old,0) ;
             ln_saldo_dol_old := Nvl(ln_saldo_dol_old,0) + Nvl(ln_imp_dol_old,0) ;

             ln_saldo_sol_old := Round(ln_saldo_dol_old * ln_tcambio_old,2) - ln_saldo_sol_old ;
             ---termina diferencia en cambio
             ln_saldo_dol := ((ln_saldo_dol + Nvl(:old.importe,0)) - Nvl(:new.importe,0))  ;
             ln_saldo_sol := (ln_saldo_sol  + (Round(Nvl(:old.importe,0) * ln_tcambio_old,2 ) - ln_saldo_sol_old) ) ;

             if ln_saldo_dol = 0 then --pagado totalmente
                lc_flag_estado := '3' ;
             elsif ln_monto_total = ln_saldo_dol then --generado
                lc_flag_estado := '1';
             elsif ln_saldo_dol > 0 then    --pagado parcialmente
                lc_flag_estado := '2';
             end if ;

          end if ;

          /**/
          /************************************************************************
           REPLICACION (replicar informacion)
          ************************************************************************/
          UPDATE cntas_pagar
             SET flag_estado = lc_flag_estado , saldo_sol = ln_saldo_sol,saldo_dol = ln_saldo_dol,
                 flag_replicacion = '1'
           WHERE (( origen       = :old.origen_ref   ) AND
                  ( cod_relacion = :old.cod_relacion ) AND
                  ( tipo_doc     = :old.tipo_ref     ) AND
                  ( nro_doc      = :old.nro_ref      ));


       END IF ;
    END IF ;





end tda_fin_doc_referencias;
