prompt
prompt Creating trigger TDA_FIN_SOLICITUD_GIRO_LIQ_DET
prompt ===============================================
prompt
CREATE OR REPLACE TRIGGER CANTABRIA.TDA_FIN_SOLICITUD_GIRO_LIQ_DET
  after delete on solicitud_giro_liq_det
  for each row
declare
  -- local variables here
lc_soles          moneda.cod_moneda%type ;
lc_dolares        moneda.cod_moneda%type ;
lc_sol_giro       doc_tipo.tipo_doc%type ;
ln_monto_total    cntas_pagar.importe_doc%type ;
ln_saldo_sol      cntas_pagar.importe_doc%type ;
ln_saldo_dol      cntas_pagar.importe_doc%type ;
lc_flag_estado    cntas_pagar.flag_estado%type ;
lc_flag_estado_og cntas_pagar.flag_estado%type ;
ln_count          number                       ;
lc_flag_ctrl_reg   cntas_pagar.flag_control_reg%type       ;
lc_flag_debhab_esp doc_pendientes_cta_cte.flag_debhab%type ;
ln_factor_esp      doc_pendientes_cta_cte.factor%type      ;
lc_cnta_ctbl       doc_pendientes_cta_cte.cnta_ctbl%type   ;

begin

   If (dbms_reputil.from_remote=true or dbms_snapshot.i_am_a_refresh=true) then
      return;
   end if;


--parametros
select doc_sol_giro into lc_sol_giro from finparam where reckey = '1' ;

select cod_soles,cod_dolares into lc_soles,lc_dolares from logparam where reckey = '1' ;


IF :old.tipo_doc = lc_sol_giro THEN
    select importe_doc,Nvl(saldo_sol,0),Nvl(saldo_dol,0),flag_estado
      into ln_monto_total,ln_saldo_sol,ln_saldo_dol,lc_flag_estado_og
      from solicitud_giro
    WHERE ((cod_relacion  = :old.proveedor  ) AND
           (nro_solicitud = :old.nro_doc   )) ;


    --contador de og..
    if lc_flag_estado_og = '3' then --pagada
       lc_flag_estado := '2' ;--aprobada

       /**Actualiza Contador de Solicitudes Pendientes **/
       /***************************************************************
         REPLICACION
       ***************************************************************/
       UPDATE maestro_param_autoriz
          SET nro_solicitudes_pend = Nvl(nro_solicitudes_pend,0) - 1,flag_replicacion = '0'
        WHERE (cod_relacion = :new.proveedor) ;

    else
       lc_flag_estado := lc_flag_estado_og ;--mantener estado
    end if ;


    if :old.cod_moneda = lc_soles then
        ln_saldo_sol := (ln_saldo_sol + Nvl(:old.importe,0)) ;
        ln_saldo_dol := (ln_saldo_dol  + Round(Nvl(:old.importe,0) / :old.tasa_cambio,2) )  ;

    elsif :old.cod_moneda = lc_dolares then
        ln_saldo_dol := ((ln_saldo_dol + Nvl(:old.importe,0)) )  ;
        ln_saldo_sol := (ln_saldo_sol  + (Round(Nvl(:old.importe,0) * :old.tasa_cambio,2 ) ) ) ;
    end if ;

    /**/
    /***************************************************************
         REPLICACION
    ***************************************************************/
    UPDATE solicitud_giro
       SET saldo_sol = ln_saldo_sol,saldo_dol = ln_saldo_dol,flag_estado = lc_flag_estado,flag_replicacion = '0'
    WHERE ((cod_relacion  = :old.proveedor  ) AND
           (nro_solicitud = :old.nro_doc   )) ;

ELSE
   --VERIFICAR SI ES TIPO CUENTA CORRIENTE
   select count(*) into ln_count from doc_grupo_relacion dg where (dg.grupo    = 'C2'          ) and
                                                                  (dg.tipo_doc = :old.tipo_doc );

   IF ln_count > 0 AND :old.flag_provisionado = 'D' THEN --NO AFECTARA DOC_PENDIENTES_CTA_CTE
      select cp.flag_control_reg into lc_flag_ctrl_reg
        from cntas_pagar cp
       where (cp.cod_relacion = :old.proveedor ) and
             (cp.tipo_doc     = :old.tipo_doc  ) and
             (cp.nro_doc      = :old.nro_doc   ) ;

      IF lc_flag_ctrl_reg = '1' THEN --invertira condicion de documento

         select count(*)
           into ln_count
           from doc_pendientes_cta_cte dp
          where (dp.cod_relacion = :old.proveedor ) and
                (dp.tipo_doc     = :old.tipo_doc  ) and
                (dp.nro_doc      = :old.nro_doc   ) ;

         if ln_count = 0 then
            lc_flag_debhab_esp := 'D'; ln_factor_esp := '1';
         else
            select dp.flag_debhab,dp.factor
             into lc_flag_debhab_esp,ln_factor_esp
              from doc_pendientes_cta_cte dp
             where (dp.cod_relacion = :old.proveedor ) and
                   (dp.tipo_doc     = :old.tipo_doc  ) and
                   (dp.nro_doc      = :old.nro_doc   ) ;

         end if;


         if lc_flag_debhab_esp = 'D' then
            lc_flag_debhab_esp := 'H' ;
         end if ;

         if ln_factor_esp = '1' then
            ln_factor_esp := '-1' ;
         end if ;

         /*************************************************************************
          REPLICACION
         *************************************************************************/
         update cntas_pagar cp set cp.flag_caja_bancos = '0' ,cp.flag_replicacion = '0'
          where (cp.cod_relacion = :old.proveedor ) and
                (cp.tipo_doc     = :old.tipo_doc  ) and
                (cp.nro_doc      = :old.nro_doc   ) ;



         update doc_pendientes_cta_cte dp set dp.flag_debhab = lc_flag_debhab_esp,
                                              dp.factor      = ln_factor_esp     ,
                                              dp.cnta_ctbl   = lc_cnta_ctbl      ,
                                              dp.flag_replicacion = '0'
          where (dp.cod_relacion = :old.proveedor ) and
                (dp.tipo_doc     = :old.tipo_doc  ) and
                (dp.nro_doc      = :old.nro_doc   ) ;

         RETURN ;

      END IF ;

   END IF ;



   select importe_doc,Nvl(saldo_sol,0),Nvl(saldo_dol,0)
     into ln_monto_total,ln_saldo_sol,ln_saldo_dol
     from cntas_pagar
    where (( cod_relacion = :old.proveedor ) AND
           ( tipo_doc     = :old.tipo_doc  ) AND
           ( nro_doc      = :old.nro_doc   ));


    if :old.cod_moneda = lc_soles then
       ln_saldo_sol := (ln_saldo_sol + Nvl(:old.importe,0)) ;
       ln_saldo_dol := (ln_saldo_dol  + Round(Nvl(:old.importe,0) / :old.tasa_cambio,2) )  ;

       if ln_saldo_sol = 0 then --pagado totalmente
          lc_flag_estado := '3' ;
       elsif ln_monto_total = ln_saldo_sol then --generado
          lc_flag_estado := '1';
       elsif ln_saldo_sol > 0 then    --pagado parcialmente
          lc_flag_estado := '2';
       end if ;

   elsif :old.cod_moneda = lc_dolares then
      ln_saldo_dol := ((ln_saldo_dol + Nvl(:old.importe,0)) )  ;
      ln_saldo_sol := (ln_saldo_sol  + (Round(Nvl(:old.importe,0) * :old.tasa_cambio,2 )    ));

      if ln_saldo_dol = 0 then --pagado totalmente
         lc_flag_estado := '3' ;
      elsif ln_monto_total = ln_saldo_dol then --generado
         lc_flag_estado := '1';
      elsif ln_saldo_dol > 0 then    --pagado parcialmente
         lc_flag_estado := '2';
      end if ;

   end if ;

   /**/




   /******************************************************************************************
    REPLICACION
   *******************************************************************************************/
   UPDATE cntas_pagar
      SET flag_estado = lc_flag_estado , saldo_sol = ln_saldo_sol,saldo_dol = ln_saldo_dol,flag_replicacion = '0'
    WHERE (( cod_relacion = :old.proveedor ) AND
           ( tipo_doc     = :old.tipo_doc  ) AND
           ( nro_doc      = :old.nro_doc   ));

END IF ;

end TDA_FIN_SOLICITUD_GIRO_LIQ_DET;
/

