prompt
CREATE OR REPLACE TRIGGER CANTABRIA.TDA_GUIA_VALE
  after delete on guia_vale
  for each row
declare
  -- local variables here

begin
  -- Edgar Morante Miercoles 10Jul2002, replicacion
  If (dbms_reputil.from_remote=true or dbms_snapshot.i_am_a_refresh=true) then
     return;
  end if;

  -- Actualiza flag de atendido total el movimiento
  Update articulo_mov
     set flag_estado = '1',
         flag_replicacion = '0'
   Where nro_vale = :old.nro_vale;

  Update vale_mov
     set flag_estado = '1',
         flag_Replicacion = '0'
   Where nro_vale = :old.nro_vale
     and cod_origen = :old.origen_vale ;

end TDA_GUIA_VALE;
