prompt
prompt Creating trigger TDA_LIQUIDACION_BENEF_DET
prompt ==========================================
prompt
CREATE OR REPLACE TRIGGER CANTABRIA.tda_liquidacion_benef_det
  after delete on liquidacion_benef_det
  for each row
declare
  -- local variables here
  ls_doc_lbs         lbs_param.doc_lbs%TYPE;
  ld_fec_cese        liquidacion_benef.fec_salida%TYPE;
  ln_year            presupuesto_ejec.ano%TYPE;
begin
  select doc_lbs
    into ls_doc_lbs
    from lbs_param
   where reckey = '1';

  if :old.flag_titulo_lbs in ('2', '3', '4') and :old.flag_estado <> '0' then

     select lb.fec_registro
       into ld_fec_cese
       from liquidacion_benef lb,
            maestro           m
      where lb.cod_trabajador  = m.cod_trabajador
        and lb.nro_liquidacion = :old.nro_liquidacion;

     ln_year :=to_number(to_char(ld_fec_cese, 'yyyy'));

     -- Elimino la ejecucion presupuestal
     delete presupuesto_ejec pe
      where pe.ano = ln_year
        and pe.cencos = :old.cencos
        and pe.cnta_prsp = :old.cnta_prsp
        and pe.tipo_doc_ref = ls_doc_lbs
        and pe.nro_doc_ref  = :old.nro_liquidacion
        and pe.item_ref     = :old.nro_item;

  end if;


end tda_liquidacion_benef_det;
/

