prompt
prompt Creating trigger TDA_MTT_PD_OT_DET
prompt ==================================
prompt
CREATE OR REPLACE TRIGGER CANTABRIA.TDA_MTT_PD_OT_DET
  after delete on pd_ot_det
  for each row


declare
  -- local variables here
 Cursor c_oper_old is
  SELECT flag_estado,cant_real
    FROM operaciones
   WHERE (tipo_orden = (select doc_ot from prod_param where reckey = '1' )  ) AND
         (nro_orden  = :old.nro_orden )
  ORDER BY flag_estado  ;

 ldc_cant_real      operaciones.cant_real%type ;
 lc_flag_est_op     Char (1) ;
 lc_flag_estado_old Char (1) ;
 ln_count           number   ;
 lb_flag_proy       boolean  ;
 lb_flag            boolean  ;
 ln_flag0           number ;
 ln_flag1           number ;
 ln_flag2           number ;
 ln_flag3           number ;
 ls_flag_externo_o  ejecutor.flag_externo%type ;

begin
  -- Edgar Morante Miercoles 10Jul2002, replicacion
If (dbms_reputil.from_remote=true or dbms_snapshot.i_am_a_refresh=true) then
    return;
end if;

lb_flag_proy := false ;
lb_flag      := false ;

--cantidad real de la operacion
select op.cant_real into ldc_cant_real from operaciones op where op.oper_sec = :old.oper_sec ;

ldc_cant_real := Nvl(ldc_cant_real,0) - Nvl(:old.cant_labor,0) ;

-- Actualizando horometraje o kilimetraje de una maquina
IF :old.cod_maquina IS NOT NULL AND :old.ind_act_maq > 0 THEN

    UPDATE maquina m
       SET m.ind_act_acumulada = NVL(m.ind_act_acumulada,0) - :old.ind_act_maq
     WHERE m.cod_maquina = :old.cod_maquina ;

END IF ;


   --encontrar estado de la operacion
   IF ldc_cant_real = 0 THEN
      lc_flag_est_op := '3' ; --PLANEADO
   ELSE
      lc_flag_est_op := '1' ; --ACTIVO
   END IF ;

   --ABRE OPERACION
   UPDATE operaciones
      SET cant_real     = (Nvl(cant_real,0)     - NVL(:old.cant_labor,0)  ) , --disminuye cantidad de labor de operacion
          avance_actual = (Nvl(avance_actual,0) - NVL(:old.cant_avance,0) ) , --disminuye cantidad
          flag_estado   = lc_flag_est_op                                    , --estado de la operacion de acuerdo cantidad real
          fec_fin       = null                                          --fecha final no termina
    WHERE oper_sec = :old.oper_sec ;

    /* Abre en articulo_mov_proy  */
--    UPDATE articulo_mov_proy
--       SET flag_estado = '1'
--     WHERE oper_sec    = :old.oper_sec and
--           flag_estado = '2' ;




--antiguo oper_sec
--ENCONTRAR ESTADO DE LA OT
--estados de la ot
--0 = anulado ,1 = activo
--2 = cerrado ,3 = proyectado
--
   SELECT count(decode(flag_estado,'0',1,0)),
          count(decode(flag_estado,'1',1,0)),
          count(decode(flag_estado,'2',1,0)),
          count(decode(flag_estado,'3',1,0))
     INTO ln_flag0, ln_flag1, ln_flag2, ln_flag3
     FROM operaciones o
    WHERE (tipo_orden = (select doc_ot from prod_param where reckey = '1' )  ) AND
         (nro_orden  = :old.nro_orden ) ;

   IF ln_flag0>0 AND ln_flag1=0 AND ln_flag2=0 AND ln_flag3=0 THEN
     lc_flag_estado_old:='0' ;
   ELSIF ln_flag2>0 AND ln_flag1=0 AND ln_flag3=0 THEN
     lc_flag_estado_old:='2' ;
   ELSIF ln_flag3>0 AND ln_flag1=0 THEN
     lc_flag_estado_old:='3' ;
   ELSE
     lc_flag_estado_old:='1' ;
   END IF ;



   /**Actualiza Estado de Orden de Trabajo**/
   /*
   For rc_oper in c_oper_old Loop
       IF rc_oper.flag_estado = '2' THEN --Cerrada
          if lb_flag_proy then
             lc_flag_estado_old := '1' ; --se activa automaticamente la ot y sale del bucle
             EXIT;
          else
             lc_flag_estado_old := '2' ; --hasta este punto ot se encontraria cerrada
             lb_flag := TRUE ; --FLAG PARA CONTROLAR ESTADO DE LA OT
          end if ;
       ELSIF rc_oper.flag_estado = '1' THEN --Activa
          lc_flag_estado_old := '1' ; --se activa automaticamente la ot y sale del bucle
          EXIT;
       ELSIF rc_oper.flag_estado = '3' THEN --Planeado
          if lb_flag then
             lc_flag_estado_old := '1' ; --se activa automaticamente la ot y sale del bucle
             EXIT;
          else
             lc_flag_estado_old := '3' ; --proyectado sigue busqueda
             lb_flag_proy := TRUE ; --FLAG PARA CONTROLAR ESTADO DE LA OT
          end if ;
       ELSIF rc_oper.flag_estado = '0' THEN --Anulado
          lc_flag_estado_old := '1' ;
       END IF;
    End Loop ;
    */

SELECT flag_externo
  INTO ls_flag_externo_o
  FROM ejecutor e
 WHERE e.cod_ejecutor=:old.cod_ejecutor ;

-- Si ejecutor es un NO EXTERNO
IF ls_flag_externo_o = '0' THEN
    UPDATE orden_trabajo ot
       SET ot.flag_estado = lc_flag_estado_old,
           ot.costo_ejecutado = NVL(ot.costo_ejecutado,0) - NVL(:old.cant_labor,0)*NVL(:old.costo_labor,0)
     WHERE (nro_orden = :old.nro_orden );
ELSE
    UPDATE orden_trabajo ot
       SET ot.flag_estado = lc_flag_estado_old
     WHERE (nro_orden = :old.nro_orden );
END IF ;

--maquina antigua
IF :old.cod_maquina is not null THEN
   if Nvl(:old.ind_act_maq,0) > 0 then
        UPDATE maquina m
           SET m.ind_act_acumulada = Nvl(m.ind_act_acumulada,0) - :old.ind_act_maq
         WHERE m.cod_maquina = :old.cod_maquina ;
   end if;
END IF ;

/*verifica si existe ot en correlativo*/
select count(*) into ln_count from campo_ciclo where nro_orden = :old.nro_orden  ;

IF ln_count > 0  THEN
   IF lc_flag_estado_old = '1' THEN --activa
      update campo_ciclo
         set flag_estado = '1' --abierto
       where nro_orden = :old.nro_orden;
   ELSIF lc_flag_estado_old = '2' THEN --cerrada
      update campo_ciclo
         set flag_estado = '0' --cerrrado
       where nro_orden = :old.nro_orden ;

   ELSIF lc_flag_estado_old = '3' THEN --planeada
      update campo_ciclo
         set flag_estado = '2'  --en proyecto
       where nro_orden = :old.nro_orden ;
   END IF ;
END IF ;


end TDA_MTT_PD_OT_DET;
/

prompt
prompt Creating trigger TDA_ORDEN_SERVICIO_DET
prompt =======================================
prompt
CREATE OR REPLACE TRIGGER CANTABRIA.TDA_ORDEN_SERVICIO_DET
  after delete on orden_servicio_det
  for each row
declare
  -- local variables here
  ls_doc_os            logparam.doc_os%type;
  ls_ori_sol           orden_servicio.sol_origen%type;
  ls_nro_sol           orden_servicio.nro_sol_serv%type;
  ln_total             orden_servicio.monto_total%type;
  ls_proveedor         orden_servicio.proveedor%TYPE;
begin
 if :old.flag_estado = '0' then return; end if;

 --==============================================================
 -- Si el movimiento esta anulado o pendiente simplemente retorno
 --==============================================================
 if :old.flag_estado in ('0', '3') then return; end if;

 SELECT doc_os
   INTO ls_doc_os
   FROM logparam
  WHERE reckey = '1' ;

  -- Datos de la orden de servicio
  Select sol_origen, nro_sol_serv, proveedor
    into ls_ori_sol, ls_nro_sol, ls_proveedor
    from orden_servicio
   where cod_origen = :old.cod_origen
     and nro_os     = :old.nro_os;

  -- Afecta presupuesto
  Delete presupuesto_ejec
   where origen_ref   = :old.cod_origen
     and tipo_doc_ref = ls_doc_os
     and nro_doc_ref  = :old.nro_os
     and item_ref     = :old.nro_item
     and cod_rel_Ref  = ls_proveedor;

  -- Actualiza tabla operaciones
   IF :old.oper_sec is not null THEN
      UPDATE operaciones o
         SET o.costo_unit = 0,
             o.flag_estado = '1'
       WHERE o.oper_sec = :old.oper_sec ;
      END IF ;


  -- Actualiza flag de sol. servicio
  if ls_nro_sol is not null then

     /*****************************************************
     **** REPLICACION
     *****************************************************/
     update sol_serv_det
        set flag_estado = '2',
            flag_Replicacion = '0'
      where cod_origen   = ls_ori_sol
        and nro_sol_serv = ls_nro_sol
        and nro_item     = :old.nro_item;
     /*****************************************************/
  end if;

  -- Actualiza total de orden en cabecera
  --=====================================
  ln_total := NVL(:old.importe,0) - NVL(:old.decuento,0) + NVL(:old.impuesto,0)
           + NVL(:old.impuesto2,0);

  /*****************************************************
  **** REPLICACION
  *****************************************************/
  Update orden_servicio os
     set os.monto_total = NVL(os.monto_total,0) - ln_total,
         flag_replicacion = '0'
   Where os.cod_origen = :old.cod_origen
     and os.nro_os     = :old.nro_os;
  /*****************************************************/
end TDA_ORDEN_SERVICIO_DET;
/

prompt
prompt Creating trigger TDA_OT_OTROS_GASTOS
prompt ====================================
prompt
CREATE OR REPLACE TRIGGER CANTABRIA.TDA_OT_OTROS_GASTOS
  after delete on ot_otros_gastos
  for each row

DECLARE

-- local variables here
ln_importe_doc     cntas_pagar.importe_doc%type ;

BEGIN

-- Busca costo en cuentas por pagar
SELECT decode( cp.cod_moneda, (SELECT l.cod_dolares FROM logparam l WHERE reckey='1'),
               cp.importe_doc, cp.importe_doc / cp.tasa_cambio)
  INTO ln_importe_doc
  FROM cntas_pagar cp
 WHERE cp.cod_relacion = :old.cod_relacion
   AND cp.tipo_doc     = :old.tipo_doc
   AND cp.nro_doc      = :old.nro_doc ;

-- Actualiza costo en orden de trabajo
UPDATE orden_trabajo ot
   SET ot.costo_estimado = NVL(ot.costo_estimado,0) + ROUND(ln_importe_doc,2)
 WHERE ot.nro_orden = :old.nro_orden ;

END TDA_OT_OTROS_GASTOS;
/

prompt
prompt Creating trigger TDA_PD_OT_ASISTENCIA
prompt =====================================
prompt
CREATE OR REPLACE TRIGGER CANTABRIA.TDA_PD_OT_ASISTENCIA
  after delete on pd_ot_asistencia
  for each row
declare
  -- local variables here
  ln_dol_prom_old        calendario.vta_dol_prom%type ;
  lc_und_lb              pd_ot_det.und_labor%type     ;
  lc_und_hr              pd_ot_det.und_labor%type     ;
  lc_flag_maq_mo         labor.flag_maq_mo%type       ;
  ln_costo_x_trab_x_item number (13,2)                ;
  ln_cant_lab            pd_ot_det.cant_labor%type    ;
  ln_costo_labor         pd_ot_det.costo_labor%type   ;
  ln_costo_unit_lab      pd_ot_det.costo_labor%type   ;
begin

  --datos de labor
  select lb.und ,lb.flag_maq_mo into lc_und_lb ,lc_flag_maq_mo from pd_ot_det pod,labor
lb
   where (pod.cod_labor = lb.cod_labor  ) and (pod.nro_parte = :old.no_parte ) and
         (pod.nro_item  = :old.nro_item ) ;

  --parametros de und
  select pp.und_hr into lc_und_hr from prod_param pp where pp.reckey = '1' ;

  IF (lc_flag_maq_mo = 'O' and lc_und_lb = lc_und_hr) THEN


          select tasa_cambio into ln_dol_prom_old
            from tt_ope_pd
           where (nro_parte = :old.no_parte) ;

      if ln_dol_prom_old = 0 then
         raise_application_error (-20000,'No Existe Tasa de Cambio para fecha de Parte
Diario Verifique !');
      end if ;


     ln_costo_x_trab_x_item := (Nvl(:old.nro_horas,0) * Nvl(:old.costo_horas,0)) *
Nvl(:old.factor,0) ;

     --convertir a dolares sueldo de trabajador
     if ln_costo_x_trab_x_item > 0 then --convertir a dolares
        ln_costo_x_trab_x_item := Round(ln_costo_x_trab_x_item / ln_dol_prom_old,2) ;
     end if ;


     --RECUPERO CANTIDAD Y LABOR DE PD_OT_DET
     select Nvl(pdo.cant_labor,0),Nvl(pdo.costo_labor,0) into ln_cant_lab,ln_costo_labor
from pd_ot_det pdo
      where (pdo.nro_parte = :old.no_parte ) and
            (pdo.nro_item  = :old.nro_item ) ;


     --calculo de costo unitario antes de agregar trabajador modificado
     ln_costo_labor := ROUND((ln_costo_labor * (ln_cant_lab   + :old.nro_horas) ) -  ((
(Nvl(:old.nro_horas,0) * Nvl(:old.costo_horas,0)) * Nvl(:old.factor,0) / ln_dol_prom_old
)),2);


     if ln_cant_lab <> 0 then
        --calculo de costo unitario final
        ln_costo_unit_lab := Round(ln_costo_labor / ln_cant_lab ,4) ;
     else
        ln_costo_unit_lab := 0.00 ;
     end if ;


     --actualiza parte diario de ot (detalle)
     update pd_ot_det pdo
        set pdo.costo_labor =  ln_costo_unit_lab
      where (pdo.nro_parte = :old.no_parte ) and
            (pdo.nro_item  = :old.nro_item ) ;


  END IF ;


end TDA_PD_OT_ASISTENCIA;
/

prompt
prompt Creating trigger TDA_PD_OT_INCIDENCIAS
prompt ======================================
prompt
CREATE OR REPLACE TRIGGER CANTABRIA.TDA_PD_OT_INCIDENCIAS
  after delete on pd_ot_incidencias
  for each row

declare
  -- local variables here
  ln_horas number(4,2);            --horas de incidencias
  ln_cant_labor number(4,2);       --horas trabajo de pd_ot_det
  ln_horas_inciden number(4,2);    --horas de Incidencia de pd_ot_det
  ls_flag  char(1);                --flag de estado de operaciones

begin

 ln_horas := ( :old.fecha_fin - :old.fecha_inicio ) * 24;

select o.flag_estado,pod.cant_labor,pod.horas_inciden
  into ls_flag,ln_cant_labor,ln_horas_inciden
  from operaciones o,pd_ot_det pod
 where pod.nro_parte = :old.nro_parte and pod.nro_item = :old.nro_item
   and pod.oper_sec = o.oper_sec;

--comprobacion de de las horas inciden no pueden ser mayores a
--horas de trabajo

 ln_horas_inciden := nvl(ln_horas_inciden,0);

 if ln_horas_inciden <> 0 then
    ln_horas_inciden := ln_horas_inciden - ln_horas;
 end if;

--revisando el flag de estado de operaciones
 if ls_flag = '1' then

   update pd_ot_det
      set horas_inciden = ln_horas_inciden
    where nro_parte = :old.nro_parte and nro_item = :old.nro_item ;

 else

   RAISE_APPLICATION_ERROR( -20000, ' Oper Sec no esta Activo , No se puede modificar las horas de Incidencias') ;

 end if;

end TDA_PD_OT_INCIDENCIAS;
/

