prompt
prompt Creating trigger TDA_PRESUPUESTO_EJEC
prompt =====================================
prompt
CREATE OR REPLACE TRIGGER CANTABRIA.TDA_PRESUPUESTO_EJEC
  after delete on presupuesto_ejec
  for each row

declare
  -- local variables here
  ln_mes   number;
begin

  ln_mes := TO_NUMBER( TO_CHAR( :old.fecha, 'MM'));

  -- Actualiza importes ejecutados
  /*****************************************************
  **** REPLICACION
  *****************************************************/
  update presupuesto_partida
     set ejec_ene = DECODE( ln_mes, 1, NVL(ejec_ene,0)  - NVL(:old.importe,0), ejec_ene),
         ejec_feb = DECODE( ln_mes, 2, NVL(ejec_feb,0)  - NVL(:old.importe,0), ejec_feb),
         ejec_mar = DECODE( ln_mes, 3, NVL(ejec_mar,0)  - NVL(:old.importe,0), ejec_mar),
         ejec_abr = DECODE( ln_mes, 4, NVL(ejec_abr,0)  - NVL(:old.importe,0), ejec_abr),
         ejec_may = DECODE( ln_mes, 5, NVL(ejec_may,0)  - NVL(:old.importe,0), ejec_may),
         ejec_jun = DECODE( ln_mes, 6, NVL(ejec_jun,0)  - NVL(:old.importe,0), ejec_jun),
         ejec_jul = DECODE( ln_mes, 7, NVL(ejec_jul,0)  - NVL(:old.importe,0), ejec_jul),
         ejec_ago = DECODE( ln_mes, 8, NVL(ejec_ago,0)  - NVL(:old.importe,0), ejec_ago),
         ejec_set = DECODE( ln_mes, 9, NVL(ejec_set,0)  - NVL(:old.importe,0), ejec_set),
         ejec_oct = DECODE( ln_mes, 10, NVL(ejec_oct,0) - NVL(:old.importe,0), ejec_oct),
         ejec_nov = DECODE( ln_mes, 11, NVL(ejec_nov,0) - NVL(:old.importe,0), ejec_nov),
         ejec_dic = DECODE( ln_mes, 12, NVL(ejec_dic,0) - NVL(:old.importe,0), ejec_dic),
         flag_replicacion = '0'
   Where ano       = :old.ano
     and cencos    = :old.cencos
     and cnta_prsp = :old.cnta_prsp;
  /*****************************************************/

end TDA_PRESUPUESTO_EJEC;
/

