prompt
prompt Creating trigger TDA_RESERVACION_DET
prompt ====================================
prompt
CREATE OR REPLACE TRIGGER CANTABRIA.tda_reservacion_det
  after delete on reservacion_det
  for each row
declare
  -- local variables here
  ls_trigger_amp         tt_trigers.trigger_amp%TYPE := '0';
  ln_count               NUMBER;
  ln_cant_reservado      articulo_mov_proy.cant_reservado%TYPE;
  ls_estado              articulo_mov_proy.flag_estado%TYPE;
BEGIN

  -- verifico si existe un registro en la tabla tt_triggers, y que este activo el flag de trigger_amp
  -- de esta manera se que el registro que se esta insertando proviene de una insercion del
  -- trigger de ARTICULO_MOV_PROY y por lo tanto este trigger se va a encargar de actualizar el
  -- saldo reservado.

  SELECT COUNT(*)
    INTO ln_count
    FROM tt_trigers;

  IF ln_count > 0 THEN
     SELECT NVL(trigger_amp, '0')
       INTO ls_trigger_amp
       FROM tt_trigers;
  END IF;

  IF ls_trigger_amp = '1' THEN RETURN; END IF;

-- Verificando si AMP sigue activo
  -- Obtengo la cantidad Libre del Requerimiento de la OT, porque es lo maximo
  -- que se puede reservar
  SELECT cant_reservado, flag_estado
    INTO ln_cant_reservado, ls_estado
    FROM articulo_mov_proy amp
   WHERE amp.cod_origen    = :OLD.org_amp_ref
     AND amp.nro_mov       = :OLD.nro_amp_ref FOR UPDATE;

  IF ls_estado = '0' THEN
     RAISE_APPLICATION_ERROR(-20000, 'Requerimiento ' || :OLD.org_amp_ref
          || to_char(:OLD.nro_amp_ref) || ' esta anulado, por favor verifique ');
  END IF;

  IF ls_estado = '3' THEN
     RAISE_APPLICATION_ERROR(-20000, 'Requerimiento ' || :OLD.org_amp_ref
          || to_char(:OLD.nro_amp_ref) || ' esta planeado, por favor verifique ');
  END IF;

 IF :OLD.flag_estado = '1' THEN
    -- Verifico que la cantidad no se haga negativa
    IF ln_cant_reservado - (:old.cantidad - :OLD.cant_procesada) < 0 THEN
       raise_application_error(-20000, 'Cantidad reservada en requerimiento se hace negativo '
          || chr(13) || 'Reservacion N?: ' || to_char(:OLD.nro_reservacion)
          || chr(13) || 'Requerimiento ' || :OLD.org_amp_ref || to_char(:OLD.nro_amp_ref)
          || chr(13) || 'Reservado en AMP_OT: ' || to_char(ln_cant_reservado)
          || chr(13) || 'Cantidad: ' || to_char(:old.cantidad - :OLD.cant_procesada));
    END IF;

    -- Se disminuye la cantidad reservada
    ln_cant_reservado := ln_cant_reservado - (:old.cantidad - :OLD.cant_procesada);

    UPDATE articulo_mov_proy amp
       SET amp.cant_reservado = ln_cant_reservado
     WHERE amp.cod_origen = :OLD.org_amp_ref
       AND amp.nro_mov    = :OLD.nro_amp_ref ;
 END IF ;

END tda_reservacion_det;
/

prompt
prompt Creating trigger TDA_VALE_MOV_TRANS_DET
prompt =======================================
prompt
CREATE OR REPLACE TRIGGER CANTABRIA.TDA_VALE_MOV_TRANS_DET
  after delete on vale_mov_trans_det
  for each row
declare
  -- Logparam
  ls_soles             logparam.cod_soles%TYPE;
  ls_oper_ing_oc       logparam.oper_ing_oc%type;       -- Ingreso x OC
  ls_doc_oc            logparam.doc_oc%TYPE;            -- Documento Orden de Compra

  -- Articulo_Mov_Tipo
  ls_tipo_mov          articulo_mov_tipo.tipo_mov%type;
  ln_fac_total         articulo_mov_tipo.factor_sldo_total%type;
  ls_flag_clase_mov    articulo_mov_tipo.flag_clase_mov%TYPE;

  -- Vale_Mov_trans
  ld_fec_documento     vale_mov_trans.fec_documento%type;
  ls_org_oc            vale_mov_trans.org_oc%TYPE;
  ls_nro_oc            vale_mov_trans.nro_oc%type;
  ls_flag_estado       vale_mov_trans.flag_estado%TYPE;
  ls_almacen           vale_mov_trans.almacen%type;
  ls_origen            vale_mov_trans.cod_origen%TYPE;

  -- Articulo_almacen
  ln_saldo_total       articulo_almacen.sldo_total%TYPE;


  -- Articulo_Mov_Proy
  ln_cant_procesada    articulo_mov_proy.cant_procesada%type;
  ln_cant_transport    articulo_mov_proy.cant_transportada%TYPE;

  -- Varios
  ln_count             number;

BEGIN

  --=================================================
  --Verifico la cantidad no sea negativa
  --=================================================
  if :old.cant_procesada < 0 then
     RAISE_APPLICATION_ERROR(-20000, 'La cantidad no puede ser negativa');
  end if;

  --==============================================================
  -- Si el movimiento esta anulado, ya no tengo nada mas que hacer
  --==============================================================
  if :old.flag_estado = '0' THEN RETURN; end if;

  --=================================================
  -- Lectura de Parametros - LogParam
  --=================================================
   SELECT cod_soles , oper_ing_oc    , doc_oc
     INTO ls_soles  , ls_oper_ing_oc , ls_doc_oc
     FROM logparam l
    WHERE reckey = '1' ;

    if ls_doc_oc is null then
       RAISE_APPLICATION_ERROR(-20000, 'No ha definido doc_oc en logparam');
    end if;

  --=================================================
  -- Vale_mov_trans
  --=================================================
  SELECT almacen    , fec_documento  , tipo_mov   , org_oc,
         nro_oc     , cod_origen
    INTO ls_almacen , ld_fec_documento, ls_tipo_mov, ls_org_oc,
         ls_nro_oc  , ls_origen
    FROM vale_mov_trans
   WHERE nro_vale   = :old.nro_vale;

  --=================================================
  -- tipo de Movimiento
  --=================================================
  SELECT Nvl(factor_sldo_total,0),  flag_clase_mov, flag_estado
    INTO ln_fac_total, ls_flag_clase_mov, ls_flag_estado
    FROM articulo_mov_tipo
   WHERE tipo_mov = ls_tipo_mov ;

  IF ls_flag_estado = '0' THEN
     RAISE_APPLICATION_ERROR(-20000, 'Tipo de movimiento ' || ls_tipo_mov || ' esta anulado');
  END IF;

  --=================================================
  -- Validaciones de referencia
  --=================================================
  IF ln_fac_total = 1 AND ls_flag_clase_mov <> 'I' THEN
     RAISE_APPLICATION_ERROR(-20000, 'Los Ingresos siempre deben estar referenciados a una OC');
  END IF;

  IF ls_flag_clase_mov = 'I' AND  (:old.org_amp_oc is null or :old.nro_amp_oc is null) then
     RAISE_APPLICATION_ERROR(-20000, 'EL MOVIMIENTO TIENE REFERENCIA EN LA CABECERA PERO EN EL DETALLE '
            || chr(13) || chr(10) || 'EL CAMPO ORG_AMP_OC O NRO_AMP_OC ESTA VACIO O NULO'
            || chr(13) || chr(10) || 'ORG_AMP_OC: ' || :old.org_amp_oc
            || chr(13) || chr(10) || 'NRO_AMP_OC: ' || :old.nro_amp_oc
            || chr(13) || chr(10) || 'NRO_OC: '     || ls_nro_oc);
  end if;


  --=================================================
  -- Lectura Articulo_almacen
  --=================================================
  select count(*)
    into ln_count
    from articulo_almacen
   where cod_art = :old.cod_art
     and almacen = ls_almacen;

  if ln_count > 0 then
     SELECT NVL(sldo_total,0)
       INTO ln_saldo_total
       FROM articulo_almacen aa
      WHERE cod_art = :old.cod_art
        and almacen = ls_almacen FOR UPDATE;
  else
      ln_saldo_total      := 0;
  end if;


  --==================================================
  -- Lectura de AMP_OC
  --==================================================
  IF :old.nro_amp_oc IS NOT NULL THEN
     SELECT NVL(cant_procesada, 0), NVL(cant_transportada, 0)
       INTO ln_cant_procesada, ln_cant_transport
       FROM articulo_mov_proy
      WHERE cod_origen = :old.org_amp_oc
        AND nro_mov    = :old.nro_amp_oc FOR UPDATE;
  ELSE
      ln_cant_procesada    := 0;
      ln_cant_transport    := 0;
  END IF;

  --=============================================================
  -- Validad las cantidades en AMP_OC
  --=============================================================
  IF :old.nro_amp_oc IS NOT NULL THEN

     IF ln_fac_total = 1 THEN
        if ln_cant_procesada - :old.cant_procesada < 0 then
              RAISE_APPLICATION_ERROR( -20005, 'la Cantidad Procesada de la OC No puede ser negativa'
                             || chr(13) || 'Cant Procesada: ' || to_char(ln_cant_procesada)
                             || chr(13) || 'Cant Movimiento : ' || to_char(:old.cant_procesada)
                             || chr(13) || 'Tipo Mov      : ' || ls_tipo_mov
                             || chr(13) || 'Cod. Art      : ' || :old.cod_art) ;
        end if;
     END IF;

     IF ln_fac_total = -1 THEN
        if ln_cant_transport - :old.cant_procesada < 0 then
              RAISE_APPLICATION_ERROR( -20005, 'la Cantidad Transportada de la OC no puede ser negativa'
                             || chr(13) || 'Cant Transportada: ' || to_char(ln_cant_transport)
                             || chr(13) || 'Cant Movimiento  : ' || to_char(:old.cant_procesada)
                             || chr(13) || 'Tipo Mov      : ' || ls_tipo_mov
                             || chr(13) || 'Cod. Art      : ' || :old.cod_art) ;
        end if;
     END IF;
  END IF;

  --============================================
  -- Acualizo el saldo total
  --============================================
  ln_saldo_total      := NVL(ln_saldo_total,0) - :old.cant_procesada * ln_fac_total;

  if ln_saldo_total < 0 then
     RAISE_APPLICATION_ERROR(-20000, 'El saldo total no puede ser negativo'
                       || chr(13) || 'Saldo Total : ' || to_char(ln_saldo_total + :old.cant_procesada * ln_fac_total)
                       || chr(13) || 'Cantidad    : ' || to_char(:old.cant_procesada * ln_fac_total)
                       || chr(13) || 'Cod Art.    : ' || :old.cod_art);
     return;
  end if;


  --===============================================================
  -- Si es un ingreso debo actualiza la cantidad procesada de la OC
  --===============================================================
  IF :old.nro_amp_oc IS NOT NULL AND ln_fac_total = 1 THEN
     /*****************************************************
      **** REPLICACION
     *****************************************************/
     -- De lo contrario actualizo la cantidad procesada de la manera normal
     UPDATE articulo_mov_proy amp
        SET amp.cant_procesada = Nvl(cant_procesada,0) - :old.cant_procesada,
            amp.flag_replicacion = '0'
      WHERE cod_origen  = :old.org_amp_oc
        AND nro_mov     = :old.nro_amp_oc;
     /*****************************************************/

  END IF;

  --===============================================================
  -- Si es una salida debo actualizar la cantidad transportada en
  -- el detalle de cada OC
  --===============================================================
  IF :old.nro_amp_oc IS NOT NULL AND ln_fac_total = -1 THEN
     /*****************************************************
      **** REPLICACION
     *****************************************************/
     -- De lo contrario actualizo la cantidad procesada de la manera normal
     UPDATE articulo_mov_proy amp
        SET amp.cant_transportada = Nvl(amp.cant_transportada, 0) - :old.cant_procesada,
            amp.flag_replicacion = '0'
      WHERE cod_origen  = :old.org_amp_oc
        AND nro_mov     = :old.nro_amp_oc;
     /*****************************************************/

  END IF;

  --==================================================
  -- Actualizacion Articulo_almacen
  --==================================================
  <<Grabacion_Articulo>>
  IF ln_fac_total <> 0 and :old.cant_procesada > 0 THEN
     /*****************************************************
     **** REPLICACION
     *****************************************************/
     UPDATE Articulo_almacen
        SET sldo_total        = ln_saldo_total,
            flag_replicacion  = '0'
      WHERE COD_ART = :old.cod_art
        and almacen = ls_almacen;
     /*****************************************************/

     if SQL%NOTFOUND then
        IF ln_fac_total = -1 THEN
           /*****************************************************
           **** REPLICACION
           *****************************************************/
           insert into articulo_almacen(
                  almacen, cod_art, sldo_total, flag_replicacion)
           values(
                  ls_almacen, :old.cod_art, ln_saldo_total, '0' );
           /*****************************************************/
        ELSE
           RAISE_APPLICATION_ERROR( -20000, 'El Articulo ' || :old.cod_art ||
                         ' no tiene saldo en el Almacen ' || ls_almacen) ;
        END IF;
     end if;
  END IF;

end TDA_VALE_MOV_TRANS_DET;
/

prompt
prompt Creating trigger TDB_AP_GUIA_RECEPCION
prompt ======================================
prompt
CREATE OR REPLACE TRIGGER CANTABRIA.TDB_AP_GUIA_RECEPCION
  before delete on ap_guia_recepcion
  for each row
declare
-- local variables here
  ls_doc_grmp        ap_param.doc_guia_mp%TYPE;
  ln_count           number;
  ls_docs            varchar2(10000);

  cursor c_cp_grmp(as_nro_grmp  ap_guia_recepcion.cod_guia_rec%TYPE) is
    select cp.tipo_doc, cp.nro_doc
      from cntas_pagar cp,
           cntas_pagar_det cpd
     where cp.cod_relacion = cpd.cod_relacion
       and cp.tipo_doc     = cpd.tipo_doc
       and cp.nro_doc      = cpd.nro_doc
       and cpd.tipo_ref    = ls_doc_grmp
       and cpd.nro_ref     = as_nro_grmp
       and cp.flag_estado  <> '0';

begin

  select count(*)
    into ln_count
    from ap_param t
   where t.origen = 'XX';

  if ln_count = 0 then
     RAISE_APPLICATION_ERROR(-20000, 'No existen paramatros generales en AP_PARAM, por favor verficar');
  end if;

  select doc_guia_mp
    into ls_doc_grmp
    from ap_param t
   where t.origen = 'XX';

  -- ahora busco si hay referencia en cntas_pagar_det
  select count(*)
    into ln_count
    from cntas_pagar     cp,
         cntas_pagar_det cpd
     where cp.cod_relacion = cpd.cod_relacion
       and cp.tipo_doc     = cpd.tipo_doc
       and cp.nro_doc      = cpd.nro_doc
       and cpd.tipo_ref    = ls_doc_grmp
       and cpd.nro_ref     = :old.cod_guia_rec
       and cp.flag_estado  <> '0';

  if ln_count > 0 then
     -- Busco el primer registro y lo muestro
     ls_docs := '';
     for lc_reg in c_cp_grmp(:old.cod_guia_rec) loop
         ls_docs := lc_reg.tipo_doc || '-' || lc_reg.nro_doc || ', ';
     end loop;
     RAISE_APPLICATION_ERROR(-20000, 'No se puede eliminar la Guia Nro: ' || :old.cod_guia_rec
                                     || ' porque ha generado los siguientes documentos x pagar: ' || ls_docs);
  end if;
end TDB_AP_GUIA_RECEPCION;
/

prompt
prompt Creating trigger TDB_AP_PD_DESCARGA_DET
prompt =======================================
prompt
CREATE OR REPLACE TRIGGER CANTABRIA.tdb_ap_pd_descarga_det
  before delete on ap_pd_descarga_det
  for each row
declare
  -- local variables here
  ls_nro_oc          orden_compra.nro_oc%TYPE;
  ls_nro_grmp        ap_guia_recepcion.cod_guia_rec%TYPE;
  ls_flag_os         orden_servicio_det.flag_estado%TYPE;
  ln_count           NUMBER;
BEGIN
  -- Verifico si la GRMP tiene OC
  SELECT COUNT(*)
    INTO ln_count
    FROM ap_guia_recepcion a,
         ap_guia_recepcion_det b
   WHERE a.cod_guia_rec = b.cod_guia_rec
     AND b.nro_parte    = :OLD.nro_parte
     AND b.item_parte   = :OLD.item;

  IF ln_count > 0 THEN
     SELECT a.nro_oc, a.cod_guia_rec
       INTO ls_nro_oc, ls_nro_grmp
       FROM ap_guia_recepcion a,
            ap_guia_recepcion_det b
      WHERE a.cod_guia_rec = b.cod_guia_rec
        AND b.nro_parte    = :OLD.nro_parte
        AND b.item_parte   = :OLD.item;


  END IF;

  IF ls_nro_oc IS NOT NULL THEN
     RAISE_APPLICATION_ERROR(-20000, 'No puede eliminar el item ' || to_char(:OLD.item) || ' del parte '
                                   || :OLD.nro_parte || ' porque ya tiene OC ' || ls_nro_oc);
  END IF;

  -- Si existe un numero de GRMP entonces elimino el detalle y anulo la cabecera
  IF ls_nro_grmp IS NOT NULL THEN
     DELETE ap_guia_recepcion_det t
      WHERE t.nro_parte  = :OLD.nro_parte
      AND t.item_parte = :OLD.item;

     UPDATE ap_guia_recepcion
        SET flag_estado = '0'
      WHERE cod_guia_rec = ls_nro_grmp;

  END IF;



  -- Verifico si tiene OS y que ademas este activo
  SELECT COUNT(*)
    INTO ln_count
    FROM orden_servicio_det osd
   WHERE osd.cod_origen = :OLD.org_os
     AND osd.nro_os     = :OLD.nro_os
     AND osd.nro_item   = :OLD.item_os;

  IF ln_count > 0 THEN
     SELECT flag_Estado
       INTO ls_flag_os
       FROM orden_servicio_det osd
      WHERE osd.cod_origen = :OLD.org_os
        AND osd.nro_os     = :OLD.nro_os
        AND osd.nro_item   = :OLD.item_os;

     IF ls_flag_os <> '1' THEN
        RAISE_APPLICATION_ERROR(-20000, 'No puede eliminar el item ' || to_char(:OLD.item) || ' del parte '
                                     || :OLD.nro_parte || ' porque el item ' || to_char(:new.item_os)
                                     || ' la OS ' || :NEW.nro_os || ' no se encuentra activo, por favor verifique');
     END IF;

     UPDATE orden_servicio_det osd
        SET flag_estado = '0'
      WHERE osd.cod_origen = :OLD.org_os
        AND osd.nro_os     = :OLD.nro_os
        AND osd.nro_item   = :OLD.item_os;


     SELECT COUNT(*)
       INTO ln_count
       FROM orden_servicio_det osd
      WHERE osd.cod_origen = :OLD.org_os
        AND osd.nro_os     = :OLD.nro_os
        AND osd.flag_estado = '1';

     -- Si no tiene detalle anulo la cabecera
     IF ln_count = 0 THEN
        UPDATE orden_servicio os
           SET flag_estado = '0'
         WHERE os.cod_origen = :OLD.org_os
           AND os.nro_os     = :OLD.nro_os;
     END IF;


  END IF;
end tdb_ap_pd_descarga_det;
/

prompt
prompt Creating trigger TDB_ARTICULO_MOV_PROY
prompt ======================================
prompt
CREATE OR REPLACE TRIGGER CANTABRIA.TDB_ARTICULO_MOV_PROY
  AFTER DELETE on articulo_mov_proy
  for each row

DECLARE
  -- LogParam
  ls_doc_otr           logparam.doc_otr%TYPE;
  ls_oper_ing_otr      logparam.oper_ing_otr%TYPE;
  ls_oper_sal_otr      logparam.oper_sal_otr%TYPE;
  ls_doc_sc            logparam.doc_sc%TYPE;
  ls_doc_prog          logparam.tipo_doc_prog_cmp%TYPE;
  ls_doc_oc            logparam.doc_oc%TYPE;
  ls_doc_ot            logparam.doc_ot%TYPE;

BEGIN

  --==============================================================
  -- Si el movimiento esta anulado ya no hay nada que hacer
  --==============================================================
  if :old.flag_estado = '0' then return; end if;

  --==============================================================
  -- Si el movimiento esta proyectado tampoco tengo nada que hacer
  --==============================================================
  if :old.flag_estado = '3' then return; end if;

  --==============================================================
  -- Si el movimiento tiene aprobación, tampoco tengo nada que hacer
  --==============================================================
  if NVL(:old.nro_aprob,' ') <> ' ' then
     RAISE_APPLICATION_ERROR(-20000, 'Registro tiene aprobacion');
     return;
  end if;

  --===============================================
  -- Lectura de parametros de logparam
  --===============================================
  select doc_sc, doc_otr, oper_sal_otr, oper_ing_otr, tipo_doc_prog_cmp,
         doc_oc, doc_ot
    into ls_doc_sc, ls_doc_otr, ls_oper_sal_otr, ls_oper_ing_otr, ls_doc_prog,
         ls_doc_oc, ls_doc_ot
  from logparam
  where reckey = '1';

  --===============================================
  -- Verificacion de parametros
  --===============================================
  if ls_doc_otr = '' or ls_doc_otr is null then
     RAISE_APPLICATION_ERROR(-20000, 'No ha definido Documento de ORDEN DE TRASLADO en LogParam');
  end if;

  if ls_doc_prog = '' or ls_doc_prog is null then
     RAISE_APPLICATION_ERROR(-20000, 'No ha definido Documento PROGRAMA DE COMPRAS en LogParam');
  end if;

  if ls_doc_ot = '' or ls_doc_ot is null then
     RAISE_APPLICATION_ERROR(-20000, 'No ha definido Documento ORDEN DE TRABAJO en LogParam');
  end if;

  --===================================================
  -- Verifico que no pueda eliminar un amp que ya
  -- tenga movimiento de almacen, facturado o reservado
  --===================================================
  if :old.tipo_doc = ls_doc_otr then
     if :old.tipo_mov = ls_oper_sal_otr then
       if :old.cant_procesada > 0 then
          RAISE_APPLICATION_ERROR( -20000, 'NO SE PUEDE ELIMINAR REGISTRO, TIENE SALIDAS DE ALMACEN');
          return;
       end if;
       if :old.cant_facturada > 0 then
          RAISE_APPLICATION_ERROR( -20000, 'NO SE PUEDE ELIMINAR REGISTRO, TIENE INGRESOS A ALMACEN');
          return;
       end if;
     end if;
  else
     if :old.cant_procesada > 0 then
        RAISE_APPLICATION_ERROR( -20000, 'NO SE PUEDE ELIMINAR REGISTRO, TIENE CANTIDAD PROCESADA');
        return;
     end if;
     if :old.cant_facturada > 0 then
        RAISE_APPLICATION_ERROR( -20000, 'NO SE PUEDE ELIMINAR REGISTRO, TIENE CANTIDAD FACTURADA');
        return;
     end if;
     if :old.cant_reservado > 0 then
        RAISE_APPLICATION_ERROR( -20000, 'NO SE PUEDE ELIMINAR REGISTRO, TIENE CANTIDAD RESERVADA');
        return;
     end if;
  end if;

end TDB_ARTICULO_MOV_PROY;
/

prompt
prompt Creating trigger TDB_FIN_CNTAS_COBRAR
prompt =====================================
prompt
CREATE OR REPLACE TRIGGER CANTABRIA.TDB_FIN_CNTAS_COBRAR
  BEFORE delete on cntas_cobrar
  for each row




declare
  -- local variables here
  lc_bol_cobrar  doc_tipo.tipo_doc%type  ;

begin
  -- Edgar Morante Miercoles 10Jul2002, replicacion
  If (dbms_reputil.from_remote=true or dbms_snapshot.i_am_a_refresh=true) then
     return;
  end if;

  IF :old.flag_detraccion = '1'THEN
     delete from detraccion where nro_detraccion = :old.nro_detraccion ;
  END IF ;

end TDB_FIN_CNTAS_COBRAR ;
/

prompt
prompt Creating trigger TDB_FIN_CNTAS_PAGAR
prompt ====================================
prompt
CREATE OR REPLACE TRIGGER CANTABRIA.tdb_fin_cntas_pagar
  before delete on cntas_pagar
  for each row

DECLARE
  -- local variables here
ln_count             number ;
ln_imp_dol_old       cntas_pagar.importe_doc%type ;
lc_dolares           logparam.cod_dolares%type ;

BEGIN

If (dbms_reputil.from_remote=true or dbms_snapshot.i_am_a_refresh=true) then
 return;
end if;

IF :old.flag_detraccion = '1' THEN
  delete from detraccion where nro_detraccion = :old.nro_detraccion ;
END IF;

-- Actualizando "ot_otros_gastos"
SELECT count(*)
 INTO ln_count
 FROM ot_otros_gastos ot
WHERE ot.cod_relacion = :old.cod_relacion
  AND ot.tipo_doc     = :old.tipo_doc
  AND ot.nro_doc      = :old.nro_doc ;

IF ln_count > 0 THEN
   SELECT l.cod_dolares
     INTO lc_dolares
     FROM logparam l
    WHERE reckey='1' ;

   -- Calculando antiguo importe
   IF :old.cod_moneda = lc_dolares THEN
      ln_imp_dol_old := :old.importe_doc ;
   ELSE
      IF :old.tasa_cambio > 0 THEN
         ln_imp_dol_old := :old.importe_doc / :old.tasa_cambio ;
      ELSE
         ln_imp_dol_old := 0 ;
      END IF ;
   END IF ;
   -- Actualizando el costo en las ordenes de trabajo afectadas
   UPDATE orden_trabajo ot
      SET ot.costo_ejecutado = NVL(ot.costo_ejecutado,0) - ln_imp_dol_old
    WHERE ot.nro_orden IN (SELECT otg.nro_orden
                             FROM ot_otros_gastos otg
                            WHERE otg.cod_relacion = :old.cod_relacion
                              AND otg.tipo_doc     = :old.tipo_doc
                              AND otg.nro_doc      = :old.nro_doc) ;
END IF ;

END tdb_fin_cntas_pagar;
/

prompt
prompt Creating trigger TDB_FIN_CNTAS_PAGAR_DET
prompt ========================================
prompt
CREATE OR REPLACE TRIGGER CANTABRIA.TDB_FIN_CNTAS_PAGAR_DET
  before delete on cntas_pagar_det
  for each row


declare
  -- local variables here
  lc_doc_oc          logparam.doc_oc%type ;
  lc_doc_os          logparam.doc_os%type ;
  lc_origen_ref      doc_referencias.origen_ref%type  ;
  lc_tipo_ref        doc_referencias.tipo_doc%type    ;
  lc_nro_ref         doc_referencias.nro_doc%type     ;
  lc_tdoc_ndp        doc_tipo.tipo_doc%type           ;
  lc_tdoc_ncp        doc_tipo.tipo_doc%type           ;
  ln_count           Number                           ;
  lc_flag_provision  finparam.flag_os_provision%type  ;
  ln_importe_x_item  cntas_pagar_det.importe%type     ;

  --Moneda
  lc_cod_moneda      moneda.cod_moneda%type           ;

  ln_tasa_cambio     calendario.cmp_dol_libre%type    ;

  -- AP_PARAM
  ls_doc_grmp        ap_param.doc_guia_mp%TYPE;

  -- AP_GUIA_RECEPCION_DET
  ls_nro_grmp        ap_guia_recepcion_det.cod_guia_rec%TYPE;
  Ln_item_grmp       ap_guia_recepcion_det.item%TYPE;

  ln_monto_fac_grmp   ap_guia_recepcion_det.monto_facturado%TYPE;
  ln_monto_tot_fac    ap_guia_recepcion_det.monto_facturado%TYPE;

  -- AP_GUIA_RECEPCION
  ls_moneda_grmp      ap_guia_recepcion.cod_moneda%TYPE;

  -- Articulo_mov_proy
  ln_Cant_facturada   articulo_mov_proy.cant_facturada%TYPE;
  ls_tipo_doc_amp     articulo_mov_proy.tipo_doc%TYPE;
  ls_nro_doc_amp      articulo_mov_proy.nro_doc%TYPE;

  -- Orden_Servicio_det
  ln_imp_provisionado orden_servicio_det.imp_provisionado%TYPE;


begin
  -- Edgar Morante Miercoles 10Jul2002, replicacion
  If (dbms_reputil.from_remote=true or dbms_snapshot.i_am_a_refresh=true) then
     return;
  end if;


  /*Recupero tipo de doc Orden de Compra*/
  select doc_oc,doc_os into lc_doc_oc,lc_doc_os
    from logparam
   where (reckey = '1') ;

  select nvl(f.flag_os_provision,'0')
    into lc_flag_provision
    from finparam f
   where reckey = '1' ;

  /*Recuperacion de Tipo de Referencia*/
  select Count(*) into ln_count from doc_referencias
   where ((cod_relacion = :old.cod_relacion ) AND
          (tipo_doc     = :old.tipo_doc     ) AND
          (nro_doc      = :old.nro_doc      ) AND
          (flab_tabor   in ('7','8')        ));

  if ln_count > 0 then
     /*Recuperacion de Tipo de Referencia*/
     select origen_ref,tipo_ref,nro_ref into lc_origen_ref,lc_tipo_ref,lc_nro_ref
       from doc_referencias
      where ((cod_relacion = :old.cod_relacion ) AND
             (tipo_doc     = :old.tipo_doc     ) AND
             (nro_doc      = :old.nro_doc      ) AND
             (flab_tabor   in ('7','8')        ));
  end if ;


  SELECT nota_cred_nfc,nota_deb_ncc,flag_os_provision
    INTO lc_tdoc_ncp,lc_tdoc_ndp,lc_flag_provision
    FROM finparam
   WHERE (reckey = '1') ;

  -- actualizo la cantidad facturada de Articulo_mov_proy (Orden de compra)
  IF  :old.org_amp_ref is not null and :old.nro_amp_ref is not null and
      :old.tipo_doc not in (pq_doc_finanzas.is_doc_ncp, pq_doc_finanzas.is_doc_ndp, pq_doc_finanzas.is_doc_cnc) THEN

      select nvl(amp.cant_facturada, 0), amp.tipo_doc, amp.nro_doc
        into ln_cant_facturada, ls_tipo_doc_amp, ls_nro_doc_amp
        from articulo_mov_proy amp
       where amp.cod_origen = :old.org_amp_ref
         and amp.nro_mov    = :old.nro_amp_ref for update;

      if ln_cant_facturada - :old.cantidad < 0 then
         RAISE_APPLICATION_ERROR( -20000, 'La cantidad a provisionar no puede sobrepasar a la cantidad procesada. Por favor verifique. '
                            || chr(13) || 'Tipo Doc: ' || ls_tipo_doc_amp
                            || chr(13) || 'Nro Doc: ' || ls_nro_doc_amp
                            || chr(13) || 'Articulo: ' || NVL(:old.cod_art,'')
                            || chr(13) || 'Cant. Facturada: ' || to_char(ln_cant_facturada, '999,990.00')
                            || chr(13) || 'Cant. Provisi?n: ' || to_char(:old.cantidad, '999,990.00'));
      end if;

       UPDATE articulo_mov_proy amp
          SET cant_facturada = ln_cant_facturada - NVL(:old.cantidad,0),
              flag_replicacion = '0'
        where amp.cod_origen = :old.org_amp_ref
         and amp.nro_mov     = :old.nro_amp_ref;
  end if;

  -- Actualizo el improte facturado de la Orden de Servicio
  if :old.org_os is not null and :old.nro_os is not null and :old.item_os is not null AND
     :old.tipo_doc not in (pq_doc_finanzas.is_doc_ncp, pq_doc_finanzas.is_doc_ndp, pq_doc_finanzas.is_doc_cnc) then

     select count(*)
       into ln_count
       from orden_servicio_det osd
      where osd.cod_origen = :old.org_os
        and osd.nro_os     = :old.nro_os
        and osd.nro_item   = :old.item_os;

     if ln_count > 0 then
        select NVL(osd.imp_provisionado, 0)
          into ln_imp_provisionado
          from orden_servicio_det osd
         where osd.cod_origen = :old.org_os
           and osd.nro_os     = :old.nro_os
           and osd.nro_item   = :old.item_os for update;

        IF ln_imp_provisionado - :old.importe < 0 THEN
            RAISE_APPLICATION_ERROR( -20000, 'El importe Facturado de la Orden de Servicio es negativo. Por favor verifique. '
                               || chr(13) || 'Tipo Doc: ' || lc_doc_os
                               || chr(13) || 'Nro Doc: ' || :old.nro_os
                               || chr(13) || 'Item OS: ' || NVL(:old.item_os,'')
                               || chr(13) || 'Importe Provisionado: ' || to_char(ln_imp_provisionado, '999,990.00')
                               || chr(13) || 'Importe. a Provisionar: ' || to_char(:old.importe, '999,990.00'));
        end if;

        UPDATE orden_servicio_det osd
           SET osd.imp_provisionado = ln_imp_provisionado - :old.importe,
               flag_replicacion     = '0'
        where osd.cod_origen = :old.org_os
          and osd.nro_os     = :old.nro_os
          and osd.nro_item   = :old.item_os;
     end if;
  END IF ;


  --============================================================================
  -- Si documento de Referencia es una Guia de Recepcion de Materia Prima
  --============================================================================
  SELECT l.doc_guia_mp
     INTO ls_doc_grmp
  FROM   ap_param l
  WHERE l.origen = 'XX';

  IF ls_doc_grmp IS NULL THEN
      RAISE_APPLICATION_ERROR(-20000, 'No ha definido documento de Guia de Recepcion de '
      || 'Materia Prima en AP_PARAM');
     RETURN ;
  END IF;

  -- Recupera el tipo de cambio
  SELECT cp.tasa_cambio
    INTO ln_tasa_cambio
    FROM cntas_pagar cp
   WHERE ((cp.cod_relacion = :OLD.cod_relacion ) AND
          (cp.tipo_doc     = :OLD.tipo_doc     ) AND
          (cp.nro_doc      = :OLD.nro_doc      ));

  IF :OLD.tipo_ref = ls_doc_grmp THEN
       ls_nro_grmp  := :OLD.nro_ref;
       ln_item_grmp := :OLD.item_ref;

       select count(*)
         into ln_count
         from ap_guia_recepcion
        where cod_guia_rec = ls_nro_grmp;


       if ln_count = 0 then
          RAISE_APPLICATION_ERROR(-20000, 'No existe la Guia de Recepcion Nro: ' || ls_nro_grmp);
       end if;

       --Obtengo la moneda de la cabecera de la GRMP
       SELECT COD_MONEDA
        INTO ls_moneda_grmp
       FROM  ap_guia_recepcion
       WHERE cod_guia_rec = ls_nro_grmp;

       -- Obtengo el monto facturado del detalle de la GRMP
       SELECT nvl(a.monto_facturado,0)
        INTO  ln_monto_fac_grmp
       FROM   ap_guia_recepcion_det a
       WHERE  a.cod_guia_rec = ls_nro_grmp
         AND  a.item         = ln_item_grmp;

       -- Verificamos que el importe facturado no sea negativo
       ln_importe_x_item := :OLD.importe ;
       IF ls_moneda_grmp <> lc_cod_moneda THEN
          IF ls_moneda_grmp = PKG_LOGISTICA.is_soles THEN
             ln_importe_x_item := ROUND(ln_importe_x_item * ln_tasa_cambio,2);
          ELSE
             ln_importe_x_item := Round(ln_importe_x_item / ln_tasa_cambio,2);
          END IF;
       END IF;

       -- Calculo el monto total facturado
       ln_monto_tot_fac := ln_monto_fac_grmp - ln_importe_x_item ;

       -- Actualizo el monto total facturado de la GRMP
       UPDATE AP_GUIA_RECEPCION_DET
           SET monto_facturado = ln_monto_tot_fac
        WHERE  cod_guia_rec = ls_nro_grmp
         AND   item         = ln_item_grmp;

  END IF;
  --============================================================================

end TDB_FIN_CNTAS_PAGAR_DET;
/

prompt
prompt Creating trigger TDB_FL_VENTAS
prompt ==============================
prompt
CREATE OR REPLACE TRIGGER CANTABRIA.tdb_fl_ventas
  before delete on fl_venta
  for each row
declare
  -- local variables here
  ln_mes 		number;
  ln_pesca  number;
  ls_nave   tg_naves.nave%TYPE;
begin

	ln_pesca := :old.cantidad_real - :old.cantidad_castigada;

  select to_number( to_char(flpp.fecha_hora_arribo, 'mm') ), flpp.nave_real
  	into ln_mes, ls_nave
  from 	fl_parte_de_pesca flpp
  where flpp.parte_pesca = :old.parte_pesca;

  update fl_pesca_proy flpy
  	set flpy.pesca_real = flpy.pesca_real - ln_pesca,
        flag_replicacion = '0'
  where flpy.mes = ln_mes
  	and flpy.nave = ls_nave;

end tdb_fl_ventas;
/

prompt
prompt Creating trigger TDB_PRESUPUESTO_EJEC
prompt =====================================
prompt
CREATE OR REPLACE TRIGGER CANTABRIA.TDB_PRESUPUESTO_EJEC
  before delete on presupuesto_ejec
  for each row
declare
  -- local variables here
  Cursor c_fondo_var_aut is
     SELECT t.nro_variacion
        FROM fondo_var_aut_log t
       WHERE t.org_prsp_ejec = :old.cod_origen
         and t.nro_prsp_ejec = :old.nro_mov;
begin

  for lc_Reg in c_fondo_var_aut loop
      Delete fondo_var_aut_log t
       where t.nro_variacion = lc_Reg.nro_variacion;

      Delete presup_variacion
       where nro_variacion = lc_reg.nro_variacion;

  end loop;

end TDB_PRESUPUESTO_EJEC;
/

