prompt
prompt Creating trigger TIA_CNTBL_ASIENTO_DET
prompt ======================================
prompt
CREATE OR REPLACE TRIGGER CANTABRIA.TIA_CNTBL_ASIENTO_DET
  after insert on cntbl_asiento_det
  for each row

declare
  -- local variables here
  ln_n1              cntblparam.nivel1%type  ;
  ln_n2              cntblparam.nivel2%type  ;
  ln_n3              cntblparam.nivel3%type  ;
  ln_n4              cntblparam.nivel4%type  ;
  ln_n5              cntblparam.nivel5%type  ;
  ln_n6              cntblparam.nivel6%type  ;
  ln_n7              cntblparam.nivel7%type  ;
  ln_n8              cntblparam.nivel8%type  ;
  ln_n9              cntblparam.nivel9%type  ;
  ln_n10             cntblparam.nivel10%type  ;
  ln_len_cnta        cntblparam.nivel10%type  ;
  ls_cuenta          varchar2(10) ;
  ln_count           number;
  ln_rc              number;

BEGIN

-- Edgar Morante Miercoles 10Jul2002, replicacion
If (dbms_reputil.from_remote=true or dbms_snapshot.i_am_a_refresh=true) then
    return;
end if;


-- Valido que si tiene tipo_doc de referencia tambien tenga nro_doc
if :new.tipo_docref1 is not null and :new.nro_docref1 is null then
   RAISE_APPLICATION_ERROR(-20000, 'CUENTA ' || rtrim(:new.cnta_ctbl) || ', TIENE TIPO DE DOCUMENTO PERO NO TIENE REFERENCIA, POR FAVOR VERIFIQUE.');
end if;

-- Lectura de tama?o de niveles
SELECT nivel1, nivel2, nivel3, nivel4, nivel5, nivel6,
       nivel7, nivel8, nivel9, nivel10
  INTO ln_n1, ln_n2, ln_n3, ln_n4, ln_n5, ln_n6,
       ln_n7, ln_n8, ln_n9, ln_n10
  FROM cntblparam
 WHERE reckey = '1' ;

-- Sumar Saldos en Tabla CNTBL_CNTA_SDO
ls_cuenta := rtrim( nvl( :new.cnta_ctbl, '') );
ln_len_cnta := length( trim( ls_cuenta ) );

ls_cuenta := SubStr(ls_cuenta, 1, ln_len_cnta) ;

-- Actualiza saldos de cuentas contables

IF Length(ls_cuenta) = nvl(ln_n10,0) THEN
   ln_rc := usf_sumar_saldo_cnta(an_ano => :new.ano,
                                 an_mes => :new.mes,
                                 as_cuenta => ls_cuenta,
                                 as_flag => :new.flag_debhab,
                                 adc_impsol => :new.imp_movsol,
                                 adc_impdol => :new.imp_movdol,
                                 adc_impaju => :new.imp_movaju) ;

   ls_cuenta := SubStr(ls_cuenta, 1, ln_n9) ;
END IF ;
IF Length(ls_cuenta) = nvl(ln_n9,0) THEN
   ln_rc := usf_sumar_saldo_cnta(an_ano => :new.ano,
                                 an_mes => :new.mes,
                                 as_cuenta => ls_cuenta,
                                 as_flag => :new.flag_debhab,
                                 adc_impsol => :new.imp_movsol,
                                 adc_impdol => :new.imp_movdol,
                                 adc_impaju => :new.imp_movaju) ;

   ls_cuenta := SubStr(ls_cuenta, 1, ln_n8) ;
END IF  ;
IF Length(ls_cuenta) = nvl(ln_n8,0) THEN
   ln_rc := usf_sumar_saldo_cnta(an_ano => :new.ano,
                                 an_mes => :new.mes,
                                 as_cuenta => ls_cuenta,
                                 as_flag => :new.flag_debhab,
                                 adc_impsol => :new.imp_movsol,
                                 adc_impdol => :new.imp_movdol,
                                 adc_impaju => :new.imp_movaju) ;

   ls_cuenta := SubStr(ls_cuenta, 1, ln_n7) ;
END IF   ;
IF Length(ls_cuenta) = nvl(ln_n7,0) THEN
   ln_rc := usf_sumar_saldo_cnta(an_ano => :new.ano,
                                 an_mes => :new.mes,
                                 as_cuenta => ls_cuenta,
                                 as_flag => :new.flag_debhab,
                                 adc_impsol => :new.imp_movsol,
                                 adc_impdol => :new.imp_movdol,
                                 adc_impaju => :new.imp_movaju) ;

   ls_cuenta := SubStr(ls_cuenta, 1, ln_n6) ;
END IF ;
IF Length(ls_cuenta) = nvl(ln_n6,0) THEN
   ln_rc := usf_sumar_saldo_cnta(an_ano => :new.ano,
                                 an_mes => :new.mes,
                                 as_cuenta => ls_cuenta,
                                 as_flag => :new.flag_debhab,
                                 adc_impsol => :new.imp_movsol,
                                 adc_impdol => :new.imp_movdol,
                                 adc_impaju => :new.imp_movaju) ;

   ls_cuenta := SubStr(ls_cuenta, 1, ln_n5) ;
END IF ;
IF Length(ls_cuenta) = nvl(ln_n5,0) THEN
   ln_rc := usf_sumar_saldo_cnta(an_ano => :new.ano,
                                 an_mes => :new.mes,
                                 as_cuenta => ls_cuenta,
                                 as_flag => :new.flag_debhab,
                                 adc_impsol => :new.imp_movsol,
                                 adc_impdol => :new.imp_movdol,
                                 adc_impaju => :new.imp_movaju) ;

   ls_cuenta := SubStr(ls_cuenta, 1, ln_n4) ;
END IF ;
IF Length(ls_cuenta) = nvl(ln_n4,0) THEN
   ln_rc := usf_sumar_saldo_cnta(an_ano => :new.ano,
                                 an_mes => :new.mes,
                                 as_cuenta => ls_cuenta,
                                 as_flag => :new.flag_debhab,
                                 adc_impsol => :new.imp_movsol,
                                 adc_impdol => :new.imp_movdol,
                                 adc_impaju => :new.imp_movaju) ;

   ls_cuenta := SubStr(ls_cuenta, 1, ln_n3) ;
END IF ;
IF Length(ls_cuenta) = nvl(ln_n3,0) THEN
   ln_rc := usf_sumar_saldo_cnta(an_ano => :new.ano,
                                 an_mes => :new.mes,
                                 as_cuenta => ls_cuenta,
                                 as_flag => :new.flag_debhab,
                                 adc_impsol => :new.imp_movsol,
                                 adc_impdol => :new.imp_movdol,
                                 adc_impaju => :new.imp_movaju) ;

   ls_cuenta := SubStr(ls_cuenta, 1, ln_n2) ;
END IF ;
IF Length(ls_cuenta) = nvl(ln_n2,0) THEN
   ln_rc := usf_sumar_saldo_cnta(an_ano => :new.ano,
                                 an_mes => :new.mes,
                                 as_cuenta => ls_cuenta,
                                 as_flag => :new.flag_debhab,
                                 adc_impsol => :new.imp_movsol,
                                 adc_impdol => :new.imp_movdol,
                                 adc_impaju => :new.imp_movaju) ;

   ls_cuenta := SubStr(ls_cuenta, 1, ln_n1) ;
END IF ;
IF Length(ls_cuenta) = nvl(ln_n1,0) THEN
   ln_rc := usf_sumar_saldo_cnta(an_ano => :new.ano,
                                 an_mes => :new.mes,
                                 as_cuenta => ls_cuenta,
                                 as_flag => :new.flag_debhab,
                                 adc_impsol => :new.imp_movsol,
                                 adc_impdol => :new.imp_movdol,
                                 adc_impaju => :new.imp_movaju) ;

END IF ;

-- Ingresando cuenta corriente, si fuera el caso
select count(*)
  into ln_count
  FROM cntbl_cnta c
 WHERE c.cnta_ctbl = :new.cnta_ctbl ;

if ln_count = 0 then
   RAISE_APPLICATION_ERROR(-20000, 'No existe cuenta contable ' || :new.cnta_ctbl) ;
end if;

/*
SELECT c.flag_codrel,   c.flag_doc_ref
  INTO ls_flag_codrel,  ls_flag_doc_ref
  FROM cntbl_cnta c
 WHERE c.cnta_ctbl = :new.cnta_ctbl ;

IF NVL(ls_flag_codrel,' ') = '1' AND
   NVL(ls_flag_doc_ref,' ') = '1' THEN

  IF :new.cnta_ctbl    IS NOT NULL AND
     :new.cod_relacion IS NOT NULL AND
     :new.tipo_docref1 IS NOT NULL AND
     :new.nro_docref1  IS NOT NULL THEN

     ln_rc := usf_cnt_sumar_cta_cte(
              :new.ano, :new.mes,
              :new.origen, :new.cod_relacion,
              :new.cnta_ctbl, :new.tipo_docref1,
              :new.nro_docref1, :new.flag_debhab,
              :new.imp_movsol, :new.imp_movdol
              ) ;

  END IF ;
END IF ;

*/


end TIA_CNTBL_ASIENTO_DET;
/

prompt
prompt Creating trigger TIA_FIN_CAJA_BANCOS
prompt ====================================
prompt
CREATE OR REPLACE TRIGGER CANTABRIA.TIA_FIN_CAJA_BANCOS
  before insert on caja_bancos
  for each row

declare
  -- local variables here
  lc_soles   moneda.cod_moneda%type ;
  lc_dolares moneda.cod_moneda%type ;
  lc_moneda  moneda.cod_moneda%type ;
  ln_importe Number (13,2);
begin

  -- Edgar Morante Miercoles 10Jul2002, replicacion
  If (dbms_reputil.from_remote=true or dbms_snapshot.i_am_a_refresh=true) then
     return;
  end if;


  SELECT cod_soles   ,
         cod_dolares
    INTO lc_soles,
         lc_dolares
    FROM logparam
   WHERE reckey = '1' ;

  /*Actualizaciones de Acuerdo a Tipo de Transaciones*/
  IF    :new.flag_tiptran = '1' THEN /*Transferencias*/
        /* Actualiza Saldo Disponible de Cuenta Banco Origen*/
        /*******************************************************************************
         REPLICACION
        *******************************************************************************/
        UPDATE banco_cnta
           SET saldo_disponible = Nvl(SALDO_DISPONIBLE,0) - :new.imp_total,flag_replicacion = '0'
         WHERE cod_ctabco = :new.cod_ctabco ;

        /* Actualiza Saldo Disponible de Cuenta Banco Destino*/
        SELECT cod_moneda
          INTO lc_moneda
          FROM banco_cnta
         WHERE cod_ctabco = :new.cod_ctabco_ref ;

        IF :new.cod_moneda = lc_moneda  THEN
           ln_importe := :new.imp_total;
        ELSIF lc_moneda = lc_soles      THEN
              ln_importe := Round(:new.imp_total * :new.tasa_cambio,2) ;
        ELSIF lc_moneda = lc_dolares    THEN
              ln_importe := Round(:new.imp_total / :new.tasa_cambio,2) ;
        END IF ;
        /****************************************************************************************
         REPLICACION
        *****************************************************************************************/
        UPDATE banco_cnta
           SET saldo_disponible = Nvl(SALDO_DISPONIBLE,0) + ln_importe ,flag_replicacion = '0'
         WHERE cod_ctabco = :new.cod_ctabco_ref ;

  ELSIF :new.flag_tiptran = '2' THEN /*Cartera de Pagos*/
        /* Actualiza Saldo Disponible de Cuenta Banco */
        /***************************************************************************************
         REPLICACION
        ****************************************************************************************/
        UPDATE banco_cnta
           SET saldo_disponible = Nvl(SALDO_DISPONIBLE,0) - :new.imp_total,flag_replicacion = '0'
         WHERE cod_ctabco = :new.cod_ctabco ;
        /**/

  ELSIF :new.flag_tiptran = '3' THEN /*Cartera de Cobros*/
        /* Actualiza Saldo Disponible de Cuenta Banco */
        /***************************************************************************************
         REPLICACION
        ****************************************************************************************/
        UPDATE banco_cnta
           SET saldo_disponible = Nvl(SALDO_DISPONIBLE,0) + :new.imp_total,flag_replicacion = '0'
         WHERE cod_ctabco = :new.cod_ctabco ;
        /**/
  ELSIF :new.flag_tiptran = '4' THEN
        Null ;
  ELSIF :new.flag_tiptran = '5' THEN
        Null ;
  ELSIF :new.flag_tiptran = '6' THEN
        Null ;
  ELSIF :new.flag_tiptran = '7' THEN /*Cargo En Cuentas*/
         /* Actualiza Saldo Disponible de Cuenta Banco */
         /***************************************************************************************
         REPLICACION
        ****************************************************************************************/
        UPDATE banco_cnta
           SET saldo_disponible = Nvl(SALDO_DISPONIBLE,0) - :new.imp_total,flag_replicacion = '0'
         WHERE cod_ctabco = :new.cod_ctabco ;
        /**/
  ELSIF :new.flag_tiptran = '8' THEN /*Abono En Cuenta*/
         /* Actualiza Saldo Disponible de Cuenta Banco */
        /***************************************************************************************
         REPLICACION
        ****************************************************************************************/
        UPDATE banco_cnta
           SET saldo_disponible = Nvl(SALDO_DISPONIBLE,0) + :new.imp_total,flag_replicacion = '0'
         WHERE cod_ctabco = :new.cod_ctabco_ref ;
        /**/
  ELSIF :new.flag_tiptran = '9' THEN /*Egresos Directos*/
        /* Actualiza Saldo Disponible de Cuenta Banco */
        /***************************************************************************************
         REPLICACION
        ****************************************************************************************/
        UPDATE banco_cnta
           SET saldo_disponible = Nvl(SALDO_DISPONIBLE,0) - :new.imp_total,flag_replicacion = '0'
         WHERE cod_ctabco = :new.cod_ctabco ;
        /**/
  ELSIF :new.flag_tiptran = 'I' THEN /*Ingresos Directos*/
        /* Actualiza Saldo Disponible de Cuenta Banco */
        /***************************************************************************************
         REPLICACION
        ****************************************************************************************/
        UPDATE banco_cnta
           SET saldo_disponible = Nvl(SALDO_DISPONIBLE,0) + :new.imp_total,flag_replicacion = '0'
         WHERE cod_ctabco = :new.cod_ctabco ;

  ELSIF :new.flag_tiptran = 'P' THEN /*Pagos Masivos*/
         /* Actualiza Saldo Disponible de Cuenta Banco */
        /***************************************************************************************
         REPLICACION
        ****************************************************************************************/
        UPDATE banco_cnta
           SET saldo_disponible = Nvl(SALDO_DISPONIBLE,0) - :new.imp_total,flag_replicacion = '0'
         WHERE cod_ctabco = :new.cod_ctabco ;
        /**/


  END IF ;

end TIA_FIN_CAJA_BANCOS;
/

prompt
prompt Creating trigger TIA_FIN_CAJA_BANCOS_DET
prompt ========================================
prompt
CREATE OR REPLACE TRIGGER CANTABRIA.TIA_FIN_CAJA_BANCOS_DET
  after insert on caja_bancos_det
  for each row
declare
  -- local variables here
  ls_flag_tiptran     caja_bancos.flag_tiptran%type  ;
  ls_moneda_cb        moneda.cod_moneda%type         ;
  ls_moneda_doc       moneda.cod_moneda%TYPE         ;
  ln_tasa_cambio      caja_bancos.tasa_cambio%type   ;
  ls_soles            moneda.cod_moneda%type         ;
  ls_dolar            moneda.cod_moneda%type         ;
  ln_saldo_sol        caja_bancos_det.importe%type   ;
  ln_saldo_dol        caja_bancos_det.importe%type   ;
  ln_imp_soles        caja_bancos_det.importe%type   ;
  ln_imp_dolar        caja_bancos_det.importe%type   ;
  ln_monto_sol_dif    caja_bancos_det.importe%type   ;
  ln_mont_pend_dol    caja_bancos_det.importe%type   ;
  ln_mont_pend_sol    caja_bancos_det.importe%type   ;
  ln_monto_total      caja_bancos_det.importe%type   ;
  ls_flag_estado      caja_bancos.flag_estado%type   ;
  ld_fecha_emision    caja_bancos.fecha_emision%type ;
  ls_usr              caja_bancos.cod_usr%type       ;
  ls_flag_estado_og   Char (1)                       ;
  ln_nro_registro     caja_bancos.nro_registro%type  ;
  ln_count            Number ;
  ln_count_cad        Number ;
  ls_origen           origen.cod_origen%type         ;
  ls_flag_debhab_esp  doc_pendientes_cta_cte.flag_debhab%type ;
  ln_factor_esp       doc_pendientes_cta_cte.factor%type      ;
  ls_flag_ctrl_reg    cntas_cobrar.flag_control_reg%type      ;
  ls_origen_cb        origen.cod_origen%type         ;
  ln_ano              caja_bancos.ano%type           ;
  ln_mes              caja_bancos.mes%type           ;
  ln_nro_libro        caja_bancos.nro_libro%type     ;
  ln_nro_asiento      caja_bancos.nro_asiento%type   ;
  ls_cnta_cntbl        cntbl_cnta.cnta_ctbl%type      ;
  ls_flag_caja_bancos cntas_pagar.flag_caja_bancos%type ;
  ls_obs              caja_bancos.obs%type              ;

  ln_f_pago           cntas_pagar.forma_pago%type ; --- Forma de Pago
  ls_pcon             forma_pago.forma_pago%TYPE;   -- Pago al contado
  ls_nro_sol_cred     cntas_pagar.nro_sol_cred_rrhh%type;
  ls_concep           rrhh_credito_solicitud.concep%type ; --- concepto
  ln_nro_cuotas       rrhh_credito_solicitud.nro_cuotas%type ; ---  nro de cuotas
  ln_tasa_interes     rrhh_credito_solicitud.tasa_interes%type ; ---  tasa de interes
  ln_monto_cuota      rrhh_credito_solicitud.importe%type ; ---  tasa de interes

  -- Documentos de retencion CRI
  ls_doc_cri          finparam.doc_ret_igv_crt%TYPE;
  ln_importe_doc      cntas_pagar.importe_doc%TYPE;
  ln_tasa_cambio_doc  cntas_pagar.tasa_cambio%TYPE;

  -- Cntas Pagar
  ld_vencimiento      cntas_pagar.vencimiento%TYPE;

  -- Presupuesto_caja
  ls_moneda_prsp      prsp_caja_det.cod_moneda%TYPE;
  ln_imp_ejecutado    prsp_caja_det.imp_ejecutado%TYPE;

begin

  --
  select l.cod_soles,l.cod_dolares
    into ls_soles,ls_dolar
    from logparam l
  where l.reckey ='1' ;

  select f.pago_contado, f.doc_ret_igv_crt
    into ls_pcon, ls_doc_cri
    from finparam f
  where f.reckey ='1' ;

  select f_pago_cnta_crte
    into ln_f_pago
    from rrhhparam
   where reckey='1';

  --
  select cb.flag_tiptran  ,cb.cod_moneda ,cb.tasa_cambio ,
         cb.fecha_emision ,cb.cod_usr    ,cb.origen      ,
         cb.ano           ,cb.mes        ,cb.nro_libro   ,
         cb.nro_asiento   ,cb.obs
    into ls_flag_tiptran  ,ls_moneda_cb  ,ln_tasa_cambio ,
         ld_fecha_emision ,ls_usr        ,ls_origen_cb   ,
         ln_ano           ,ln_mes        ,ln_nro_libro   ,
         ln_nro_asiento   ,ls_obs
    from caja_bancos cb
   where cb.origen       = :new.origen
     and cb.nro_registro = :new.nro_registro;

  --Cerrando documentos de control documentario
  ln_count := usf_fin_cierra_control_doc(:new.cod_relacion, :new.tipo_doc, :new.nro_doc);
  --

  -- Calculo los importes para todos lo demas que venga
  if :new.cod_moneda = ls_soles then
     ln_imp_soles := :new.importe;
     ln_imp_dolar := :new.importe / ln_tasa_cambio;
  else
     ln_imp_soles := :new.importe * ln_tasa_cambio;
     ln_imp_dolar := :new.importe;
  end if;

  -- Los cri solo pueden pagarse por cartera de pagos, al ser un documento exclusivo de pago para retenciones
  if :new.tipo_doc = ls_doc_cri then
     if ls_flag_tiptran <> '2' then
        RAISE_APPLICATION_ERROR(-20000, 'Los comprobantes de Retencion solo pueden estar en cartera de pagos, por favor verifique!'
                                   || chr(13) || 'Cod Relacion: ' || :new.cod_relacion
                                   || chr(13) || 'Tipo Doc: ' || :new.tipo_doc
                                   || chr(13) || 'Nro Doc: ' || :new.nro_doc);
     end if;

     -- Si es cartera de pagos entonces simplemente obtengo los datos que necesito
     -- Obtengo los datos del comprobante de retencion
     select count(*)
       into ln_count
       from retencion_igv_crt t
      where t.nro_certificado = :new.nro_doc;

     if ln_count = 0 then
        RAISE_APPLICATION_ERROR(-20000, 'El Comprobante de retencion no existe, por favor verifique!'
                                   || chr(13) || 'Cod Relacion: ' || :new.cod_relacion
                                   || chr(13) || 'Tipo Doc: ' || :new.tipo_doc
                                   || chr(13) || 'Nro Doc: ' || :new.nro_doc);
     end if;

     select saldo_sol, saldo_dol
       into ln_saldo_sol, ln_saldo_dol
       from retencion_igv_crt t
      where t.nro_certificado = :new.nro_doc for update;

     if ln_saldo_sol - ln_imp_soles < 0 then
        RAISE_APPLICATION_ERROR(-20000, 'Importe por Pagado excede al saldo del Comprobante de Retencion, por favor verifique!'
                                   || chr(13) || 'Cod Relacion: ' || :new.cod_relacion
                                   || chr(13) || 'Tipo Doc: ' || :new.tipo_doc
                                   || chr(13) || 'Nro Doc: ' || :new.nro_doc
                                   || chr(13) || 'Saldo S/.: ' || to_Char(ln_saldo_sol, '999,990.00')
                                   || chr(13) || 'Importe a Pagar: ' || to_Char(ln_imp_soles, '999,990.00'));

     end if;
     ln_saldo_sol := ln_saldo_sol - ln_imp_soles;
     ln_saldo_dol := ln_saldo_dol - ln_imp_dolar;

     if ln_saldo_dol < 0 then ln_saldo_dol := 0; end if;

     update retencion_igv_crt r
        set r.saldo_sol = ln_saldo_sol,
            r.saldo_dol = ln_saldo_dol
      where r.nro_certificado = :new.nro_doc;

  end if;

  --Este cambio corresponde a la ejecucion del presupuesto de Caja
  if :new.nro_prsp is not null and :new.item_prsp is not null then
     -- Obtengo la moneda de la cabecera del presupuesto de caja
     select count(*)
       into ln_count
       from prsp_caja_det pd
      where pd.nro_presupuesto  = :new.nro_prsp
        and pd.nro_item         = :new.item_prsp;

     if ln_count = 0 then
        RAISE_APPLICATION_ERROR(-20000, 'No existe el item en el presupuesto de Caja, por favor verifique!'
                                    || chr(13) || 'Nro presupuesto: ' || :new.nro_prsp
                                    || chr(13) || 'Nro presupuesto: ' || to_char(:new.item_prsp));
     end if;

     select cod_moneda, nvl(pd.imp_ejecutado, 0)
       into ls_moneda_prsp, ln_imp_ejecutado
       from prsp_caja_det pd
      where pd.nro_presupuesto  = :new.nro_prsp
        and pd.nro_item         = :new.item_prsp for update;

     if :new.cod_moneda = ls_moneda_prsp then
        ln_imp_ejecutado := ln_imp_ejecutado + :new.importe;
     elsif :new.cod_moneda = ls_soles then
        ln_imp_ejecutado := ln_imp_ejecutado + :new.importe * ln_tasa_cambio;
     elsif :new.cod_moneda = ls_dolar then
        ln_imp_ejecutado := ln_imp_ejecutado + :new.importe / ln_tasa_cambio;
     end if;

     -- Actualizo el importe ejecutado
     update prsp_caja_det pd
        set pd.imp_ejecutado = ln_imp_ejecutado
      where pd.nro_presupuesto  = :new.nro_prsp
        and pd.nro_item         = :new.item_prsp;
  end if;

  -- Pagos de Documentos x Pagar Directo o Cobros de Documento por Cobrar Directo (Sea Gasto / Ingreso Directo o cuenta Corriente)
  -- CARTERA DE PAGOS,CARTERA DE COBROS,APLICACION DE DOCUMENTOS
  IF (ls_flag_tiptran = '2' OR ls_flag_tiptran = '3' OR ls_flag_tiptran = '4') THEN

     IF :new.flab_tabor = '1' THEN --CUENTAS COBRAR
        select cc.flag_control_reg, cc.flag_caja_bancos, cc.nro_sol_cred_rrhh, cc.saldo_sol, cc.saldo_dol, cc.cod_moneda,
               cc.tasa_cambio, cc.importe_doc, cc.fecha_vencimiento
          into ls_flag_ctrl_reg, ls_flag_caja_bancos, ls_nro_sol_cred, ln_saldo_sol, ln_saldo_dol, ls_moneda_doc,
               ln_tasa_cambio_doc, ln_importe_doc, ld_vencimiento

          from cntas_cobrar cc
         where cc.cod_relacion = :new.cod_relacion
           and cc.tipo_doc     = :new.tipo_doc
           and cc.nro_doc      = :new.nro_doc for update;

     ELSIF :new.flab_tabor = '3' THEN --CUENTAS POR PAGAR

        select cp.flag_control_reg, cp.flag_caja_bancos, cp.nro_sol_cred_rrhh, cp.saldo_sol, cp.saldo_dol, cp.cod_moneda,
               cp.tasa_cambio, cp.importe_doc, cp.vencimiento
          into ls_flag_ctrl_reg, ls_flag_caja_bancos, ls_nro_sol_cred, ln_saldo_sol, ln_saldo_dol, ls_moneda_doc,
               ln_tasa_cambio_doc, ln_importe_doc, ld_vencimiento
          from cntas_pagar cp
         where cp.cod_relacion = :new.cod_relacion
           and cp.tipo_doc     = :new.tipo_doc
           and cp.nro_doc      = :new.nro_doc for update;

     END IF ;

     --DOCUMENTO TIPO CUENTA CORRIENTE
     IF :new.flag_provisionado = 'D' AND ls_flag_ctrl_reg = '1' AND ls_flag_caja_bancos = '0' AND (:new.flab_tabor = '1' or :new.flab_tabor = '3') THEN
        /*
          :new.flag_tabor = '1' Cuentas x Cobrar
          :new.flag_tabor = '3' Cuentas x Pagar
        */

        if :new.flab_tabor not in ('1', '3') then
           raise_application_error(-20000,'flag TABOR en Documento no esta permitido o es inv?lido para Documentos Tipo Cuenta Corriente, por favor verifique!'
                               || chr(13) || 'Cod. Relacion: ' || :new.cod_relacion
                               || chr(13) || 'Tipo Doc: ' || :new.tipo_doc
                               || chr(13) || 'Nro Doc: ' || :new.nro_doc
                               || chr(13) || 'Flab TABOR: ' || :new.flab_tabor);
        end if;

        if :new.flab_tabor = '1' then--CUENTAS POR COBRAR
           --verifica que documento sea tipo cuenta corriente por cobrar
           select count(*)
             into ln_count
             from doc_grupo_relacion dg
            where dg.grupo    = 'C1'
              and dg.tipo_doc = :new.tipo_doc;

           if ln_count = 0 then --documento no esta definido como cuenta corriente
              raise_application_error(-20000,'Documento no esta definido en grupo de cuenta corriente para Documento por Pagar (Grupo C1). Por favor verifique!'
                               || chr(13) || 'Cod. Relacion: ' || :new.cod_relacion
                               || chr(13) || 'Tipo Doc: ' || :new.tipo_doc
                               || chr(13) || 'Nro Doc: ' || :new.nro_doc);

           END IF;
        elsif :new.flab_tabor = '3' then --CUENTAS POR PAGAR

            --verifica que documento sea tipo cuenta corriente por pagar
           select count(*)
             into ln_count
             from doc_grupo_relacion dg
            where dg.grupo    = 'C2'
              and dg.tipo_doc = :new.tipo_doc;

           if ln_count = 0 then --documento no esta definido como cuenta corriente
              raise_application_error(-20000,'Documento no esta definido en grupo de cuenta corriente para Documentos por Cobrar (Grupo C2). Por favor verifique!'
                               || chr(13) || 'Cod. Relacion: ' || :new.cod_relacion
                               || chr(13) || 'Tipo Doc: ' || :new.tipo_doc
                               || chr(13) || 'Nro Doc: ' || :new.nro_doc);
           end if;
        end if;

        -- Verifico que el monto no supere al documento
        if ls_moneda_doc = ls_soles then
           if ln_saldo_sol - ln_imp_soles < 0 then
              if :new.flab_tabor = '1' then
                 raise_application_error(-20000,'Importe a Cobrar no puede ser mayor al importe del documento, por favor verifique!'
                                  || chr(13) || 'Cod. Relacion: ' || :new.cod_relacion
                                  || chr(13) || 'Tipo Doc: '      || :new.tipo_doc
                                  || chr(13) || 'Nro Doc: '       || :new.nro_doc
                                  || chr(13) || 'Saldo : ' || ls_moneda_doc || ' ' || to_char(ln_saldo_sol, '999,990.00')
                                  || chr(13) || 'Importe a cobrar: '       || to_char(ln_imp_soles, '999,990.00'));
              elsif :new.flab_tabor = '3' then
                 raise_application_error(-20000,'Importe a Pagar no puede ser mayor al importe del documento, por favor verifique!'
                                  || chr(13) || 'Cod. Relacion: ' || :new.cod_relacion
                                  || chr(13) || 'Tipo Doc: '      || :new.tipo_doc
                                  || chr(13) || 'Nro Doc: '       || :new.nro_doc
                                  || chr(13) || 'Saldo : ' || ls_moneda_doc || ' ' || to_char(ln_saldo_sol, '999,990.00')
                                  || chr(13) || 'Importe a pagar: '       || :new.cod_moneda || to_char(ln_imp_soles, '999,990.00'));
              end if;

           end if;
        elsif ls_moneda_doc = ls_dolar then
           if ln_saldo_dol - ln_imp_dolar < 0 then
              if :new.flab_tabor = '1' then
                 raise_application_error(-20000,'Importe a Cobrar no puede ser mayor al importe del documento, por favor verifique!'
                                  || chr(13) || 'Cod. Relacion: ' || :new.cod_relacion
                                  || chr(13) || 'Tipo Doc: '      || :new.tipo_doc
                                  || chr(13) || 'Nro Doc: '       || :new.nro_doc
                                  || chr(13) || 'Saldo : ' || ls_moneda_doc || ' ' || to_char(ln_saldo_dol, '999,990.00')
                                  || chr(13) || 'Importe a cobrar: '       || to_char(ln_imp_dolar, '999,990.00'));
              elsif :new.flab_tabor = '3' then
                 raise_application_error(-20000,'Importe a Pagar no puede ser mayor al importe del documento, por favor verifique!'
                                  || chr(13) || 'Cod. Relacion: ' || :new.cod_relacion
                                  || chr(13) || 'Tipo Doc: '      || :new.tipo_doc
                                  || chr(13) || 'Nro Doc: '       || :new.nro_doc
                                  || chr(13) || 'Saldo : ' || ls_moneda_doc || ' ' || to_char(ln_saldo_dol, '999,990.00')
                                  || chr(13) || 'Importe a pagar: '       || to_char(ln_imp_dolar, '999,990.00'));
              end if;
           end if;
        end if;

        ln_saldo_sol := ln_saldo_sol - ln_imp_soles;
        ln_saldo_dol := ln_saldo_dol - ln_imp_dolar;
        if ln_saldo_sol <= 0 then ln_saldo_sol := 0; end if;
        if ln_saldo_dol <= 0 then ln_saldo_dol := 0; end if;

        if (ls_moneda_doc = ls_soles and ln_saldo_sol > 0) or (ls_moneda_doc = ls_dolar and ln_saldo_dol > 0) then
           -- Si hay saldo en el DPD o DCD Tipo cuenta corriente entonces simplemente lo aplico como un Gasto o Ingreso Directo
           -- Quedando un saldo pendiente
           if :new.flab_tabor = '1' then
              update cntas_cobrar cc
                 set cc.saldo_sol = ln_saldo_sol,
                     cc.saldo_dol = ln_saldo_dol
               where cc.cod_relacion = :new.cod_relacion
                 and cc.tipo_doc     = :new.tipo_doc
                 and cc.nro_doc      = :new.nro_doc;
           elsif  :new.flab_tabor = '3' then
              update cntas_pagar cc
                 set cc.saldo_sol = ln_saldo_sol,
                     cc.saldo_dol = ln_saldo_dol
               where cc.cod_relacion = :new.cod_relacion
                 and cc.tipo_doc     = :new.tipo_doc
                 and cc.nro_doc      = :new.nro_doc;
           end if;

        else
           -- Si no hay saldo significa que se ha pagado toda la cuenta corriente por lo que ahora simplemente tengo que cambiar el documento
           if ls_moneda_doc = ls_soles then
              ln_saldo_sol := ln_importe_doc;
              ln_saldo_dol := ln_importe_doc / ln_tasa_cambio_doc;
           else
              ln_saldo_dol := ln_importe_doc;
              ln_saldo_sol := ln_importe_doc * ln_tasa_cambio_doc;
           end if;

           --busco datos en documentos pendientes
           select dp.flag_debhab, dp.factor
             into ls_flag_debhab_esp, ln_factor_esp
             from doc_pendientes_cta_cte dp
            where dp.cod_relacion = :new.cod_relacion
              and dp.tipo_doc     = :new.tipo_doc
              and dp.nro_doc      = :new.nro_doc for update;

           if :new.flab_tabor = '1' then

              if ls_flag_debhab_esp = 'D' then
                 ls_flag_debhab_esp := 'H' ;
              else --Documentos tienen problemas
                 raise_application_error(-20000,'Documento tiene problemas verifique datos Ingresados, debe tener el flag DEBE si es un DPD Tipo Cuenta Corriente, por favor verifique!.'
                               || chr(13) || 'Cod. Relacion: ' || :new.cod_relacion
                               || chr(13) || 'Tipo Doc: ' || :new.tipo_doc
                               || chr(13) || 'Nro Doc: ' || :new.nro_doc);
              end if ;

              if ln_factor_esp = 1 then
                 ln_factor_esp := -1 ;
              else
                 raise_application_error(-20000,'Documento tiene problemas verifique datos Ingresados, el documento debe tener factor 1 si un DPD Tipo Cuenta corriente. Por favor Verifique!'
                                  || chr(13) || 'Cod. Relacion: ' || :new.cod_relacion
                                  || chr(13) || 'Tipo Doc: ' || :new.tipo_doc
                                  || chr(13) || 'Nro Doc: ' || :new.nro_doc);
              end if ;

           elsif :new.flab_tabor = '3' then

              if ls_flag_debhab_esp = 'H' then
                 ls_flag_debhab_esp := 'D' ;
              else --docuementos tiene problemas verifique datos del documento
                 raise_application_error(-20000,'Documento tiene problemas verifique datos Ingresados, debe tener el flag HABER si es un DCD Tipo Cuenta Corriente, por favor verifique!.'
                                  || chr(13) || 'Cod. Relacion: ' || :new.cod_relacion
                                  || chr(13) || 'Tipo Doc: ' || :new.tipo_doc
                                  || chr(13) || 'Nro Doc: ' || :new.nro_doc);
              end if ;

              if ln_factor_esp = -1 then
                 ln_factor_esp := 1 ;
              else
                 raise_application_error(-20000,'Documento tiene problemas verifique datos Ingresados, el documento debe tener factor -1 si un DCD Tipo Cuenta corriente. Por favor Verifique!'
                                  || chr(13) || 'Cod. Relacion: ' || :new.cod_relacion
                                  || chr(13) || 'Tipo Doc: ' || :new.tipo_doc
                                  || chr(13) || 'Nro Doc: ' || :new.nro_doc);
              end if ;
           end if;

           -- Busco la Cuenta Corriente Correspondiente, que debe estar en el asiento generado por la Cartera de Pagos o de cobros
           -- Cabe indicar que primero se debe grabar la cabecera y detalle del asiento generado y luego se procede a grabar
           -- la cabecera y detalle del movimiento de Tesorer?a
           select count(*)
             into ln_count_cad
             from cntbl_asiento_det cad
            where cad.origen       = ls_origen_cb
              and cad.ano          = ln_ano
              and cad.mes          = ln_mes
              and cad.nro_libro    = ln_nro_libro
              and cad.nro_asiento  = ln_nro_asiento
              and cad.cod_relacion = :new.cod_relacion
              and cad.tipo_docref1 = :new.tipo_doc
              and cad.nro_docref1  = :new.nro_doc;

           if ln_count_cad > 0 then
              --BUSCAR CUENTA CONTABLE
              select cad.cnta_ctbl
                into ls_cnta_cntbl
                from cntbl_asiento_det cad
               where cad.origen       = ls_origen_cb
                 and cad.ano          = ln_ano
                 and cad.mes          = ln_mes
                 and cad.nro_libro    = ln_nro_libro
                 and cad.nro_asiento  = ln_nro_asiento
                 and cad.cod_relacion = :new.cod_relacion
                 and cad.tipo_docref1 = :new.tipo_doc
                 and cad.nro_docref1  = :new.nro_doc
                 and rownum           = 1
              order by cad.item;
           else
               raise_application_error(-20000,'Asientos de Tesorer?a Tiene problemas, no existe un cuenta contable tipo cuenta corriente para el documento, por favor Verifique!.'
                                || chr(13) || 'Cod. Relacion: ' || :new.cod_relacion
                                || chr(13) || 'Tipo Doc: ' || :new.tipo_doc
                                || chr(13) || 'Nro Doc: ' || :new.nro_doc);
           end if ;

           if :new.flab_tabor = '1' then
              --ACTUALIZA CNTAS POR cobrar
              update cntas_cobrar cc
                 set cc.flag_caja_bancos = '1' ,
                     cc.flag_replicacion ='0',
                     cc.saldo_sol        = ln_saldo_sol,
                     cc.saldo_dol        = ln_saldo_dol
               where cc.cod_relacion = :new.cod_relacion
                 and cc.tipo_doc     = :new.tipo_doc
                 and cc.nro_doc      = :new.nro_doc     ;

           elsif :new.flab_tabor = '3' then
              --ACTUALIZA CNTAS POR PAGAR
              update cntas_pagar cp
                 set cp.flag_caja_bancos = '1' ,
                     cp.flag_replicacion = '0',
                     cp.saldo_sol        = ln_saldo_sol,
                     cp.saldo_dol        = ln_saldo_dol
               where cp.cod_relacion = :new.cod_relacion
                 and cp.tipo_doc     = :new.tipo_doc
                 and cp.nro_doc      = :new.nro_doc  ;


              --CAMBIO PARA RRHH SOLICITUD DE CEDITO
              IF (ls_nro_sol_cred is not null) then
                 select concep, nro_cuotas, tasa_interes
                   into ls_concep, ln_nro_cuotas ,ln_tasa_interes
                   from rrhh_credito_solicitud
                  where nro_solicitud = ls_nro_sol_cred for update;

                 ln_monto_cuota := Round(:new.importe / ln_nro_cuotas,2) ;

                 --  Inserta cuenta corriente del trabajador
                 insert into cnta_crrte  (
                         cod_trabajador ,tipo_doc   ,nro_doc       ,fec_prestamo ,concep        ,
                         flag_estado    ,nro_cuotas ,mont_original ,mont_cuota   ,sldo_prestamo ,
                         cod_sit_prest  ,cod_moneda ,cod_usr       ,tasa_interes ,forma_pago )
                 values(
                          :new.cod_relacion ,:new.tipo_doc   ,:new.nro_doc ,sysdate         ,ls_concep    ,
                          '1'               ,ln_nro_cuotas   ,:new.importe,ln_monto_cuota  ,:new.importe ,
                          'A'               ,:new.cod_moneda ,ls_usr,ln_tasa_interes , ln_f_pago ) ;

                 --ACTUALIZA ESTADO DE SOLICTUD
                 update rrhh_credito_solicitud
                    set flag_estado = '5'
                  where nro_solicitud = ls_nro_sol_cred;
              END IF ;

           end if;

           --actuliza docuemnto tipo cuenta corriente en doc_pendientes
           update doc_pendientes_cta_cte dp
              set dp.flag_debhab      = ls_flag_debhab_esp,
                  dp.factor           = ln_factor_esp     ,
                  dp.cnta_ctbl        = ls_cnta_cntbl      ,
                  dp.flag_replicacion = '0'          ,
                  dp.saldo_dol        = ln_saldo_dol ,
                  dp.sldo_sol         = ln_saldo_sol
            where dp.cod_relacion = :new.cod_relacion
              and dp.tipo_doc     = :new.tipo_doc
              and dp.nro_doc      = :new.nro_doc  ;

           if SQL%NOTFOUND then
              insert into doc_pendientes_cta_cte(
                     cod_relacion, tipo_doc, nro_doc, flag_tabla, cnta_ctbl, cod_moneda, flag_debhab, sldo_sol, saldo_dol, fecha_doc,
                     factor, fecha_vencimiento)
              values(
                     :new.cod_Relacion, :new.tipo_doc, :new.nro_doc, '3', ls_cnta_cntbl, ls_moneda_doc, ls_flag_debhab_esp, ln_saldo_sol,
                     ln_saldo_dol, ld_fecha_emision, ln_factor_esp, ld_vencimiento);
           end if;


        end if;


        RETURN ;


     END IF ;

    --*cuenta corriente*--------
    -- DOCUMENTO PROVISIONADOS


   IF :new.flag_provisionado IN ('R', 'D', 'O') THEN --REFERENCIA / DIRECTO / ORDEN DE GIRO ...

       IF :new.flab_tabor = '1' THEN /*Cuentas x Cobrar*/

          select Nvl(cc.importe_doc,0),Nvl(cc.saldo_sol,0),Nvl(cc.saldo_dol,0), flag_caja_bancos
            into ln_monto_total, ln_saldo_sol, ln_saldo_dol, ls_flag_caja_bancos
            from cntas_cobrar cc
           where cc.cod_relacion = :new.cod_relacion
             AND cc.tipo_doc     = :new.tipo_doc
             AND cc.nro_doc      = :new.nro_doc ;

          if :new.cod_moneda = ls_soles THEN
             ln_imp_soles := :new.importe ;
             ln_imp_dolar := :new.importe / ln_tasa_cambio ;

             --encontrar estado del documento
             ln_saldo_sol := ln_saldo_sol - ln_imp_soles ;
             ln_saldo_dol := ln_saldo_dol - ln_imp_dolar ;

             if ln_monto_total = ln_saldo_sol then --activo
                ls_flag_estado := '1';
             elsif ln_saldo_sol = 0 then           --pagado totalmente
                ls_flag_estado := '3';
             elsif ln_saldo_sol > 0 then           --pagado parcialmente
                ls_flag_estado := '2';
             end if ;

          elsif  :new.cod_moneda = ls_dolar THEN

             ln_imp_dolar := :new.importe ;
             ln_imp_soles := Round(:new.importe * ln_tasa_cambio,2) ;

             --diferencia en cambiode documentos
             select Nvl(sldo_sol,0), Nvl(saldo_dol,0)
               into ln_mont_pend_sol,ln_mont_pend_dol
               from doc_pendientes_cta_cte
             where cod_relacion = :new.cod_relacion
               and tipo_doc     = :new.tipo_doc
               and nro_doc      = :new.nro_doc  ;

             ln_monto_sol_dif := Round(ln_mont_pend_dol * ln_tasa_cambio,2) - ln_mont_pend_sol  ;


             --encontrar estado del documento
             ln_saldo_dol := ln_saldo_dol - ln_imp_dolar ;
             ln_saldo_sol := (ln_saldo_sol + ln_monto_sol_dif) - ln_imp_soles ;

             if ln_monto_total = ln_saldo_dol then --activo
                ls_flag_estado := '1';
             elsif ln_saldo_dol = 0 then           --pagado totalmente
                ls_flag_estado := '3';
             elsif ln_saldo_dol > 0 then           --pagado parcialmente
                ls_flag_estado := '2';
             end if ;

          end if ;


          if (ls_flag_estado is null) then
             RAISE_APPLICATION_ERROR( -20000, :new.tipo_doc||' '||:new.nro_doc || ' tiene flag estado nulo, por favor verifique!'
                                        || chr(13) || 'Importe Doc: ' || to_char(ln_monto_total, '999,990.00')
                                        || chr(13) || 'Saldo Sol: ' || to_char(ln_saldo_sol, '999,990.00')
                                        || chr(13) || 'Saldo Dol: ' || to_char(ln_saldo_Dol, '999,990.00')
                                        || chr(13) || 'Moneda: ' || :new.cod_moneda
                                        || chr(13) || 'Tasa Cambio: ' || to_char(ln_tasa_cambio, '999,990.0000'));
          end if ;

          --actualizo cntas x cobrar
          /*************************************************************************
           REPLICACION
          *************************************************************************/
          UPDATE cntas_cobrar
             SET flag_estado = ls_flag_estado ,
                 saldo_sol   = ln_saldo_sol,
                 saldo_dol   = ln_saldo_dol,
                 flag_replicacion = '0'
           WHERE cod_relacion = :new.cod_relacion
             AND tipo_doc     = :new.tipo_doc
             AND nro_doc      = :new.nro_doc ;


          /*Actualizar Doc_Pendientes_cta_cte*/
          if ls_flag_caja_bancos = '1' THEN  --cta cte ha sido cancelada
             --buscar cta ctble de ultima transacion
              select min(cnta_ctbl)
                into ls_cnta_cntbl
                from cntbl_asiento_det cad
               where cad.cod_relacion = :new.cod_relacion
                 and cad.tipo_docref1 = :new.tipo_doc
                 and cad.nro_docref1  = :new.nro_doc   ;

              /*REPLICACION*/
              update doc_pendientes_cta_cte
                 set cnta_ctbl        = ls_cnta_cntbl,
                     flag_replicacion = '0'
               where cod_relacion = :new.cod_relacion
                 and tipo_doc     = :new.tipo_doc
                 and nro_doc      = :new.nro_doc      ;

           end if ;

       ELSIF :new.flab_tabor = '6' THEN /*Solicitud de Giro */
          SELECT flag_estado, importe_doc, Nvl(saldo_sol,0), Nvl(saldo_dol,0), nro_reg_caja_banco
            INTO ls_flag_estado_og, ln_monto_total, ln_saldo_sol , ln_saldo_dol, ln_nro_registro
            FROM solicitud_giro
           WHERE origen        = :new.origen_doc
             AND nro_solicitud = :new.nro_doc for update;

          IF ls_flag_estado_og = '2' THEN
             /**Actualiza Contador de Solicitudes Pendientes **/
             /*************************************************************************
              REPLICACION
             *************************************************************************/
             --UPDATE maestro_param_autoriz
             --   SET nro_solicitudes_pend = Nvl(nro_solicitudes_pend,0) + 1,flag_replicacion= '0'
             -- WHERE (cod_relacion = :new.cod_relacion) ;

             ls_flag_estado  := '3' ;
             ls_origen       := :new.origen ;
             ln_nro_registro := :new.nro_registro ;

             /**Actualiza Estado **/
            /*************************************************************************
             REPLICACION
            *************************************************************************/
            UPDATE solicitud_giro sg
               SET sg.nro_reg_caja_banco = ln_nro_registro,
                   sg.origen_caja_banc0  = ls_origen      ,
                   sg.flag_replicacion   = '0'
            WHERE origen        = :new.origen_doc
              AND nro_solicitud = :new.nro_doc ;

          ELSE
             ls_flag_estado  := ls_flag_estado_og ;

          END IF ;

          ln_saldo_sol := abs(ln_saldo_sol) ;
          ln_saldo_dol := abs(ln_saldo_dol) ;

          if :new.cod_moneda = ls_soles THEN
             ln_imp_soles := :new.importe ;
             ln_imp_dolar := :new.importe / ln_tasa_cambio ;

             --encontrar estado del documento
             ln_saldo_sol := ln_saldo_sol - ln_imp_soles ;
             ln_saldo_dol := ln_saldo_dol - ln_imp_dolar ;

             IF ln_saldo_dol <> 0  THEN
                ln_saldo_dol := ln_saldo_dol * -1 ;
             END IF ;


          elsif  :new.cod_moneda = ls_dolar THEN

             ln_imp_dolar := :new.importe ;
             ln_imp_soles := :new.importe * ln_tasa_cambio;

             --diferencia en cambiode documentos
             select Nvl(sldo_sol,0),Nvl(saldo_dol,0)
               into ln_mont_pend_sol,ln_mont_pend_dol
               from doc_pendientes_cta_cte
              where cod_relacion = :new.cod_relacion
                and tipo_doc     = :new.tipo_doc
                and nro_doc      = :new.nro_doc for update;

             ln_monto_sol_dif := Round(ln_mont_pend_dol * ln_tasa_cambio,2) - ln_mont_pend_sol  ;

             --encontrar estado del documento
             ln_saldo_dol := ln_saldo_dol - ln_imp_dolar;
             ln_saldo_sol := (ln_saldo_sol + ln_monto_sol_dif) - ln_imp_soles;

             IF ln_saldo_dol <> 0  THEN
                ln_saldo_dol := ln_saldo_dol * -1 ;
             END IF ;
          end if ;


          /**Actualiza Estado **/
          /*************************************************************************
           REPLICACION
          *************************************************************************/
          UPDATE solicitud_giro
             SET flag_estado = ls_flag_estado ,
                 saldo_sol   = ln_saldo_sol  ,
                 saldo_dol   = ln_saldo_dol   ,
                 flag_replicacion = '0'
           WHERE ((origen        = :new.origen_doc ) AND
                  (nro_solicitud = :new.nro_doc   )) ;


       ELSIF :new.flab_tabor = '3' THEN --Cuentas por pagar

          select importe_doc,Nvl(saldo_sol,0),Nvl(saldo_dol,0),flag_caja_bancos
            into ln_monto_total,ln_saldo_sol , ln_saldo_dol ,ls_flag_caja_bancos
            from cntas_pagar cp
           where cp.cod_relacion = :new.cod_relacion
             AND cp.tipo_doc     = :new.tipo_doc
             AND cp.nro_doc      = :new.nro_doc    for update;


          if :new.cod_moneda = ls_soles THEN
             ln_imp_soles := :new.importe ;
             ln_imp_dolar := Round(:new.importe / ln_tasa_cambio,2) ;

             --encontrar estado del documento
             ln_saldo_sol := ln_saldo_sol - ln_imp_soles ;
             ln_saldo_dol := ln_saldo_dol - ln_imp_dolar ;

             if ln_monto_total = ln_saldo_sol then --activo
                ls_flag_estado := '1';
             elsif ln_saldo_sol = 0 then           --pagado totalmente
                ls_flag_estado := '3';
             elsif ln_saldo_sol > 0 then           --pagado parcialmente
                ls_flag_estado := '2';
             end if ;

          elsif  :new.cod_moneda = ls_dolar THEN
             ln_imp_dolar := :new.importe ;
             ln_imp_soles := Round(:new.importe * ln_tasa_cambio,2) ;

             --diferencia en cambiode documentos
             SELECT COUNT(*)
               INTO ln_count
               from doc_pendientes_cta_cte
              where (cod_relacion = :new.cod_relacion ) and
                    (tipo_doc     = :new.tipo_doc     ) and
                    (nro_doc      = :new.nro_doc      ) ;

             IF ln_count = 0 THEN
                RAISE_APPLICATION_ERROR(-20000, 'Documento no esta en Cuenta Corriente'
                                     || chr(13) || 'cod_relacion:' || :new.cod_relacion
                                     || chr(13) || 'tipo_doc:' || :new.tipo_doc
                                     || chr(13) || 'nro_doc:' ||:new.nro_doc      );
             END IF;

             select Nvl(sldo_sol,0),Nvl(saldo_dol,0)
               into ln_mont_pend_sol,ln_mont_pend_dol
               from doc_pendientes_cta_cte
              where (cod_relacion = :new.cod_relacion ) and
                    (tipo_doc     = :new.tipo_doc     ) and
                    (nro_doc      = :new.nro_doc      ) ;

             ln_monto_sol_dif := Round(ln_mont_pend_dol * ln_tasa_cambio,2) - ln_mont_pend_sol  ;


             --encontrar estado del documento
             ln_saldo_dol := ln_saldo_dol - ln_imp_dolar ;
             ln_saldo_sol := (ln_saldo_sol + ln_monto_sol_dif) - ln_imp_soles ;

             if ln_monto_total = ln_saldo_dol then --activo
                ls_flag_estado := '1';
             elsif ln_saldo_dol <= 0 then           --pagado totalmente
                ls_flag_estado := '3';
             elsif ln_saldo_dol > 0 then           --pagado parcialmente
                ls_flag_estado := '2';
             end if ;

          end if ;

          if (ls_flag_estado is null) then
             RAISE_APPLICATION_ERROR( -20000, :new.tipo_doc||' '||:new.nro_doc || ' tiene flag estado nulo, por favor verifique'
                                      || chr(13) || 'Monto Total : ' || to_char(ln_monto_total, '999,990.00')
                                      || chr(13) || 'Saldo Sol: ' || to_char(ln_saldo_sol, '999,990.00')
                                      || chr(13) || 'Saldo Dol: ' || to_char(ln_saldo_dol, '999,990.00') );
          end if ;

          /*************************************************************************
           REPLICACION
          *************************************************************************/
          --actualizo cntas x pagar
           UPDATE cntas_pagar
              SET flag_estado = ls_flag_estado ,
                  saldo_sol   = ln_saldo_sol ,
                  saldo_dol   = ln_saldo_dol   ,
                  flag_replicacion = '0'
            WHERE cod_relacion = :new.cod_relacion
              AND tipo_doc     = :new.tipo_doc
              AND nro_doc      = :new.nro_doc     ;



           /*Actualizar Doc_Pendientes_cta_cte*/
           if ls_flag_caja_bancos = '1' THEN  --cta cte ha sido cancelada
              --buscar cta ctble de ultima transacion
              select min(cnta_ctbl) into ls_cnta_cntbl from cntbl_asiento_det
               where (cod_relacion = :new.cod_relacion ) and (tipo_docref1 = :new.tipo_doc) and
                     (nro_docref1  = :new.nro_doc      ) ;

              /*REPLICACION*/
              update doc_pendientes_cta_cte
                 set cnta_ctbl = ls_cnta_cntbl,
                     flag_replicacion = '0'
               where (cod_relacion = :new.cod_relacion ) and
                     (tipo_doc     = :new.tipo_doc     ) and
                     (nro_doc      = :new.nro_doc      ) ;

           end if ;




       END IF ;
   ELSIF (:new.flag_provisionado = 'N' AND ls_flag_tiptran = '2' )   THEN
      --INDIRECTO...CARTERA DE PAGOS
      /*************************************************************************
           REPLICACION
      *************************************************************************/
      -- Verifico si el documento existe o no
      select count(*)
        into ln_count
        from cntas_pagar cp
       where cp.cod_relacion = :new.cod_relacion
         and cp.tipo_doc     = :new.tipo_doc
         and cp.nro_doc      = :new.nro_doc;

      if ln_count > 0 then
         RAISE_APPLICATION_ERROR(-20000, 'El documento por Pagar Directo que ha ingresado en el detalle del voucher ya existe, por favor cambiarlo y volver a grabar.'
                                  || chr(13) || 'Cod Relacion: ' || :new.cod_relacion
                                  || chr(13) || 'Tipo Doc: ' || :new.Tipo_doc
                                  || chr(13) || 'Nro Doc: ' || :new.nro_doc);

      end if;

      --se ingresa cancelado totalmente
      insert into cntas_pagar(
             cod_relacion     ,tipo_doc         ,nro_doc      ,
             flag_estado      ,fecha_registro   ,fecha_emision,
             vencimiento      ,cod_moneda       ,tasa_cambio  ,
             cod_usr          ,origen           ,descripcion  ,
             flag_provisionado,importe_doc      ,saldo_sol    ,
             saldo_dol        ,forma_pago       ,flag_replicacion)
      values(
             :new.cod_relacion     ,:new.tipo_doc  ,:new.nro_doc       ,
             '3'                   ,ld_fecha_emision,ld_fecha_emision   ,
             ld_fecha_emision      ,:new.cod_moneda,ln_tasa_cambio     ,
             ls_usr                ,:new.origen_doc,ls_obs             ,
             :new.flag_provisionado,:new.importe   ,0.00               ,
             0.00                  ,ls_pcon        ,'0');

      --afectacion presupuestal
      /*************************************************************************
           REPLICACION
      *************************************************************************/
      --se ingresa cancelado totalmente
      insert into cntas_pagar_det(
             cod_relacion ,tipo_doc    ,nro_doc ,
             item         ,descripcion ,cod_art ,
             confin       ,cantidad    ,importe ,
             cencos       ,cnta_prsp   ,flag_replicacion ,
             centro_benef)
      values(
             :new.cod_relacion ,:new.tipo_doc    ,:new.nro_doc  ,
             1                 ,ls_obs           ,null          ,
             null              ,1                ,:new.importe  ,
             :new.cencos       ,:new.cnta_prsp   ,'0'           ,
             :new.centro_benef);

   ELSIF (:new.flag_provisionado = 'N' AND ls_flag_tiptran = '3' )   THEN
      --INDIRECTO...CARTERA DE COBROS
      /*************************************************************************
           REPLICACION
      *************************************************************************/

      -- Verifico si el documento existe o no
      select count(*)
        into ln_count
        from cntas_cobrar cc
       where cc.tipo_doc     = :new.tipo_doc
         and cc.nro_doc      = :new.nro_doc;

      if ln_count > 0 then
         ROLLBACK;
         RAISE_APPLICATION_ERROR(-20000, 'El documento por Cobrar Directo que ha ingresado en el detalle del voucher ya existe, por favor cambiarlo y volver a grabar.'
                                  || chr(13) || 'Cod Relacion: ' || :new.cod_relacion
                                  || chr(13) || 'Tipo Doc: ' || :new.Tipo_doc
                                  || chr(13) || 'Nro Doc: ' || :new.nro_doc);

      end if;

      --se ingresa cancelado totalmente
      Insert Into cntas_cobrar (
             tipo_doc          ,nro_doc       ,cod_relacion    ,
             flag_estado       ,fecha_registro,fecha_documento ,
             fecha_vencimiento ,cod_moneda    ,tasa_cambio     ,
             cod_usr           ,origen        ,observacion     ,
             flag_provisionado ,importe_doc   ,saldo_sol       ,
             saldo_dol         ,forma_pago    ,flag_replicacion)
      Values(
             :new.tipo_doc         ,:new.nro_doc     ,:new.cod_relacion  ,
             '3'                   ,ld_fecha_emision ,ld_fecha_emision   ,
             ld_fecha_emision      ,:new.cod_moneda  ,ln_tasa_cambio     ,
             ls_usr                ,:new.origen_doc  ,substr(ls_obs,1,40),
             :new.flag_provisionado,:new.importe     ,0.00               ,
             0.00                  , ls_pcon,'0');

      -- detalle
      /*************************************************************************
           REPLICACION
      *************************************************************************/

      Insert Into cntas_cobrar_det(
             tipo_doc    ,nro_doc  ,item ,
             descripcion ,cantidad ,precio_unitario,
             flag_replicacion,centro_benef )
      Values(
             :new.tipo_doc     ,:new.nro_doc , 1           ,
             ls_obs            ,1            ,:new.importe ,
             '0'               ,:new.centro_benef);

   END IF;
END IF ;


end TIA_FIN_CAJA_BANCOS_DET;
/

prompt
prompt Creating trigger TIA_FIN_CNTAS_COBRAR
prompt =====================================
prompt
CREATE OR REPLACE TRIGGER CANTABRIA.tia_fin_cntas_cobrar
  after insert on cntas_cobrar
  for each row

declare
  -- local variables here
  lc_cnta_ctbl   cntbl_cnta.cnta_ctbl%type          ;
  lc_flag_debhab cntbl_asiento_det.flag_debhab%type ;
  ln_factor      doc_tipo.factor%type               ;
  ln_existe                                 integer ;
  lc_forma_pago       cntas_cobrar.forma_pago%type ; --- variable Forma de Pago
  ln_monto_cuota      rrhh_credito_solicitud.importe%type ; --- variable tasa de interes
  lc_concep           rrhh_credito_solicitud.concep%type ; --- variable concepto
  ln_nro_cuotas       rrhh_credito_solicitud.nro_cuotas%type ; --- variable nro de cuotas
  ln_tasa_interes     rrhh_credito_solicitud.tasa_interes%type ; --- variable tasa de interes
  ln_importe          rrhh_credito_solicitud.importe%type ; --- variable tasa de interes
  lc_nro_doc          rrhh_credito_solicitud.nro_solicitud%type ; --- variable numero doc


begin
  If (dbms_reputil.from_remote=true or dbms_snapshot.i_am_a_refresh=true) then
     return;
  end if;

  --  Inicio de modificacion realizada por JORGE. FARFAN  LINEA 72

select Nvl(factor,0) into ln_factor from doc_tipo where (tipo_doc = :new.tipo_doc) ;

if ln_factor = 0 then
   RAISE_APPLICATION_ERROR(-20000,'Factor de Documento '||:new.tipo_doc||' es igual a 0 debera Colocar Algun Valor 1 o -1');
end if ;

  --documento provisionado
IF :new.flag_provisionado = 'R' THEN
   --recupero cuenta contable de documento provisionado


  usp_fin_cntbl_asiento_det(:new.origen,:new.ano,:new.mes,:new.nro_libro,:new.nro_asiento,:new.tipo_doc,:new.nro_doc,:new.cod_relacion,lc_cnta_ctbl ,lc_flag_debhab);
   /*****************************************************************
        REPLICACION
   ****************************************************************/

   Insert into doc_pendientes_cta_cte
   (cod_relacion ,tipo_doc ,nro_doc  ,flag_tabla ,cnta_ctbl ,cod_moneda ,
    flag_debhab  ,sldo_sol ,saldo_dol,fecha_doc  ,factor    ,flag_replicacion,
    fecha_vencimiento)
   Values
   (:new.cod_relacion, :new.tipo_doc  ,:new.nro_doc  ,'1',lc_cnta_ctbl  ,:new.cod_moneda,
    lc_flag_debhab   , :new.saldo_sol ,:new.saldo_dol,:new.fecha_documento,ln_factor,'0',
    :new.fecha_vencimiento) ;

ELSIF :new.flag_provisionado = 'D' THEN -- DIRECTO NO PROVISIONADO

   if ln_factor = 1 then
      lc_flag_debhab := 'D' ;
   elsif ln_factor = -1 then
      lc_flag_debhab := 'H' ;
   end if ;

   /*****************************************************************
        REPLICACION
   ****************************************************************/
   Insert Into doc_pendientes_cta_cte
   (cod_relacion ,tipo_doc  ,nro_doc   ,flag_tabla ,cod_moneda ,flag_debhab ,
    sldo_sol     ,saldo_dol ,fecha_doc ,factor     , flag_replicacion,
    fecha_vencimiento)
   Values
   (:new.cod_relacion, :new.tipo_doc  ,:new.nro_doc  ,'1',:new.cod_moneda,
    lc_flag_debhab   , :new.saldo_sol ,:new.saldo_dol,:new.fecha_documento,ln_factor,'0',
    :new.fecha_vencimiento) ;

END IF;

--  Inicio de modificacion realizada por JORGE. FARFAN
-- ***************************************************************
-- ***  Genera cuenta corriente de las Factura & Boletas       ***
-- ***************************************************************

ln_existe:=0;

select count(*) into  ln_existe  from rrhh_credito_solicitud
 where (nro_solicitud = :new.nro_sol_cred_rrhh) and (flag_estado = '2')  and ( flag_tipo_solic_cred = 'C');

if ln_existe > 0 then
   --- Captura informacion de rrhh_credito_solicitud
   select nro_solicitud, concep, nro_cuotas, tasa_interes, importe
     into lc_nro_doc, lc_concep, ln_nro_cuotas, ln_tasa_interes, ln_importe
     from rrhh_credito_solicitud
    where (nro_solicitud = :new.nro_sol_cred_rrhh) and (flag_estado = '2') and ( flag_tipo_solic_cred = 'C');

    ln_monto_cuota := Round(ln_importe / ln_nro_cuotas,2) ; -- variable donde se alla el monto de la cuota

    select f_pago_cnta_crte into lc_forma_pago from rrhhparam where reckey='1';
    if :new.importe_doc <= ln_importe then
        --- Inserta Cuenta Corriente del Trabajador
        insert into cnta_crrte
                   (cod_trabajador, tipo_doc, nro_doc, fec_prestamo, concep, flag_estado,
                    nro_cuotas, mont_original, mont_cuota, sldo_prestamo, cod_sit_prest, cod_moneda, cod_usr,
                    tasa_interes, forma_pago )
             values
                   (:new.cod_relacion, :new.tipo_doc, :new.nro_doc,  sysdate, lc_concep, '1', ln_nro_cuotas,
                    ln_importe, ln_monto_cuota, ln_importe, 'A', :new.cod_moneda, :new.cod_usr, ln_tasa_interes, lc_forma_pago );

             update rrhh_credito_solicitud  set flag_estado = '5' WHERE (nro_solicitud = lc_nro_doc);
     else
             Raise_application_error(-20001,' El importe de la Factura y/o Boleta  es Mayor al importe de la Solicitud de Credito' );
     end if;
end if;

--  Fin de modificacion realizada por J. Farfan
end tia_fin_cntas_cobrar;
/

prompt
prompt Creating trigger TIA_FIN_CNTAS_COBRAR_DET
prompt =========================================
prompt
CREATE OR REPLACE TRIGGER CANTABRIA.TIA_FIN_CNTAS_COBRAR_DET
  after insert on cntas_cobrar_det
  for each row


declare

  -- local variables here
  lc_bol_cobrar  doc_tipo.tipo_doc%type  ;
  lc_fac_cobrar  doc_tipo.tipo_doc%type  ;
  lc_doc_ov      doc_tipo.tipo_doc%type  ;
  lc_orden_venta orden_venta.nro_ov%type ;
  lc_flag_estado orden_venta.flag_estado%type ;
  lc_cod_art     articulo.cod_art%type   ;
  ln_cantidad    cntas_cobrar_det.cantidad%type ;
  ln_cant_x_fac  cntas_cobrar_det.cantidad%type ;
  lc_grupo_ventas finparam.doc_ventas%type ;
  ln_count        number ;
  Cursor c_art_mov  is /*Articulo Movimiento Proyectado*/
  SELECT cant_procesada ,
         cant_facturada ,
         cant_proyect
    FROM articulo_mov_proy
   WHERE (tipo_doc = lc_doc_ov      ) AND
         (nro_doc  = lc_orden_venta ) ;

  Cursor c_articulo  is /*Articulo que falta facturar*/
  SELECT a.cod_origen, a.nro_mov,
         cant_procesada ,
         cant_facturada ,
         cant_proyect   ,
         ( nvl(cant_proyect,0) - nvl(cant_facturada,0) ) as cant_x_fact
    FROM articulo_mov_proy a
   WHERE (tipo_doc = lc_doc_ov      ) AND
         (nro_doc  = lc_orden_venta ) AND
         (cod_art  = :new.cod_art   ) AND
         (flag_estado <>'0'         ) AND
         (NVL(cant_proyect,0)-nvl(cant_facturada,0))>0 ;

begin
  -- Edgar Morante Miercoles 10Jul2002, replicacion
  If (dbms_reputil.from_remote=true or dbms_snapshot.i_am_a_refresh=true) then
     return;
  end if;


  SELECT doc_fact_cobrar,doc_bol_cobrar,doc_ventas INTO lc_fac_cobrar, lc_bol_cobrar, lc_grupo_ventas from finparam  WHERE (reckey = '1') ;


  select count(*) into ln_count from doc_grupo_relacion dgr where dgr.grupo = lc_grupo_ventas and dgr.tipo_doc = :new.tipo_doc ;


   IF (ln_count > 0 ) then

      /*Recupero Orden Venta*/
      lc_doc_ov      := :new.tipo_ref   ;
      lc_orden_venta := :new.nro_ref    ;
      ln_cantidad    := nvl(:new.cantidad,0)  ;

      /*Actualiza Articulo Movimiento Proyectado, si referencia es una orden de venta*/
      FOR rc_art in c_articulo LOOP
          IF ln_cantidad > rc_art.cant_x_fact THEN
             ln_cant_x_fac := rc_art.cant_x_fact ;
          ELSE
             ln_cant_x_fac := ln_cantidad  ;
          END IF ;

          IF ln_cantidad > 0 THEN
            /*****************************************************************
                 REPLICACION
            ****************************************************************/
             UPDATE articulo_mov_proy a
                SET cant_facturada = Nvl(cant_facturada,0) + Nvl(ln_cant_x_fac,0) ,flag_replicacion = '0'
              WHERE (a.cod_origen = rc_art.cod_origen) AND
                    (a.nro_mov    = rc_art.nro_mov   ) ;

              ln_cantidad := ln_cantidad - Nvl(ln_cant_x_fac,0) ;
          ELSE
              -- sale de bucle
              exit ;
          END IF ;
      END LOOP ;

   --      modificado el 27/12/2004  FELIZ NAVIDAD Y PROSPERO A?O NUEVO JOJOJO
   --   lc_flag_estado := '5' ; /*Facturacion Total*/
   --  /*Verifica Estado de Orden de Venta en Articulo Movimiento Proyectado*/
   --   For rc_art_mov in c_art_mov  Loop
   --       If rc_art_mov.cant_proyect > rc_art_mov.cant_facturada  then
   --          lc_flag_estado := '4' ;  /*Facturacion Parcial*/
   --          Exit ;
   --       End if ;
   --   End Loop ;

      /*****************************************************************
              REPLICACION
      ****************************************************************/
   --   UPDATE orden_venta
   --      SET flag_estado = lc_flag_estado ,flag_replicacion = '0'
   --    WHERE (nro_ov           = lc_orden_venta ) ;


   END IF ;

end TIA_FIN_CNTAS_COBRAR_DET;
/

prompt
prompt Creating trigger TIA_FIN_CNTAS_PAGAR
prompt ====================================
prompt
CREATE OR REPLACE TRIGGER CANTABRIA.tia_fin_cntas_pagar
  after insert on cntas_pagar
  for each row

declare
  -- local variables here
  lc_cnta_ctbl   cntbl_cnta.cnta_ctbl%type          ;
  lc_flag_debhab cntbl_asiento_det.flag_debhab%type ;
  ln_factor      doc_tipo.factor%type               ;
  ln_count       number ;

  CURSOR c_asiento_det IS
     SELECT cd.cnta_ctbl, cd.flag_debhab, cd.imp_movsol
       FROM cntbl_asiento_det cd
      WHERE cd.origen            = :new.origen
        and cd.ano               = :new.ano
        and cd.mes               = :new.mes
        and cd.nro_libro         = :new.nro_libro
        and cd.nro_asiento       = :new.nro_asiento
        and cd.tipo_docref1      = :new.tipo_doc
        and trim(cd.nro_docref1) = trim(:new.nro_doc)
        and cd.cod_relacion      = :new.cod_relacion
     ORDER BY cd.imp_movsol desc ;


BEGIN
  If (dbms_reputil.from_remote=true or dbms_snapshot.i_am_a_refresh=true) then
     return;
  end if;

--FACTOR DE DOCUMENTO
select Nvl(factor,0) into ln_factor from doc_tipo where (tipo_doc = :new.tipo_doc) ;

if ln_factor = 0 THEN
   RAISE_APPLICATION_ERROR( -20000,'Factor de Documento '||:new.tipo_doc|| 'es igual a 0 debera Colocar alguna valor 1 o -1 ' ) ;
end if ;


--documento provisionado
IF :new.flag_provisionado = 'R' THEN

   --recupero cuenta contable de documento provisionado
    For rc_as_det in c_asiento_det Loop
      lc_cnta_ctbl   := rc_as_det.cnta_ctbl;
      lc_flag_debhab := rc_as_det.flag_debhab;
      EXIT ;
    End Loop;

   /*****************************************************************
     REPLICACION
   *****************************************************************/
   Insert into doc_pendientes_cta_cte
   (cod_relacion ,tipo_doc ,nro_doc  ,flag_tabla ,cnta_ctbl ,cod_moneda      ,
    flag_debhab  ,sldo_sol ,saldo_dol,fecha_doc  ,factor    ,flag_replicacion,
    fecha_vencimiento)
   Values
   (:new.cod_relacion, :new.tipo_doc  ,:new.nro_doc  ,'3',lc_cnta_ctbl  ,:new.cod_moneda,
    lc_flag_debhab   , :new.saldo_sol ,:new.saldo_dol,:new.fecha_emision,ln_factor,'0'  ,
    :new.vencimiento ) ;


ELSE

   if ln_factor = 1 then
      lc_flag_debhab := 'D' ;
   elsif ln_factor = -1 then
      lc_flag_debhab := 'H' ;
   end if ;

   /*****************************************************************
     REPLICACION
   *****************************************************************/

   Insert into doc_pendientes_cta_cte
   (cod_relacion ,tipo_doc ,nro_doc  ,flag_tabla ,cod_moneda ,
    flag_debhab  ,sldo_sol ,saldo_dol,fecha_doc  ,factor     ,flag_replicacion,
    fecha_vencimiento)
   Values
   (:new.cod_relacion, :new.tipo_doc  ,:new.nro_doc  ,'3',:new.cod_moneda,
    lc_flag_debhab   , :new.saldo_sol ,:new.saldo_dol,:new.fecha_emision,ln_factor ,'0',
    :new.vencimiento) ;
END IF;

-- Actualizando tabla de control documentario, en caso exista
SELECT count(*)
  INTO ln_count
  FROM cd_doc_recibido c
 WHERE c.cod_relacion = :new.cod_relacion
   AND c.tipo_doc = :new.tipo_doc
   AND SUBSTR(c.nro_doc,1,10) = :new.nro_doc ;

IF ln_count > 0 THEN
   UPDATE cd_doc_recibido c
      SET c.flag_provisionado = 'P'
    WHERE c.cod_relacion = :new.cod_relacion
      AND c.tipo_doc = :new.tipo_doc
      AND SUBSTR(c.nro_doc,1,10) = :new.nro_doc ;
END IF ;

end tia_fin_cntas_pagar;
/

prompt
prompt Creating trigger TIA_FIN_CNTAS_PAGAR_DET
prompt ========================================
prompt
CREATE OR REPLACE TRIGGER CANTABRIA.TIA_FIN_CNTAS_PAGAR_DET
  after insert on cntas_pagar_det
  for each row

declare
  -- local variables here
  lc_doc_oc          logparam.doc_oc%type ;
  lc_doc_os          logparam.doc_os%type ;
  lc_ncred_x_pagar   doc_tipo.tipo_doc%type           ;
  lc_ndeb_x_pagar    doc_tipo.tipo_doc%type           ;
  lc_comp_egr        doc_tipo.tipo_doc%type           ;
  ln_importe_x_item  cntas_pagar_det.importe%type     ;
  ln_importe_dol     cntas_pagar_det.importe%type     ;


  lc_cod_moneda      moneda.cod_moneda%type           ;
  lc_soles           moneda.cod_moneda%type           ;
  lc_dolares         moneda.cod_moneda%type           ;
  ln_tasa_cambio     calendario.cmp_dol_libre%type    ;
  lc_flag_control    presupuesto_partida.flag_ctrl%type ;
  ld_fecha_emision   cntas_pagar.fecha_emision%type   ;
  ln_ano             Number(4) ;
  ln_mes             Number(2) ;
  ln_count           Number ;
  ln_referencias     number;
  lc_cod_origen      cntas_pagar.origen%type          ;

  lc_flag_provisionado  cntas_pagar.flag_provisionado%TYPE;
  lc_flag_afecta_presup doc_tipo.flag_afecta_prsp%type      ;
  lc_flag_provision     finparam.flag_os_provision%type     ;
  lc_usr                usuario.cod_usr%type                ;

  -- Articulo_mov_proy
  ln_cant_procesada     articulo_mov_proy.cant_procesada%TYPE;
  ln_cant_facturada     articulo_mov_proy.cant_facturada%TYPE;
  ls_tipo_doc_amp       articulo_mov_proy.tipo_doc%TYPE;
  ls_nro_doc_amp        articulo_mov_proy.nro_doc%TYPE;

  --Orden de Servicio
  ln_importe_os         orden_Servicio_det.importe%TYPE;
  ln_imp_provisionado   orden_servicio_det.imp_provisionado%TYPE;

 -- AP_Param
  ls_doc_grmp        ap_param.doc_guia_mp%TYPE;

  --Ap_guia_recepcion
  ls_moneda_grmp     ap_guia_recepcion.cod_moneda%TYPE;
  ls_nro_grmp        ap_guia_recepcion.cod_guia_rec%TYPE;

  --Ap_guia_recepcion_det
  ln_importe_grmp     ap_guia_recepcion_det.monto_facturado%TYPE;
  ln_precio_grmp      ap_guia_recepcion_det.precio_unitario%TYPE;
  ln_peso_grmp        ap_guia_recepcion_det.peso_venta%TYPE;
  ln_item_grmp        ap_guia_recepcion_det.item%TYPE;
  ln_monto_fac_grmp   ap_guia_recepcion_det.monto_facturado%TYPE;
  ln_monto_tot_fac    ap_guia_recepcion_det.monto_facturado%TYPE;
  --



begin

  -- Edgar Morante Miercoles 10Jul2002, replicacion
  If (dbms_reputil.from_remote=true or dbms_snapshot.i_am_a_refresh=true) then
     return;
  end if;

  /*Buscar Soles , Dolares , Orden Compra*/

  SELECT cod_soles ,cod_dolares ,doc_oc  ,doc_os
    INTO lc_soles  ,lc_dolares ,lc_doc_oc ,lc_doc_os
    FROM logparam
   WHERE (reckey = '1') ;

  /************************/

  /*Buscar Nota Debito , Nota de Credito x Pagar*/
  select f.nota_cred_nfc,f.nota_deb_ncc,Nvl(f.flag_os_provision,'0')
    into lc_ncred_x_pagar,lc_ndeb_x_pagar,lc_flag_provision
    from finparam f
   where (reckey = '1') ;

  -- actualizo la cantidad facturada de Articulo_mov_proy (Orden de compra)
  IF  :new.org_amp_ref is not null and :new.nro_amp_ref is not null and
      :new.tipo_doc not in (pq_doc_finanzas.is_doc_ncp, pq_doc_finanzas.is_doc_ndp, pq_doc_finanzas.is_doc_cnc)   THEN

      select nvl(amp.cant_procesada, 0), nvl(amp.cant_facturada, 0), amp.tipo_doc, amp.nro_doc
        into ln_cant_procesada, ln_cant_facturada, ls_tipo_doc_amp, ls_nro_doc_amp
        from articulo_mov_proy amp
       where amp.cod_origen = :new.org_amp_ref
         and amp.nro_mov    = :new.nro_amp_ref for update;

      if ln_cant_procesada < ln_cant_facturada + :new.cantidad then
         RAISE_APPLICATION_ERROR( -20000, 'La cantidad a provisionar no puede sobrepasar a la cantidad procesada. Por favor verifique. '
                            || chr(13) || 'Tipo Doc: ' || ls_tipo_doc_amp
                            || chr(13) || 'Nro Doc: ' || ls_nro_doc_amp
                            || chr(13) || 'Articulo: ' || NVL(:new.cod_art,'')
                            || chr(13) || 'Cant. Procesada: ' || to_char(ln_cant_procesada, '999,990.00')
                            || chr(13) || 'Cant. Facturada: ' || to_char(ln_cant_facturada, '999,990.00')
                            || chr(13) || 'Cant. a Provisionar: ' || to_char(:new.cantidad, '999,990.00'));
      end if;

       UPDATE articulo_mov_proy amp
          SET cant_facturada = ln_cant_facturada + NVL(:new.cantidad,0),
              flag_replicacion = '0'
        where amp.cod_origen = :new.org_amp_ref
         and amp.nro_mov     = :new.nro_amp_ref;
  end if;

  -- Actualizo el improte facturado de la Orden de Servicio
  if :new.org_os is not null and :new.nro_os is not null and :new.item_os is not null and
     :new.tipo_doc not in (pq_doc_finanzas.is_doc_ncp, pq_doc_finanzas.is_doc_ndp, pq_doc_finanzas.is_doc_cnc) then

     select (Nvl(osd.importe,0) - Nvl(osd.decuento,0)), NVL(osd.imp_provisionado, 0)
       into ln_importe_os, ln_imp_provisionado
       from orden_servicio_det osd
      where osd.cod_origen = :new.org_os
        and osd.nro_os     = :new.nro_os
        and osd.nro_item   = :new.item_os for update;

     IF ln_importe_os < ln_imp_provisionado + :new.importe THEN
         RAISE_APPLICATION_ERROR( -20000, 'El importe de la factura no puede superar al importe del item de la Orden de Servicio. Por favor verifique. '
                            || chr(13) || 'Tipo Doc: ' || lc_doc_os
                            || chr(13) || 'Nro Doc: ' || :new.nro_os
                            || chr(13) || 'Item OS: ' || NVL(:new.item_os,'')
                            || chr(13) || 'Importe OS: ' || to_char(ln_importe_os, '999,990.00')
                            || chr(13) || 'Importe Provisionado: ' || to_char(ln_imp_provisionado, '999,990.00')
                            || chr(13) || 'Importe. a Provisionar: ' || to_char(:new.importe, '999,990.00'));
     end if;

     UPDATE orden_servicio_det osd
        SET osd.imp_provisionado = ln_imp_provisionado + :new.importe,
            flag_replicacion     = '0'
     where osd.cod_origen = :new.org_os
        and osd.nro_os     = :new.nro_os
        and osd.nro_item   = :new.item_os;

  END IF ;

  /*Afectacion Presupuestal*/
  SELECT Count(*)
    INTO ln_count
    FROM doc_referencias
   WHERE ((cod_relacion = :new.cod_relacion ) AND
          (tipo_doc     = :new.tipo_doc     ) AND
          (nro_doc      = :new.nro_doc      )) ;

--
  select cp.cod_moneda,cp.tasa_cambio,cp.fecha_emision,cp.origen,mes,cp.flag_provisionado,cp.cod_usr
    into lc_cod_moneda,ln_tasa_cambio,ld_fecha_emision,lc_cod_origen,ln_mes,lc_flag_provisionado,lc_usr
    FROM cntas_pagar cp
   WHERE ((cp.cod_relacion = :new.cod_relacion ) AND
          (cp.tipo_doc     = :new.tipo_doc     ) AND
          (cp.nro_doc      = :new.nro_doc      ));



  --datos de maestro de documentos (flag de afectacion presupuestal para documentos porpagardirecto)
  select dt.flag_afecta_prsp
    into lc_flag_afecta_presup
    from doc_tipo dt
   where dt.tipo_doc =:new.tipo_doc ;

  IF lc_soles = lc_cod_moneda THEN
    /*Convertir a Dolares*/

    ln_importe_x_item := :new.importe ;
    ln_importe_dol    := Round(ln_importe_x_item / ln_tasa_cambio ,2) ;

  ELSE
    ln_importe_dol    := :new.importe ;
  END IF ;


  /*Documento Comprobante de Egreso*/
  SELECT comprobante_egr
    INTO lc_comp_egr
    FROM finparam
   WHERE (reckey = '1') ;

  IF lc_flag_provisionado = 'D' OR  lc_flag_provisionado = 'N' THEN --DIRECTO
     ln_mes := to_number(to_char(ld_fecha_emision,'MM'  )) ;
  END IF ;

  ln_ano := to_number(to_char(ld_fecha_emision,'YYYY')) ;

  IF (ln_referencias = 0 OR lc_flag_provisionado in ('D','N')) and lc_flag_afecta_presup = '1' THEN
     IF Not(:new.cencos is null ) THEN


        /*VERIFICA PARTIDA*/
        USP_FIN_VERIF_PRESUP_PARTIDA(ln_ano,:new.cencos,:new.cnta_prsp,lc_flag_control) ;

        IF lc_flag_control <> '0' THEN
           --Valida Afectacion presupuestalmente
           usp_pto_afecta_ejecucion(ln_mes,ln_ano, :new.cencos,:new.cnta_prsp,Nvl(ln_importe_dol,0) );
        END IF ;

        /*Inserta Presupuesto Ejecucion*/
        --replicacion
        Insert Into presupuesto_ejec
        (cod_origen   ,ano         ,cencos  ,cnta_prsp  ,
         fecha        ,descripcion ,importe ,origen_ref ,
         tipo_doc_ref ,nro_doc_ref ,item_ref,flag_replicacion,
         cod_rel_ref  ,cod_usr, centro_benef)
        Values
        (lc_cod_origen     ,ln_ano, :new.cencos,:new.cnta_prsp ,
         ld_fecha_emision  ,Substr(rtrim(ltrim(:new.descripcion)),1,40),Nvl(ln_importe_dol *-1,0),
         lc_cod_origen     ,:new.tipo_doc, :new.nro_doc,:new.item,'0' ,
         :new.cod_relacion ,lc_usr, :NEW.centro_benef ) ;
     ELSE
        raise_application_error(-20000,'Debe Colocar Centro de Costo ,Verifique !') ;
     END IF;
  ELSE


     /*Afectacion Presupuestal de Acuerdo a Documento*/
     IF :new.tipo_doc = lc_ndeb_x_pagar THEN
        /*Nota debito x Pagar (Disminuir)*/
        /*VERIFICA PARTIDA*/
        USP_FIN_VERIF_PRESUP_PARTIDA(ln_ano,:new.cencos,:new.cnta_prsp,lc_flag_control);

        IF lc_flag_control <> '0' THEN
           --Valida Afectacion presupuestalmente
           usp_pto_afecta_ejecucion(ln_mes         ,ln_ano      , :new.cencos,
                                   :new.cnta_prsp ,ln_importe_dol );
        END IF ;

        /*Inserta Presupuesto Ejecucion*/
        --replicacion
        Insert Into presupuesto_ejec
        (cod_origen   ,ano         ,cencos  ,cnta_prsp  ,
         fecha        ,descripcion ,importe ,origen_ref ,
         tipo_doc_ref ,nro_doc_ref ,item_ref,flag_replicacion ,
         cod_rel_ref  ,cod_usr, centro_benef)
        Values
        (lc_cod_origen    ,ln_ano        ,:new.cencos ,:new.cnta_prsp ,
         ld_fecha_emision ,Substr(rtrim(ltrim(:new.descripcion)),1,40),ln_importe_dol *-1,
         lc_cod_origen    ,:new.tipo_doc ,:new.nro_doc,:new.item,'0',
         :new.cod_relacion,lc_usr, :NEW.centro_benef);

     ELSIF :new.tipo_doc = lc_ncred_x_pagar THEN
        /*Nota Credito x Pagar (Devolver)*/
        /*VERIFICA PARTIDA*/
        USP_FIN_VERIF_PRESUP_PARTIDA(ln_ano,:new.cencos,:new.cnta_prsp,lc_flag_control);

        IF lc_flag_control <> '0' THEN
           /*Inserta Presupuesto Ejecucion*/
           usp_pto_afecta_ejecucion(ln_mes,ln_ano, :new.cencos,
                                   :new.cnta_prsp ,ln_importe_dol * -1);
        END IF ;
        --replicacion
        Insert Into presupuesto_ejec
        (cod_origen   ,ano         ,cencos  ,cnta_prsp  ,
         fecha        ,descripcion ,importe ,origen_ref ,
         tipo_doc_ref ,nro_doc_ref,item_ref,flag_replicacion,
         cod_rel_ref  ,cod_usr, centro_benef)
        Values
        (lc_cod_origen    ,ln_ano        ,:new.cencos ,:new.cnta_prsp ,
         ld_fecha_emision ,Substr(rtrim(ltrim(:new.descripcion)),1,40),ln_importe_dol ,
         lc_cod_origen    ,:new.tipo_doc ,:new.nro_doc ,:new.item,'0' ,
         :new.cod_relacion, lc_usr, :NEW.centro_benef) ;

     END IF ;
  END IF ;

 --============================================================================
 -- Si documento de Referencia es una Guia de Recepcion de Materia Prima
 --============================================================================
  SELECT count(*)
     INTO ln_count
  FROM   ap_param l
  WHERE l.origen = 'XX';

  if ln_count = 0 then
      RAISE_APPLICATION_ERROR(-20000, 'No ha definido parametros generasles en AP_PARAM ');
  end if;

  SELECT l.doc_guia_mp
     INTO ls_doc_grmp
  FROM   ap_param l
  WHERE l.origen = 'XX';

  IF ls_doc_grmp IS NULL THEN
      RAISE_APPLICATION_ERROR(-20000, 'No ha definido documento de Guia de Recepcion de '
      || 'Materia Prima en AP_PARAM');
  END IF;

  IF :NEW.tipo_ref = ls_doc_grmp THEN
       ls_nro_grmp  := :NEW.nro_ref;
       ln_item_grmp := :NEW.item_ref;

       --Obtengo la moneda de la cabecera de la GRMP
       SELECT COD_MONEDA
         INTO ls_moneda_grmp
         FROM  ap_guia_recepcion
        WHERE cod_guia_rec = ls_nro_grmp;

       -- Obtengo el precio y peso del detalle de la GRMP
       SELECT NVL(a.precio_unitario, 0) + NVL(a.precio_unitario_castigo, 0) +
              NVL(a.precio_representacion, 0 ) + NVL(a.precio_ajuste_cntbl,0),
              NVL(a.peso_venta,0),
              NVL(a.monto_facturado,0)
        INTO  ln_precio_grmp, ln_peso_grmp, ln_monto_fac_grmp
       FROM   ap_guia_recepcion_det a
       WHERE  a.cod_guia_rec = ls_nro_grmp
         AND  a.item         = ln_item_grmp;
       -- Obtengo el monto total del detalle de la GRMP
       ln_importe_grmp := ROUND(ln_precio_grmp * ln_peso_grmp, 2);

       -- Verificamos que el importe facturado no exceda el monto por facturar de la grmp
       ln_importe_x_item := :new.importe ;
       IF ls_moneda_grmp <> lc_cod_moneda THEN
          IF ls_moneda_grmp = lc_soles THEN
             ln_importe_x_item := Round(ln_importe_x_item * ln_tasa_cambio,2);
          ELSE
             ln_importe_x_item := Round(ln_importe_x_item / ln_tasa_cambio,2);
          END IF;
       END IF;

       -- Calculo el monto total facturado
       ln_monto_tot_fac := ln_monto_fac_grmp + ln_importe_x_item ;

       -- Actualizo el monto total facturado de la GRMP
       IF ln_monto_tot_fac <= (ln_importe_grmp + 1) THEN
            UPDATE AP_GUIA_RECEPCION_DET
               SET monto_facturado = ln_monto_tot_fac
            WHERE  cod_guia_rec = ls_nro_grmp
             AND   item         = ln_item_grmp;
       ELSE
           RAISE_APPLICATION_ERROR(-20000, 'Monto a Facturar excede el monto total de la GRMP '
            ||CHR(13) || 'Por favor Verifique '
            ||CHR(13) || 'Nro de GRMP     ==> ' || ls_nro_grmp
            ||CHR(13) || 'Nro de Item GRMP==> ' || TO_CHAR(ln_item_grmp)
            ||CHR(13) || 'Monto_Item_GRMP ==> ' || TO_CHAR(ln_importe_grmp)
            ||CHR(13) || 'Monto_Facturado ==> ' || TO_CHAR(ln_monto_tot_fac));
           RETURN ;
       END IF;

  END IF;
  --============================================================================

end TIA_FIN_CNTAS_PAGAR_DET;

---COMENTARIOS
--ULTIMO CAMBIO PARA ACTUALIZAR IMPORTE PROVISIONADO
--Ultimo cambio para referencias las GRMP,
/

prompt
prompt Creating trigger TIA_FIN_DOC_REFERENCIAS
prompt ========================================
prompt
CREATE OR REPLACE TRIGGER CANTABRIA.tia_fin_doc_referencias
  after insert on doc_referencias
  for each row

declare
  -- local variables here
  ls_tipo_ref_gr       doc_tipo.tipo_doc%type             ;
  lc_fact_cobrar       finparam.doc_fact_cobrar%type      ;
  lc_letra_cobrar      finparam.doc_letra_cobrar%type     ;
  lc_letra_pagar       finparam.doc_letra_pagar%type      ;
  lc_flag_ctrl_reg     cntas_pagar.flag_control_reg%type  ;
  lc_flag_caja_bancos  cntas_pagar.flag_control_reg%type  ;
  lc_flag_debhab_esp   doc_pendientes_cta_cte.flag_debhab%type ;
  ln_cnta_ctbl         cntbl_cnta.cnta_ctbl%Type               ;
  ln_factor_esp        doc_pendientes_cta_cte.factor%type      ;
  lc_origen_cb         origen.cod_origen%type             ;
  ln_ano               cntas_pagar.ano%Type               ;
  ln_mes               cntas_pagar.mes%type               ;
  ln_nro_libro         cntas_pagar.nro_libro%Type         ;
  ln_nro_asiento       cntas_pagar.nro_asiento%type       ;
  ls_doc_oc          logparam.doc_oc%type;
  ls_doc_os          logparam.doc_os%type;
  lc_flag_estado     char(1);
  lc_cod_moneda      moneda.cod_moneda%type ;
  ln_tasa_cambio     calendario.cmp_dol_libre%type ;
  lc_soles           moneda.cod_moneda%type ;
  lc_dolares         moneda.cod_moneda%type ;
  ln_importe_soles   doc_referencias.importe%type ;
  ln_importe_dolares doc_referencias.importe%type ;
  ln_monto_total     cntas_pagar.total_pagar%type ;
  ln_monto_fact      cntas_pagar.total_pagar%type ;
  ln_count           Number ;
  ln_count_cad       Number ;


  lc_doc_chq_dif     doc_tipo.tipo_doc%Type       ;

  --new changes
  ln_saldo_sol       Number (13,2);
  ln_saldo_dol       Number (13,2);
  ln_mont_pend_sol   Number (13,2);
  ln_mont_pend_dol   Number (13,2);
  ln_monto_sol_dif   Number (13,2);

begin
  -- Edgar Morante Miercoles 10Jul2002, replicacion
  If (dbms_reputil.from_remote=true or dbms_snapshot.i_am_a_refresh=true) then
     return;
  end if;


   /**Selecione tipo de doc Guia de Remision**/
   SELECT doc_gr, doc_oc, doc_os, cod_soles, cod_dolares
     INTO ls_tipo_ref_gr, ls_doc_oc, ls_doc_os,lc_soles,lc_dolares
     FROM logparam
    WHERE reckey = '1' ;
   /*****************************************/
   /***Selecione tipo de Facturas x Cobrar***/
   SELECT doc_fact_cobrar,doc_letra_pagar,doc_letra_cobrar,doc_cheque_dif
     INTO lc_fact_cobrar,lc_letra_pagar,lc_letra_cobrar,lc_doc_chq_dif
     FROM finparam f
    WHERE reckey = '1' ;
   /*****************************************/

   /*Cuentas Por Cobrar*/
   /*Considerar de Guia de Remision */
    IF :new.tipo_mov = 'C' AND :new.tipo_ref  = ls_tipo_ref_gr THEN
       /**************************************************************************
         REPLICACION
       **************************************************************************/
          UPDATE guia
             SET flag_estado = '3' ,tipo_doc = :new.tipo_doc,nro_doc = :new.nro_doc ,flag_replicacion = '0'
           WHERE cod_origen = :new.origen_ref  AND
                 nro_guia   = :new.nro_ref     ;



    ELSIF :new.tipo_mov = 'P' AND :new.tipo_ref = ls_doc_oc THEN  /* Orden de Compra */

       /*Actualizacion de Monto de Orden de Comnpra*/
       /**************************************************************************
         REPLICACION
       **************************************************************************/
          UPDATE orden_compra
             SET monto_facturado = Nvl(monto_facturado,0) + :new.importe  ,flag_replicacion = '0'
           WHERE ((cod_origen = :new.origen_ref )  AND
                  (nro_oc     = :new.nro_ref    )) ;


    ELSIF :new.tipo_mov = 'P' AND :new.tipo_ref = ls_doc_os THEN  /*Orden de Servicio*/


          /*Actualizacion de Monto de Orden de Servicio*/
         /**************************************************************************
          REPLICACION
         **************************************************************************/

          UPDATE orden_servicio
             SET monto_facturado = Nvl(monto_facturado,0) + :new.importe,flag_replicacion = '0'
           WHERE ((cod_origen = :new.origen_ref )  AND
                  (nro_os     = :new.nro_ref    )) ;


          SELECT monto_total ,monto_facturado
            INTO ln_monto_total , ln_monto_fact
            FROM orden_servicio
           WHERE ((cod_origen = :new.origen_ref )  AND
                  (nro_os     = :new.nro_ref    )) ;

          IF ln_monto_fact >=  ln_monto_total THEN
             /*Facturado Total  */
             UPDATE orden_servicio
                SET flag_estado = '2',flag_replicacion = '0'
              WHERE ((cod_origen = :new.origen_ref )  AND
                     (nro_os     = :new.nro_ref    )) ;


          END IF ;

       /**************************************************************************
         REPLICACION
       **************************************************************************/




    ELSIF :new.tipo_mov = 'C' AND (:new.tipo_doc = lc_letra_cobrar OR :new.tipo_doc = lc_doc_chq_dif )THEN /*LETRAS x COBRAR y CHEUQES DIFERIDOS*/

       select tasa_cambio into ln_tasa_cambio
         from cntas_cobrar
        where (cod_relacion = :new.cod_relacion ) and
              (tipo_doc     = :new.tipo_doc     ) and
              (nro_doc      = :new.nro_doc      ) ;

       IF :new.flab_tabor = '1'   THEN /*Cuentas x Cobrar*/

          select importe_doc,Nvl(saldo_sol,0),Nvl(saldo_dol,0),cod_moneda
            into ln_monto_total,ln_saldo_sol , ln_saldo_dol ,lc_cod_moneda
            from cntas_cobrar
           where (( origen       = :new.origen_ref   ) AND
                  ( cod_relacion = :new.proveedor_ref ) AND
                  ( tipo_doc     = :new.tipo_ref     ) AND
                  ( nro_doc      = :new.nro_ref      ));


          if lc_cod_moneda = lc_soles THEN
             ln_importe_soles   := :new.importe ;
             ln_importe_dolares := Round(:new.importe / ln_tasa_cambio,2) ;



             --encontrar estado del documento
             ln_saldo_sol := ln_saldo_sol - ln_importe_soles ;
             ln_saldo_dol := ln_saldo_dol - ln_importe_dolares ;

             if ln_monto_total = ln_saldo_sol then --activo
                lc_flag_estado := '1';
             elsif ln_saldo_sol = 0 then           --pagado totalmente
                lc_flag_estado := '3';
             elsif ln_saldo_sol > 0 then           --pagado parcialmente
                lc_flag_estado := '2';
             end if ;

          elsif  lc_cod_moneda = lc_dolares THEN
             ln_importe_dolares := :new.importe ;
             ln_importe_soles   := Round(:new.importe * ln_tasa_cambio,2) ;

             --diferencia en cambiode documentos
             select Nvl(sldo_sol,0),Nvl(saldo_dol,0) into ln_mont_pend_sol,ln_mont_pend_dol from doc_pendientes_cta_cte
             where (cod_relacion = :new.cod_relacion ) and
                   (tipo_doc     = :new.tipo_ref     ) and
                   (nro_doc      = :new.nro_ref      ) ;

             ln_monto_sol_dif := Round(ln_mont_pend_dol * ln_tasa_cambio,2) - ln_mont_pend_sol  ;


             --encontrar estado del documento
             ln_saldo_dol := ln_saldo_dol - ln_importe_dolares ;
             ln_saldo_sol := (ln_saldo_sol + ln_monto_sol_dif) - ln_importe_soles ;

             if ln_monto_total = ln_saldo_dol then --activo
                lc_flag_estado := '1';
             elsif ln_saldo_dol = 0 then           --pagado totalmente
                lc_flag_estado := '3';
             elsif ln_saldo_dol > 0 then           --pagado parcialmente
                lc_flag_estado := '2';
             end if ;

          end if ;

          --actualizo cntas x pagar
          /**************************************************************************
              REPLICACION
           **************************************************************************/
           UPDATE cntas_cobrar
              SET flag_estado = lc_flag_estado ,saldo_sol = ln_saldo_sol, saldo_dol = ln_saldo_dol ,flag_replicacion = '0'
            WHERE (( origen       = :new.origen_ref   ) AND
                   ( cod_relacion = :new.proveedor_ref ) AND
                   ( tipo_doc     = :new.tipo_ref     ) AND
                   ( nro_doc      = :new.nro_ref      ));


       ELSIF :new.flab_tabor = '3' THEN

          select importe_doc,Nvl(saldo_sol,0),Nvl(saldo_dol,0),cod_moneda
            into ln_monto_total,ln_saldo_sol , ln_saldo_dol ,lc_cod_moneda
            from cntas_pagar
           where (( origen       = :new.origen_ref   ) AND
                  ( cod_relacion = :new.proveedor_ref ) AND
                  ( tipo_doc     = :new.tipo_ref     ) AND
                  ( nro_doc      = :new.nro_ref      ));


          if lc_cod_moneda = lc_soles THEN
             ln_importe_soles   := :new.importe ;
             ln_importe_dolares := Round(:new.importe / ln_tasa_cambio,2) ;



             --encontrar estado del documento
             ln_saldo_sol := ln_saldo_sol - ln_importe_soles ;
             ln_saldo_dol := ln_saldo_dol - ln_importe_dolares ;

             if ln_monto_total = ln_saldo_sol then --activo
                lc_flag_estado := '1';
             elsif ln_saldo_sol = 0 then           --pagado totalmente
                lc_flag_estado := '3';
             elsif ln_saldo_sol > 0 then           --pagado parcialmente
                lc_flag_estado := '2';
             end if ;

          elsif  lc_cod_moneda = lc_dolares THEN
             ln_importe_dolares := :new.importe ;
             ln_importe_soles   := Round(:new.importe * ln_tasa_cambio,2) ;

             --diferencia en cambiode documentos
             select Nvl(sldo_sol,0),Nvl(saldo_dol,0) into ln_mont_pend_sol,ln_mont_pend_dol from doc_pendientes_cta_cte
             where (cod_relacion = :new.cod_relacion ) and
                   (tipo_doc     = :new.tipo_ref     ) and
                   (nro_doc      = :new.nro_ref      ) ;

             ln_monto_sol_dif := Round(ln_mont_pend_dol * ln_tasa_cambio,2) - ln_mont_pend_sol  ;


             --encontrar estado del documento
             ln_saldo_dol := ln_saldo_dol - ln_importe_dolares ;
             ln_saldo_sol := (ln_saldo_sol + ln_monto_sol_dif) - ln_importe_soles ;

             if ln_monto_total = ln_saldo_dol then --activo
                lc_flag_estado := '1';
             elsif ln_saldo_dol = 0 then           --pagado totalmente
                lc_flag_estado := '3';
             elsif ln_saldo_dol > 0 then           --pagado parcialmente
                lc_flag_estado := '2';
             end if ;

          end if ;

          --actualizo cntas x pagar
          /**************************************************************************
              REPLICACION
           **************************************************************************/
           UPDATE cntas_pagar
              SET flag_estado = lc_flag_estado ,saldo_sol = ln_saldo_sol, saldo_dol = ln_saldo_dol,flag_replicacion = '0'
            WHERE (( origen       = :new.origen_ref   ) AND
                   ( cod_relacion = :new.proveedor_ref ) AND
                   ( tipo_doc     = :new.tipo_ref     ) AND
                   ( nro_doc      = :new.nro_ref      ));



       END IF ;
    ELSIF :new.tipo_mov = 'P' AND :new.tipo_doc = lc_letra_pagar THEN /*LETRAS X PAGAR*/
      --recupera datos de la cabecera
       select tasa_cambio ,cp.origen,cp.ano,cp.mes,cp.nro_libro,cp.nro_asiento
         into ln_tasa_cambio ,lc_origen_cb ,ln_ano,ln_mes,ln_nro_libro,ln_nro_asiento
         from cntas_pagar cp
        where (cod_relacion = :new.cod_relacion ) and
              (tipo_doc     = :new.tipo_doc     ) and
              (nro_doc      = :new.nro_doc      ) ;






       IF :new.flab_tabor = '3'   THEN /*Cuentas x Pagar*/



          select importe_doc,Nvl(saldo_sol,0),Nvl(saldo_dol,0),cod_moneda,flag_control_reg,flag_caja_bancos
            into ln_monto_total,ln_saldo_sol , ln_saldo_dol ,lc_cod_moneda,lc_flag_ctrl_reg,lc_flag_caja_bancos
            from cntas_pagar
           where (( origen       = :new.origen_ref   ) AND
                  ( cod_relacion = :new.proveedor_ref ) AND
                  ( tipo_doc     = :new.tipo_ref     ) AND
                  ( nro_doc      = :new.nro_ref      ));

          --VERIFICAR SI ES CTA CTE
          IF :new.flag_provisionado = 'D' AND lc_flag_ctrl_reg = '1' and
             lc_flag_caja_bancos    = '0' THEN

             --verifica que documento sea tipo cuenta corriente por pagar
             select count(*) into ln_count from doc_grupo_relacion dg
              where (dg.grupo    = 'C2'          ) and
                    (dg.tipo_doc = :new.tipo_ref ) ;

             if ln_count = 0 then --documento no esta definido como cuenta corriente
                raise_application_error(-20000,'Documento no esta definido en grupo de cuenta corriente ');
             else
                --busco datos en documentos pendientes
                select dp.flag_debhab     , dp.factor
                  into lc_flag_debhab_esp , ln_factor_esp
                  from doc_pendientes_cta_cte dp
                 where (dp.cod_relacion = :new.proveedor_ref ) and
                       (dp.tipo_doc     = :new.tipo_ref     ) and
                       (dp.nro_doc      = :new.nro_ref      ) ;

                if lc_flag_debhab_esp = 'H' then
                   lc_flag_debhab_esp := 'D' ;
                else --docuementos tiene problemas verifique datos del documento
                   raise_application_error(-20000,'Documento tiene problemas verifique datos Ingresados');
                end if ;

                if ln_factor_esp = '-1' then
                   ln_factor_esp := '1' ;
                else
                   raise_application_error(-20000,'Documento tiene problemas verifique datos Ingresados');
                end if ;

                select count(*)
                  into ln_count_cad
                  from cntbl_asiento_det cad
                 where (cad.origen     = lc_origen_cb      ) and (cad.ano          = ln_ano            ) and
                     (cad.mes          = ln_mes            ) and (cad.nro_libro    = ln_nro_libro      ) and
                     (cad.nro_asiento  = ln_nro_asiento    ) and (cad.cod_relacion = :new.proveedor_ref ) and
                     (cad.tipo_docref1 = :new.tipo_ref     ) and (cad.nro_docref1  = :new.nro_ref      ) ;

                if ln_count_cad > 0 then
                   --BUSCAR CUENTA CONTABLE
                   select cad.cnta_ctbl into ln_cnta_ctbl from cntbl_asiento_det cad
                    where (cad.origen       = lc_origen_cb      ) and (cad.ano          = ln_ano            ) and
                          (cad.mes          = ln_mes            ) and (cad.nro_libro    = ln_nro_libro      ) and
                          (cad.nro_asiento  = ln_nro_asiento    ) and (cad.cod_relacion = :new.proveedor_ref ) and
                          (cad.tipo_docref1 = :new.tipo_ref     ) and (cad.nro_docref1  = :new.nro_ref      ) ;
                else
                   raise_application_error(-20000,'Asientos de Documento Tiene problemas ,Verifique!');
                end if ;

                --ACTUALIZA CNTAS POR PAGAR
                update cntas_pagar cp
                  set cp.flag_caja_bancos = '1' ,
                      cp.flag_replicacion = '0'
                 where (cp.cod_relacion = :new.proveedor_ref ) and
                       (cp.tipo_doc     = :new.tipo_ref     ) and
                       (cp.nro_doc      = :new.nro_ref      ) ;




             end if ;

             --actualiza docuemnto tipo cuenta corriente en doc_pendientes
             update doc_pendientes_cta_cte dp
                set dp.flag_debhab = lc_flag_debhab_esp,
                    dp.factor      = ln_factor_esp     ,
                    dp.cnta_ctbl   = ln_cnta_ctbl      ,
                    dp.flag_replicacion = '0'
               where (dp.cod_relacion = :new.proveedor_ref ) and
                     (dp.tipo_doc     = :new.tipo_ref     ) and
                     (dp.nro_doc      = :new.nro_ref      ) ;

             RETURN ;

          END IF ;



          if lc_cod_moneda = lc_soles THEN
             ln_importe_soles   := :new.importe ;
             ln_importe_dolares := Round(:new.importe / ln_tasa_cambio,2) ;



             --encontrar estado del documento
             ln_saldo_sol := ln_saldo_sol - ln_importe_soles ;
             ln_saldo_dol := ln_saldo_dol - ln_importe_dolares ;

             if ln_monto_total = ln_saldo_sol then --activo
                lc_flag_estado := '1';
             elsif ln_saldo_sol = 0 then           --pagado totalmente
                lc_flag_estado := '3';
             elsif ln_saldo_sol > 0 then           --pagado parcialmente
                lc_flag_estado := '2';
             end if ;

          elsif  lc_cod_moneda = lc_dolares THEN
             ln_importe_dolares := :new.importe ;
             ln_importe_soles   := Round(:new.importe * ln_tasa_cambio,2) ;

             --diferencia en cambiode documentos
             select Nvl(sldo_sol,0),Nvl(saldo_dol,0) into ln_mont_pend_sol,ln_mont_pend_dol from doc_pendientes_cta_cte
             where (cod_relacion = :new.proveedor_ref ) and
                   (tipo_doc     = :new.tipo_ref     ) and
                   (nro_doc      = :new.nro_ref      ) ;

             ln_monto_sol_dif := Round(ln_mont_pend_dol * ln_tasa_cambio,2) - ln_mont_pend_sol  ;


             --encontrar estado del documento
             ln_saldo_dol := ln_saldo_dol - ln_importe_dolares ;
             ln_saldo_sol := (ln_saldo_sol + ln_monto_sol_dif) - ln_importe_soles ;

             if ln_monto_total = ln_saldo_dol then --activo
                lc_flag_estado := '1';
             elsif ln_saldo_dol = 0 then           --pagado totalmente
                lc_flag_estado := '3';
             elsif ln_saldo_dol > 0 then           --pagado parcialmente
                lc_flag_estado := '2';
             end if ;

          end if ;

          --actualizo cntas x pagar
          /**************************************************************************
              REPLICACION
           **************************************************************************/
           UPDATE cntas_pagar
              SET flag_estado = lc_flag_estado ,
                  saldo_sol = ln_saldo_sol,
                  saldo_dol = ln_saldo_dol,
                  flag_replicacion = '0'
            WHERE (( origen       = :new.origen_ref   ) AND
                   ( cod_relacion = :new.proveedor_ref ) AND
                   ( tipo_doc     = :new.tipo_ref     ) AND
                   ( nro_doc      = :new.nro_ref      ));


       END IF ;
   END IF;



end tia_fin_doc_referencias;
/

prompt
prompt Creating trigger TIA_FIN_RETENCION_IGV_CRT
prompt ==========================================
prompt
CREATE OR REPLACE TRIGGER CANTABRIA.TIA_FIN_RETENCION_IGV_CRT
  after insert on retencion_igv_crt
  for each row
declare
  -- local variables here
  lc_doc_cri      doc_tipo.tipo_doc%type    ;
  ln_factor       doc_tipo.factor%type      ;
  lc_cnta_ctbl    cntbl_cnta.cnta_ctbl%type ;
  lc_soles        moneda.cod_moneda%type    ;
  lc_flag_debhab  cntbl_asiento_det.flag_debhab%type;

begin

--PARAMETROS
select f.doc_ret_igv_crt,f.cnta_cntbl_ret_igv into lc_doc_cri,lc_cnta_ctbl from finparam f where (reckey = '1') ;
--
select l.cod_soles into lc_soles from logparam l where (l.reckey = '1') ;

--FACTOR DE DOCUMENTO
select Nvl(factor,0) into ln_factor from doc_tipo where (tipo_doc = lc_doc_cri) ;

if ln_factor = 0 THEN
   RAISE_APPLICATION_ERROR( -20000,'Factor de Documento '||lc_doc_cri|| 'es igual a 0 debera Colocar alguna valor 1 o -1 ' ) ;
end if ;



if ln_factor = 1 then
   lc_flag_debhab := 'D' ;
else
   lc_flag_debhab := 'H' ;
end if ;

/**********************************************************************************
     REPLICACION
 ***********************************************************************************/
Insert into doc_pendientes_cta_cte
(cod_relacion ,tipo_doc ,nro_doc  ,flag_tabla ,cnta_ctbl ,cod_moneda ,
 flag_debhab  ,sldo_sol ,saldo_dol,fecha_doc  ,factor    ,flag_replicacion )
Values
(:new.proveedor , lc_doc_cri  ,:new.nro_certificado  ,'R',lc_cnta_ctbl  ,lc_soles,
 lc_flag_debhab , :new.saldo_sol ,:new.saldo_dol,:new.fecha_emision,ln_factor ,'0') ;




end TIA_FIN_RETENCION_IGV_CRT;
/

prompt
prompt Creating trigger TIA_FIN_SOLICITUD_GIRO_LIQ_DET
prompt ===============================================
prompt
CREATE OR REPLACE TRIGGER CANTABRIA.TIA_FIN_SOLICITUD_GIRO_LIQ_DET
  after insert on solicitud_giro_liq_det
  for each row


declare
  -- local variables here
  --PRE LIQUIDACION DE ORDEN DE GIRO / FONDO FIJO
  lc_sol_giro        doc_tipo.tipo_doc%type       ;
  ln_monto_total     cntas_pagar.importe_doc%type ;
  ln_saldo_sol       cntas_pagar.importe_doc%type ;
  ln_saldo_dol       cntas_pagar.importe_doc%type ;
  lc_soles           logparam.cod_soles%type      ;
  lc_dolares         logparam.cod_dolares%type    ;
  ln_importe_soles   cntas_pagar.importe_doc%type ;
  ln_importe_dolares cntas_pagar.importe_doc%type ;
  lc_flag_estado     cntas_pagar.flag_estado%type ;
  --ln_mont_pend_sol   cntas_pagar.importe_doc%type ;
  --ln_mont_pend_dol   cntas_pagar.importe_doc%type ;
  --ln_monto_sol_dif   cntas_pagar.importe_doc%type ;
  lc_flag_estado_og  cntas_pagar.flag_estado%type ;
  ln_count           Number                       ;
  lc_flag_ctrl_reg   cntas_pagar.flag_control_reg%type       ;
  lc_flag_debhab_esp doc_pendientes_cta_cte.flag_debhab%type ;
  ln_factor_esp      doc_pendientes_cta_cte.factor%type      ;
  lc_cnta_ctbl       doc_pendientes_cta_cte.cnta_ctbl%type   ;

begin
    If (dbms_reputil.from_remote=true or dbms_snapshot.i_am_a_refresh=true) then
       return;
    End if;

--parametros
select doc_sol_giro into lc_sol_giro from finparam where reckey = '1' ;

select cod_soles,cod_dolares into lc_soles,lc_dolares from logparam where reckey = '1' ;


IF lc_sol_giro = :new.tipo_doc THEN --SOLICITUD DE GIRO (VERIFICAR ESTADO)
   SELECT flag_estado,importe_doc,Nvl(saldo_sol,0),Nvl(saldo_dol,0)
     INTO lc_flag_estado_og,ln_monto_total,ln_saldo_sol , ln_saldo_dol
     FROM solicitud_giro
    WHERE ((cod_relacion  = :new.proveedor  ) AND
           (nro_solicitud = :new.nro_doc   )) ;

   IF lc_flag_estado_og = '2' THEN
      /**Actualiza Contador de Solicitudes Pendientes **/
      /************************************************************
        REPLICACION
      *************************************************************/
      UPDATE maestro_param_autoriz
         SET nro_solicitudes_pend = Nvl(nro_solicitudes_pend,0) + 1 ,flag_replicacion = '0'
       WHERE (cod_relacion = :new.proveedor) ;

      lc_flag_estado  := '3' ;

   ELSE
      lc_flag_estado  := lc_flag_estado_og ;
   END IF ;

   if :new.cod_moneda = lc_soles THEN
      ln_importe_soles   := :new.importe ;
      ln_importe_dolares := Round(:new.importe / :new.tasa_cambio,2) ;

      --encontrar estado del documento
      ln_saldo_sol := ln_saldo_sol - ln_importe_soles ;
      ln_saldo_dol := ln_saldo_dol - ln_importe_dolares ;

   elsif  :new.cod_moneda = lc_dolares THEN
      ln_importe_dolares := :new.importe ;
      ln_importe_soles   := Round(:new.importe * :new.tasa_cambio,2) ;

      --encontrar estado del documento
      ln_saldo_dol := ln_saldo_dol - ln_importe_dolares ;
      ln_saldo_sol := ln_saldo_sol - ln_importe_soles ;
   end if ;


   /**Actualiza Estado **/
   /************************************************************
      REPLICACION
    *************************************************************/

   UPDATE solicitud_giro
      SET flag_estado = lc_flag_estado ,saldo_sol        = ln_saldo_sol ,
          saldo_dol   = ln_saldo_dol   ,flag_replicacion = '0'
    WHERE ((cod_relacion  = :new.proveedor  ) AND
           (nro_solicitud = :new.nro_doc   )) ;



ELSE --documentos x pagar
   select count(*)
     into ln_count
     from cntas_pagar
    where ( cod_relacion = :new.proveedor ) AND
          ( tipo_doc     = :new.tipo_doc  ) AND
          ( nro_doc      = :new.nro_doc   );

   if ln_count = 0 then return; end if;

   select importe_doc,Nvl(saldo_sol,0),Nvl(saldo_dol,0)
     into ln_monto_total,ln_saldo_sol , ln_saldo_dol
     from cntas_pagar
    where ( cod_relacion = :new.proveedor ) AND
          ( tipo_doc     = :new.tipo_doc  ) AND
          ( nro_doc      = :new.nro_doc   );

   if :new.cod_moneda = lc_soles THEN
      ln_importe_soles   := :new.importe ;
      ln_importe_dolares := Round(:new.importe / :new.tasa_cambio,2) ;

      --encontrar estado del documento
      ln_saldo_sol := ln_saldo_sol - ln_importe_soles   ;
      ln_saldo_dol := ln_saldo_dol - ln_importe_dolares ;

      if ln_monto_total = ln_saldo_sol then --activo
         lc_flag_estado := '1';
      elsif ln_saldo_sol = 0 then           --pagado totalmente
         lc_flag_estado := '3';
      elsif ln_saldo_sol > 0 then           --pagado parcialmente
         lc_flag_estado := '2';
      end if ;

   elsif  :new.cod_moneda = lc_dolares THEN
      ln_importe_dolares := :new.importe ;
      ln_importe_soles   := Round(:new.importe * :new.tasa_cambio,2) ;


      --encontrar estado del documento
      ln_saldo_dol := ln_saldo_dol - ln_importe_dolares ;
      ln_saldo_sol := ln_saldo_sol  - ln_importe_soles ;

      if ln_monto_total = ln_saldo_dol then --activo
         lc_flag_estado := '1';
      elsif ln_saldo_dol = 0 then           --pagado totalmente
         lc_flag_estado := '3';
      elsif ln_saldo_dol > 0 then           --pagado parcialmente
         lc_flag_estado := '2';
      end if ;

   end if ;



   --VERIFICAR SI ES TIPO CUENTA CORRIENTE
   select count(*) into ln_count from doc_grupo_relacion dg where (dg.grupo    = 'C2'          ) and
                                                                  (dg.tipo_doc = :new.tipo_doc );

   IF ln_count > 0 AND :new.flag_provisionado = 'D' THEN --NO AFECTARA DOC_PENDIENTES_CTA_CTE
      select cp.flag_control_reg into lc_flag_ctrl_reg
        from cntas_pagar cp
       where (cp.cod_relacion = :new.proveedor ) and
             (cp.tipo_doc     = :new.tipo_doc  ) and
             (cp.nro_doc      = :new.nro_doc   ) ;

      IF lc_flag_ctrl_reg = '1' THEN --invertira condicion de documento

         select dp.flag_debhab,dp.factor into lc_flag_debhab_esp,ln_factor_esp
           from doc_pendientes_cta_cte dp
          where (dp.cod_relacion = :new.proveedor ) and
                (dp.tipo_doc     = :new.tipo_doc  ) and
                (dp.nro_doc      = :new.nro_doc   ) ;

         if lc_flag_debhab_esp = 'H' then
            lc_flag_debhab_esp := 'D' ;
         end if ;

         if ln_factor_esp = '-1' then
            ln_factor_esp := '1' ;
         end if ;


         /*************************************************************************
          REPLICACION
         *************************************************************************/
         update cntas_pagar cp set cp.flag_caja_bancos = '1' ,cp.flag_replicacion = '0'
          where (cp.cod_relacion = :new.proveedor ) and
                (cp.tipo_doc     = :new.tipo_doc  ) and
                (cp.nro_doc      = :new.nro_doc   ) ;



         update doc_pendientes_cta_cte dp set dp.flag_debhab = lc_flag_debhab_esp,
                                              dp.factor      = ln_factor_esp     ,
                                              dp.cnta_ctbl   = lc_cnta_ctbl      ,
                                              dp.flag_replicacion = '0'
          where (dp.cod_relacion = :new.proveedor ) and
                (dp.tipo_doc     = :new.tipo_doc  ) and
                (dp.nro_doc      = :new.nro_doc   ) ;

         RETURN ;

      END IF ;

   END IF ;

   --actualizo cntas x pagar
   /************************************************************
    REPLICACION
    *************************************************************/
   UPDATE cntas_pagar
      SET flag_estado = lc_flag_estado ,saldo_sol = ln_saldo_sol, saldo_dol = ln_saldo_dol ,flag_replicacion = '0'
    WHERE (( cod_relacion = :new.proveedor ) AND
           ( tipo_doc     = :new.tipo_doc  ) AND
           ( nro_doc      = :new.nro_doc   ));

     IF ln_saldo_sol=0 OR ln_saldo_dol=0 THEN
        ln_count := usf_fin_cierra_control_doc(:new.proveedor, :new.tipo_doc, :new.nro_doc);
     END IF ;

END IF ;


end TIA_FIN_SOLICITUD_GIRO_LIQ_DET;
/

