prompt
prompt Creating trigger TIA_MTT_PD_OT_DET
prompt ==================================
prompt
CREATE OR REPLACE TRIGGER CANTABRIA.tia_mtt_pd_ot_det
  after insert on pd_ot_det
  for each row

DECLARE
  -- local variables here
  Cursor c_oper is
   SELECT flag_estado, cant_real
     FROM operaciones
    WHERE (tipo_orden = (select doc_ot from prod_param where reckey = '1' )  ) AND
          (nro_orden  = :new.nro_orden )
   ORDER BY nro_operacion ;

 lc_flag_estado    Char (1) ;
 lc_flag_estado_op Char (1) ;
 ln_count          Number   ;
 lb_flag           Boolean  ;
 lb_flag_proy      Boolean  ;
 ls_flag_est_old   Char(1)  ;
 ld_fecha_operac   date ;
 ln_flag0          Number ;
 ln_flag1          Number ;
 ln_flag2          Number ;
 ln_flag3          Number ;
 ls_flag_externo_n ejecutor.flag_externo%type ;

BEGIN
  -- Edgar Morante Miercoles 10Jul2002, replicacion
  IF (dbms_reputil.from_remote=true or dbms_snapshot.i_am_a_refresh=true) then
     return;
  END IF;

 lb_flag      := FALSE ;
 lb_flag_proy := FALSE ;

 SELECT o.flag_estado, o.fec_inicio
   INTO ls_flag_est_old, ld_fecha_operac
   FROM operaciones o
  WHERE o.oper_sec = :new.oper_sec ;

 IF (:new.cod_maquina IS NOT NULL AND :new.ind_act_maq > 0) THEN
    UPDATE maquina m
       SET m.ind_act_acumulada = NVL(m.ind_act_acumulada,0) + :new.ind_act_maq
     WHERE m.cod_maquina = :new.cod_maquina ;
 END IF ;

 -- Asignando fecha de parte diario si operacion es proyectada
 IF ls_flag_est_old='3' THEN
    ld_fecha_operac := :new.hora_inicio ;
 END IF ;

 --Actualizar Operacion Cerrada
 IF :new.flag_terminado = '1' THEN
    -- Verifica fecha de inicio de labor
    --COnsiderar HORAS_INCIDEN?
    UPDATE operaciones
      --SET cant_real     = Nvl(cant_real,0)     + NVL(:new.cant_labor,0) , --acumula cantidad de labor de operacion
      SET cant_real     = Nvl(cant_real,0)     + (NVL(:new.cant_labor,0) - NVL(:new.horas_inciden,0)) , --acumula cantidad de labor de operacion
          flag_estado   = '2'                                           , --terminado
          fec_inicio    = ld_fecha_operac                               , --fecha inicio
          fec_fin       = :new.hora_fin                                 , --fecha final de la operacion
          avance_actual = Nvl(avance_actual,0) + NVL(:new.cant_avance,0),  --cantidad
          flag_replicacion = '0'
    WHERE (oper_sec = :new.oper_sec ) ;

   /*
   -- El trigger de la operacion ya lo hace. No repetir.
   -- Actualiza articulo_mov_proy (cierra articulos para no ser despachados)
   UPDATE articulo_mov_proy amp
      SET amp.flag_estado = '2',
          flag_replicacion = '0'
    WHERE amp.oper_sec = :new.oper_sec and
          amp.flag_estado in ('1','3') and
          amp.tipo_doc = (select doc_ot from prod_param where reckey = '1' ) ;
    */

   --Actualiza Maquina
   IF :new.cod_maquina is not null THEN
      -- IF DE PRUEBA 15 / 4 / 2005
      if Nvl(:new.ind_act_maq,0) > 0 then

          UPDATE maquina
             SET ind_act_acumulada = :new.ind_act_maq,
                 flag_replicacion = '0'
           WHERE (cod_maquina = :new.cod_maquina) ;

      end if;
   END IF;

 ELSE
    /*verificar que no este cerrado ar*/
    select count(*)
      into ln_count
      from operaciones
     where (oper_sec    = :new.oper_sec) and
           (flag_estado = '2'          ) ;


    IF ln_count > 0 THEN --SE ENCUENTRA CERRADO
       RAISE_APPLICATION_ERROR( -20001, 'Operacion cerrada '||:new.oper_sec||', '|| 'Primero debe abrir la operacion' ) ;
       lc_flag_estado_op := '2' ; --SIGUE CERRADO
    ELSE
       lc_flag_estado_op := '1' ; --SE MANTIENE ACTIVO
    END IF;


    --Actualizar Operacion Proyectada o Activa
    UPDATE operaciones
       --SET cant_real     = Nvl(cant_real,0)     + NVL(:new.cant_labor,0) ,  --ACUMULA CANTIDAD DE LABOR
           SET cant_real     = Nvl(cant_real,0)     + (NVL(:new.cant_labor,0)-nvl(:new.horas_inciden,0)) ,  --ACUMULA CANTIDAD DE LABOR
           avance_actual = Nvl(avance_actual,0) + NVL(:new.cant_avance,0),  --ACUMULA AVANCE
           flag_estado   = lc_flag_estado_op                             ,  --ESTADO DE LA OPERACION
           fec_inicio    = ld_fecha_operac                               , --fecha inicio
           flag_replicacion = '0'                                        , -- replicacion
           fec_fin       = NULL                                          --FEC FINAL NULA
     WHERE (oper_sec = :new.oper_sec ) ;


     IF :new.cod_maquina is not null and :new.ind_act_maq > 0 THEN
        UPDATE maquina
           SET ind_act_acumulada = Nvl(ind_act_acumulada,0) + NVL(:new.ind_act_maq,0),
               flag_replicacion  = '0'
         WHERE (cod_maquina = :new.cod_maquina) ;
     END IF;


 END IF ;

--ENCONTRAR ESTADO DE LA OT
--estados de la ot
--0 = anulado ,1 = activo
--2 = cerrado ,3 = proyectado

SELECT count(decode(flag_estado,'0',1,0)),
       count(decode(flag_estado,'1',1,0)),
       count(decode(flag_estado,'2',1,0)),
       count(decode(flag_estado,'3',1,0))
  INTO ln_flag0, ln_flag1, ln_flag2, ln_flag3
  FROM operaciones o
 WHERE (tipo_orden = (select doc_ot from prod_param where reckey = '1' )  ) AND
       (nro_orden  = :new.nro_orden ) ;

-- Operacion anulada
IF ln_flag0>0 AND ln_flag1=0 AND ln_flag2=0 AND ln_flag3=0 THEN
   lc_flag_estado:='0' ;
-- Operacion cerrada
ELSIF ln_flag2>0 AND ln_flag1=0 AND ln_flag3=0 THEN
   lc_flag_estado:='2' ;
ELSIF ln_flag3>0 AND ln_flag1=0 THEN
   lc_flag_estado:='3' ;
ELSE
   lc_flag_estado:='1' ;
END IF ;


FOR rc_oper in c_oper LOOP
    IF rc_oper.flag_estado = '2' THEN --Cerrada
       if lb_flag_proy then
          lc_flag_estado := '1' ; --se activa automaticamente la ot y sale del bucle
          EXIT;
       else
          lc_flag_estado := '2' ; --hasta este punto ot se encontraria cerrada
          lb_flag := TRUE ; --FLAG PARA CONTROLAR ESTADO DE LA OT
       end if ;
    ELSIF rc_oper.flag_estado = '1' THEN --Activa
       lc_flag_estado := '1' ; --se activa automaticamente la ot y sale del bucle
       EXIT;
    ELSIF rc_oper.flag_estado = '3' THEN --Planeado
        IF lb_flag THEN
           lc_flag_estado := '1' ; --se activa automaticamente la ot y sale del bucle
           EXIT;
        ELSE
           lc_flag_estado := '3' ; --proyectado sigue busqueda
           lb_flag_proy := TRUE ; --FLAG PARA CONTROLAR ESTADO DE LA OT
        END IF;
    ELSIF rc_oper.flag_estado = '0' THEN --Anulado
        lc_flag_estado := '1' ;
     END IF;
END LOOP;

-- Verificando si es ejecutor EXTERNO o no?
SELECT flag_externo
INTO ls_flag_externo_n
FROM ejecutor e
WHERE e.cod_ejecutor=:new.cod_ejecutor ;

/**Actualiza Estado de Orden de Trabajo**/
IF ls_flag_externo_n = '0' THEN
    UPDATE orden_trabajo ot
       SET flag_estado = lc_flag_estado,
           ot.costo_ejecutado = NVL(ot.costo_ejecutado,0) + NVL(:new.cant_labor,0)*NVL(:new.costo_labor,0),
           flag_replicacion = '0'
     WHERE (nro_orden = :new.nro_orden );
ELSE
    UPDATE orden_trabajo ot
       SET flag_estado = lc_flag_estado,
           ot.costo_ejecutado = NVL(ot.costo_ejecutado,0) + NVL(:new.cant_labor,0)*NVL(:new.costo_labor,0),
           flag_replicacion = '0'
     WHERE (nro_orden = :new.nro_orden );
END IF ;

/*verifica si existe ot en correlativo*/
select count(*) into ln_count from campo_ciclo where nro_orden = :new.nro_orden  ;

IF ln_count > 0  THEN
   IF lc_flag_estado = '1' THEN --activa
      update campo_ciclo
         set flag_estado = '1', --abierto
             flag_replicacion = '0'
       where nro_orden = :new.nro_orden;

   ELSIF lc_flag_estado = '2' THEN --cerrada
      update campo_ciclo
         set flag_estado = '0', --cerrrado
             flag_replicacion = '0'
       where nro_orden = :new.nro_orden ;

   ELSIF lc_flag_estado = '3' THEN --planeada
      update campo_ciclo
         set flag_estado = '2',  --en proyecto
             flag_replicacion = '0'
       where nro_orden = :new.nro_orden ;
   END IF ;
END IF ;


end tia_mtt_pd_ot_det;
/

