prompt
prompt Creating trigger TIA_OPE_ORDEN_TRABAJO
prompt ======================================
prompt
CREATE OR REPLACE TRIGGER CANTABRIA.TIA_OPE_ORDEN_TRABAJO
  after insert on orden_trabajo
  for each row
declare
  -- local variables here
  ls_flag_cenbef       logparam.flag_centro_benef%TYPE;
BEGIN

  -- Verificando flag_estado de la OT
  IF :NEW.flag_estado IS NULL THEN
     RAISE_APPLICATION_ERROR(-20000, 'La OT no puede tener flag_estado nulo');
  END IF;

  SELECT NVL(flag_centro_benef, '0')
    INTO ls_flag_cenbef
    FROM logparam
   WHERE reckey = '1' ;

  -- Verificar Centro de Beneficio
  if :new.centro_benef is NULL AND ls_flag_cenbef = '1' then
     RAISE_APPLICATION_ERROR(-20000, 'La OPERACION debe tener obligatoriamente un Centro de Beneficio');
  end if;

  IF Not (:new.nro_solicitud is null ) THEN
     --ACTUALIZA ESTADO DE LA SOLICITUD DE TRABAJO ACEPTADA
     UPDATE solicitud_ot
        SET flag_estado = '2',
            flag_replicacion = '0'
      WHERE nro_solicitud = :new.nro_solicitud ;
  END IF ;

  -- Actualizar Programa Ciclico de Mantenimiento
  if (:new.PROG_MNT is not null or trim(:new.PROG_MNT)  <> '') and
     :new.flag_estado <> '0' then

     if NVL(:new.MNT_UND_ACT_REAL,0) <> 0 then

        IF :new.FEC_INICIO is null then
           RAISE_APPLICATION_ERROR(-20000, 'LA FECHA DE INICIO DE LA OT NO PUEDE SER NULA');
        end if;

        update mt_prog_ciclo_mantto t
           set ULTIMO_MNT = NVL(:new.MNT_UND_ACT_REAL,0),
               t.Fecha_Ultimo_Mnt = :new.FEC_INICIO,
               flag_replicacion = '0'
         where PROG_MNT = :new.PROG_MNT;
     end if;
  end if;

end TIA_OPE_ORDEN_TRABAJO;
/

prompt
prompt Creating trigger TIA_OPE_PD_OT_ASISTENCIA
prompt =========================================
prompt
CREATE OR REPLACE TRIGGER CANTABRIA.TIA_OPE_PD_OT_ASISTENCIA
  after insert on pd_ot_asistencia
  for each row
declare
  -- local variables here
  ln_costo_x_trab_x_item Number (13,2)    ;
  ld_fecha               pd_ot.fecha%type ;
  ln_dol_prom            calendario.vta_dol_prom%type ;
  lc_und_lb              labor.und%type               ;
  lc_und_hr              labor.und%type               ;
  lc_flag_maq_mo         labor.flag_maq_mo%type       ;
  ln_cant_lab            pd_ot_det.cant_labor%type    ;
  ln_costo_labor         pd_ot_det.costo_labor%type   ;
  ln_costo_unit_lab      Number (13,4)                ;


begin

--datos de labor
select lb.und ,lb.flag_maq_mo into lc_und_lb ,lc_flag_maq_mo from pd_ot_det pod,labor lb
 where (pod.cod_labor = lb.cod_labor  ) and
       (pod.nro_parte = :new.no_parte ) and
       (pod.nro_item  = :new.nro_item ) ;

--parametros de und
select pp.und_hr into lc_und_hr from prod_param pp where pp.reckey = '1' ;


IF (lc_flag_maq_mo = 'O' and lc_und_lb = lc_und_hr) THEN
   --RECUPERO tasa de cambio de acuerdo a cabecera
   select Nvl(c.vta_dol_prom,0.000) into ln_dol_prom
     from calendario c
    where to_char(c.fecha,'yyyymmdd') = (select to_char(pd.fecha,'yyyymmdd')
                                           from pd_ot pd
                                          where pd.nro_parte = :new.no_parte );

   if ln_dol_prom = 0 then
      raise_application_error(-20000,'No Existe tasa de cambio para fecha de parte diario
Verifique!') ;
   end if ;

   ln_costo_x_trab_x_item := (nvl(:new.nro_horas,0) * nvl(:new.costo_horas,0)) *
nvl(:new.factor,0) ;


   --convertir a dolares
   if Nvl(ln_costo_x_trab_x_item,0) > 0 then --convertir a dolares
      ln_costo_x_trab_x_item := Round(ln_costo_x_trab_x_item / ln_dol_prom,2) ;
   end if ;


   --recuperar cantidad de la labor de pd_ot_det
   select nvl(pdo.cant_labor,0),Nvl(pdo.costo_labor,0) into ln_cant_lab,ln_costo_labor
     from pd_ot_det pdo  where (pdo.nro_parte = :new.no_parte ) and
                               (pdo.nro_item  = :new.nro_item ) ;

    ln_cant_lab := (Nvl(ln_cant_lab,0) - :new.nro_horas ) ;






    --promedio de costo unitario
    ln_costo_unit_lab := round((((ln_costo_labor * ln_cant_lab ) + ln_costo_x_trab_x_item
) / (ln_cant_lab + :new.nro_horas)),4) ;



   --Actualiza parte diario de ot (detalle)
   update pd_ot_det pdo
      set pdo.costo_labor = ln_costo_unit_lab
    where (pdo.nro_parte = :new.no_parte ) and
          (pdo.nro_item  = :new.nro_item ) ;



END IF ;



end TIA_OPE_PD_OT_ASISTENCIA;
/

prompt
prompt Creating trigger TIA_OPERACIONES
prompt ================================
prompt
CREATE OR REPLACE TRIGGER CANTABRIA.TIA_OPERACIONES
  after insert on operaciones
  for each row

declare
  -- local variables here
  ld_fec_estimada       date ;
  ld_fec_inicio         date ;
  ld_fecha_fin_estimada date ;
  ld_fecha_ult_pd       date ;
  ls_flag_cenbef        logparam.flag_centro_benef%TYPE;

BEGIN
  -- Edgar Morante Miercoles 10Jul2002, replicacion
  IF (dbms_reputil.from_remote=true or dbms_snapshot.i_am_a_refresh=true) then
     return;
  END IF;

  SELECT NVL(flag_centro_benef, '0')
    INTO ls_flag_cenbef
    FROM logparam
   WHERE reckey = '1' ;

  -- Verificar Centro de Beneficio
  if :new.centro_benef is NULL AND ls_flag_cenbef = '1' then
     RAISE_APPLICATION_ERROR(-20000, 'Las operaciones debe tener obligatoriamente un Centro de Beneficio');
  end if;

-- Comentado por mmoran
 SELECT fec_estimada, fec_inicio, fecha_fin_estimada, fecha_ult_pd
   INTO ld_fec_estimada, ld_fec_inicio, ld_fecha_fin_estimada, ld_fecha_ult_pd
   FROM orden_trabajo ot
  WHERE ot.nro_orden = :new.nro_orden ;

 IF :new.fec_inicio_est < ld_fec_estimada THEN
    ld_fec_estimada := :new.fec_inicio_est ;
 END IF ;
 IF :new.fec_inicio < ld_fec_inicio THEN
    ld_fec_inicio := :new.fec_inicio ;
 END IF ;
 IF :new.fec_inicio > ld_fecha_fin_estimada THEN
    ld_fecha_fin_estimada := :new.fec_inicio ;
 END IF ;

 UPDATE orden_trabajo ot
    SET ot.fec_estimada = ld_fec_estimada,
        ot.fec_inicio = ld_fec_inicio,
        ot.fecha_fin_estimada = ld_fecha_fin_estimada,
        ot.costo_estimado = NVL(ot.costo_estimado,0) + NVL(:new.cant_proyect,0) * NVL(:new.costo_unit,0)
   WHERE ot.nro_orden = :new.nro_orden ;

END TIA_OPERACIONES;
/

prompt
prompt Creating trigger TIA_OT_OTROS_GASTOS
prompt ====================================
prompt
CREATE OR REPLACE TRIGGER CANTABRIA.TIA_OT_OTROS_GASTOS
  after insert on ot_otros_gastos
  for each row

DECLARE

-- local variables here
ln_importe_doc     cntas_pagar.importe_doc%type ;

BEGIN

-- Busca costo en cuentas por pagar
SELECT decode( cp.cod_moneda, (SELECT l.cod_dolares FROM logparam l WHERE reckey='1'),
               cp.importe_doc, cp.importe_doc / cp.tasa_cambio )
  INTO ln_importe_doc
  FROM cntas_pagar cp
 WHERE cp.cod_relacion = :new.cod_relacion
   AND cp.tipo_doc     = :new.tipo_doc
   AND cp.nro_doc      = :new.nro_doc ;

-- Actualiza costo en orden de trabajo
UPDATE orden_trabajo ot
   SET ot.costo_estimado = NVL(ot.costo_estimado,0) + ROUND(ln_importe_doc,2)
 WHERE ot.nro_orden = :new.nro_orden ;

END TIA_OT_OTROS_GASTOS;
/

prompt
prompt Creating trigger TIA_PD_OT_INCIDENCIAS
prompt ======================================
prompt
CREATE OR REPLACE TRIGGER CANTABRIA.TIA_PD_OT_INCIDENCIAS
  after insert on pd_ot_incidencias
  for each row

declare
 -- local variables here
  ln_horas number(4,2);            --horas de incidencias
  ln_cant_labor number(4,2);       --horas trabajo de pd_ot_det
  ln_horas_inciden number(4,2);    --horas de Incidencia de pd_ot_det
  ls_flag  char(1);                --flag de estado de operaciones
  ln_error_max_redond number(3,2); --Error maximo por redondeo

begin
ln_error_max_redond := 0.01;
ln_horas := ( :new.fecha_fin - :new.fecha_inicio) * 24;

select o.flag_estado,pod.cant_labor,pod.horas_inciden
  into ls_flag,ln_cant_labor,ln_horas_inciden
  from operaciones o,pd_ot_det pod
 where pod.nro_parte = :new.nro_parte and pod.nro_item = :new.nro_item
   and pod.oper_sec = o.oper_sec;

 --comprobacion de de las horas inciden no pueden ser mayores a
 --horas de trabajo

 ln_horas_inciden := nvl(ln_horas_inciden,0);

 ln_horas_inciden := ln_horas_inciden + ln_horas;

 if ln_cant_labor < ln_horas_inciden  then
    if ln_horas_inciden <= ln_cant_labor + ln_error_max_redond then
       ln_horas_inciden := ln_cant_labor;
    else
        RAISE_APPLICATION_ERROR( -20000, ' La cantidad de Horas de Incidencia no pueden ser mayores a las horas de labor '|| ln_cant_labor ||'<'|| ln_horas_inciden) ;
        return;
    end if;
 end if;

 --revisando el flag de estado de operaciones

 if ls_flag = '1' then
   update pd_ot_det
      set horas_inciden = ln_horas_inciden
    where nro_parte = :new.nro_parte and nro_item = :new.nro_item ;
 else
   RAISE_APPLICATION_ERROR( -20000, 'OperSec no esta Activo , No se puede modificar las horas de Incidencias ' ) ;
   return;
 end if;

end TIA_PD_OT_INCIDENCIAS;
/

