prompt
prompt Creating trigger TIB_ALM_ARTICULO
prompt =================================
prompt
CREATE OR REPLACE TRIGGER CANTABRIA.tib_alm_articulo
  before insert on articulo
  for each row
declare
  -- local variables here
begin
  if upper(ORA_LOGIN_USER) = 'REPP5' then return; end if;

  if :new.flag_inventariable is null then :new.flag_inventariable := '0'; end if;
  if :new.costo_ult_compra   is null then :new.costo_ult_compra   := 0;   end if;
  if :new.SLDO_TOTAL         is null then :new.SLDO_TOTAL         := 0;   end if;
  if :new.SLDO_POR_LLEGAR    is null then :new.SLDO_POR_LLEGAR    := 0;   end if;
  if :new.SLDO_SOLICITADO    is null then :new.SLDO_SOLICITADO    := 0;   end if;
  if :new.SLDO_CONSIGNACION  is null then :new.SLDO_CONSIGNACION  := 0;   end if;
  if :new.SLDO_TOTAL_UND2    is null then :new.SLDO_TOTAL_UND2    := 0;   end if;
  if :new.SLDO_RESERVADO     is null then :new.SLDO_RESERVADO     := 0;   end if;

  If :new.costo_ult_compra = 0 and :new.flag_inventariable = '1' then
     RAISE_APPLICATION_ERROR(-20000, 'El precio de ultima compra del Articulo ' || trim(:new.cod_art) || ' no puede ser cero');
  end if;

  IF :new.costo_ult_compra > 0 THEN
     UPDATE articulo_almacen aa
        SET costo_ult_compra = :new.costo_ult_compra
      WHERE aa.cod_art = :new.cod_art
        AND NVL(aa.costo_ult_compra,0) = 0 ;
  END IF ;



  --====================================================================
  -- Debo Validar que el saldo reservado no sea mayor que el saldo total
  --====================================================================
  if :new.sldo_reservado > :new.sldo_total then
     RAISE_APPLICATION_ERROR(-20000, 'No saldo reservado no puede ser mayor '
                     || 'que el saldo total'
                     || chr(13) || 'Cod Art: ' || :new.cod_art);
  end if;

end tib_alm_Articulo;
/

