prompt Creating trigger TIB_CNTAS_COBRAR
prompt =================================
prompt
CREATE OR REPLACE TRIGGER CANTABRIA.TIB_CNTAS_COBRAR
  before insert
  on cntas_cobrar
  for each row
declare
  -- local variables here
begin
  -- Valido la creacio de los documentos electronicos
  if :new.tipo_doc = 'BVC' then
     if substr(:new.nro_doc, 1, 1) in ('F', 'B') then
        if substr(:new.nro_doc, 1, 1) = 'F' then
           RAISE_APPLICATION_ERROR(-20000, 'Error en la generación del comprobante electronico, '
                                        || 'una BOLETA DE VENTA solo puede aceptar series que comiencen con la letra "B"'
                                        || chr(13) || 'Serie ingresada: ' || PKG_FACT_ELECTRONICA.of_get_serie(:new.nro_doc));
        end if;
     end if;
  elsif :new.tipo_doc = 'FAC' then
     if substr(:new.nro_doc, 1, 1) in ('F', 'B') then
        if substr(:new.nro_doc, 1, 1) = 'B' then
           RAISE_APPLICATION_ERROR(-20000, 'Error en la generación del comprobante electronico, '
                                        || 'una FACTURA solo puede aceptar series que comiencen con la letra "f"'
                                        || chr(13) || 'Serie ingresada: ' || PKG_FACT_ELECTRONICA.of_get_serie(:new.nro_doc));
        end if;
     end if;
  end if;

  :new.full_nro_doc := PKG_FACT_ELECTRONICA.of_get_full_nro(:new.nro_doc);
end TIB_CNTAS_COBRAR;
/

