prompt
prompt Creating trigger TIB_FL_VENTAS
prompt ==============================
prompt
CREATE OR REPLACE TRIGGER CANTABRIA.tib_fl_ventas
  before insert on fl_venta
  for each row
declare
  -- local variables here
  ln_mes 		number;
  ls_nave   tg_naves.nave%TYPE;
  ln_pesca  fl_pesca_proy.pesca_real%TYPE;

begin
	if :new.cantidad_real is null then
  	:new.cantidad_real := 0;
  end if;

	if :new.cantidad_estimada is null then
  	:new.cantidad_estimada := 0;
  end if;

	if :new.cantidad_castigada is null then
  	:new.cantidad_castigada := 0;
  end if;

	if :new.cantidad_declarada is null then
  	:new.cantidad_declarada := 0;
  end if;

  if :new.parte_pesca is null then
  	return;
  end if;

  ln_pesca := :new.cantidad_real - :new.cantidad_castigada;

  select to_number( to_char(flpp.fecha_hora_arribo, 'mm') ), flpp.nave_real
  	into ln_mes, ls_nave
  from 	fl_parte_de_pesca flpp
  where flpp.parte_pesca = :new.parte_pesca;


  update fl_pesca_proy flpy
 		set flpy.pesca_real = nvl(flpy.pesca_real,0) + ln_pesca,
        flag_replicacion = '0'
  where flpy.mes = ln_mes
  	and flpy.nave = ls_nave;

end tib_fl_ventas;
/

