prompt
prompt Creating trigger TIB_LIQUIDACION_BENEF_DET
prompt ==========================================
prompt
CREATE OR REPLACE TRIGGER CANTABRIA.tib_liquidacion_benef_det
  before insert on liquidacion_benef_det
  for each row
declare
  -- local variables here
  ls_origen          liquidacion_benef.cod_origen%TYPE;
  ld_fec_cese        liquidacion_benef.fec_salida%TYPE;
  ln_year            presupuesto_ejec.ano%TYPE;
  ls_obs             presupuesto_ejec.descripcion%TYPE;
  ls_cod_usr         liquidacion_benef.cod_usr%TYPE;
  ls_tipo_trabaj     maestro.tipo_trabajador%TYPE;

  ln_tasa_cambio     calendario.vta_dol_prom%TYPE;
  ln_imp_dol         presupuesto_ejec.importe%TYPE;
  ls_doc_lbs         lbs_param.doc_lbs%TYPE;
begin

  select doc_lbs
    into ls_doc_lbs
    from lbs_param
   where reckey = '1';

  if :new.flag_titulo_lbs in ('2', '3', '4') then

     select lb.cod_origen, lb.fec_registro, substr(lb.obs, 1, 100), lb.cod_usr,
            m.tipo_trabajador
       into ls_origen, ld_fec_cese, ls_obs, ls_cod_usr,
            ls_tipo_trabaj
       from liquidacion_benef lb,
            maestro           m
      where lb.cod_trabajador  = m.cod_trabajador
        and lb.nro_liquidacion = :new.nro_liquidacion;

     if :new.flag_titulo_lbs = '2' then
        ls_obs := substr('GRATIFICACION TRUNCA ' || ls_obs,1, 100);
     elsif :new.flag_titulo_lbs = '3' then
        ls_obs := substr('CTS TRUNCA ' || ls_obs,1, 100);
     elsif :new.flag_titulo_lbs = '4' then
        ls_obs := substr('VACACIONES TRUNCA ' || ls_obs,1, 100);
     end if;

     ln_year :=to_number(to_char(ld_fec_cese, 'yyyy'));
     ln_tasa_cambio := usf_fin_tasa_cambio(ld_fec_cese) ;

     ln_imp_dol := :new.importe / ln_tasa_cambio * -1;

     insert into presupuesto_ejec(
            cod_origen, ano, cencos, cnta_prsp, fecha, descripcion, importe, origen_ref,
            tipo_doc_ref, nro_doc_ref, item_ref, cod_usr, tipo_trabajador)
     values(
            ls_origen, ln_year, :new.cencos, :new.cnta_prsp, ld_fec_cese, ls_obs, ln_imp_dol, ls_origen,
            ls_doc_lbs, :new.nro_liquidacion, :new.nro_item, ls_cod_usr, ls_tipo_trabaj);


  end if;
end tib_liquidacion_benef_det;
/

