prompt
prompt Creating trigger TIB_OPE_PD_OT_DET
prompt ==================================
prompt
CREATE OR REPLACE TRIGGER CANTABRIA.TIB_OPE_PD_OT_DET
  before insert on pd_ot_det
  for each row
declare
  -- local variables here
  --variables
  ln_tasa_cambio   calendario.vnt_dol_libre%type      ;
  lc_dolares       moneda.cod_moneda%type             ;
  lc_und_lb        labor.cod_labor%type ;
  lc_und_hr        labor.cod_labor%type ;
  lc_flag_maq_mo   labor.und%type       ;
  ln_costo_unit_lb labor_ejecutor.costo_unitario%type ;
  lc_moneda_lb     moneda.cod_moneda%type             ;
  ln_costo_labor   Number  (13,2)                     ;
  lb_mod           Boolean                            ;
  ld_fecha         Date                               ;
  lc_tipo_doc      doc_tipo.tipo_doc%type             ;

begin

--******************************
--Proceso de Costo de la labor
--******************************
--fecha de cabecera de parte diario
select fecha into ld_fecha from pd_ot po where po.nro_parte = :new.nro_parte ;


-- Recuperacion de tipo de documento
SELECT l.doc_ot INTO lc_tipo_doc FROM logparam l WHERE l.reckey='1' ;
-- ojo, revisar este caso Jhonny, porque viene mal asignado (MM)
if :new.tipo_doc <> lc_tipo_doc THEN
   :new.tipo_doc := lc_tipo_doc ;
end if;


--recuperacion de la labor
select und,flag_maq_mo into lc_und_lb,lc_flag_maq_mo from labor
 where (cod_labor = :new.cod_labor ) ;

--parametros
select pp.und_hr into lc_und_hr from prod_param pp where reckey = '1' ;

select l.cod_dolares into lc_dolares from logparam l where reckey = '1' ;

--tipo de cambio
ln_tasa_cambio := usf_fin_tasa_cambio(ld_fecha) ;



--costo de maestro de labor ejecutor y moneda
select Nvl(le.costo_unitario,0) ,le.cod_moneda into ln_costo_unit_lb,lc_moneda_lb from labor_ejecutor le
 where (le.cod_labor    = :new.cod_labor    ) and
       (le.cod_ejecutor = :new.cod_ejecutor ) ;

if (lc_flag_maq_mo = 'M' AND lc_und_lb = lc_und_hr) then --LABOR MECANIZADA Y CALCULANDO HRS
   if lc_moneda_lb = lc_dolares then
      ln_costo_labor := Round(ln_costo_unit_lb,4) ;
      lb_mod := true ;
   else --convertir a dolares
      ln_costo_labor := Round(ln_costo_unit_lb / ln_tasa_cambio,4) ;
      lb_mod := true ;
   end if  ;
elsif (lc_flag_maq_mo = 'O' AND lc_und_lb = lc_und_hr) then --MANO DE OBRA Y CALCULANDO HRS
   --SE ACTUALIZA EN TRIGGER DE PD_OT_ASISTENCIA
   lb_mod         := false ;
elsif  (lc_und_lb <> lc_und_hr) then --LABOR UNIDAD NO SE MIDE EN HRS
   if lc_moneda_lb = lc_dolares then
      ln_costo_labor := Round(ln_costo_unit_lb,4) ;
      lb_mod := true ;
   else --convertir a dolares
      ln_costo_labor := Round(ln_costo_unit_lb / ln_tasa_cambio,4) ;
      lb_mod := true ;
   end if  ;
end if ;


if lb_mod then --actualiza costo labor
   :new.costo_labor := ln_costo_labor ;
end if;

end TIB_OPE_PD_OT_DET;
/

