prompt Creating trigger TIB_ORDEN_SERVICIO
prompt ===================================
prompt
CREATE OR REPLACE TRIGGER CANTABRIA.TIB_ORDEN_SERVICIO
  before insert on orden_servicio
  for each row

declare
  -- local variables here
begin
    -- Edgar Morante Miercoles 10Jul2002, replicacion
  If (dbms_reputil.from_remote=true or dbms_snapshot.i_am_a_refresh=true) then
     return;
  end if;

  --==============================================================
  -- Si el movimiento esta anulado o pendiente simplemente retorno
  --==============================================================
  if :new.flag_estado in ('0', '3') then return; end if;


  -- Actualiza flag de estado de la sol. Serv.
  IF :new.nro_sol_serv IS NOT NULL then  -- En transito

  /*****************************************************
  **** REPLICACION
  *****************************************************/
     Update sol_serv ss
        set flag_estado = '3',
            flag_replicacion = '0'
      where ss.cod_origen   = :new.sol_origen
        and ss.nro_sol_serv = :new.nro_sol_serv;
  /*****************************************************/
  END IF;

end TIB_ORDEN_SERVICIO;
/

prompt
prompt Creating trigger TIB_ORDEN_SERVICIO_DET
prompt =======================================
prompt
CREATE OR REPLACE TRIGGER CANTABRIA.TIB_ORDEN_SERVICIO_DET
  before insert on orden_servicio_det
  for each row
declare
  -- local variables here
  ln_ano               presupuesto_partida.ano%type;
  ls_dolares           logparam.cod_dolares%type;
  ls_doc_os            logparam.doc_os%type;
  ls_moneda            orden_servicio.cod_moneda%type;
  ls_ori_sol           orden_servicio.sol_origen%type;
  ls_nro_sol           orden_servicio.nro_sol_serv%type;
  ln_precio            number;
  ln_total             orden_servicio.monto_total%type;
  ls_proveedor         proveedor.proveedor%type;
  ls_cod_usr           usuario.cod_usr%TYPE;
  ls_flag_cenbef       logparam.flag_centro_benef%TYPE;
  ls_und               labor.und%type ;

  --Parametros para la afectacion del IGV
  ls_flag_prsp_igv     origen.flag_prsp_igv%TYPE;
  ls_cencos_igv        origen.cencos_igv%type;
  ls_cnta_prsp_igv     origen.cnta_prsp_igv%TYPE;
  ln_importe           presupuesto_ejec.importe%TYPE;
  ls_desc_pto          presupuesto_ejec.descripcion%TYPE;
  ls_IGV               logparam.cod_igv%TYPE;


begin

  if :new.nro_os is null then
     RAISE_APPLICATION_ERROR(-20000, 'No has especificado un nro de Orden de Servicio');
  end if;

  if :new.importe   is null then :new.importe   := 0; end if;
  if :new.decuento  is null then :new.decuento  := 0; end if;
  if :new.impuesto  is null then :new.impuesto  := 0; end if;
  if :new.impuesto2 is null then :new.impuesto2 := 0; end if;

  if :new.servicio is null then
     RAISE_APPLICATION_ERROR(-20000, 'No puede ingresar un detalle de OS sin tipo de servicio');
  end if;

  --==============================================================
  -- Si el movimiento esta anulado o pendiente simplemente retorno
  --==============================================================
  if :new.flag_estado in ('0', '3') then return; end if;

  SELECT cod_dolares, doc_os, NVL(flag_centro_benef, '0'), cod_igv
    INTO ls_dolares, ls_doc_os, ls_flag_cenbef, ls_IGV
    FROM logparam
   WHERE reckey = '1' ;

  -- Verificar Centro de Beneficio
  if :new.centro_benef is NULL AND ls_flag_cenbef = '1' then
     RAISE_APPLICATION_ERROR(-20000, 'La Orden de Servicio debe tener Centro de Beneficio');
  end if;

  --===============================================
  -- Parametros por Origen
  --===============================================
  Select o.cencos_igv, o.cnta_prsp_igv, NVL(o.flag_prsp_igv,'0')
    into ls_cencos_igv, ls_cnta_prsp_igv, ls_flag_prsp_igv
    from origen o
   where o.cod_origen = :new.cod_origen;

  if ls_flag_prsp_igv = '1' then
     if ls_cencos_igv is null or ls_cencos_igv = '' then
        RAISE_APPLICATION_ERROR(-20000, 'NO SE ESPECIFICADO CENTROS DE COSTOS DEL IGV PARA EL ORIGEN ' || :new.cod_origen);
     end if;
     if ls_cnta_prsp_igv is null or ls_cnta_prsp_igv = '' then
        RAISE_APPLICATION_ERROR(-20000, 'NO SE ESPECIFICADO CUENTA PRESUPUESTAL DEL IGV PARA EL ORIGEN ' || :new.cod_origen);
     end if;
  end if;

  -- Datos de la orden de servicio
  Select cod_moneda, sol_origen, nro_sol_serv, proveedor, cod_usr
    into ls_moneda, ls_ori_sol, ls_nro_sol, ls_proveedor, ls_cod_usr
    from orden_servicio
   where cod_origen = :new.cod_origen
     and nro_os     = :new.nro_os;

  ln_ano := TO_NUMBER( TO_CHAR(:new.fec_proyect, 'YYYY'));
  ln_precio := usf_fl_conv_mon(:new.importe - :new.decuento, ls_moneda, ls_dolares,
            :new.fec_proyect);

  ln_precio := ln_precio * - 1;

  -- Adiciona registro al presupuesto ejecucion

  /*****************************************************
  **** REPLICACION
  *****************************************************/
  Insert into presupuesto_ejec(
         cod_origen, ano, cencos, cnta_prsp, fecha,
         Descripcion, importe, origen_ref, tipo_doc_ref,
         nro_doc_ref, item_ref, cod_rel_ref, cod_usr,
         centro_benef, flag_replicacion)
  values(
         :new.cod_origen, ln_ano, :new.cencos, :new.cnta_prsp, :new.fec_proyect,
         SUBSTR( :new.descripcion, 1,40), ln_precio, :new.cod_origen, ls_doc_os,
         :new.nro_os, :new.nro_item, ls_proveedor, ls_cod_usr, :NEW.centro_benef, '0');
  /*****************************************************/

  --===============================================
  -- Actualizar el Presupuesto para el IGV
  --===============================================
  if ls_flag_prsp_igv = '1' and :new.tipo_impuesto = ls_IGV then
     ln_importe         := usf_fl_conv_mon(:new.impuesto, ls_moneda, ls_dolares, :new.fec_proyect) * -1;
     ln_ano             := TO_NUMBER( TO_CHAR(:new.fec_proyect, 'YYYY'));

     -- Descripcion
     ls_desc_pto := substr(:new.descripcion,1,100);

     if ln_importe <> 0 then
        Insert into presupuesto_ejec(
            cod_origen, ano, cencos, cnta_prsp, fecha,
            Descripcion, importe, origen_ref, tipo_doc_ref,
            nro_doc_ref, item_ref, cod_rel_ref, cod_usr, flag_preventivo,
            centro_benef, flag_replicacion)
        values (
            :new.cod_origen, ln_ano, ls_cencos_igv, ls_cnta_prsp_igv, :new.fec_proyect,
            ls_desc_pto, ln_importe ,:new.cod_origen, ls_doc_os,
            :new.nro_os, :new.nro_item, ls_proveedor, ls_cod_usr, '0',
            :new.centro_benef, '0');

     end if;
  end if;

  -- Actualiza precio en tabla de operaciones si oper_sec no es nulo
  IF :new.oper_sec IS NOT NULL THEN
     SELECT NVL(l.und,'X')
       INTO ls_und
       FROM operaciones o, labor l
      WHERE o.cod_labor=l.cod_labor and
            o.oper_sec=:new.oper_sec ;

     IF ls_und <> ls_dolares THEN
         UPDATE operaciones o
            SET o.costo_unit = ABS(ln_precio),
                o.cant_proyect = 1,
                o.cant_real = 1,
                o.flag_estado = '2'
          WHERE o.oper_sec = :new.oper_sec ;
     ELSIF ls_und <>'X' THEN
         UPDATE operaciones o
            SET o.costo_unit = 1,
                o.cant_proyect = ABS(ln_precio),
                o.cant_real = ABS(ln_precio),
                o.flag_estado = '2'
          WHERE o.oper_sec = :new.oper_sec ;
     END IF ;
  END IF ;

  -- Actualiza flag de sol. servicio
  if ls_nro_sol is not null then
     /*****************************************************
     **** REPLICACION
     *****************************************************/
     update sol_serv_det
        set flag_estado = '3',
            flag_replicacion = '0'
      where cod_origen   = ls_ori_sol
        and nro_sol_serv = ls_nro_sol
        and nro_item     = :new.nro_item;
     /*****************************************************/
  end if;

  -- Actualiza total de orden en cabecera
  --=====================================
  ln_total := :new.importe - :new.decuento + :new.impuesto + :new.impuesto2;
  /*****************************************************
  **** REPLICACION
  *****************************************************/
  Update orden_servicio os
     set os.monto_total = NVL(os.monto_total,0) + ln_total,
         flag_Replicacion = '0'
   Where os.cod_origen = :new.cod_origen
     and os.nro_os     = :new.nro_os;
  /*****************************************************/

end TIB_ORDEN_SERVICIO_DET;
/

prompt
prompt Creating trigger TIB_PRESUPUESTO_EJEC
prompt =====================================
prompt
CREATE OR REPLACE TRIGGER CANTABRIA.TIB_PRESUPUESTO_EJEC
  before insert on presupuesto_ejec
  for each row

declare
  -- Proyectado
  ln_proy_ene       presupuesto_partida.proy_ene%TYPE;
  ln_proy_feb       presupuesto_partida.proy_feb%TYPE;
  ln_proy_mar       presupuesto_partida.proy_mar%TYPE;
  ln_proy_abr       presupuesto_partida.proy_abr%TYPE;
  ln_proy_may       presupuesto_partida.proy_may%TYPE;
  ln_proy_jun       presupuesto_partida.proy_jun%TYPE;
  ln_proy_jul       presupuesto_partida.proy_jul%TYPE;
  ln_proy_ago       presupuesto_partida.proy_ago%TYPE;
  ln_proy_set       presupuesto_partida.proy_set%TYPE;
  ln_proy_oct       presupuesto_partida.proy_oct%TYPE;
  ln_proy_nov       presupuesto_partida.proy_nov%TYPE;
  ln_proy_dic       presupuesto_partida.proy_dic%TYPE;

  -- Variacion
  ln_var_ene        presupuesto_partida.var_ene%TYPE;
  ln_var_feb        presupuesto_partida.var_feb%TYPE;
  ln_var_mar        presupuesto_partida.var_mar%TYPE;
  ln_var_abr        presupuesto_partida.var_abr%TYPE;
  ln_var_may        presupuesto_partida.var_may%TYPE;
  ln_var_jun        presupuesto_partida.var_jun%TYPE;
  ln_var_jul        presupuesto_partida.var_jul%TYPE;
  ln_var_ago        presupuesto_partida.var_ago%TYPE;
  ln_var_set        presupuesto_partida.var_set%TYPE;
  ln_var_oct        presupuesto_partida.var_oct%TYPE;
  ln_var_nov        presupuesto_partida.var_nov%TYPE;
  ln_var_dic        presupuesto_partida.var_dic%TYPE;

  -- Ejecucion
  ln_ejec_ene       presupuesto_partida.ejec_ene%TYPE;
  ln_ejec_feb       presupuesto_partida.ejec_feb%TYPE;
  ln_ejec_mar       presupuesto_partida.ejec_mar%TYPE;
  ln_ejec_abr       presupuesto_partida.ejec_abr%TYPE;
  ln_ejec_may       presupuesto_partida.ejec_may%TYPE;
  ln_ejec_jun       presupuesto_partida.ejec_jun%TYPE;
  ln_ejec_jul       presupuesto_partida.ejec_jul%TYPE;
  ln_ejec_ago       presupuesto_partida.ejec_ago%TYPE;
  ln_ejec_set       presupuesto_partida.ejec_set%TYPE;
  ln_ejec_oct       presupuesto_partida.ejec_oct%TYPE;
  ln_ejec_nov       presupuesto_partida.ejec_nov%TYPE;
  ln_ejec_dic       presupuesto_partida.ejec_dic%TYPE;

  -- Otros
  ln_limite         presupuesto_partida.ejec_dic%TYPE;
  ln_ejecut         presupuesto_partida.ejec_dic%TYPE;
  ln_mes            NUMBER(2);
  ln_prctg_var      presupuesto_partida.prctg_var%TYPE;
  ls_fondo_var      presupuesto_partida.fondo_var_aut%TYPE;
  ls_variacion      presup_variacion.nro_variacion%TYPE;
  ln_ult_nro        num_presup_variacion.ult_nro%TYPE;
  ln_fondo          fondo_var_aut.fondo%TYPE;
  ln_asignado       fondo_var_aut.asignado%TYPE;
  ln_cant_var       presup_variacion.importe%TYPE;
  ls_flag_var       char(1);

  -- Flag de Controles
  ls_flag_estado    presupuesto_partida.flag_estado%TYPE;
  ls_flag_ctrl      presupuesto_partida.flag_ctrl%TYPE;
  ls_flag_ingr_egr  presupuesto_partida.flag_ctrl%TYPE;

  -- Flag de Presup_param
  ls_flag_cntr_acc_cntas presup_param.flag_cntr_acc_cntas%TYPE;

  ln_count          number;
  ln_count1         number;
  ln_count2         number;


begin
--================================================
-- Validar si se Puede Afectar a la Partida
--================================================
if :new.ano is null or :new.cencos is null or :new.cnta_prsp is null then
   RAISE_APPLICATION_ERROR(-20000, 'El centro de Costos o la Cnta Prsp o el a?o estan en Nulo'
                          || chr(13) || 'A?o: '        || :new.ano
                          || chr(13) || 'Cencos: '     || :new.cencos
                          || chr(13) || 'Cnta Prsp: '  || :new.cnta_prsp
                          || chr(13) || 'Documento: '  || :new.tipo_doc_ref || '/' || :new.nro_doc_ref
                          || chr(13) || 'Item Ref: '   || to_char(:new.item_ref) );
   return;
end if;

--================================================
-- Valido que tenga Cod_usr
--================================================
if :new.cod_usr is null then
   RAISE_APPLICATION_ERROR(-20000, 'La ejecucion Presupuestal no tiene codigo de usuario, por favor verifique');
   return;
end if;

--=================================================
-- Verifico la fecha de ejecucion, no debe ser nula
--=================================================
if :new.fecha is null then
   RAISE_APPLICATION_ERROR(-20000, 'La fecha no puede ser nula');
   return;
end if;

--=================================================
-- Controlo el acceso del usuario a la Partida Prsp
--=================================================
select NVL(l.flag_cntr_acc_cntas, '0')
  into ls_flag_cntr_acc_cntas
from presup_param l
where llave = '1';

if ls_flag_cntr_acc_cntas = '1' then
   -- Si el flag esta activo entonces lo busco, primero por el rol
   select count(*)
     into ln_count
     from rol_prsp_cnta_prsp a,
          usr_rol_prsp       b
    where a.rol = b.rol
      and b.cod_usr   = :new.cod_usr
      and a.cnta_prsp = :new.cnta_prsp
      and a.cencos    = :new.cencos;

   if ln_count = 0 then
      -- Si por el rol no tiene acceso a la Partida Presupuestal, ahora lo
      -- Busco por la cuenta especificamente
      select count(*)
        into ln_count
        from usr_cnta_prsp a
       where a.cod_usr   = :new.cod_usr
         and a.cnta_prsp = :new.cnta_prsp
         and a.cencos    = :new.cencos;

      if ln_count = 0 then
         -- Si llega hasta aca es que definitivamente el usuario no tiene
         -- acceso a la partida presupuestal
         RAISE_APPLICATION_ERROR(-20000, 'No tiene acceso para afectar a la partida presupuestal '
                              || chr(13) || 'Usuario: ' || :new.cod_usr
                              || chr(13) || 'Cencos: ' || :new.cencos
                              || chr(13) || 'Cnta Prsp: ' || :new.cnta_prsp);
         return;
      end if;

   end if;
end if;

--==============================================================================
-- Reviso si la cuenta presupuestal esta retringida para determinados documentos
--==============================================================================
select count(*)
  into ln_count1
  from presup_cnta_doc_tipo t
 where t.cnta_prsp = :new.cnta_prsp;

-- Ahora verifico si el tipo de documento esta restringido en alguna
-- cuenta presupuestal
select count(*)
  into ln_count2
  from presup_cnta_doc_tipo t
 where t.tipo_doc = :new.tipo_doc_ref;

-- Si hay mas de un registro quiere decir que la Cuenta Presupuestal esta
-- restringida a algunos documentos (no es libre)
if ln_count1 > 0 or ln_count2 > 0 then
   -- Ahora verifico si esta permitido afectar a este documento
  select count(*)
    into ln_count
    from presup_cnta_doc_tipo t
   where t.cnta_prsp = :new.cnta_prsp
     and t.tipo_doc  = :new.tipo_doc_ref;

  if ln_count = 0 then
     -- No esta permitido afectar a esta partida este tipo de documento
     RAISE_APPLICATION_ERROR(-20000, 'No esta permitido afectar este tipo de documento '
                                 || 'en la Partida presupuestal indicada, por favor verifique o consulte con '
                                 || 'area de COSTOS Y PRESUPUESTO '
                             || chr(13) || 'Cnta Prsp: ' || :new.cnta_prsp
                             || chr(13) || 'Tipo Doc: '  || :new.tipo_doc_ref);
     return;
  end if;
end if;

--=================================================
-- Verifico si existe la Partida presupuestal
--=================================================
select count(*)
  into ln_count
  FROM presupuesto_partida
 WHERE ano       = :new.ano
   AND cencos    = :new.cencos
   AND cnta_prsp = :new.cnta_prsp;

IF ln_count = 0 then
   RAISE_APPLICATION_ERROR(-20000, 'No existe partida presupuestal: '
                         || chr(13) || 'A?o: '        || to_char(:new.ano)
                         || chr(13) || 'Cencos: '     || :new.cencos
                         || chr(13) || 'Cnta Prsp: '  || :new.cnta_prsp);
end if;

SELECT NVL(prctg_var,0), NVL(flag_estado,'0'), NVL(flag_ctrl,''), NVL(flag_ingr_egr, ''),
       NVL(proy_ene,0), NVL(proy_feb,0), NVL(proy_mar,0), NVL(proy_abr,0),
       NVL(proy_may,0), NVL(proy_jun,0), NVL(proy_jul,0), NVL(proy_ago,0),
       NVL(proy_set,0), NVL(proy_oct,0), NVL(proy_nov,0), NVL(proy_dic,0),
       NVL(var_ene,0),  NVL(var_feb,0),  NVL(var_mar,0),  NVL(var_abr,0),
       NVL(var_may, 0), NVL(var_jun, 0), NVL(var_jul, 0), NVL(var_ago, 0),
       NVL(var_set,0),  NVL(var_oct,0),  NVL(var_nov, 0), NVL(var_dic, 0),
       NVL(ejec_ene,0), NVL(ejec_feb,0), NVL(ejec_mar,0), NVL(ejec_abr,0),
       NVL(ejec_may,0), NVL(ejec_jun,0), NVL(ejec_jul,0), NVL(ejec_ago,0),
       NVL(ejec_set,0), NVL(ejec_oct,0), NVL(ejec_nov,0), NVL(ejec_dic,0),
       fondo_var_aut
  INTO ln_prctg_var, ls_flag_estado, ls_flag_ctrl, ls_flag_ingr_egr,
       ln_proy_ene , ln_proy_feb   , ln_proy_mar , ln_proy_abr , ln_proy_may , ln_proy_jun ,
       ln_proy_jul , ln_proy_ago   , ln_proy_set , ln_proy_oct , ln_proy_nov , ln_proy_dic ,
       ln_var_ene  , ln_var_feb    , ln_var_mar  , ln_var_abr  , ln_var_may  , ln_var_jun  ,
       ln_var_jul  , ln_var_ago    , ln_var_set  , ln_var_oct  , ln_var_nov  , ln_var_dic  ,
       ln_ejec_ene , ln_ejec_feb   , ln_ejec_mar , ln_ejec_abr , ln_ejec_may , ln_ejec_jun ,
       ln_ejec_jul , ln_ejec_ago   , ln_ejec_set , ln_ejec_oct , ln_ejec_nov , ln_ejec_dic ,
       ls_fondo_var
  FROM presupuesto_partida
 WHERE ano       = :new.ano
   AND cencos    = :new.cencos
   AND cnta_prsp = :new.cnta_prsp  FOR UPDATE ;

If NVL(ls_flag_ctrl, '') = '' then
   RAISE_APPLICATION_ERROR( -20000, 'Partida presupuestal no tiene Flag de Control '
           || chr(13) || 'A?o : ' || to_char(:NEW.ano)
           || chr(13) || 'Centro de Costo : ' || TRIM(:new.cencos)
           || chr(13) || 'Cuenta Presupuestal: ' || trim(:new.cnta_prsp) );
   return;
end if;

IF ls_flag_estado NOT IN ('1', '2') THEN
   RAISE_APPLICATION_ERROR( -20000, 'Partida con Flag de estado Desactivado '
           || chr(13) || 'Centro de Costo    : ' || trim(:new.cencos)
           || chr(13) || 'Cuenta Presupuestal: ' || trim(:new.cnta_prsp) );
END IF;

ln_mes    := TO_NUMBER( TO_CHAR(:new.fecha, 'MM'));
ln_limite := 0 ;

IF ls_flag_ctrl = '0' THEN
    GOTO Grabacion_Presupuesto_Partida ;
END IF;

--=========================
-- Total Anual
--=========================
IF ls_flag_ctrl = '1' THEN
   ln_limite := ln_proy_ene + ln_proy_feb + ln_proy_mar + ln_proy_abr +
                ln_proy_may + ln_proy_jun + ln_proy_jul + ln_proy_ago +
                ln_proy_set + ln_proy_oct + ln_proy_nov + ln_proy_dic +
                ln_var_ene  + ln_var_feb  + ln_var_mar  + ln_var_abr +
                ln_var_may  + ln_var_jun  + ln_var_jul  + ln_var_ago +
                ln_var_set  + ln_var_oct  + ln_var_nov  + ln_var_dic;
   ln_ejecut := ln_ejec_ene + ln_ejec_feb + ln_ejec_mar + ln_ejec_abr +
                ln_ejec_may + ln_ejec_jun + ln_ejec_jul + ln_ejec_ago +
                ln_ejec_set + ln_ejec_oct + ln_ejec_nov + ln_ejec_dic ;
   GOTO Comparacion_Saldo ;
END IF ;

--=========================
-- Acumulado a la fecha
--=========================
IF ls_flag_ctrl = '2' THEN
  IF ln_mes = 1 THEN
     ln_limite := ln_proy_ene + ln_var_ene ;
     ln_ejecut := ln_ejec_ene ;
  ELSIF ln_mes = 2 THEN
     ln_limite := ln_proy_ene + ln_var_ene + ln_proy_feb +
                  ln_var_feb ;
     ln_ejecut := ln_ejec_ene + ln_ejec_feb;
  ELSIF ln_mes = 3 THEN
     ln_limite := ln_proy_ene + ln_var_ene + ln_proy_feb +
                  ln_var_feb + ln_proy_mar + ln_var_mar ;
     ln_ejecut := ln_ejec_ene + ln_ejec_feb + ln_ejec_mar;
  ELSIF ln_mes = 4 THEN
     ln_limite := ln_proy_ene + ln_var_ene + ln_proy_feb +
                  ln_var_feb + ln_proy_mar + ln_var_mar +
                  ln_proy_abr + ln_var_abr ;
     ln_ejecut := ln_ejec_ene + ln_ejec_feb + ln_ejec_mar +
                  ln_ejec_abr;
  ELSIF ln_mes = 5 THEN
     ln_limite := ln_proy_ene + ln_var_ene + ln_proy_feb +
                  ln_var_feb + ln_proy_mar + ln_var_mar +
                  ln_proy_abr + ln_var_abr + ln_proy_may +
                  ln_var_may ;
     ln_ejecut := ln_ejec_ene + ln_ejec_feb +
                  ln_ejec_mar + ln_ejec_abr + ln_ejec_may ;
  ELSIF ln_mes = 6 THEN
     ln_limite := ln_proy_ene + ln_var_ene + ln_proy_feb +
                  ln_var_feb + ln_proy_mar + ln_var_mar +
                  ln_proy_abr + ln_var_abr + ln_proy_may +
                  ln_var_may + ln_proy_jun + ln_var_jun ;
     ln_ejecut := ln_ejec_ene + ln_ejec_feb + ln_ejec_mar +
                  ln_ejec_abr + ln_ejec_may + ln_ejec_jun ;
  ELSIF ln_mes = 7 THEN
     ln_limite := ln_proy_ene + ln_var_ene + ln_proy_feb +
                  ln_var_feb + ln_proy_mar + ln_var_mar +
                  ln_proy_abr + ln_var_abr + ln_proy_may +
                  ln_var_may + ln_proy_jun + ln_var_jun +
                  ln_proy_jul + ln_var_jul ;
     ln_ejecut := ln_ejec_ene + ln_ejec_feb + ln_ejec_mar +
                  ln_ejec_abr + ln_ejec_may + ln_ejec_jun +
                  ln_ejec_jul ;
  ELSIF ln_mes = 8 THEN
     ln_limite := ln_proy_ene + ln_var_ene + ln_proy_feb +
                  ln_var_feb + ln_proy_mar + ln_var_mar +
                  ln_proy_abr + ln_var_abr + ln_proy_may +
                  ln_var_may + ln_proy_jun + ln_var_jun +
                  ln_proy_jul + ln_var_jul + ln_proy_ago +
                  ln_var_ago ;
     ln_ejecut := ln_ejec_ene + ln_ejec_feb +
                  ln_ejec_mar + ln_ejec_abr + ln_ejec_may +
                  ln_ejec_jun + ln_ejec_jul + ln_ejec_ago ;
  ELSIF ln_mes = 9 THEN
     ln_limite := ln_proy_ene + ln_var_ene + ln_proy_feb +
                  ln_var_feb + ln_proy_mar + ln_var_mar +
                  ln_proy_abr + ln_var_abr + ln_proy_may +
                  ln_var_may + ln_proy_jun + ln_var_jun +
                  ln_proy_jul + ln_var_jul + ln_proy_ago +
                  ln_var_ago + ln_proy_set + ln_var_set ;
     ln_ejecut := ln_ejec_ene + ln_ejec_feb + ln_ejec_mar +
                  ln_ejec_abr + ln_ejec_may + ln_ejec_jun +
                  ln_ejec_jul + ln_ejec_ago + ln_ejec_set ;
  ELSIF ln_mes = 10 THEN
     ln_limite := ln_proy_ene + ln_var_ene + ln_proy_feb +
                  ln_var_feb + ln_proy_mar + ln_var_mar +
                  ln_proy_abr + ln_var_abr + ln_proy_may +
                  ln_var_may + ln_proy_jun + ln_var_jun +
                  ln_proy_jul + ln_var_jul + ln_proy_ago +
                  ln_var_ago + ln_proy_set + ln_var_set +
                  ln_proy_oct + ln_var_oct ;
     ln_ejecut := ln_ejec_ene +
                  ln_ejec_feb + ln_ejec_mar + ln_ejec_abr +
                  ln_ejec_may + ln_ejec_jun + ln_ejec_jul +
                  ln_ejec_ago + ln_ejec_set + ln_ejec_oct  ;
  ELSIF ln_mes = 11 THEN
     ln_limite := ln_proy_ene + ln_var_ene + ln_proy_feb +
                  ln_var_feb + ln_proy_mar + ln_var_mar +
                  ln_proy_abr + ln_var_abr + ln_proy_may +
                  ln_var_may + ln_proy_jun + ln_var_jun +
                  ln_proy_jul + ln_var_jul + ln_proy_ago +
                  ln_var_ago + ln_proy_set + ln_var_set +
                  ln_proy_oct + ln_var_oct + ln_proy_nov +
                  ln_var_nov ;
     ln_ejecut := ln_ejec_ene + ln_ejec_feb +
                  ln_ejec_mar + ln_ejec_abr + ln_ejec_may +
                  ln_ejec_jun + ln_ejec_jul + ln_ejec_ago +
                  ln_ejec_set + ln_ejec_oct + ln_ejec_nov  ;
  ELSE
     ln_limite := ln_proy_ene + ln_var_ene + ln_proy_feb +
                  ln_var_feb + ln_proy_mar + ln_var_mar +
                  ln_proy_abr + ln_var_abr + ln_proy_may +
                  ln_var_may + ln_proy_jun + ln_var_jun +
                  ln_proy_jul + ln_var_jul + ln_proy_ago +
                  ln_var_ago + ln_proy_set + ln_var_set +
                  ln_proy_oct + ln_var_oct + ln_proy_nov +
                  ln_var_nov + ln_proy_dic + ln_var_dic ;
     ln_ejecut := ln_ejec_ene + ln_ejec_feb + ln_ejec_mar +
                  ln_ejec_abr + ln_ejec_may + ln_ejec_jun +
                  ln_ejec_jul + ln_ejec_ago + ln_ejec_set +
                  ln_ejec_oct + ln_ejec_nov + ln_ejec_dic ;
  END IF;
  GOTO Comparacion_Saldo ;
END IF ;

--=========================
-- Mensual
--=========================
IF ls_flag_ctrl = '3' THEN

   IF ln_mes = 1 THEN
      ln_limite := ln_proy_ene + ln_var_ene ;
      ln_ejecut := ln_ejec_ene;
   ELSIF ln_mes = 2 THEN
      ln_limite := ln_proy_feb + ln_var_feb ;
      ln_ejecut := ln_ejec_feb;
   ELSIF ln_mes = 3 THEN
      ln_limite := ln_proy_mar + ln_var_mar ;
      ln_ejecut := ln_ejec_mar;
   ELSIF ln_mes = 4 THEN
      ln_limite := ln_proy_abr + ln_var_abr ;
      ln_ejecut := ln_ejec_abr;
   ELSIF ln_mes = 5 THEN
      ln_limite := ln_proy_may + ln_var_may ;
      ln_ejecut := ln_ejec_may;
   ELSIF ln_mes = 6 THEN
      ln_limite := ln_proy_jun + ln_var_jun ;
      ln_ejecut := ln_ejec_jun;
   ELSIF ln_mes = 7 THEN
      ln_limite := ln_proy_jul + ln_var_jul ;
      ln_ejecut := ln_ejec_jul;
   ELSIF ln_mes = 8 THEN
      ln_limite := ln_proy_ago + ln_var_ago ;
      ln_ejecut := ln_ejec_ago ;
   ELSIF ln_mes = 9 THEN
      ln_limite :=  ln_proy_set + ln_var_set ;
      ln_ejecut := ln_ejec_set ;
   ELSIF ln_mes = 10 THEN
      ln_limite := ln_proy_oct + ln_var_oct ;
      ln_ejecut := ln_ejec_oct ;
   ELSIF ln_mes = 11 THEN
      ln_limite := ln_proy_nov + ln_var_nov ;
      ln_ejecut := ln_ejec_nov ;
   ELSE
      ln_limite :=  ln_proy_dic + ln_var_dic ;
      ln_ejecut := ln_ejec_dic ;
   END IF;
   GOTO Comparacion_Saldo ;
END IF  ;

--======================================
-- Ultimos 3 Meses (Trimestre Acumulado)
--======================================
IF ls_flag_ctrl = '4' THEN
   IF ln_mes = 1 then
      ln_limite := ln_proy_ene + ln_var_ene;
      ln_ejecut := ln_ejec_ene;
   ELSIf ln_mes = 2 then
      ln_limite := ln_proy_ene + ln_var_ene
                 + ln_proy_feb + ln_var_feb;
      ln_ejecut := ln_ejec_ene + ln_ejec_feb;
   ELSIF ln_mes = 3 then
       ln_limite := ln_proy_ene + ln_var_ene
                  + ln_proy_feb + ln_var_feb
                  + ln_proy_mar + ln_var_mar ;
       ln_ejecut := ln_ejec_ene + ln_ejec_feb + ln_ejec_mar;
   ELSIF ln_mes = 4 then
       ln_limite := ln_proy_feb + ln_var_feb
                  + ln_proy_mar + ln_var_mar
                  + ln_proy_abr + ln_var_abr;
       ln_ejecut := ln_ejec_feb + ln_ejec_mar + ln_ejec_abr;
   ELSIF ln_mes = 5 then
       ln_limite := ln_proy_mar + ln_var_mar
                  + ln_proy_abr + ln_var_abr
                  + ln_proy_may + ln_var_may;
       ln_ejecut := ln_ejec_mar + ln_ejec_abr + ln_ejec_may;
   ELSIF ln_mes = 6 then
       ln_limite := ln_proy_abr + ln_var_abr
                  + ln_proy_may + ln_var_may
                  + ln_proy_jun + ln_var_jun;
       ln_ejecut := ln_ejec_abr + ln_ejec_may + ln_ejec_jun;
   ELSIF ln_mes = 7 then
       ln_limite := ln_proy_may + ln_var_may
                  + ln_proy_jun + ln_var_jun
                  + ln_proy_jul + ln_var_jul;
       ln_ejecut := ln_ejec_may + ln_ejec_jun + ln_ejec_jul;
   ELSIF ln_mes = 8 then
       ln_limite := ln_proy_jun + ln_var_jun
                  + ln_proy_jul + ln_var_jul
                  + ln_proy_ago + ln_var_ago;
       ln_ejecut := ln_ejec_jun + ln_ejec_jul + ln_ejec_ago;
   ELSIF ln_mes = 9 then
       ln_limite := ln_proy_jul + ln_var_jul
                  + ln_proy_ago + ln_var_ago
                  + ln_proy_set + ln_var_set;
       ln_ejecut := ln_ejec_jul + ln_ejec_ago + ln_ejec_set;
   ELSIF ln_mes = 10 then
       ln_limite := ln_proy_ago + ln_var_ago
                  + ln_proy_set + ln_var_set
                  + ln_proy_oct + ln_var_oct;
       ln_ejecut := ln_ejec_ago + ln_ejec_set + ln_ejec_oct;
   ELSIF ln_mes = 11 then
       ln_limite := ln_proy_set + ln_var_set
                  + ln_proy_oct + ln_var_oct
                  + ln_proy_nov + ln_var_nov;
       ln_ejecut := ln_ejec_set + ln_ejec_oct + ln_ejec_nov;
   ELSIF ln_mes = 12 then
       ln_limite := ln_proy_oct + ln_var_oct
                  + ln_proy_nov + ln_var_nov
                  + ln_proy_dic + ln_var_dic;
       ln_ejecut := ln_ejec_oct + ln_ejec_nov + ln_ejec_dic;
   END IF;
END IF;

--==============================
-- Semestral
--==============================
IF ls_flag_ctrl = '5' THEN
   IF ln_mes BETWEEN 1 AND 6 THEN
      ln_limite := ln_proy_ene + ln_proy_feb + ln_proy_mar +
                   ln_proy_abr + ln_proy_may + ln_proy_jun +
                   ln_var_ene  + ln_var_feb  + ln_var_mar +
                   ln_var_abr  + ln_var_may  + ln_var_jun;
      ln_ejecut := ln_ejec_ene + ln_ejec_feb + ln_ejec_mar +
                   ln_ejec_abr + ln_ejec_may + ln_ejec_jun;
   ELSIF ln_mes BETWEEN 7 AND 12 THEN
      ln_limite := ln_proy_jul + ln_proy_ago + ln_proy_set +
                   ln_proy_oct + ln_proy_nov + ln_proy_dic +
                   ln_var_jul  + ln_var_ago  + ln_var_set +
                   ln_var_oct  + ln_var_nov  + ln_var_dic;
      ln_ejecut := ln_ejec_jul + ln_ejec_ago + ln_ejec_set +
                   ln_ejec_oct + ln_ejec_nov + ln_ejec_dic;
   END IF;
END IF;

--==============================
-- Comparacion de Disponibilidad
--==============================
<<Comparacion_Saldo>>

IF ln_prctg_var > 0 THEN
   ln_limite := ln_limite * (1+ ln_prctg_var/100);
END IF;

IF ls_flag_ingr_egr='E' THEN
  --ln_factor := 1 ;
  ls_flag_var := '0';
  delete tt_datos_prsp_ejec;

  IF (ln_limite + ln_ejecut) < - NVL(:new.importe,0) THEN
     IF ls_fondo_var is null THEN
         RAISE_APPLICATION_ERROR( -20001, 'Excede la Partida presupuestal '
                 || chr(13) || 'Centro de Costo    : ' || trim(:new.cencos)
                 || chr(13) || 'Cuenta Presupuestal: ' || trim(:new.cnta_prsp)
                 || chr(13) || 'A?o Ejecucion      : ' || to_char(:new.ano)
                 || chr(13) || 'Mes Ejecucion      : ' || to_char(:new.fecha, 'mm')
                 || chr(13) || 'Saldo Actual       : ' || to_char(ln_limite + ln_ejecut, '999,999,999.99')
                 || chr(13) || 'Importe            : ' || to_char(-NVL(:new.importe,0), '999,999,999.99') ) ;
     ELSE
        -- En este punto si la partida presupuestal tiene un fondo de Variacion Automatica
        -- entonces se debe generar una variacion en automatico
        ln_cant_var := - NVL(:new.importe, 0) - (ln_limite + ln_ejecut);

        -- Primero verifico si el monto asignado no supera al monto del fondo
        select fondo, asignado
          into ln_fondo, ln_asignado
          from fondo_var_aut
        where fondo_var_aut = ls_fondo_var for update;

        if ln_asignado + ln_cant_var > ln_fondo then
           RAISE_APPLICATION_ERROR(-20000, 'Ya no tiene disponible en el fondo de Variacion Automatica'
                                    || chr(13) || 'Fondo: ' || ls_fondo_var
                                    || chr(13) || 'Monto Fondo: ' || to_char(ln_fondo, '999,990.00')
                                    || chr(13) || 'Monto Asignado: ' || to_char(ln_asignado, '999,990.00')
                                    || chr(13) || 'Monto Adicional: ' || to_char(ln_cant_var, '999,990.00'));
        end if;

        -- Si hay disponiblidad genero una variacion
        select count(*)
          into ln_count
        from num_presup_variacion
        where origen = :new.cod_origen;

        if ln_count = 0 then
           insert into num_presup_variacion(origen, ult_nro)
           values(:new.cod_origen, 1);

           ln_ult_nro := 1;

        else
           select ult_nro
             into ln_ult_nro
           from num_presup_variacion
           where origen = :new.cod_origen for update;
        end if;

        ls_variacion := ltrim(rtrim(:new.cod_origen)) || rtrim(ltrim(to_char(ln_ult_nro, '00000000')));

        ln_ult_nro := ln_ult_nro + 1;

        insert into presup_variacion(
               ano, cencos_origen, cnta_prsp_origen, mes_origen, fecha,
               flag_automatico,importe, descripcion, cod_usr, tipo_variacion,
               nro_variacion)
        values(
               :new.ano, :new.cencos, :new.cnta_prsp, ln_mes, :new.fecha,
               '2', ln_cant_var, 'VARIACION AUTOMATICA DE FONDO DE VARIACION x INSERCION',
               :new.cod_usr, 'A', ls_variacion);

        ls_flag_var := '1';

        update num_presup_variacion
           set ult_nro = ln_ult_nro
        where origen = :new.cod_origen;

        insert into tt_datos_prsp_ejec(nro_variacion, flag_var, fondo_var_aut)
        values(ls_variacion, ls_flag_var, ls_fondo_var);
     END IF;
  END IF;
END IF ;
--=================================================
    -- Actualiza importes ejecutados
--=================================================
<<Grabacion_Presupuesto_Partida>>
/*****************************************************
**** REPLICACION
*****************************************************/
update presupuesto_partida
   set ejec_ene = DECODE( ln_mes, 1, ln_ejec_ene + NVL(:new.importe,0), ln_ejec_ene),
       ejec_feb = DECODE( ln_mes, 2, ln_ejec_feb + NVL(:new.importe,0), ln_ejec_feb),
       ejec_mar = DECODE( ln_mes, 3, ln_ejec_mar + NVL(:new.importe,0), ln_ejec_mar),
       ejec_abr = DECODE( ln_mes, 4, ln_ejec_abr + NVL(:new.importe,0), ln_ejec_abr),
       ejec_may = DECODE( ln_mes, 5, ln_ejec_may + NVL(:new.importe,0), ln_ejec_may),
       ejec_jun = DECODE( ln_mes, 6, ln_ejec_jun + NVL(:new.importe,0), ln_ejec_jun),
       ejec_jul = DECODE( ln_mes, 7, ln_ejec_jul + NVL(:new.importe,0), ln_ejec_jul),
       ejec_ago = DECODE( ln_mes, 8, ln_ejec_ago + NVL(:new.importe,0), ln_ejec_ago),
       ejec_set = DECODE( ln_mes, 9, ln_ejec_set + NVL(:new.importe,0), ln_ejec_set),
       ejec_oct = DECODE( ln_mes, 10,ln_ejec_oct + NVL(:new.importe,0), ln_ejec_oct),
       ejec_nov = DECODE( ln_mes, 11,ln_ejec_nov + NVL(:new.importe,0), ln_ejec_nov),
       ejec_dic = DECODE( ln_mes, 12,ln_ejec_dic + NVL(:new.importe,0), ln_ejec_dic),
       flag_replicacion = '0'
 Where ano       = :new.ano
   and cencos    = :new.cencos
   and cnta_prsp = :new.cnta_prsp;
/*****************************************************/

--================================================
--Numeracion Automatica del Primary Key
--================================================
<<Grabacion_Presupuesto_Ejec>>
 SELECT Seq_pto_presupuesto_ejec.NEXTVAL
   INTO :new.nro_mov
   FROM dual;
--================================================



end TIB_PRESUPUESTO_EJEC;
/

prompt
prompt Creating trigger TIB_PRESUPUESTO_PARTIDA
prompt ========================================
prompt
CREATE OR REPLACE TRIGGER CANTABRIA.TIB_PRESUPUESTO_PARTIDA
  before insert on presupuesto_partida
  for each row
declare
  -- local variables here
  ls_tipo_fijo       presup_param.tipo_prtda_prsp_fijo%TYPE;
BEGIN

  -- Inicializa valor en 0, en caso venga dato nulo
  if :new.proy_ene is null then :new.proy_ene := 0; end if;
  if :new.proy_feb is null then :new.proy_feb := 0; end if;
  if :new.proy_mar is null then :new.proy_mar := 0; end if;
  if :new.proy_abr is null then :new.proy_abr := 0; end if;
  if :new.proy_may is null then :new.proy_may := 0; end if;
  if :new.proy_jun is null then :new.proy_jun := 0; end if;
  if :new.proy_jul is null then :new.proy_jul := 0; end if;
  if :new.proy_ago is null then :new.proy_ago := 0; end if;
  if :new.proy_set is null then :new.proy_set := 0; end if;
  if :new.proy_oct is null then :new.proy_oct := 0; end if;
  if :new.proy_nov is null then :new.proy_nov := 0; end if;
  if :new.proy_dic is null then :new.proy_dic := 0; end if;

  -- Valida que datos no vengan negativos
  if (:new.proy_ene < 0 or :new.proy_feb < 0 or :new.proy_mar < 0 or :new.proy_abr < 0 or
      :new.proy_may < 0 or :new.proy_jun < 0 or :new.proy_jul < 0 or :new.proy_ago < 0 or
      :new.proy_set < 0 or :new.proy_oct < 0 or :new.proy_nov < 0 or :new.proy_dic < 0 ) then

      RAISE_APPLICATION_ERROR( -20000, 'Monto digitado en partida no puede ser negativo' ) ;
      Return ;
  end if;

  SELECT t.tipo_prtda_prsp_fijo
    INTO ls_tipo_fijo
    FROM presup_param t
   WHERE t.llave = '1';

  IF :NEW.TIPO_PRTDA_PRSP IS NULL THEN
     :NEW.TIPO_PRTDA_PRSP := ls_tipo_fijo;
  END IF;

end TIB_PRESUPUESTO_PARTIDA;
/

prompt
prompt Creating trigger TIB_PROVEEDOR
prompt ==============================
prompt
CREATE OR REPLACE TRIGGER CANTABRIA.TIB_PROVEEDOR
  before insert on proveedor
  for each row
declare
  -- local variables here
  ln_ult_nro    num_proveedor.ult_nro%TYPE;
  ls_proveedor  proveedor.proveedor%TYPE;
  ln_count      number;

BEGIN
  IF :new.ruc IS NOT NULL THEN
    IF length(TRIM(:new.ruc))<11 THEN
       --RAISE_APPLICATION_ERROR( -20000, 'RUC no puede tener menos de 11 digitos' ) ;
       Return ;
    END IF ;
  END IF ;

  if :new.proveedor is null then
    select count(*)
      into ln_count
      from num_proveedor
     where origen = 'XX';

    if ln_count = 0 then
      insert into num_proveedor(ult_nro, origen)
      values (1, 'XX');
    end if;

    select ult_nro
      into ln_ult_nro
      from num_proveedor
     where origen = 'XX' for update;

    update num_proveedor
       set ult_nro = ln_ult_nro + 1
     where origen = 'XX';

    ls_proveedor := 'E' || trim(to_char(ln_ult_nro, '0000000'));

    select ls_proveedor into :new.proveedor from dual;
  end if;
END TIB_PROVEEDOR;
/

