prompt
prompt Creating trigger TIB_RESERVACION_DET
prompt ====================================
prompt
CREATE OR REPLACE TRIGGER CANTABRIA.TIB_RESERVACION_DET
  BEFORE insert on reservacion_det
  for each row

DECLARE
  -- Presupuesto_partida
  ln_cant_libre_ot        articulo_mov_proy.cant_proyect%type ;
  ln_cant_reservado       articulo_mov_proy.cant_reservado%TYPE;
  ln_count                number ;
  ls_trigger_amp          tt_trigers.trigger_amp%TYPE := 0;
  ls_estado               articulo_mov_proy.flag_estado%TYPE;
  ls_tipo_doc             articulo_mov_proy.tipo_doc%TYPE;
  ls_nro_doc              articulo_mov_proy.nro_doc%TYPE;

BEGIN
  -- Verificando si AMP sigue activo
  -- Obtengo la cantidad Libre del Requerimiento de la OT, porque es lo maximo
  -- que se puede reservar
  SELECT tipo_doc, nro_doc
    INTO ls_tipo_doc, ls_nro_doc
    FROM articulo_mov_proy amp
   WHERE amp.cod_origen    = :NEW.org_amp_ref
     AND amp.nro_mov       = :NEW.nro_amp_ref FOR UPDATE;


  RAISE_APPLICATION_ERROR(-20000, 'Nro Requerimiento ' || :NEW.org_amp_ref
          || to_char(:NEW.nro_amp_ref) || ' de la ' || ls_tipo_doc || ' ' || ls_nro_doc
          || ' esta ingresando cantidad reservada, por favor verifique ');
  
  if :new.cant_procesada is null then :new.cant_procesada := 0; end if;
  -- verifico si existe un registro en la tabla tt_triggers, y que este activo el flag de trigger_amp
  -- de esta manera se que el registro que se esta insertando proviene de una insercion del
  -- trigger de ARTICULO_MOV_PROY y por lo tanto este trigger se va a encargar de actualizar el
  -- saldo reservado.

  SELECT COUNT(*)
    INTO ln_count
    FROM tt_trigers;

  IF ln_count > 0 THEN
     SELECT NVL(trigger_amp, '0')
       INTO ls_trigger_amp
       FROM tt_trigers;
  END IF;

  IF ls_trigger_amp = '1' THEN RETURN; END IF;

  -- Verificando si AMP sigue activo
  -- Obtengo la cantidad Libre del Requerimiento de la OT, porque es lo maximo
  -- que se puede reservar
  SELECT cant_reservado, flag_estado,
         usf_alm_cant_libre_ot(amp.cod_origen, amp.nro_mov),
         tipo_doc, nro_doc
    INTO ln_cant_reservado, ls_estado, ln_cant_libre_ot, ls_tipo_doc, ls_nro_doc
    FROM articulo_mov_proy amp
   WHERE amp.cod_origen    = :NEW.org_amp_ref
     AND amp.nro_mov       = :NEW.nro_amp_ref FOR UPDATE;


  IF ls_estado = '0' THEN
     RAISE_APPLICATION_ERROR(-20000, 'Nro Requerimiento ' || :NEW.org_amp_ref
          || to_char(:NEW.nro_amp_ref) || ' de la ' || ls_tipo_doc || ' ' || ls_nro_doc
          || ' esta anulado, por favor verifique ');
  END IF;

  IF ls_estado = '3' THEN
     RAISE_APPLICATION_ERROR(-20000, 'Nro Requerimiento ' || :NEW.org_amp_ref
          || to_char(:NEW.nro_amp_ref) || ' de la ' || ls_tipo_doc || ' ' || ls_nro_doc
          || ' esta proyectado, por favor verifique ');
  END IF;

  IF ls_estado = '2' THEN
     RAISE_APPLICATION_ERROR(-20000, 'Nro Requerimiento ' || :NEW.org_amp_ref
          || to_char(:NEW.nro_amp_ref) || ' de la ' || ls_tipo_doc || ' ' || ls_nro_doc
          || ' esta cerrado, por favor verifique ');
  END IF;

  -- Verifico si esta vencida el requerimiento simplemente lo cierro
  IF trunc(:NEW.fec_vencimiento) < trunc(SYSDATE) AND :new.flag_estado = '1' THEN
     :NEW.flag_estado := '5';  -- Vencido
  END IF;

  IF ln_cant_libre_ot < 0 THEN ln_cant_libre_ot := 0; END IF;

  -- Si la cant procesada es mayor o igual a la cantidad reservada entonces
  -- Cierro el item
  IF :NEW.cant_procesada >= :NEW.cantidad AND :new.flag_estado = '1' THEN
     :NEW.flag_estado := '2';  -- Cerrado
  END IF;

  IF :NEW.flag_estado = '1' THEN
     -- Verifico que la cantidad no se haga negativa
     IF (:NEW.cantidad - :NEW.cant_procesada) > ln_cant_libre_ot THEN
        raise_application_error(-20000, 'Cantidad reservada no puede ser mayor a la cantidad Libre del Requerimiento '
           || chr(13) || 'Reservacion N?: ' || to_char(:NEW.nro_reservacion)
           || chr(13) || 'Requerimiento ' || :NEW.org_amp_ref || to_char(:NEW.nro_amp_ref)
           || chr(13) || 'Libre en AMP_OT: ' || to_char(ln_cant_libre_ot)
           || ( CASE WHEN ln_cant_reservado > 0 THEN
                   chr(13) || 'Reservado Actualmente: ' || to_char(ln_cant_reservado)
                ELSE '' END)
           || chr(13) || 'Cantidad: ' || to_char(:NEW.cantidad + :NEW.cant_procesada));
        --:NEW.cantidad := ln_cant_libre_ot;
     END IF;

     -- Se disminuye la cantidad reservada
     ln_cant_reservado := ln_cant_reservado + (:NEW.cantidad - :NEW.cant_procesada);

     UPDATE articulo_mov_proy amp
        SET amp.cant_reservado = ln_cant_reservado
      WHERE amp.cod_origen = :NEW.org_amp_ref
        AND amp.nro_mov    = :NEW.nro_amp_ref ;

  END IF ;



END TIB_RESERVACION_DET ;
/

prompt
prompt Creating trigger TIB_SOLICITUD_GIRO_LIQ_DET
prompt ===========================================
prompt
CREATE OR REPLACE TRIGGER CANTABRIA.TIB_SOLICITUD_GIRO_LIQ_DET
  before insert on solicitud_giro_liq_det
  for each row
declare

  -- local variables here
  lc_origen  origen.cod_origen%type ;
  ln_saldo_sol doc_pendientes_cta_cte.sldo_sol%type  ;
  ln_saldo_dol doc_pendientes_cta_cte.saldo_dol%type ;
  ln_count     number                 ;
  ls_tip_doc   doc_tipo.tipo_doc%type ;

begin

  IF :new.flag_ret_igv = '1' THEN
     --parametros de moneda



     select Count(*) into ln_count from cntas_pagar cp
     where (cp.cod_relacion      = :new.proveedor) and
           (cp.tipo_doc          = :new.tipo_doc ) and
           (cp.nro_doc           = :new.nro_doc  ) and
           (cp.flag_provisionado = 'R'           ) ;

     if ln_count = 0 then
        RAISE_APPLICATION_ERROR(-20000,'Documento no ha Sido Provisionado ,Verifique!') ;
     else
        select origen into lc_origen from cntas_pagar cp
         where (cp.cod_relacion      = :new.proveedor) and
               (cp.tipo_doc          = :new.tipo_doc ) and
               (cp.nro_doc           = :new.nro_doc  ) and
               (cp.flag_provisionado = 'R'           ) ;

     end if ;

     --GENERA RETENCION ....(Verificacion )
     IF :new.nro_retencion is null or Trim(:new.nro_retencion) = '' THEN
        RAISE_APPLICATION_ERROR(-20000,'Debe Colocar el Nro de Retencion , Verifique!')  ;
     END IF ;

     IF :new.importe_ret_igv is null or :new.importe_ret_igv = 0 THEN
        RAISE_APPLICATION_ERROR(-20000,'Debe Generar algun importe para generar importe de Retencion  , Verifique!')  ;
     END IF ;


     --Archivo de Parametros
     select doc_ret_igv_crt  into ls_tip_doc from finparam where (reckey = '1')  ;

     --encontrar saldos de acuerdo a tipo de moneda
    ln_saldo_sol := Round(:new.importe_ret_igv ,2) ;
    ln_saldo_dol := Round(:new.importe_ret_igv / :new.tasa_cambio,2) ;
     --


     Insert Into retencion_igv_crt
     (nro_certificado ,fecha_emision ,origen    ,flag_estado   ,
      flag_tabla		  ,importe_doc	 ,saldo_sol	,saldo_dol 	  ,
      proveedor)
     Values
     (:new.nro_retencion ,:new.fecha_doc       ,lc_origen    ,'1'         ,
      '3'                ,:new.importe_ret_igv ,ln_saldo_sol ,ln_saldo_dol,
      :new.proveedor )  ;



      update cntas_pagar cp set cp.nro_certificado = :new.nro_retencion
       where (cp.cod_relacion      = :new.proveedor) and
             (cp.tipo_doc          = :new.tipo_doc ) and
             (cp.nro_doc           = :new.nro_doc  ) and
             (cp.flag_provisionado = 'R'           ) ;

  END IF ;

end TIB_SOLICITUD_GIRO_LIQ_DET;
/

