prompt
prompt Creating trigger TIB_VALE_MOV_TRANS_DET
prompt =======================================
prompt
CREATE OR REPLACE TRIGGER CANTABRIA.TIB_VALE_MOV_TRANS_DET
  before insert on vale_mov_trans_det
  for each row
declare

  -- Articulo_Mov_Tipo
  ls_tipo_mov          articulo_mov_tipo.tipo_mov%type;
  ln_fac_total         articulo_mov_tipo.factor_sldo_total%type;
  ls_flag_clase_mov    articulo_mov_tipo.flag_clase_mov%TYPE;

  -- Vale_Mov_trans
  ld_fec_documento     vale_mov_trans.fec_documento%type;
  ls_org_oc            vale_mov_trans.org_oc%TYPE;
  ls_nro_oc            vale_mov_trans.nro_oc%type;
  ls_flag_estado       vale_mov_trans.flag_estado%TYPE;
  ls_almacen           vale_mov_trans.almacen%type;
  ls_origen            vale_mov_trans.cod_origen%TYPE;

  -- Articulo_almacen
  ld_fec_ult_salida    articulo_almacen.fec_ult_salida%TYPE;
  ln_saldo_total       articulo_almacen.sldo_total%TYPE;

  -- Articulo_Mov_Proy
  ln_cant_proyect      articulo_mov_proy.cant_proyect%type;
  ln_cant_procesada    articulo_mov_proy.cant_procesada%type;
  ln_cant_transport    articulo_mov_proy.cant_transportada%TYPE;

  -- Varios
  ln_count             number;

BEGIN

  --=================================================
  --Actualizo la fecha de registro
  --=================================================
  :new.fec_registro := sysdate;
  IF :NEW.cant_proc_am IS NULL THEN :NEW.cant_proc_am := 0; END IF;

  --=================================================
  --Verifico la cantidad no sea negativa
  --=================================================
  if :new.cant_procesada < 0 then
     RAISE_APPLICATION_ERROR(-20000, 'La cantidad no puede ser negativa');
  end if;

  --==============================================================
  -- Si el movimiento esta anulado, ya no tengo nada mas que hacer
  --==============================================================
  if :new.flag_estado = '0' THEN RETURN; end if;

  --=================================================
  -- Vale_mov_trans
  --=================================================
  SELECT almacen    , fec_documento  , tipo_mov   , org_oc,
         nro_oc     , cod_origen
    INTO ls_almacen , ld_fec_documento, ls_tipo_mov, ls_org_oc,
         ls_nro_oc  , ls_origen
    FROM vale_mov_trans
   WHERE nro_vale   = :new.nro_vale;

  --=================================================
  -- tipo de Movimiento
  --=================================================
  SELECT Nvl(factor_sldo_total,0),  flag_clase_mov, flag_estado
    INTO ln_fac_total, ls_flag_clase_mov, ls_flag_estado
    FROM articulo_mov_tipo
   WHERE tipo_mov = ls_tipo_mov ;

  IF ls_flag_estado = '0' THEN
     RAISE_APPLICATION_ERROR(-20000, 'Tipo de movimiento ' || ls_tipo_mov || ' esta anulado');
  END IF;

  --=================================================
  -- Validaciones de referencia
  --=================================================
  IF ln_fac_total = 1 AND ls_flag_clase_mov <> 'I' THEN
     RAISE_APPLICATION_ERROR(-20000, 'Los Ingresos siempre deben estar referenciados a una OC');
  END IF;

  IF ls_flag_clase_mov = 'I' AND  (:new.org_amp_oc is null or :new.nro_amp_oc is null) then
     RAISE_APPLICATION_ERROR(-20000, 'EL MOVIMIENTO TIENE REFERENCIA EN LA CABECERA PERO EN EL DETALLE '
            || chr(13) || chr(10) || 'EL CAMPO ORG_AMP_OC O NRO_AMP_OC ESTA VACIO O NULO'
            || chr(13) || chr(10) || 'ORG_AMP_OC: ' || :new.org_amp_oc
            || chr(13) || chr(10) || 'NRO_AMP_OC: ' || :new.nro_amp_oc
            || chr(13) || chr(10) || 'NRO_OC: '     || ls_nro_oc);
  end if;


  --=================================================
  -- Lectura Articulo_almacen
  --=================================================
  select count(*)
    into ln_count
    from articulo_almacen
   where cod_art = :new.cod_art
     and almacen = ls_almacen;

  if ln_count > 0 then
     SELECT NVL(sldo_total,0), fec_ult_salida
       INTO ln_saldo_total, ld_fec_ult_salida
       FROM articulo_almacen aa
      WHERE cod_art = :new.cod_art
        and almacen = ls_almacen FOR UPDATE;
  else
      ln_saldo_total      := 0;
  end if;


  --==================================================
  -- Lectura de AMP_OC
  --==================================================
  IF :new.nro_amp_oc IS NOT NULL THEN
     SELECT NVL(cant_proyect, 0), NVL(cant_procesada, 0), NVL(cant_transportada, 0)
       INTO ln_cant_proyect, ln_cant_procesada, ln_cant_transport
       FROM articulo_mov_proy
      WHERE cod_origen = :new.org_amp_oc
        AND nro_mov    = :new.nro_amp_oc FOR UPDATE;
  ELSE
      ln_cant_proyect      := 0;
      ln_cant_procesada    := 0;
      ln_cant_transport    := 0;
  END IF;

  --=============================================================
  -- Validad las cantidades en AMP_OC
  --=============================================================
  IF :new.nro_amp_oc IS NOT NULL THEN

     IF ln_fac_total = 1 THEN
        if ln_cant_proyect < ln_cant_procesada + :new.cant_procesada then
              RAISE_APPLICATION_ERROR( -20005, 'la Cantidad Procesada No puede ser mayor a la cantidad proyectada de la OC'
                             || chr(13) || 'Cant Procesada: ' || to_char(ln_cant_procesada)
                             || chr(13) || 'Cant Comprada : ' || to_char(ln_cant_proyect)
                             || chr(13) || 'Cant Movimiento : ' || to_char(:new.cant_procesada)
                             || chr(13) || 'Tipo Mov      : ' || ls_tipo_mov
                             || chr(13) || 'Cod. Art      : ' || :new.cod_art) ;
        end if;
     END IF;

     IF ln_fac_total = -1 THEN
        if ln_cant_proyect < ln_cant_transport + :new.cant_procesada then
              RAISE_APPLICATION_ERROR( -20005, 'la Cantidad Transportada no puede ser mayor a la cantidad proyectada OC'
                             || chr(13) || 'Cant Transportada: ' || to_char(ln_cant_transport)
                             || chr(13) || 'Cant Comprada    : ' || to_char(ln_cant_proyect)
                             || chr(13) || 'Cant Movimiento  : ' || to_char(:new.cant_procesada)
                             || chr(13) || 'Tipo Mov      : ' || ls_tipo_mov
                             || chr(13) || 'Cod. Art      : ' || :new.cod_art) ;
        end if;
     END IF;
  END IF;

  --============================================
  -- Acualizo el saldo total
  --============================================
  ln_saldo_total      := NVL(ln_saldo_total,0) + :new.cant_procesada * ln_fac_total;

  if ln_saldo_total < 0 then
     RAISE_APPLICATION_ERROR(-20000, 'El saldo total no puede ser negativo'
                       || chr(13) || 'Saldo Total : ' || to_char(ln_saldo_total - :new.cant_procesada * ln_fac_total)
                       || chr(13) || 'Cantidad    : ' || to_char(:new.cant_procesada * ln_fac_total)
                       || chr(13) || 'Cod Art.    : ' || :new.cod_art);
     return;
  end if;

  --======================================================
  -- Si son salidas, entonces debo grabar la ultima salida
  --======================================================
  IF ln_fac_total = -1 THEN
     if ld_fec_documento > ld_fec_ult_salida or ld_fec_ult_salida is null then
        ld_fec_ult_salida := ld_fec_documento;
     end if;
  END IF;

  --===============================================================
  -- Si es un ingreso debo actualiza la cantidad procesada de la OC
  --===============================================================
  IF :new.nro_amp_oc IS NOT NULL AND ln_fac_total = 1 THEN
     /*****************************************************
      **** REPLICACION
     *****************************************************/
     -- De lo contrario actualizo la cantidad procesada de la manera normal
     UPDATE articulo_mov_proy amp
        SET amp.cant_procesada = Nvl(cant_procesada,0) + :new.cant_procesada,
            amp.flag_replicacion = '0'
      WHERE cod_origen  = :new.org_amp_oc
        AND nro_mov     = :new.nro_amp_oc;
     /*****************************************************/

  END IF;

  --===============================================================
  -- Si es una salida debo actualizar la cantidad transportada en
  -- el detalle de cada OC
  --===============================================================
  IF :new.nro_amp_oc IS NOT NULL AND ln_fac_total = -1 THEN
     /*****************************************************
      **** REPLICACION
     *****************************************************/
     -- De lo contrario actualizo la cantidad procesada de la manera normal
     UPDATE articulo_mov_proy amp
        SET amp.cant_transportada = Nvl(amp.cant_transportada, 0) + :new.cant_procesada,
            amp.flag_replicacion = '0'
      WHERE cod_origen  = :new.org_amp_oc
        AND nro_mov     = :new.nro_amp_oc;
     /*****************************************************/

  END IF;

  --==================================================
  -- Actualizacion Articulo_almacen
  --==================================================
  <<Grabacion_Articulo>>
  IF ln_fac_total <> 0 and :new.cant_procesada > 0 THEN
     /*****************************************************
     **** REPLICACION
     *****************************************************/
     UPDATE Articulo_almacen
        SET sldo_total        = ln_saldo_total,
            fec_ult_salida    = ld_fec_ult_salida,
            flag_replicacion  = '0'
      WHERE COD_ART = :new.cod_art
        and almacen = ls_almacen;
     /*****************************************************/

     if SQL%NOTFOUND then
        IF ln_fac_total = 1 THEN
           /*****************************************************
           **** REPLICACION
           *****************************************************/
           insert into articulo_almacen(
                  almacen, cod_art, sldo_total, fec_ult_salida, flag_replicacion)
           values(
                  ls_almacen, :new.cod_art, ln_saldo_total, ld_fec_ult_salida, '0' );
           /*****************************************************/
        ELSE
           RAISE_APPLICATION_ERROR( -20000, 'El Articulo ' || :new.cod_art ||
                         ' no tiene saldo en el Almacen ' || ls_almacen) ;
        END IF;
     end if;
  END IF;

end TIB_VALE_MOV_TRANS_DET;
/

prompt
prompt Creating trigger TIUA_ARTICULO_MOV_PROY
prompt =======================================
prompt
CREATE OR REPLACE TRIGGER CANTABRIA.TIUA_ARTICULO_MOV_PROY
  after insert or update on articulo_mov_proy
  for each row
declare
  -- local variables here
  ls_doc_sc          logparam.doc_sc%type;
  ls_doc_ot          logparam.doc_ot%type ;
  ls_tipo_mov        articulo_mov_tipo.tipo_mov%type ;

begin
   if :new.flag_estado = '0' then
      return;
   end if;

   SELECT l.doc_sc, l.doc_ot, l.oper_cons_interno
     INTO ls_doc_sc, ls_doc_ot, ls_tipo_mov
     FROM logparam l
    WHERE reckey = '1';

  --===============================================
  -- Actualizar Datos de Solicitud de Compra
  --===============================================
  IF :new.tipo_ref = ls_doc_sc THEN
  /*****************************************************
  **** REPLICACION
  *****************************************************/
      UPDATE sol_comp_det sc
         set sc.nro_mov         = :new.nro_mov,
             sc.origen_mov_proy = :new.cod_origen,
             sc.cant_procesada  = Nvl(sc.cant_procesada,0) + :new.cant_proyect,
             flag_replicacion   = '0'
       where nro_sol_comp = :new.referencia
         and cod_art      = :new.cod_art;
  /*****************************************************/

  END IF;


END TIUA_ARTICULO_MOV_PROY;
/

prompt
prompt Creating trigger TIUA_COD_CLIENTE
prompt =================================
prompt
CREATE OR REPLACE TRIGGER CANTABRIA.tiua_cod_cliente
  after insert or update on maestro
  for each row

declare

ls_nombres        varchar2(60) ;

begin

  -- Edgar Morante Miercoles 10Jul2002, replicacion
  If (dbms_reputil.from_remote=true or dbms_snapshot.i_am_a_refresh=true) then
     return;
  end if;

ls_nombres := rtrim(:new.apel_paterno)||' '||rtrim(:new.apel_materno)||' '||
              nvl(rtrim(:new.nombre1),' ')||' '||nvl(rtrim(:new.nombre2),' ') ;

--  Actualiza datos en la tabla CODIGO_RELACION
update codigo_relacion
 set cod_relacion = :new.cod_trabajador,
     nombre       = ls_nombres,
     flag_tabla   = 'M' ,
     flag_replicacion = '0'
 where cod_relacion = :new.cod_trabajador ;

--  Inserta registros en la tabla proveedores
if sql%notfound then

  insert into codigo_relacion (
    cod_relacion, nombre, flag_tabla, flag_replicacion )
  Values (
    :new.cod_trabajador, ls_nombres, 'M', '0' ) ;

end if ;


end tiua_cod_cliente ;
/

prompt
prompt Creating trigger TIUA_NEW_PROVEEDOR
prompt ===================================
prompt
CREATE OR REPLACE TRIGGER CANTABRIA.tiua_new_proveedor
  after insert or update on maestro
  for each row

declare

ls_nombres        proveedor.nom_proveedor%TYPE ;

begin

  -- Edgar Morante Miercoles 10Jul2002, replicacion
  If (dbms_reputil.from_remote=true or dbms_snapshot.i_am_a_refresh=true) then
     return;
  end if;

ls_nombres := rtrim(:new.apel_paterno)||' '||rtrim(:new.apel_materno)||' '||
              nvl(rtrim(:new.nombre1),' ')||' '||nvl(rtrim(:new.nombre2),' ') ;

--  Actualiza datos en la tabla proveedores

/*****************************************************
**** REPLICACION
*****************************************************/
Update proveedor p
  set email             = substr(:new.email,1,40) ,
      nom_proveedor     = ls_nombres ,
      tipo_doc_ident    = '1',
      nro_doc_ident     = :new.dni ,
      flag_replicacion  = '0',
      p.flag_nac_ext    = 'N',
      flag_estado   = :new.flag_estado
  where proveedor = :new.cod_trabajador ;
/*****************************************************/

--  Inserta registros en la tabla proveedores
If sql%notfound then
  /*****************************************************
  **** REPLICACION
  *****************************************************/
    insert into proveedor (
      proveedor, flag_estado, nom_proveedor,
      email, tipo_doc_ident, nro_doc_ident , flag_replicacion, flag_nac_ext )
    Values (
      :new.cod_trabajador, '1', ls_nombres,
      :new.email, '1',:new.dni, '0', 'N' ) ;
  /*****************************************************/
End if ;

End tiua_new_proveedor ;
/

