prompt
CREATE OR REPLACE TRIGGER CANTABRIA.TIUB_AP_GUIA_RECEPCION_DET
  before insert or update
  on AP_GUIA_RECEPCION_DET
  for each row
declare
  -- local variables here
begin
  if INSERTING then
     :new.flag_estado := '3';
  elsif UPDATING then
     if :new.flag_estado = '1'  then

        if :new.aprobador is null then
           :new.flag_estado := '3';
        end if;
     elsif :new.flag_estado = '3' and :new.aprobador is not null then
        :new.flag_estado := '1';
     end if;
  end if;

end TIUB_AP_GUIA_RECEPCION_DET;
