prompt
prompt Creating trigger TIUB_ARTICULO_MOV
prompt ==================================
prompt
CREATE OR REPLACE TRIGGER CANTABRIA.TIUB_ARTICULO_MOV
  before insert or update
  on ARTICULO_MOV 
  for each row
declare
  -- local variables here
begin
  if :new.precio_unit < 0 then
     :new.precio_unit := 0;
     --RAISE_APPLICATION_ERROR(-20000, 'El precio no puede ser negativo, por favor verifique!!'
     --                                || chr(13) || 'Nro Vale: ' || :new.nro_vale 
     --                                || chr(13) || 'Cod Articulo: ' || :new.cod_art );
  end if;
  
  if :new.cant_procesada < 0 then
     RAISE_APPLICATION_ERROR(-20000, 'La cantidad procesada no puede ser negativo, por favor verifique!!'
                                     || chr(13) || 'Nro Vale: ' || :new.nro_vale 
                                     || chr(13) || 'Cod Articulo: ' || :new.cod_art );
  end if;
end TIUB_ARTICULO_MOV;
/

prompt
prompt Creating trigger TIUB_ASISTENCIA_HT580
prompt ======================================
prompt
CREATE OR REPLACE TRIGGER CANTABRIA.TIUB_ASISTENCIA_HT580
  before INSERT OR UPDATE
  on ASISTENCIA_HT580 
  for each row
declare
  -- local variables here
  ln_count number;
begin
  -- Valido que el codigo exista en el maestro de trabaajdores
  select count(*)
    into ln_count
    from maestro m
   where m.cod_trabajador = :new.codigo;
  
  if ln_count = 0 then
     RAISE_APPLICATION_ERROR(-20000, 'El codigo ' || :new.codigo || ' no existe en el maestro de trabajadores o no se encuentra activo');
  end if;
  
  -- Valido si esta de vacaciones o de permiso en la tabla de inasistencias
  select count(*)
    into ln_count
    from inasistencia i
   where i.cod_trabajador = :new.codigo
     and trunc(:new.fec_registro) between trunc(i.fec_desde) and trunc(i.fec_hasta);

  if ln_count > 0 then
     RAISE_APPLICATION_ERROR(-20000, 'El codigo ' || :new.codigo || ' esta en un periodo de AUSENCIA, ya sea por vacaciones o licencia, por favor confirmar');
  end if;


end TIUB_ASISTENCIA_HT580;
/

