prompt
prompt Creating trigger TIUB_MAESTRO
prompt =============================
prompt
CREATE OR REPLACE TRIGGER CANTABRIA.TIUB_MAESTRO
  before insert or update on maestro
  for each row
declare
  -- local variables here
  ln_ult_nro         num_maestro.ult_nro%TYPE;
  ln_count           number;
begin

  -- Obtengo el Id del trabajador
  if :new.cod_Trabajador is null then
     select count(*)
       into ln_count
       from num_maestro m
      where m.origen = :new.cod_origen;

     if ln_count > 0 then
        select ult_nro
          into ln_ult_nro
          from num_maestro m
         where m.origen = :new.cod_origen for update;

        :new.cod_trabajador := ln_ult_nro;

        update num_maestro m
           set m.ult_nro = ln_ult_nro + 1
         where m.origen = :new.cod_origen;

     end if;
  end if;

  -- Actulizo el dni
  if :new.tipo_doc_ident_rtps = 1 and :new.nro_doc_ident_rtps is not null then
     :new.dni := substr(:new.nro_doc_ident_rtps,1,8);
  end if;

end TIUB_MAESTRO;
/

