prompt
prompt Creating trigger TUA_ALM_ORDEN_TRASLADO
prompt =======================================
prompt
CREATE OR REPLACE TRIGGER CANTABRIA.tua_alm_orden_traslado
  after update on orden_traslado
  for each row
declare
  -- local variables here
  ls_doc_otr         logparam.doc_otr%TYPE;
  ll_count           number;
  ll_ano             number;
  ll_mes             number;
  ll_cerrado         number;

begin

  select count(*)
    into ll_count
  from logparam
  where reckey ='1';

  if ll_count = 0 then
     RAISE_APPLICATION_ERROR(-20000, 'NO HA DEFINIDO PARAMETROS EN LOGPARAM');
     return;
  end if;

  select doc_otr
    into ls_doc_otr
  from logparam
  where reckey = '1';

  if ls_doc_otr = '' or ls_doc_otr is null then
     RAISE_APPLICATION_ERROR(-20000, 'NO HA DEFINIDO DOCUMENTO DE ORDEN DE TRASLADO EN LOGPARAM');
     return;
  end if;

  select count(*)
    into ll_count
  from articulo_mov_proy
  where tipo_doc = ls_doc_otr
    and nro_doc  = :new.nro_otr;

  if ll_count = 0 then
     RAISE_APPLICATION_ERROR(-20000, 'LA ORDEN DE TRASLADO: ' || :new.nro_otr
                       || ' NO TIENE DETALLE EN ARTICULO_MOV_PROY');
     return;
  end if;

  -- No puedo cambiar el estado de la orden de traslado si el periodo contable esta cerrado
  ll_ano := to_number(to_char(:new.fec_registro, 'yyyy'));
  ll_mes := to_number(to_char(:new.fec_registro, 'mm'));

  -- Busca si esta cerrado contablemente
  Select NVL( flag_gen_asnt_autom,0)
  	into ll_cerrado
  from cntbl_cierre
  where ano = ll_ano
    and mes = ll_mes;


  if ll_cerrado = 0 then
     RAISE_APPLICATION_ERROR(-20000, 'NO PUEDE CAMBIAR EL ESTADO DE LA ORDEN DE TRASLADO, '
                          || ' EL PERIODO CONTABLE SE ENCUENTRA CERRADO');
     return;
  end if;

  -- Aprobando la Orden de traslado
  if :old.flag_estado = '1' and :new.flag_estado = '2' then

    /*****************************************************
    **** REPLICACION
    *****************************************************/

     update articulo_mov_proy
        set flag_modificacion = '0',
            flag_replicacion  = '0'
      where tipo_doc = ls_doc_otr
        and nro_doc  = :new.nro_otr;
    /*****************************************************/
     return;
  end if;

  -- Desaprobando la Orden de traslado
  if :old.flag_estado = '2' and :new.flag_estado = '1' then

    /*****************************************************
    **** REPLICACION
    *****************************************************/
     update articulo_mov_proy
        set flag_modificacion = '1',
            flag_replicacion  = '0'
      where tipo_doc = ls_doc_otr
        and nro_doc  = :new.nro_otr;
    /*****************************************************/
     return;
  end if;

end tua_alm_orden_traslado;
/

prompt
prompt Creating trigger TUA_ALM_VALE_MOV
prompt =================================
prompt
CREATE OR REPLACE TRIGGER CANTABRIA.TUA_ALM_VALE_MOV
  after update on vale_mov
  for each row
declare
-- local variables here
  ln_ano               number(4)                       ;
  ln_mes               Number(2)                       ;
  ln_rc                number := 0                     ;
  ln_reg               integer                         ;

  CURSOR c_mov (ls_nro_vale IN articulo_mov.nro_vale%type) is
  select am.cod_art, am.cant_procesada, am.precio_unit
    from articulo_mov am
   where am.nro_vale = ls_nro_vale ;

begin

--  ==============================
--  ** Articulo Saldo Mensual **
--  ==============================
IF :old.fec_registro <> :new.fec_registro or :old.tipo_mov <> :new.tipo_mov then

  For c_as in c_mov(:old.nro_vale)  loop

   -- ** Restando el registro anterior
   ln_ano := to_number(TO_CHAR(:old.fec_registro,'YYYY'));
   ln_mes := to_number(TO_CHAR(:old.fec_registro,'MM'));

--   ln_rc := USF_DEL_ART_SALDO_MENSUAL(ln_ano, ln_mes,c_as.cod_art, :old.almacen, :old.tipo_mov , :old.fec_registro, c_as.cant_procesada, c_as.precio_unit  ) ;

   --  ** Actualizando el registro actual
   ln_ano := to_number(TO_CHAR(:new.fec_registro,'YYYY'));
   ln_mes := to_number(TO_CHAR(:new.fec_registro,'MM'));

--   ln_rc := USF_INS_ART_SALDO_MENSUAL(ln_ano, ln_mes,c_as.cod_art, :new.almacen, :new.tipo_mov , :new.fec_registro, c_as.cant_procesada, c_as.precio_unit  ) ;
  End Loop ;
End If ;

End TUA_ALM_VALE_MOV;
/

prompt
prompt Creating trigger TUA_ARTICULO_MOV
