prompt
CREATE OR REPLACE TRIGGER CANTABRIA.TUA_ARTICULO_MOV
  after update on articulo_mov
  for each row
declare
  -- local variables here
  ls_almacen           almacen.almacen%type           ;
  ln_ano               number(4)                      ;
  ln_mes               Number(2)                      ;
  ls_tipo_mov          articulo_mov_tipo.tipo_mov%type;
