if :old.cod_art <> :new.cod_art or :old.cant_procesada <> :new.cant_procesada or :old.precio_unit <> :new.precio_unit then
    --  ** Restando el registro anterior
    select vm.almacen, vm.tipo_mov, vm.fec_registro
      into ls_almacen, ls_tipo_mov, ld_fecha_reg
