    --ln_rc := USF_DEL_ART_SALDO_MENSUAL(ln_ano, ln_mes,:old.cod_art, ls_almacen, ls_tipo_mov , ld_fecha_reg, :old.cant_procesada, :old.precio_unit  ) ;

    --  ** Actualizando el registro actual
    --ln_rc := USF_INS_ART_SALDO_MENSUAL(ln_ano, ln_mes,:new.cod_art, ls_almacen, ls_tipo_mov , ld_fecha_reg, :new.cant_procesada, :new.precio_unit  ) ;

end if ;
end TUA_ARTICULO_MOV;
/

