prompt
prompt Creating trigger TUA_FIN_CAJA_BANCOS
prompt ====================================
prompt
CREATE OR REPLACE TRIGGER CANTABRIA.TUA_FIN_CAJA_BANCOS
  after update on caja_bancos
  for each row

declare
  -- local variables here
  lc_soles           moneda.cod_moneda%type ;
  lc_dolares         moneda.cod_moneda%type ;
  lc_moneda_des_new  moneda.cod_moneda%type ;
  lc_moneda_des_old  moneda.cod_moneda%type ;
  ln_importe_des_new Number(13,2);
  ln_importe_des_old Number(13,2);

begin

 -- Edgar Morante Miercoles 10Jul2002, replicacion
  If (dbms_reputil.from_remote=true or dbms_snapshot.i_am_a_refresh=true) then
     return;
  end if;

  SELECT cod_soles,cod_dolares
    INTO lc_soles,lc_dolares
    FROM logparam
   WHERE reckey = '1' ;





--inserta tipo de cambio old en tabla temporal
Insert into tt_fin_tasa_cambio_cb
(origen ,nro_registro ,tasa_cambio,fecha_old)
Values
(:new.origen,:new.nro_registro,:old.tasa_cambio,:old.fecha_emision) ;



  IF    :new.flag_tiptran = '1' THEN    /* Transferencias */
        IF :new.cod_ctabco <> :old.cod_ctabco THEN   /**/
           /*Actualizo Banco Origen Nuevo */
           /******************************************************************
            REPLICACION
           *******************************************************************/

           UPDATE banco_cnta
              SET saldo_disponible = (Nvl(saldo_disponible,0) - :new.imp_total) ,flag_replicacion = '0'
            WHERE cod_ctabco = :new.cod_ctabco ;
           /*Actualizo Banco Origen Antiguo */
           /******************************************************************
            REPLICACION
           *******************************************************************/
           UPDATE banco_cnta
              SET saldo_disponible = (Nvl(saldo_disponible,0) + :old.imp_total) ,flag_replicacion = '0'
            WHERE cod_ctabco = :old.cod_ctabco ;
        END IF ;
           /******************************************************************
            REPLICACION
           *******************************************************************/
            UPDATE banco_cnta
               SET saldo_disponible = (Nvl(saldo_disponible,0) + :old.imp_total) - :new.imp_total,flag_replicacion = '0'
             WHERE (cod_ctabco      = :new.cod_ctabco ) AND
                   (:new.cod_ctabco = :old.cod_ctabco );

             /* Recuperacion del Destino de la Moneda */
             SELECT cod_moneda
               INTO lc_moneda_des_new
               FROM banco_cnta
              WHERE cod_ctabco = :new.cod_ctabco_ref ;

             /*Calculo de Importe Nuevo*/
             IF :new.cod_moneda = lc_moneda_des_new THEN
                ln_importe_des_new := :new.imp_total ;
             ELSIF lc_moneda_des_new = lc_soles     THEN
                ln_importe_des_new := Round(:new.imp_total * :new.tasa_cambio ,2);
             ELSIF lc_moneda_des_new = lc_dolares   THEN
                ln_importe_des_new := Round(:new.imp_total / :new.tasa_cambio ,2);
             END IF ;

             /*Calculo de Importe Antiguo*/
             IF :old.cod_moneda = lc_moneda_des_new THEN
                ln_importe_des_old := :old.imp_total ;
             ELSIF lc_moneda_des_new = lc_soles     THEN
                ln_importe_des_old := Round(:old.imp_total * :old.tasa_cambio ,2);
             ELSIF lc_moneda_des_new = lc_dolares   THEN
                ln_importe_des_old := Round(:old.imp_total / :old.tasa_cambio ,2);
             END IF ;

               IF :new.cod_ctabco_ref <> :old.cod_ctabco_ref THEN   /**/
                  /*Actualizo Banco Destino Nuevo */
                  /******************************************************************
                     REPLICACION
                   *******************************************************************/

                  UPDATE banco_cnta
                     SET saldo_disponible = (Nvl(saldo_disponible,0) + ln_importe_des_new),flag_replicacion = '0'
                   WHERE cod_ctabco = :new.cod_ctabco_ref ;

                /* Recuperacion del Destino de la Moneda Antiguo*/
                SELECT cod_moneda
                  INTO lc_moneda_des_old
                  FROM banco_cnta
                 WHERE cod_ctabco = :old.cod_ctabco_ref ;

                /*Calculo de Importe Antiguo*/
                IF :old.cod_moneda = lc_moneda_des_old THEN
                   ln_importe_des_old := :old.imp_total ;
                ELSIF lc_moneda_des_old = lc_soles     THEN
                   ln_importe_des_old := Round(:old.imp_total * :old.tasa_cambio ,2);
                ELSIF lc_moneda_des_old = lc_dolares   THEN
                   ln_importe_des_old := Round(:old.imp_total / :old.tasa_cambio ,2);
                END IF ;

                 /*Actualizo Banco destino Antiguo */
                 /******************************************************************
                   REPLICACION
                  *******************************************************************/

                 UPDATE banco_cnta
                    SET saldo_disponible = (Nvl(saldo_disponible,0) - ln_importe_des_old),flag_replicacion = '1'
                  WHERE cod_ctabco = :old.cod_ctabco_ref ;

              END IF ;

             /******************************************************************
               REPLICACION
              *******************************************************************/
             UPDATE banco_cnta
                SET saldo_disponible = (Nvl(saldo_disponible,0) - ln_importe_des_old) + ln_importe_des_new ,flag_replicacion = '0'
              WHERE ( cod_ctabco         = :new.cod_ctabco_ref ) AND
                    (:new.cod_ctabco_ref = :old.cod_ctabco_ref );


  ELSIF :new.flag_tiptran = '2' THEN /*Cartera de Pagos*/
           IF :new.cod_ctabco <> :old.cod_ctabco THEN   /**/
              /*Actualizo Banco Origen Nuevo */
              /******************************************************************
               REPLICACION
              *******************************************************************/
              UPDATE banco_cnta
                 SET saldo_disponible = (Nvl(saldo_disponible,0) - :new.imp_total),flag_replicacion = '0'
               WHERE cod_ctabco = :new.cod_ctabco ;

              /*Actualizo Banco Origen Antiguo */
              /******************************************************************
               REPLICACION
              *******************************************************************/
              UPDATE banco_cnta
                 SET saldo_disponible = (Nvl(saldo_disponible,0) + :old.imp_total),flag_replicacion = '0'
               WHERE cod_ctabco = :old.cod_ctabco ;
           END IF ;

           /******************************************************************
               REPLICACION
           *******************************************************************/
           UPDATE banco_cnta
              SET saldo_disponible = (Nvl(saldo_disponible,0) + :old.imp_total) - :new.imp_total,flag_replicacion = '0'
            WHERE (cod_ctabco      = :new.cod_ctabco ) AND
                  (:new.cod_ctabco = :old.cod_ctabco );

  ELSIF :new.flag_tiptran = '3' THEN /*Cartera de Cobros*/
           IF :new.cod_ctabco <> :old.cod_ctabco THEN   /**/
              /*Actualizo Banco Origen Nuevo */
              /******************************************************************
                REPLICACION
               *******************************************************************/

              UPDATE banco_cnta
                 SET saldo_disponible = (Nvl(saldo_disponible,0) + :new.imp_total),flag_replicacion = '0'
               WHERE cod_ctabco = :new.cod_ctabco ;
              /*Actualizo Banco Origen Antiguo */

              /******************************************************************
                REPLICACION
               *******************************************************************/

              UPDATE banco_cnta
                 SET saldo_disponible = (Nvl(saldo_disponible,0) - :old.imp_total),flag_replicacion = '0'
               WHERE cod_ctabco = :old.cod_ctabco ;

           END IF ;

           /******************************************************************
             REPLICACION
           *******************************************************************/
           UPDATE banco_cnta
              SET saldo_disponible = (Nvl(saldo_disponible,0) - :old.imp_total) + :new.imp_total,flag_replicacion = '0'
            WHERE (cod_ctabco      = :new.cod_ctabco ) AND
                  (:new.cod_ctabco = :old.cod_ctabco );

  END IF ;

end TUA_FIN_CAJA_BANCOS;
/

prompt
prompt Creating trigger TUA_FIN_CAJA_BANCOS_DET
prompt ========================================
prompt
CREATE OR REPLACE TRIGGER CANTABRIA.TUA_FIN_CAJA_BANCOS_DET
  after update on caja_bancos_det
  for each row
declare
  -- local variables here
  lc_flag_tiptran    caja_bancos.flag_tiptran%type   ;
  ln_monto_total      caja_bancos_det.importe%type   ;
  ln_saldo_sol        caja_bancos_det.importe%type   ;
  ln_saldo_dol        caja_bancos_det.importe%type   ;
  ln_imp_dol_old      caja_bancos_det.importe%type   ;
  ln_imp_sol_old      caja_bancos_det.importe%type   ;
  ln_Tasa_cambio          caja_bancos_det.importe%type   ;
  ls_soles            logparam.cod_soles%type        ;
  ls_dolares          logparam.cod_soles%type        ;
  lc_flag_estado      caja_bancos.flag_estado%type   ;
  ln_saldo_sol_old    caja_bancos_det.importe%type   ;
  ln_saldo_dol_old    caja_bancos_det.importe%type   ;
  ln_saldo_sol_new    caja_bancos_det.importe%type   ;
  lc_origen           caja_bancos.origen%type        ;
  ln_ano              caja_bancos.ano%type           ;
  ln_mes              caja_bancos.mes%type           ;
  ln_nro_libro        caja_bancos.nro_libro%type     ;
  ln_nro_asiento      caja_bancos.nro_asiento%type   ;
  ld_fecha            caja_bancos.fecha_emision%type ;
  ln_count            number ;
  ln_count_cad        number ;
  ln_cnta_ctbl        cntbl_cnta.cnta_ctbl%type               ;
  lc_flag_caja_bancos cntas_pagar.flag_caja_bancos%type       ;
  lc_cnta_ctbl        doc_pendientes_cta_cte.cnta_ctbl%type   ;
  lc_flag_ctrl_reg    cntas_cobrar.flag_control_reg%type      ;
  lb_control          boolean ;

  -- Presupuesto_caja
  ls_moneda_prsp       prsp_caja_det.cod_moneda%TYPE;
  ln_imp_ejecutado     prsp_caja_det.imp_ejecutado%TYPE;

  -- Comprobante de retencion
  ls_doc_cri           finparam.doc_ret_igv_crt%TYPE;
  ls_flag_tiptran      caja_bancos.flag_tiptran%TYPE;
  ln_imp_soles         retencion_igv_crt.saldo_sol%TYPE;
  ln_imp_dolar         retencion_igv_crt.saldo_dol%TYPE;
  ln_imp_retencion     retencion_igv_crt.importe_doc%TYPE;
  ln_Tasa_cambio_cri       retencion_igv_crt.tasa_cambio%TYPE;

begin


  /*******************************************************
   REPLICACION
  ********************************************************/
  IF ORA_LOGIN_USER = 'REPP5' THEN
     RETURN ;
  END IF;


  lb_control := FALSE ;

  select cb.flag_tiptran ,cb.tasa_cambio,
         cb.origen       ,cb.ano        ,
         cb.mes          ,cb.nro_libro  ,
         cb.nro_asiento  ,cb.fecha_emision,
         cb.flag_tiptran
    into lc_flag_tiptran ,ln_Tasa_cambio  ,
         lc_origen       ,ln_ano      ,
         ln_mes          ,ln_nro_libro,
         ln_nro_asiento  ,ld_fecha,
         ls_flag_tiptran
    from caja_bancos cb
   where (origen       = :new.origen      ) and
         (nro_registro = :new.nro_registro) ;

  -- Parametros de Logistica
  select cod_soles,cod_dolares
    into ls_soles,ls_dolares
    from logparam
   where reckey = '1' ;

  -- Parametros de Finanzas
  select f.doc_ret_igv_crt
    into ls_doc_cri
    from finparam f
   where f.reckey = '1';

  -- Los cri solo pueden pagarse por cartera de pagos, al ser un documento exclusivo de pago para retenciones
  if :old.tipo_doc = ls_doc_cri then
     if :new.importe <> :old.importe then
        if ls_flag_tiptran <> '2' then
           RAISE_APPLICATION_ERROR(-20000, 'Los comprobantes de Retencion solo pueden estar en cartera de pagos, por favor verifique!'
                                       || chr(13) || 'Cod Relacion: ' || :old.cod_relacion
                                       || chr(13) || 'Tipo Doc: ' || :old.tipo_doc
                                       || chr(13) || 'Nro Doc: ' || :old.nro_doc);
        end if;

        -- Si es cartera de pagos entonces simplemente obtengo los datos que necesito
        -- Obtengo los datos del comprobante de retencion
        select count(*)
          into ln_count
          from retencion_igv_crt t
         where t.nro_certificado = :old.nro_doc;

        if ln_count = 0 then
           RAISE_APPLICATION_ERROR(-20000, 'El Comprobante de retencion no existe, por favor verifique!'
                                       || chr(13) || 'Cod Relacion: ' || :old.cod_relacion
                                       || chr(13) || 'Tipo Doc: ' || :old.tipo_doc
                                       || chr(13) || 'Nro Doc: ' || :old.nro_doc);
        end if;

        -- Calculo los importes para todos lo demas que venga
        if :old.cod_moneda = ls_soles then
           ln_imp_soles := :old.importe;
           ln_imp_dolar := :old.importe / ln_tasa_cambio;
        else
           ln_imp_soles := :old.importe * ln_tasa_cambio;
           ln_imp_dolar := :old.importe;
        end if;

        select saldo_sol, saldo_dol, t.tasa_cambio
          into ln_saldo_sol, ln_saldo_dol, ln_Tasa_cambio_cri
          from retencion_igv_crt t
         where t.nro_certificado = :old.nro_doc for update;

        if ln_saldo_sol + ln_imp_soles >= ln_imp_retencion then
           ln_saldo_sol := ln_imp_retencion;
           ln_saldo_dol := ln_saldo_sol / ln_Tasa_cambio_cri;
           /*RAISE_APPLICATION_ERROR(-20000, 'Importe por Pagado excede al saldo del Comprobante de Retencion, por favor verifique!'
                                       || chr(13) || 'Cod Relacion: ' || :old.cod_relacion
                                       || chr(13) || 'Tipo Doc: ' || :old.tipo_doc
                                       || chr(13) || 'Nro Doc: ' || :old.nro_doc
                                       || chr(13) || 'Saldo S/.: ' || to_Char(ln_saldo_sol, '999,990.00')
                                       || chr(13) || 'Importe a Pagar: ' || to_Char(ln_imp_soles, '999,990.00'));*/

        else
           ln_saldo_sol := ln_saldo_sol + ln_imp_soles;
           ln_saldo_dol := ln_saldo_dol + ln_imp_dolar;
        end if;

        if ln_saldo_dol > ln_imp_retencion / ln_Tasa_cambio_cri then
           ln_saldo_dol := ln_saldo_sol / ln_Tasa_cambio_cri;
        end if;

        update retencion_igv_crt r
           set r.saldo_sol = ln_saldo_sol,
               r.saldo_dol = ln_saldo_dol
         where r.nro_certificado = :old.nro_doc;

     end if;

  end if;

  --Este cambio corresponde a la ejecucion del presupuesto de Caja
  if :old.nro_prsp is not null and :old.item_prsp is not null then
     if :old.importe             <> :new.importe or
        nvl(:old.nro_prsp, 'XX') <> nvl(:new.nro_prsp, 'XX') or
        nvl(:old.item_prsp, 0)   <> nvl(:new.item_prsp, 0) then

        -- Obtengo la moneda de la cabecera del presupuesto de caja
        select cod_moneda, nvl(pd.imp_ejecutado, 0)
          into ls_moneda_prsp, ln_imp_ejecutado
          from prsp_caja_det pd
         where pd.nro_presupuesto  = :old.nro_prsp
           and pd.nro_item         = :old.item_prsp for update;

        if :old.cod_moneda = ls_moneda_prsp then
           ln_imp_ejecutado := ln_imp_ejecutado - :old.importe;
        elsif :old.cod_moneda = ls_soles then
           ln_imp_ejecutado := ln_imp_ejecutado - :old.importe * ln_tasa_cambio;
        elsif :old.cod_moneda = ls_dolares then
           ln_imp_ejecutado := ln_imp_ejecutado - :old.importe / ln_tasa_cambio;
        end if;

        if ln_imp_ejecutado < 0 then ln_imp_ejecutado := 0; end if;

        -- Actualizo el importe ejecutado
        update prsp_caja_det pd
           set pd.imp_ejecutado = ln_imp_ejecutado
         where pd.nro_presupuesto  = :old.nro_prsp
           and pd.nro_item         = :old.item_prsp;

     end if;

  end if;

  -- Los cri solo pueden pagarse por cartera de pagos, al ser un documento exclusivo de pago para retenciones
  if :new.tipo_doc = ls_doc_cri then
     if :new.importe <> :old.importe then
         if ls_flag_tiptran <> '2' then
            RAISE_APPLICATION_ERROR(-20000, 'Los comprobantes de Retencion solo pueden estar en cartera de pagos, por favor verifique!'
                                       || chr(13) || 'Cod Relacion: ' || :new.cod_relacion
                                       || chr(13) || 'Tipo Doc: ' || :new.tipo_doc
                                       || chr(13) || 'Nro Doc: ' || :new.nro_doc);
         end if;

         -- Si es cartera de pagos entonces simplemente obtengo los datos que necesito
         -- Obtengo los datos del comprobante de retencion
         select count(*)
           into ln_count
           from retencion_igv_crt t
          where t.nro_certificado = :new.nro_doc;

         if ln_count = 0 then
            RAISE_APPLICATION_ERROR(-20000, 'El Comprobante de retencion no existe, por favor verifique!'
                                       || chr(13) || 'Cod Relacion: ' || :new.cod_relacion
                                       || chr(13) || 'Tipo Doc: ' || :new.tipo_doc
                                       || chr(13) || 'Nro Doc: ' || :new.nro_doc);
         end if;

         -- Calculo los importes para todos lo demas que venga
         if :new.cod_moneda = ls_soles then
            ln_imp_soles := :new.importe;
            ln_imp_dolar := :new.importe / ln_tasa_cambio;
         else
            ln_imp_soles := :new.importe * ln_tasa_cambio;
            ln_imp_dolar := :new.importe;
         end if;

         select saldo_sol, saldo_dol
           into ln_saldo_sol, ln_saldo_dol
           from retencion_igv_crt t
          where t.nro_certificado = :new.nro_doc for update;

         if ln_saldo_sol - ln_imp_soles < 0 then
            RAISE_APPLICATION_ERROR(-20000, 'Importe por Pagado excede al saldo del Comprobante de Retencion, por favor verifique!'
                                       || chr(13) || 'Cod Relacion: ' || :new.cod_relacion
                                       || chr(13) || 'Tipo Doc: ' || :new.tipo_doc
                                       || chr(13) || 'Nro Doc: ' || :new.nro_doc
                                       || chr(13) || 'Saldo S/.: ' || to_Char(ln_saldo_sol, '999,990.00')
                                       || chr(13) || 'Importe a Pagar: ' || to_Char(ln_imp_soles, '999,990.00'));

         end if;
         ln_saldo_sol := ln_saldo_sol - ln_imp_soles;
         ln_saldo_dol := ln_saldo_dol - ln_imp_dolar;

         if ln_saldo_dol < 0 then ln_saldo_dol := 0; end if;

         update retencion_igv_crt r
            set r.saldo_sol = ln_saldo_sol,
                r.saldo_dol = ln_saldo_dol
          where r.nro_certificado = :new.nro_doc;
     end if;

  end if;

  --Este cambio corresponde a la ejecucion del presupuesto de Caja
  if :new.nro_prsp is not null and :new.item_prsp is not null then
     if :old.importe             <> :new.importe or
        nvl(:old.nro_prsp, 'XX') <> nvl(:new.nro_prsp, 'XX') or
        nvl(:old.item_prsp, 0)   <> nvl(:new.item_prsp, 0) then

         -- Obtengo la moneda de la cabecera del presupuesto de caja
         select cod_moneda, nvl(pd.imp_ejecutado, 0)
           into ls_moneda_prsp, ln_imp_ejecutado
           from prsp_caja_det pd
          where pd.nro_presupuesto  = :new.nro_prsp
            and pd.nro_item         = :new.item_prsp for update;

         if :new.cod_moneda = ls_moneda_prsp then
            ln_imp_ejecutado := ln_imp_ejecutado + :new.importe;
         elsif :new.cod_moneda = ls_soles then
            ln_imp_ejecutado := ln_imp_ejecutado + :new.importe * ln_tasa_cambio;
         elsif :new.cod_moneda = ls_dolares then
            ln_imp_ejecutado := ln_imp_ejecutado + :new.importe / ln_tasa_cambio;
         end if;

         -- Actualizo el importe ejecutado
         update prsp_caja_det pd
            set pd.imp_ejecutado = ln_imp_ejecutado
          where pd.nro_presupuesto  = :new.nro_prsp
            and pd.nro_item         = :new.item_prsp;

     end if;
  end if;

    if :old.importe <> :new.importe or
       :old.impt_ret_igv <> :new.impt_ret_igv then

       IF (lc_flag_tiptran = '2' OR lc_flag_tiptran = '3' OR lc_flag_tiptran = '4') THEN --CARTERADE PAGOS ,CARTERA DE COBROS ,APLICACION DE DOCUMENTOS

           if :new.flab_tabor = '1' then --cuentas por cobrar
              select cc.flag_estado,cc.flag_caja_bancos,cc.flag_control_reg
                into lc_flag_estado,lc_flag_caja_bancos,lc_flag_ctrl_reg
                from cntas_cobrar cc
               where cc.cod_relacion = :new.cod_relacion
                 and cc.tipo_doc     = :new.tipo_doc
                 and cc.nro_doc      = :new.nro_doc for update;

              /*verificaicon de asignacion en grupo de doc tipo cta cte*/
              select count(*)
                into ln_count
                from doc_grupo_relacion dg
               where dg.grupo    = 'C1'
                 and dg.tipo_doc = :new.tipo_doc ;

           elsif :new.flab_tabor = '3' then --cuentas por pagar

              select cp.flag_estado,cp.flag_caja_bancos,cp.flag_control_reg
                into lc_flag_estado,lc_flag_caja_bancos,lc_flag_ctrl_reg
                from cntas_pagar cp
               where cp.cod_relacion = :new.cod_relacion
                 and cp.tipo_doc     = :new.tipo_doc
                 and cp.nro_doc      = :new.nro_doc    for update;

              /*verificaicon de asignaci?n en grupo de doc tipo cta cte*/
              select count(*)
                into ln_count
                from doc_grupo_relacion dg
               where dg.grupo    = 'C2'
                 and dg.tipo_doc = :new.tipo_doc ;

            end if ;


            if lc_flag_ctrl_reg = '1' and lc_flag_caja_bancos = '1' then --documento por cobrar verifico si es cuenta corriente
               if ln_count = 0 then
                  raise_application_error(-20000,'Verifique Documento '||:new.tipo_doc||' no esta Considerado en Grupo de Cta Cte') ;
               end if ;

               --verificar que sea transacion de tipo cuenta corriente
               if lc_flag_tiptran = '2' or lc_flag_tiptran = '4' then --cartera de pagos y aplicacion de documentos
                  if :new.factor = -1  and :new.flab_tabor = '1' then --primer cobro de cntas cobrar
                     --enciende control de cta cte
                     lb_control := TRUE ;
                  elsif :new.factor = 1  and :new.flab_tabor = '3' then --primer pago de cntas pagar
                     --enciende control de cta cte
                     lb_control := TRUE ;
                  end if ;

               elsif lc_flag_tiptran = '3' then --cartera de cobros
                  if :new.factor = 1  and :new.flab_tabor = '1' then --primer cobro de cntas cobrar
                     --enciende control de cta cte
                     lb_control := TRUE ;
                  elsif :new.factor = -1  and :new.flab_tabor = '3' then --primer pago de cntas pagar
                     --enciende control de cta cte
                     lb_control := TRUE ;
               end if ;
            end if ;

            if lb_control = TRUE then
               if not(:new.importe = :old.importe and :new.confin = :old.confin) then
                  if lc_flag_estado <> '1' then
                     raise_application_error(-20000,'Verifique Documento '||:new.cod_relacion||' '||:new.tipo_doc||' '||:new.nro_doc ||' ya ha sido Aplicado') ;
                  end if;
               end if ;

               select count(*)
                 into ln_count_cad
                 from cntbl_asiento_det cad
                where cad.origen       = lc_origen
                  and cad.ano          = ln_ano
                  and cad.mes          = ln_mes
                  and cad.nro_libro    = ln_nro_libro
                  and cad.nro_asiento  = ln_nro_asiento
                  and cad.cod_relacion = :new.cod_relacion
                  and cad.tipo_docref1 = :new.tipo_doc
                  and cad.nro_docref1  = :new.nro_doc
                  and cad.imp_movsol   > 0
                  and cad.imp_movdol   > 0;

               if ln_count_cad > 0 then
                  --BUSCAR CUENTA CONTABLE
                  select cad.cnta_ctbl
                    into ln_cnta_ctbl
                    from cntbl_asiento_det cad
                   where cad.origen       = lc_origen
                     and cad.ano          = ln_ano
                     and cad.mes          = ln_mes
                     and cad.nro_libro    = ln_nro_libro
                     and cad.nro_asiento  = ln_nro_asiento
                     and cad.cod_relacion = :new.cod_relacion
                     and cad.tipo_docref1 = :new.tipo_doc
                     and cad.nro_docref1  = :new.nro_doc
                     and cad.imp_movsol   > 0
                     and cad.imp_movdol   > 0
                     and rownum = 1;
               end if ;

               update doc_pendientes_cta_cte dp
                  set dp.cnta_ctbl   = ln_cnta_ctbl ,
                      dp.flag_replicacion = '1'
                where dp.cod_relacion = :new.cod_relacion
                  and dp.tipo_doc     = :new.tipo_doc
                  and dp.nro_doc      = :new.nro_doc      ;

              RETURN ;
           end if ;
        end if ;

        --REFERENCIA / DIRECTO / ORDEN DE GIRO ...
        IF (:new.flag_provisionado = 'R' OR :new.flag_provisionado = 'D' OR :new.flag_provisionado = 'O') THEN

          if :new.flab_tabor = '1' then /*cuentas x cobrar*/

             select importe_doc,Nvl(saldo_sol,0),Nvl(saldo_dol,0),flag_caja_bancos
               into ln_monto_total,ln_saldo_sol,ln_saldo_dol,lc_flag_caja_bancos
               from cntas_cobrar
              where origen       = :new.origen_doc
                AND cod_relacion = :new.cod_relacion
                AND tipo_doc     = :new.tipo_doc
                AND nro_doc      = :new.nro_doc  for update;

              ln_imp_dol_old := ln_saldo_dol ;
              ln_imp_sol_old := ln_saldo_sol ;


              if :new.cod_moneda = ls_soles then
                 ln_saldo_sol := ((ln_saldo_sol + Nvl(:old.importe,0)) - Nvl(:new.importe,0))  ;
                 ln_saldo_dol := (ln_saldo_dol  + Round(Nvl(:old.importe,0) / ln_Tasa_cambio,2)) - Round(Nvl(:new.importe,0) / ln_Tasa_cambio,2) ;

                 if ln_saldo_sol = 0 then --pagado totalmente
                    lc_flag_estado := '3' ;
                 elsif ln_monto_total = ln_saldo_sol then --generado
                    lc_flag_estado := '1';
                 elsif ln_saldo_sol > 0 then    --pagado parcialmente
                    lc_flag_estado := '2';
                 end if ;

              elsif :new.cod_moneda = ls_dolares then
                 ln_saldo_sol_old := 0.00 ;
                 ln_saldo_dol_old := 0.00 ;

                 --monto anterior a transaci?n x diferencia en cambio
                 usp_fin_monto_asiento_x_doc(lc_origen,ln_ano,ln_mes,ln_nro_libro,ln_nro_asiento,:new.cod_relacion,:new.tipo_doc,:new.nro_doc,ln_saldo_sol_old,ln_saldo_dol_old);

                 ln_saldo_sol_new := ln_saldo_sol_old ;

                 ln_saldo_sol_old := Nvl(ln_saldo_sol_old,0) + Nvl(ln_imp_sol_old,0) ;
                 ln_saldo_sol_new := Nvl(ln_saldo_sol_new,0) + Nvl(ln_imp_sol_old,0) ;
                 ln_saldo_dol_old := Nvl(ln_saldo_dol_old,0) + Nvl(ln_imp_dol_old,0) ;

                 ln_saldo_sol_old := Round(ln_saldo_dol_old * ln_Tasa_cambio,2) -ln_saldo_sol_old ;
                 ln_saldo_sol_new := Round(ln_saldo_dol_old * ln_Tasa_cambio,2) - ln_saldo_sol_new;

                 --TERMINA CALCULO DE DIFERENCIA EN CAMBIO
                 ln_saldo_dol := ((ln_saldo_dol + Nvl(:old.importe,0)) - Nvl(:new.importe,0))  ;
                 ln_saldo_sol := (ln_saldo_sol  + (Round(Nvl(:old.importe,0) * ln_Tasa_cambio,2) - ln_saldo_sol_old) ) - Round(Nvl(:new.importe,0) * ln_Tasa_cambio,2) ;

                 --aumento monto por diferencia en cambio en columna de soles
                 ln_saldo_sol := ln_saldo_sol + ln_saldo_sol_new ;

                 if ln_saldo_dol = 0 then --pagado totalmente
                    lc_flag_estado := '3' ;
                 elsif ln_monto_total = ln_saldo_dol then --generado
                    lc_flag_estado := '1';
                 elsif ln_saldo_dol > 0 then    --pagado parcialmente
                    lc_flag_estado := '2';
                 end if ;

              end if ;

              /**/
              /*****************************************************************************
                  REPLICACION (replicar registro)
              ******************************************************************************/
              UPDATE cntas_cobrar
                 SET flag_estado = lc_flag_estado ,
                     saldo_sol   = ln_saldo_sol,
                     saldo_dol   = ln_saldo_dol,
                     flag_replicacion = '1'
               WHERE origen       = :new.origen_doc
                 AND cod_relacion = :new.cod_relacion
                 AND tipo_doc     = :new.tipo_doc
                 AND nro_doc      = :new.nro_doc     ;

              /*Actualizar Doc_Pendientes_cta_cte*/
              if lc_flag_caja_bancos = '1' THEN  --cta cte ha sido cancelada
                 --buscar cta ctble de ultima transacion
                 select min(cnta_ctbl) into lc_cnta_ctbl from cntbl_asiento_det
                  where (cod_relacion = :new.cod_relacion ) and (tipo_docref1 = :new.tipo_doc) and
                        (nro_docref1  = :new.nro_doc      ) ;

                 /*REPLICACION*/
                 update doc_pendientes_cta_cte
                    set cnta_ctbl = lc_cnta_ctbl,
                        flag_replicacion = '1'
                  where (cod_relacion = :new.cod_relacion ) and
                        (tipo_doc     = :new.tipo_doc     ) and
                        (nro_doc      = :new.nro_doc      ) ;

              end if ;


           ELSIF :new.flab_tabor = '6' then /*solicitud de giro*/

              select importe_doc,Nvl(saldo_sol,0),Nvl(saldo_dol,0)
                into ln_monto_total,ln_saldo_sol,ln_saldo_dol
                from solicitud_giro sg
               where (( origen        = :new.origen_doc ) AND
                      ( nro_solicitud = :new.nro_doc    ));


              ln_saldo_sol := abs(ln_saldo_sol) ;
              ln_saldo_dol := abs(ln_saldo_dol) ;

              ln_imp_dol_old := ln_saldo_dol ;
              ln_imp_sol_old := ln_saldo_sol ;


              if :new.cod_moneda = ls_soles then
                 ln_saldo_sol := ((ln_saldo_sol + Nvl(:old.importe,0)) - Nvl(:new.importe,0))  ;
                 ln_saldo_dol := (ln_saldo_dol  + Round(Nvl(:old.importe,0) / ln_Tasa_cambio,2)) - Round(Nvl(:new.importe,0) / ln_Tasa_cambio,2) ;


              elsif :new.cod_moneda = ls_dolares then
                 ln_saldo_sol_old := 0.00 ;
                 ln_saldo_dol_old := 0.00 ;

                 --monto anterior a transaci?n x diferencia en cambio
                 usp_fin_monto_asiento_x_doc(lc_origen,ln_ano,ln_mes,ln_nro_libro,ln_nro_asiento,:new.cod_relacion,:new.tipo_doc,:new.nro_doc,ln_saldo_sol_old,ln_saldo_dol_old);

                 ln_saldo_sol_new := ln_saldo_sol_old ;

                 ln_saldo_sol_old := Nvl(ln_saldo_sol_old,0) + Nvl(ln_imp_sol_old,0) ;
                 ln_saldo_sol_new := Nvl(ln_saldo_sol_new,0) + Nvl(ln_imp_sol_old,0) ;
                 ln_saldo_dol_old := Nvl(ln_saldo_dol_old,0) + Nvl(ln_imp_dol_old,0) ;

                 ln_saldo_sol_old := Round(ln_saldo_dol_old * ln_Tasa_cambio,2) -ln_saldo_sol_old ;
                 ln_saldo_sol_new := Round(ln_saldo_dol_old * ln_Tasa_cambio,2) - ln_saldo_sol_new;

                 --TERMINA CALCULO DE DIFERENCIA EN CAMBIO

                 ln_saldo_dol := ((ln_saldo_dol + Nvl(:old.importe,0)) - Nvl(:new.importe,0))  ;
                 ln_saldo_sol := (ln_saldo_sol  + (Round(Nvl(:old.importe,0) * ln_Tasa_cambio,2) - ln_saldo_sol_old) ) - Round(Nvl(:new.importe,0) * ln_Tasa_cambio,2) ;

                 --aumento monto por diferencia en cambio en columna de soles
                 ln_saldo_sol := ln_saldo_sol + ln_saldo_sol_new ;


              end if ;

              /**/
              /*****************************************************************************
                  REPLICACION (replicar registro)
              ******************************************************************************/
              UPDATE solicitud_giro
                 SET saldo_sol = ln_saldo_sol,saldo_dol = ln_saldo_dol,flag_replicacion = '1'
               WHERE ((origen        = :new.origen_doc ) AND
                      (nro_solicitud = :new.nro_doc    )) ;

           ELSIF :new.flab_tabor = '3' then /*cuentas x PAGAR*/
              select cp.importe_doc,Nvl(cp.saldo_sol,0),Nvl(cp.saldo_dol,0),cp.flag_caja_bancos
                into ln_monto_total,ln_saldo_sol,ln_saldo_dol,lc_flag_caja_bancos
                from cntas_pagar cp,doc_tipo dt
               where  ( cp.tipo_doc   = dt.tipo_doc       ) AND
                     (( cp.origen       = :new.origen_doc   ) AND
                      ( cp.cod_relacion = :new.cod_relacion ) AND
                      ( cp.tipo_doc     = :new.tipo_doc     ) AND
                      ( cp.nro_doc      = :new.nro_doc      ));

              ln_imp_dol_old := ln_saldo_dol ;
              ln_imp_sol_old := ln_saldo_sol ;


              if :new.cod_moneda = ls_soles then
                 ln_saldo_sol := ((ln_saldo_sol + Nvl(:old.importe,0)) - Nvl(:new.importe,0))  ;
                 ln_saldo_dol := (ln_saldo_dol  + Round(Nvl(:old.importe,0) / ln_Tasa_cambio,2)) - Round(Nvl(:new.importe,0) / ln_Tasa_cambio,2) ;

                 if ln_saldo_sol = 0 then --pagado totalmente
                    lc_flag_estado := '3' ;
                 elsif ln_monto_total = ln_saldo_sol then --generado
                    lc_flag_estado := '1';
                 elsif ln_saldo_sol > 0 then    --pagado parcialmente
                    lc_flag_estado := '2';
                 end if ;

              elsif :new.cod_moneda = ls_dolares then
                 ln_saldo_sol_old := 0.00 ;
                 ln_saldo_dol_old := 0.00 ;

                 --monto anterior a transaci?n x diferencia en cambio
                 usp_fin_monto_asiento_x_doc(lc_origen,ln_ano,ln_mes,ln_nro_libro,ln_nro_asiento,:new.cod_relacion,:new.tipo_doc,:new.nro_doc,ln_saldo_sol_old,ln_saldo_dol_old);

                 ln_saldo_sol_new := ln_saldo_sol_old ;

                 ln_saldo_sol_old := Nvl(ln_saldo_sol_old,0) + Nvl(ln_imp_sol_old,0) ;
                 ln_saldo_sol_new := Nvl(ln_saldo_sol_new,0) + Nvl(ln_imp_sol_old,0) ;
                 ln_saldo_dol_old := Nvl(ln_saldo_dol_old,0) + Nvl(ln_imp_dol_old,0) ;

                 ln_saldo_sol_old := Round(ln_saldo_dol_old * ln_Tasa_cambio,2) - ln_saldo_sol_old ;
                 ln_saldo_sol_new := Round(ln_saldo_dol_old * ln_Tasa_cambio,2) - ln_saldo_sol_new;

                 --TERMINA CALCULO DE DIFERENCIA EN CAMBIO

                 ln_saldo_dol := ((ln_saldo_dol + Nvl(:old.importe,0)) - Nvl(:new.importe,0))  ;
                 ln_saldo_sol := (ln_saldo_sol  + (Round(Nvl(:old.importe,0) * ln_Tasa_cambio,2) - ln_saldo_sol_old) ) - Round(Nvl(:new.importe,0) * ln_Tasa_cambio,2) ;

                 --aumento monto por diferencia en cambio en columna de soles
                 ln_saldo_sol := ln_saldo_sol + ln_saldo_sol_new ;

                 if ln_saldo_dol = 0 then --pagado totalmente
                    lc_flag_estado := '3' ;
                 elsif ln_monto_total = ln_saldo_dol then --generado
                    lc_flag_estado := '1';
                 elsif ln_saldo_dol > 0 then    --pagado parcialmente
                    lc_flag_estado := '2';
                 end if ;

              end if ;

              /**/
              /*****************************************************************************
                  REPLICACION (replicar registro)
              ******************************************************************************/
              UPDATE cntas_pagar
                 SET flag_estado = lc_flag_estado , saldo_sol = ln_saldo_sol,saldo_dol = ln_saldo_dol,flag_replicacion = '1'
               WHERE (( origen       = :new.origen_doc   ) AND
                      ( cod_relacion = :new.cod_relacion ) AND
                      ( tipo_doc     = :new.tipo_doc     ) AND
                      ( nro_doc      = :new.nro_doc      ));



              /*Actualizar Doc_Pendientes_cta_cte*/
               if lc_flag_caja_bancos = '1' THEN  --cta cte ha sido cancelada
                  --buscar cta ctble de ultima transacion
                  select min(cnta_ctbl) into lc_cnta_ctbl from cntbl_asiento_det
                   where (cod_relacion = :new.cod_relacion ) and (tipo_docref1 = :new.tipo_doc) and
                         (nro_docref1  = :new.nro_doc      ) ;

                  /*REPLICACION*/
                  update doc_pendientes_cta_cte
                     set cnta_ctbl = lc_cnta_ctbl,flag_replicacion = '1'
                   where (cod_relacion = :new.cod_relacion ) and
                         (tipo_doc     = :new.tipo_doc     ) and
                         (nro_doc      = :new.nro_doc      ) ;

               end if ;

           END IF ;


          null;
       ELSIF (:new.flag_provisionado = 'N' AND rtrim(ltrim(lc_flag_tiptran)) = '2' )THEN
    --INDIRECTO...CARTERA DE PAGOS

          IF (:new.importe <> :old.importe) OR (:new.cod_moneda <> :old.cod_moneda) OR
             (:new.cencos  <> :old.cencos ) OR (:new.cnta_prsp <> :old.cnta_prsp) THEN

             --CABECERA
             /*****************************************************************************
                  REPLICACION (replicar registro)
              ******************************************************************************/
             update cntas_pagar cp
                set cp.importe_doc   = :new.importe ,cp.cod_moneda       = :new.cod_moneda ,
                    cp.tasa_cambio   = ln_Tasa_cambio   ,cp.fecha_registro   = ld_fecha        ,
                    cp.fecha_emision = ld_fecha     ,cp.flag_replicacion = '1'
              where (cp.cod_relacion = :new.cod_relacion ) and
                    (cp.tipo_doc     = :new.tipo_doc     ) and
                    (cp.nro_doc      = :new.nro_doc      ) ;


             --DETALLE
             /*****************************************************************************
                  REPLICACION (replicar registro)
              ******************************************************************************/
             update cntas_pagar_det cpd
                set cpd.importe = :new.importe ,cpd.cencos = :new.cencos,cpd.cnta_prsp = :new.cnta_prsp,cpd.flag_replicacion = '1',
                    cpd.centro_benef = :new.centro_benef
              where (cpd.cod_relacion = :new.cod_relacion ) and
                    (cpd.tipo_doc     = :new.tipo_doc     ) and
                    (cpd.nro_doc      = :new.nro_doc      ) ;
          END IF ;

       ELSIF (:new.flag_provisionado = 'N' AND lc_flag_tiptran = '3' )THEN --INDIRECTO...CARTERADE COBROS
          IF (:new.importe    <> :old.importe   ) OR (:new.cod_moneda <> :old.cod_moneda)  THEN

             --CABECERA
             /*****************************************************************************
                  REPLICACION (replicar registro)
              ******************************************************************************/

             update cntas_cobrar cb
                set cb.importe_doc      = :new.importe ,cb.cod_moneda        = :new.cod_moneda ,
                    cb.tasa_cambio      = ln_Tasa_cambio   ,cb.fecha_registro    = ld_fecha        ,
                    cb.fecha_documento  = ld_fecha     ,cb.fecha_vencimiento = ld_fecha        ,
                    cb.flag_replicacion = '1'
              where (cb.cod_relacion = :new.cod_relacion ) and
                    (cb.tipo_doc     = :new.tipo_doc     ) and
                    (cb.nro_doc      = :new.nro_doc      ) ;


             --DETALLE
             /*****************************************************************************
                REPLICACION (replicar registro)
              ******************************************************************************/
             update cntas_cobrar_det cbd
                set cbd.precio_unitario = :new.importe ,flag_replicacion = '1',
                    cbd.centro_benef = :new.centro_benef
              where (cbd.tipo_doc     = :new.tipo_doc     ) and
                    (cbd.nro_doc      = :new.nro_doc      ) ;
          END IF ;


       END IF;

    end if;

END IF;

end TUA_FIN_CAJA_BANCOS_DET ;
/

prompt
prompt Creating trigger TUA_FIN_CNTAS_COBRAR
prompt =====================================
prompt
CREATE OR REPLACE TRIGGER CANTABRIA.TUA_FIN_CNTAS_COBRAR
  AFTER UPDATE on cntas_cobrar
  for each row

declare
  -- local variables here
  lc_cnta_ctbl   cntbl_cnta.cnta_ctbl%type          ;
  lc_flag_debhab cntbl_asiento_det.flag_debhab%type ;
  ln_factor      doc_tipo.factor%type               ;
  lc_soles       moneda.cod_moneda%type             ;
  lc_dolares     moneda.cod_moneda%type             ;
  --ln_monto_cuota      rrhh_credito_solicitud.importe%type ; ---  tasa de interes
  --lc_concep           rrhh_credito_solicitud.concep%type ; ---  concepto
  --ln_nro_cuotas       rrhh_credito_solicitud.nro_cuotas%type ; ---  nro de cuotas
  --ln_tasa_interes     rrhh_credito_solicitud.tasa_interes%type ; ---  tasa de interes
  --ln_importe          rrhh_credito_solicitud.importe%type ; ---  tasa de interes
  --lc_nro_doc          rrhh_credito_solicitud.nro_solicitud%type ; ---  numero doc
  ln_descuento        rrhh_credito_solicitud.nro_cuotas%type ; ---  nro de Descuentos
  ln_existe_cnta_crrte   integer ;

  --- Jorge Farfan - los cambios estan en la linea 200


begin
  -- Edgar Morante Miercoles 10Jul2002, replicacion
  If (dbms_reputil.from_remote=true or dbms_snapshot.i_am_a_refresh=true) then
     return;
  end if;

  select cod_soles,cod_dolares into lc_soles,lc_dolares from logparam where reckey = '1' ;

  IF :new.flag_detraccion = '1' and :new.flag_estado = '0' THEN
     update detraccion set flag_estado = '0' , importe = 0 where nro_detraccion = :new.nro_detraccion ;
  END IF ;


  select nvl(factor,0) into ln_factor from doc_tipo where (tipo_doc = :new.tipo_doc) ;

  IF ln_factor = 0 THEN
    RAISE_APPLICATION_ERROR(-20000,'Factor de Documento '||:new.tipo_doc||' es Igual a 0 debera colocar Algun Valor 1 o -1') ;
  END IF ;


  --documento provisionado

  IF :new.flag_provisionado = 'R' THEN
     --se ingresa informacion en tabla temporal
     insert into tt_fin_tasa_cambio
     (cod_relacion,tipo_doc,nro_doc,tasa_cambio)
     values
     (:new.cod_relacion,:new.tipo_doc,:new.nro_doc,:old.tasa_cambio) ;


     IF :new.saldo_sol <> 0 OR :new.saldo_dol <> 0 THEN
        --recupero cuenta contable de documento provisionado
        usp_fin_cntbl_asiento_det(:new.origen,:new.ano,:new.mes,:new.nro_libro,:new.nro_asiento,:new.tipo_doc,:new.nro_doc,:new.cod_relacion,lc_cnta_ctbl ,lc_flag_debhab);

        if :new.saldo_sol < 0 or :new.saldo_dol < 0 then --ajuste por conversion
           if :new.cod_moneda = lc_soles then
              if :new.saldo_sol <= 0 then
                 if ln_factor = -1 then
                    ln_factor := 1 ;
                    lc_flag_debhab := 'D' ;
                 else
                    ln_factor := -1 ;
                    lc_flag_debhab := 'H' ;
                 end if ;

              end if;
           else
              if :new.saldo_dol <= 0 then
                 if ln_factor = -1 then
                    ln_factor := 1 ;
                    lc_flag_debhab := 'D' ;
                 else
                    ln_factor := -1 ;
                    lc_flag_debhab := 'H' ;
                 end if ;
             end if;
           end if;

        end if ;

        /*****************************************************************************
         REPLICACION
        ******************************************************************************/

        update doc_pendientes_cta_cte
           set cnta_ctbl = lc_cnta_ctbl        ,cod_moneda  = :new.cod_moneda    ,
               sldo_sol  = abs(:new.saldo_sol) ,saldo_dol   = abs(:new.saldo_dol),
               fecha_doc = :new.fecha_documento,flag_debhab = lc_flag_debhab     ,
               factor    = ln_factor           ,flag_replicacion = '0'           ,
               fecha_vencimiento = :new.fecha_vencimiento
         where ((cod_relacion = :new.cod_relacion ) and
                (tipo_doc     = :new.tipo_doc     ) and
                (nro_doc      = :new.nro_doc      )) ;

        IF SQL%NOTFOUND THEN
           /***************************************************************************
             REPLICACION
           *****************************************************************************/
           Insert into doc_pendientes_cta_cte
           (cod_relacion ,tipo_doc ,nro_doc  ,flag_tabla ,cnta_ctbl ,cod_moneda ,
            flag_debhab  ,sldo_sol ,saldo_dol,fecha_doc  ,factor    ,flag_replicacion,
            fecha_vencimiento)
           Values
           (:new.cod_relacion, :new.tipo_doc  ,:new.nro_doc  ,'1',lc_cnta_ctbl  ,:new.cod_moneda,
            lc_flag_debhab   , abs(:new.saldo_sol) ,abs(:new.saldo_dol),:new.fecha_documento,ln_factor,
            '0' ,:new.fecha_vencimiento) ;
        END IF ;

     ELSE --NO EXISTE SALDO
        DELETE FROM DOC_PENDIENTES_CTA_CTE
        WHERE ((cod_relacion = :new.cod_relacion ) AND
               (tipo_doc     = :new.tipo_doc     ) AND
               (nro_doc      = :new.nro_doc      )) ;
     END IF;

            --- ******************************************************************************************
            --- Cambio de Estado a Eliminacion de una Factura y/o Boleta procesada en Cta. Cte. Trabajador
            --- ******************************************************************************************
            If  :new.flag_estado = '0' then

                select count(*) into ln_descuento  from cnta_crrte_detalle
                where (cod_trabajador = :old.cod_relacion ) and
                      (tipo_doc       = :old.tipo_doc     ) and
                      (nro_doc        = :old.nro_doc      ) ;

                If ln_descuento > 0 then
                   Raise_application_error(-20001, ' No se Puede eliminar el  Documento ' ||:old.nro_doc||'  porque ya se realizo el descuento al Trabajador');
                ElSE

                 select count(*) into ln_existe_cnta_crrte  from cnta_crrte
                  where (cod_trabajador = :old.cod_relacion ) and
                        (tipo_doc       = :old.tipo_doc     ) and
                        (nro_doc        = :old.nro_doc      ) ;

                   If ln_existe_cnta_crrte > 0 then
                      delete from cnta_crrte
                       where (cod_trabajador = :old.cod_relacion ) and
                             (tipo_doc       = :old.tipo_doc     ) and
                             (nro_doc        = :old.nro_doc      ) ;
                      update rrhh_credito_solicitud
                         set flag_estado = '2'
                       where (cod_trabajador = :old.cod_relacion ) and
                             (nro_solicitud  = :old.nro_sol_cred_rrhh) ;
                   End If;
                End If;
            End If;
          --- Fin de Cta. Cte del TRabajador
  ELSIF :new.flag_provisionado = 'D' THEN --DIRECTO SIN PROVISIONAR
     if ln_factor = 1 then
        lc_flag_debhab := 'D' ;
     else
        lc_flag_debhab := 'H' ;
     end if ;

      if :new.saldo_sol < 0 or :new.saldo_dol < 0 then --ajuste por conversion
           if :new.cod_moneda = lc_soles then
              if :new.saldo_sol <= 0 then
                 if ln_factor = -1 then
                    ln_factor := 1 ;
                    lc_flag_debhab := 'D' ;
                 else
                    ln_factor := -1 ;
                    lc_flag_debhab := 'H' ;
                 end if ;

              end if;
           else
              if :new.saldo_dol <= 0 then
                 if ln_factor = -1 then
                    ln_factor := 1 ;
                    lc_flag_debhab := 'D' ;
                 else
                    ln_factor := -1 ;
                    lc_flag_debhab := 'H' ;
                 end if ;
             end if;
           end if;
      end if ;

     if :new.saldo_sol <> 0 or :new.saldo_dol <> 0 then
        IF :new.flag_caja_bancos = '1' THEN
           if ln_factor = -1 then
              lc_flag_debhab := 'D' ;
              ln_factor      := 1   ;
           else
              lc_flag_debhab := 'H' ;
              ln_factor      := -1  ;
           end if;

        END IF ;


        /***************************************************************************
         REPLICACION
        ****************************************************************************/
        update doc_pendientes_cta_cte
           set cod_moneda       = :new.cod_moneda     ,sldo_sol  = abs(:new.saldo_sol)  ,
               saldo_dol        = abs(:new.saldo_dol) ,fecha_doc = :new.fecha_documento ,
               flag_debhab      = lc_flag_debhab      ,factor    = ln_factor            ,
               flag_replicacion = '0'                 ,fecha_vencimiento = :new.fecha_vencimiento
         where ((cod_relacion = :new.cod_relacion ) and
                (tipo_doc     = :new.tipo_doc     ) and
                (nro_doc      = :new.nro_doc      )) ;

        if sql%notfound then
           /***************************************************************************
             REPLICACION
            ****************************************************************************/
           Insert into doc_pendientes_cta_cte
           (cod_relacion,tipo_doc ,nro_doc  ,flag_tabla,cod_moneda,flag_debhab,
            sldo_sol    ,saldo_dol,fecha_doc,factor    ,flag_replicacion,
            fecha_vencimiento)
           Values
           (:new.cod_relacion,:new.tipo_doc ,:new.nro_doc      ,'1',:new.cod_moneda,lc_flag_debhab,
            abs(:new.saldo_sol)   ,abs(:new.saldo_dol),:new.fecha_documento,ln_factor,'0',
            :new.fecha_vencimiento)  ;
        end if ;
     else --no existe saldo
        delete from doc_pendientes_cta_cte
        where (cod_relacion = :new.cod_relacion ) and
              (tipo_doc     = :new.tipo_doc     ) and
              (nro_doc      = :new.nro_doc      ) ;
     end if ;


  -- Para cualquier otro caso, porque hay un monton de flag_provisionado
  ELSE
      if :new.saldo_sol <> 0 or :new.saldo_dol <> 0 then
        update doc_pendientes_cta_cte
           set cod_moneda       = :new.cod_moneda     ,sldo_sol  = abs(:new.saldo_sol)  ,
               saldo_dol        = abs(:new.saldo_dol) ,fecha_doc = :new.fecha_documento,
               flag_replicacion = '0'                 ,fecha_vencimiento = :new.fecha_vencimiento
         where ((cod_relacion = :new.cod_relacion ) and
                (tipo_doc     = :new.tipo_doc     ) and
                (nro_doc      = :new.nro_doc      )) ;
      end if ;
  END IF ;


end TUA_FIN_CNTAS_COBRAR ;
/

prompt
prompt Creating trigger TUA_FIN_CNTAS_COBRAR_DET
prompt =========================================
prompt
CREATE OR REPLACE TRIGGER CANTABRIA.TUA_FIN_CNTAS_COBRAR_DET
  after update on cntas_cobrar_det
  for each row


declare
  -- local variables here
  lc_bol_cobrar  doc_tipo.tipo_doc%type  ;
  lc_fac_cobrar  doc_tipo.tipo_doc%type  ;
  lc_cod_art     cntas_cobrar_det.cod_art%type ;
  lc_origen_ov   origen.cod_origen%type  ;
  lc_doc_ov      doc_tipo.tipo_doc%type  ;
  lc_orden_venta orden_venta.nro_ov%type ;
  lc_flag_estado orden_venta.flag_estado%type ;
  ln_cant_dif    cntas_cobrar_det.cantidad%type ;
  ln_cant_ov     cntas_cobrar_det.cantidad%type ;
  lc_grupo_ventas finparam.doc_ventas%type ;
  ln_count        number ;

  Cursor c_art_mov  is /*Articulo Movimiento Proyectado*/
  SELECT cant_procesada ,
         cant_facturada ,
         cant_proyect
    FROM articulo_mov_proy
   WHERE (tipo_doc = lc_doc_ov      ) AND
         (nro_doc  = lc_orden_venta ) ;

  Cursor c_articulo(as_tipo_doc cntas_cobrar.tipo_doc%type,
                    as_nro_doc  cntas_cobrar.nro_doc%type,
                    as_cod_art  cntas_cobrar_det.cod_art%type)  is
  /*Articulo facturarado a modificar*/
  SELECT a.cod_origen, a.nro_mov,
         nvl(cant_proyect,0) as cant_proyect   ,
         nvl(cant_procesada,0) as cant_procesada ,
         nvl(cant_facturada,0) as cant_facturada ,
         ( nvl(cant_proyect,0) - nvl(cant_facturada,0) ) as cant_x_fact
    FROM articulo_mov_proy a
   WHERE (tipo_doc = as_tipo_doc      ) AND
         (nro_doc  = as_nro_doc ) AND
         (cod_art  = as_cod_art   ) AND
         (flag_estado <>'0'         )
    ORDER BY ( nvl(cant_proyect,0) - nvl(cant_facturada,0) ) desc ;

begin

  -- Edgar Morante Miercoles 10Jul2002, replicacion
  If (dbms_reputil.from_remote=true or dbms_snapshot.i_am_a_refresh=true) then
     return;
  end if;




  SELECT doc_fact_cobrar,doc_bol_cobrar,doc_ventas INTO lc_fac_cobrar, lc_bol_cobrar, lc_grupo_ventas from finparam  WHERE (reckey = '1') ;


  select count(*) into ln_count from doc_grupo_relacion dgr where dgr.grupo = lc_grupo_ventas and dgr.tipo_doc = :old.tipo_doc ;


  IF (ln_count > 0 ) then

      lc_doc_ov      := :new.tipo_ref   ;
      lc_orden_venta := :new.nro_ref    ;
      lc_cod_art     := :new.cod_art    ;

      -- Modifica cantidad facturada
      IF :old.cantidad <> :new.cantidad then

         ln_cant_dif    := ( nvl(:new.cantidad,0) - nvl(:old.cantidad,0))  ;

         FOR rc_art in c_articulo(lc_doc_ov, lc_orden_venta, lc_cod_art ) LOOP
             /*Actualiza Articulo Movimiento Proyectado, si referencia es una orden de venta*/
             IF ln_cant_dif > 0 THEN

                 IF (rc_art.cant_proyect - rc_art.cant_facturada) >= ln_cant_dif THEN
                    ln_cant_ov := ln_cant_dif ;
                 ELSE
                    ln_cant_ov := (rc_art.cant_proyect - rc_art.cant_facturada) ;
                 END IF ;

                 /**********************************************
                   REPLICACION
                 ***********************************************/

                 UPDATE articulo_mov_proy a
                    SET cant_facturada = Nvl(cant_facturada,0) + Nvl(ln_cant_ov,0) ,flag_replicacion = '0'
                  WHERE (a.cod_origen = rc_art.cod_origen) AND
                        (a.nro_mov    = rc_art.nro_mov   ) ;

                 ln_cant_dif := ln_cant_dif - Nvl(ln_cant_ov,0) ;

             ELSIF ln_cant_dif < 0 THEN
                 -- IF (rc_art.cant_proyect - rc_art.cant_facturada) > abs(ln_cant_dif) THEN
                 IF rc_art.cant_facturada > abs(ln_cant_dif) THEN
                    ln_cant_ov := abs(ln_cant_dif) ;
                 ELSE
                    ln_cant_ov := rc_art.cant_facturada ;
                 END IF ;

                 /**********************************************
                   REPLICACION
                 ***********************************************/

                 UPDATE articulo_mov_proy a
                    SET cant_facturada = Nvl(cant_facturada,0) - Nvl(ln_cant_ov,0)  ,flag_replicacion = '0'
                  WHERE (a.cod_origen = rc_art.cod_origen) AND
                        (a.nro_mov    = rc_art.nro_mov   ) ;

                 ln_cant_dif := ln_cant_dif + Nvl(ln_cant_ov,0) ;
             ELSE
                 exit ;
             END IF ;
          END LOOP ;
      END IF ;

      /*
      UPDATE articulo_mov_proy
         SET cant_facturada = (Nvl(cant_facturada,0) -  Nvl(:old.cantidad,0)) + Nvl(:new.cantidad,0)
       WHERE (cod_art  = :new.cod_art   ) AND
             (tipo_doc = lc_doc_ov      ) AND
             (nro_doc  = lc_orden_venta ) ;
       */
       --Modificado el 27/12/2004 Feliz y prospero a?o nuevo JOJOJ
--      lc_flag_estado := '5' ; /*Facturacion Total*/
      /*Verifica Estado de Orden de Venta en Articulo Movimiento Proyectado*/
--      For rc_art_mov in c_art_mov  Loop
--          If Nvl(rc_art_mov.cant_facturada,0) = 0 then
--             If rc_art_mov.cant_proyect > rc_art_mov.cant_procesada  AND  rc_art_mov.cant_procesada > 0  then /*Despachado Parcial*/
--                lc_flag_estado := '2' ; /*Despachado Parcial*/
--             Elsif rc_art_mov.cant_proyect <= rc_art_mov.cant_procesada  AND  rc_art_mov.cant_procesada > 0 then /*Despachado Total  */
--                lc_flag_estado := '3' ; /*Despachado Total*/
--             Elsif Nvl(rc_art_mov.cant_procesada,0) = 0 then
--                lc_flag_estado := '1' ; /*Generado*/
--             End if ;

--          Elsif Nvl(rc_art_mov.cant_facturada,0) > 0 then /*Cantidad Facturada*/
--             If rc_art_mov.cant_proyect > rc_art_mov.cant_facturada  then
--                lc_flag_estado := '4' ;  /*Facturacion Parcial*/
--                Exit ;
--             End if ;
--          End if ;
--      End Loop ;

      /**********************************************
        REPLICACION
      ***********************************************/


--      UPDATE orden_venta
--         SET flag_estado = lc_flag_estado,flag_replicacion = '0'
--       WHERE  (nro_ov     = lc_orden_venta ) ;

  End if;

end TUA_FIN_CNTAS_COBRAR_DET ;
/

prompt
prompt Creating trigger TUA_FIN_CNTAS_PAGAR
prompt ====================================
prompt
CREATE OR REPLACE TRIGGER CANTABRIA.tua_fin_cntas_pagar
  after update on cntas_pagar
  for each row

declare
  -- local variables here
  lc_cnta_ctbl      cntbl_cnta.cnta_ctbl%type          ;
  lc_flag_debhab    cntbl_asiento_det.flag_debhab%type ;
  ln_factor         doc_tipo.factor%type               ;
  ls_soles          logparam.cod_soles%TYPE            ;
  ls_dolares        logparam.cod_dolares%TYPE          ;
  ln_count          number                             ;
  ln_imp_dol_new    cntas_pagar.importe_doc%type       ;
  ln_imp_dol_old    cntas_pagar.importe_doc%type       ;
  ls_doc_lc         ap_param.doc_lc%TYPE               ;


BEGIN

If (dbms_reputil.from_remote=true or dbms_snapshot.i_am_a_refresh=true) then
   return;
end if;

select cod_soles, cod_dolares
  into ls_soles, ls_dolares
from logparam
where reckey = '1' ;

select doc_lc
  into ls_doc_lc
  from ap_param p
 where p.origen = 'XX';

  --FACTOR DE DOCUMENTO
select Nvl(factor,0)
  into ln_factor
  from doc_tipo
where (tipo_doc = :new.tipo_doc) ;

if ln_factor = 0 THEN
   RAISE_APPLICATION_ERROR( -20000, 'Factor de Documento '||:new.tipo_doc|| 'es igual a 0 debera Colocar alguna valor 1 o -1 ' ) ;
end if ;

-- Actualizando "ot_otros_gastos". Cualquier problema con MM
IF ( (:old.cod_moneda  <> :new.cod_moneda)   OR
     (:old.tasa_cambio <> :new.tasa_cambio)  OR
     (:old.importe_doc <> :new.importe_doc)  ) THEN

      SELECT count(*)
        INTO ln_count
        FROM ot_otros_gastos ot
       WHERE ot.cod_relacion = :new.cod_relacion
         AND ot.tipo_doc     = :new.tipo_doc
         AND ot.nro_doc      = :new.nro_doc ;

      IF ln_count > 0 THEN
         -- Calculando nuevo importe
         IF :new.cod_moneda = ls_dolares THEN
            ln_imp_dol_new := :new.importe_doc ;
         ELSE
            IF :new.tasa_cambio > 0 THEN
               ln_imp_dol_new := :new.importe_doc / :new.tasa_cambio ;
            ELSE
               ln_imp_dol_new := 0 ;
            END IF ;
         END IF ;
         -- Calculando antiguo importe
         IF :old.cod_moneda = ls_dolares THEN
            ln_imp_dol_old := :old.importe_doc ;
         ELSE
            IF :old.tasa_cambio > 0 THEN
               ln_imp_dol_old := :new.importe_doc / :new.tasa_cambio ;
            ELSE
               ln_imp_dol_old := 0 ;
            END IF ;
         END IF ;
         -- Actualizando el costo en las ordenes de trabajo afectadas
         UPDATE orden_trabajo ot
            SET ot.costo_ejecutado = NVL(ot.costo_ejecutado,0) + ln_imp_dol_new - ln_imp_dol_old
          WHERE ot.nro_orden IN (SELECT otg.nro_orden
                                   FROM ot_otros_gastos otg
                                  WHERE otg.cod_relacion = :new.cod_relacion
                                    AND otg.tipo_doc     = :new.tipo_doc
                                    AND otg.nro_doc      = :new.nro_doc) ;
      END IF ;
END IF ;

--documento provisionado
IF :new.flag_provisionado = 'R' THEN
   --se ingresa informacion en tabla temporal
   insert into tt_fin_tasa_cambio
   (cod_relacion,tipo_doc,nro_doc,tasa_cambio)
   values
   (:new.cod_relacion,:new.tipo_doc,:new.nro_doc,:old.tasa_cambio) ;



   IF :new.saldo_sol <> 0 OR :new.saldo_dol <> 0 THEN
      --recupero cuenta contable de documento provisionado
      --recuperar datos

        select count(*)
          into ln_count
          from cntbl_asiento_det cad
         where cad.origen            = :new.origen
           and cad.ano               = :new.ano
           and cad.mes               = :new.mes
           and cad.nro_libro         = :new.nro_libro
           and cad.nro_asiento       = :new.nro_asiento
           and cad.cod_relacion      = :new.cod_relacion
           and cad.tipo_docref1      = :new.tipo_doc
           and cad.nro_docref1       = :new.nro_doc;


      if ln_count = 0 then
         RAISE_APPLICATION_ERROR(-20000, 'No existe registros en el asiento para el documento , por favor verifique'
                           || chr(13) || 'Tipo Doc: ' || :new.Tipo_Doc
                           || chr(13) || 'Nro Doc: ' || :new.nro_doc
                           || chr(13) || 'Cod.Relacion: ' || :new.cod_relacion
                           || chr(13) || 'voucher: ' || :new.origen || trim(to_char(:new.ano, '0000')) || trim(to_char(:new.mes, '00')) || trim(to_char(:new.nro_libro, '00'))
                                                     || trim(to_char(:new.nro_Asiento, '000000')));

      end if;
      /*
      if ln_count > 1 then
         RAISE_APPLICATION_ERROR(-20000, 'Existe mas de un registro en el asiento para el documento , por favor verifique'
                           || chr(13) || 'Tipo Doc: ' || :new.Tipo_Doc
                           || chr(13) || 'Nro Doc: ' || :new.nro_doc
                           || chr(13) || 'Cod.Relacion: ' || :new.cod_relacion
                           || chr(13) || 'voucher: ' || :new.origen || trim(to_char(:new.ano, '0000')) || trim(to_char(:new.mes, '00')) || trim(to_char(:new.nro_libro, '00'))
                                                     || trim(to_char(:new.nro_Asiento, '000000')));

      end if;
      */
      select s.cnta_ctbl, s.flag_debhab
        into lc_cnta_ctbl, lc_flag_debhab
        from ( select cad.item, cad.cnta_ctbl, cad.flag_debhab
                 from cntbl_asiento_det cad
                where cad.origen            = :new.origen
                  and cad.ano               = :new.ano
                  and cad.mes               = :new.mes
                  and cad.nro_libro         = :new.nro_libro
                  and cad.nro_asiento       = :new.nro_asiento
                  and cad.cod_relacion      = :new.cod_relacion
                  and cad.tipo_docref1      = :new.tipo_doc
                  and cad.nro_docref1       = :new.nro_doc
                  and cad.cnta_ctbl         not in ('42201101', '42201102')
                order by cad.item) s
       where rownum = 1;


      if :new.saldo_sol < 0 or :new.saldo_dol < 0 then --ajuste por conversion

         if :new.cod_moneda = ls_soles then
            if :new.saldo_sol <= 0 then
               if ln_factor = -1 then
                  ln_factor := 1 ;
                  lc_flag_debhab := 'D' ;
               else
                  ln_factor := -1 ;
                  lc_flag_debhab := 'H' ;
               end if ;

            end if;
         else
            if :new.saldo_dol <= 0 then
               if ln_factor = -1 then
                  ln_factor := 1 ;
                  lc_flag_debhab := 'D' ;
               else
                  ln_factor := -1 ;
                  lc_flag_debhab := 'H' ;
               end if ;

            end if;
         end if;


      end if ;

      /************************************************************************
       REPLICACION
      *************************************************************************/
      update doc_pendientes_cta_cte dp
         set cnta_ctbl = lc_cnta_ctbl        ,cod_moneda  = :new.cod_moneda    ,
             sldo_sol  = Abs(:new.saldo_sol) ,saldo_dol   = Abs(:new.saldo_dol),
             fecha_doc = :new.fecha_emision  ,flag_debhab = lc_flag_debhab     ,
             factor    = ln_factor           ,flag_replicacion = '0'           ,
             fecha_vencimiento = :new.vencimiento
       where ((cod_relacion = :new.cod_relacion ) and
              (tipo_doc     = :new.tipo_doc     ) and
              (nro_doc      = :new.nro_doc      )) ;

      IF SQL%NOTFOUND THEN
         /************************************************************************
           REPLICACION
         *************************************************************************/
         Insert into doc_pendientes_cta_cte
         (cod_relacion ,tipo_doc ,nro_doc  ,flag_tabla ,cnta_ctbl ,cod_moneda       ,
          flag_debhab  ,sldo_sol ,saldo_dol,fecha_doc  ,factor    ,flag_replicacion ,
          fecha_vencimiento)
         Values
         (:new.cod_relacion, :new.tipo_doc  ,:new.nro_doc  ,'3',lc_cnta_ctbl  ,:new.cod_moneda,
          lc_flag_debhab   , Abs(:new.saldo_sol) ,Abs(:new.saldo_dol),:new.fecha_emision,ln_factor,'0',
          :new.vencimiento) ;
      END IF ;


   ELSE --NO EXISTE SALDO
      DELETE FROM DOC_PENDIENTES_CTA_CTE
      WHERE ((cod_relacion = :new.cod_relacion ) AND
             (tipo_doc     = :new.tipo_doc     ) AND
             (nro_doc      = :new.nro_doc      )) ;
   END IF;

ELSIF :new.flag_provisionado = 'D' THEN --DIRECTO SIN PROVISIONAR

   if ln_factor = 1 then
      lc_flag_debhab := 'D' ;
   elsif ln_factor = -1 then
      lc_flag_debhab := 'H' ;
   end if ;


    if :new.saldo_sol < 0 or :new.saldo_dol < 0 then --ajuste por conversion
         if :new.cod_moneda = ls_soles then
            if :new.saldo_sol <= 0 then
               if ln_factor = -1 then
                  ln_factor := 1 ;
                  lc_flag_debhab := 'D' ;
               else
                  ln_factor := -1 ;
                  lc_flag_debhab := 'H' ;
               end if ;

            end if;
         else
            if :new.saldo_dol <= 0 then
               if ln_factor = -1 then
                  ln_factor := 1 ;
                  lc_flag_debhab := 'D' ;
               else
                  ln_factor := -1 ;
                  lc_flag_debhab := 'H' ;
               end if ;

            end if;
         end if;

    end if ;


    IF :new.saldo_sol <> 0 OR :new.saldo_dol <> 0 THEN
       /***********************************************************
         REPLICACION
       ************************************************************/
       IF :new.flag_caja_bancos = '1' THEN
          if ln_factor = -1 then
             lc_flag_debhab := 'D' ;
             ln_factor      := 1   ;
          else
             lc_flag_debhab := 'H' ;
             ln_factor      := -1  ;
          end if;

       END IF ;


       update doc_pendientes_cta_cte
          set cod_moneda       = :new.cod_moneda,sldo_sol  = abs(:new.saldo_sol)    ,
              saldo_dol        = abs(:new.saldo_dol),fecha_doc = :new.fecha_emision,
              flag_replicacion = '0'                ,fecha_vencimiento = :new.vencimiento
        where ((cod_relacion = :new.cod_relacion ) and
               (tipo_doc     = :new.tipo_doc     ) and
               (nro_doc      = :new.nro_doc      )) ;

       IF SQL%NOTFOUND THEN
          /***********************************************************
            REPLICACION
          ************************************************************/
          Insert into doc_pendientes_cta_cte
          (cod_relacion ,tipo_doc ,nro_doc  ,flag_tabla ,cod_moneda ,
           flag_debhab  ,sldo_sol ,saldo_dol,fecha_doc  ,factor     ,
           flag_replicacion ,fecha_vencimiento)
          Values
          (:new.cod_relacion, :new.tipo_doc  ,:new.nro_doc  ,'3',:new.cod_moneda ,
           lc_flag_debhab   , abs(:new.saldo_sol) ,abs(:new.saldo_dol),:new.fecha_emision  ,ln_factor,
           '0',:new.vencimiento) ;

       END IF ;

   ELSE --NO EXISTE SALDO
      DELETE FROM DOC_PENDIENTES_CTA_CTE
      WHERE ((cod_relacion = :new.cod_relacion ) AND
             (tipo_doc     = :new.tipo_doc     ) AND
             (nro_doc      = :new.nro_doc      )) ;
   END IF;
-- Para otros casos de flag_provisionado
ELSE
   IF :new.saldo_sol <> 0 OR :new.saldo_dol <> 0 THEN
       update doc_pendientes_cta_cte
          set cod_moneda       = :new.cod_moneda,
              sldo_sol         = abs(:new.saldo_sol),
              saldo_dol        = abs(:new.saldo_dol),
              fecha_doc        = :new.fecha_emision,
              flag_replicacion = '0'                ,
              fecha_vencimiento = :new.vencimiento
        where ((cod_relacion = :new.cod_relacion ) and
               (tipo_doc     = :new.tipo_doc     ) and
               (nro_doc      = :new.nro_doc      )) ;
   END IF ;
END IF;

--actualiza documentos d epago de planilla
update calc_doc_pagar_plla cdpc
   set flag_estado = :new.flag_estado
 where ((cod_relacion = :new.cod_relacion ) and
        (tipo_doc     = :new.tipo_doc     ) and
        (nro_doc      = :new.nro_doc      )) ;


-- elimina registro en doc_refencias si anula documento
-- Desactiva de control documentario
IF :new.flag_estado='0' THEN
   DELETE FROM doc_referencias d
   WHERE d.cod_relacion=:new.cod_relacion
     AND d.tipo_doc=:new.tipo_doc
     AND d.nro_doc=:new.nro_doc ;

   UPDATE cd_doc_recibido c
      SET c.flag_estado='0',
          c.flag_transfer='1',
          c.cod_user_transfer = null
    WHERE c.cod_relacion = :old.cod_relacion AND
          c.tipo_doc = :old.tipo_doc AND
          SUBSTR(c.nro_doc,1,10) = :old.nro_doc ;
END IF ;

/*if :new.flag_estado = '0' and :new.nro_asiento is not null and:new.tipo_doc <> ls_doc_lc then
   RAISE_APPLICATION_ERROR(-20000, 'Comprobante de Pago de Registro de Compras esta siendo anulado, esta operacion no es permitida, por favor verifique!'
                           || chr(13) || 'Cod Relacion: ' || :new.cod_relacion
                           || chr(13) || 'Tipo Doc: ' || :new.tipo_doc
                           || chr(13) || 'Nro Doc: ' || :new.nro_doc
                           || chr(13) || 'Voucher: ' || :new.origen || '-' || trim(to_char(:new.ano, '0000')) || '-'
                                      || trim(to_char(:new.mes, '00')) || '-'
                                      || trim(to_char(:new.nro_libro, '00')) || '-'
                                      || trim(to_char(:new.nro_asiento, '000000')) );
end if;*/


END tia_fin_cntas_pagar;
/

prompt
prompt Creating trigger TUA_FIN_DOC_REFERENCIAS
prompt ========================================
prompt
CREATE OR REPLACE TRIGGER CANTABRIA.TUA_FIN_DOC_REFERENCIAS
  after update on doc_referencias
  for each row


declare
  -- local variables here
  lc_letra_cobrar    doc_tipo.tipo_doc%type ;
  lc_letra_pagar     doc_tipo.tipo_doc%type ;
  lc_soles           moneda.cod_moneda%type ;
  lc_dolares         moneda.cod_moneda%type ;
  lc_cod_moneda      moneda.cod_moneda%type ;
  lc_doc_oc          doc_tipo.tipo_doc%type ;
  lc_doc_os          doc_tipo.tipo_doc%type ;
  ln_tcambio         calendario.cmp_dol_libre%type           ;
  ln_monto_fact      orden_compra.monto_facturado%type       ;
  ln_monto_total     orden_compra.monto_facturado%type       ;
  --
  lc_flag_estado     cntas_cobrar.flag_estado%type           ;
  ln_saldo_sol       cntas_pagar.saldo_sol%type              ;
  ln_saldo_dol       cntas_pagar.saldo_dol%type              ;
  ln_tcambio_old cntas_pagar.tasa_cambio%type            ;
  lc_origen          cntas_pagar.origen%type                 ;
  ln_ano             cntas_pagar.ano%type                    ;
  ln_mes             cntas_pagar.mes%type                    ;
  ln_nro_libro       cntas_pagar.nro_libro%type              ;
  ln_nro_asiento     cntas_pagar.nro_asiento%type            ;
  ln_saldo_sol_old   cntas_pagar.saldo_sol%type              ;
  ln_saldo_dol_old   cntas_pagar.saldo_dol%type              ;
  ln_imp_sol_old     cntas_pagar.saldo_sol%type              ;
  ln_imp_dol_old     cntas_pagar.saldo_dol%type              ;
  ln_saldo_sol_new   cntas_pagar.saldo_dol%type              ;
  lc_doc_chq_dif     doc_tipo.tipo_doc%type                  ;

begin
  -- Edgar Morante Miercoles 10Jul2002, replicacion
  If (dbms_reputil.from_remote=true or dbms_snapshot.i_am_a_refresh=true) then
     return;
  end if;


  /*******************************************************
    REPLICACION
  ********************************************************/
  IF ORA_LOGIN_USER = 'REPP5' THEN
     RETURN ;
  END IF;

   /*Tipo de Monedas*/
   SELECT cod_soles, cod_dolares,doc_oc,doc_os
     INTO lc_soles,lc_dolares,lc_doc_oc,lc_doc_os
     FROM logparam
    WHERE reckey = '1' ;

   /*Tipo de Documentos*/
   SELECT doc_letra_cobrar,doc_letra_pagar,doc_cheque_dif
     INTO lc_letra_cobrar,lc_letra_pagar,lc_doc_chq_dif
     FROM finparam
    WHERE reckey = '1' ;

IF :new.tipo_mov = 'C' AND (:new.tipo_doc  = lc_letra_cobrar or :new.tipo_doc = lc_doc_chq_dif )THEN /*Actualiza Letra X Cobrar Canje Renovacion o cheques diferidos*/
   select tasa_cambio,origen,ano,mes,nro_libro,nro_asiento
     into ln_tcambio,lc_origen,ln_ano,ln_mes,ln_nro_libro,ln_nro_asiento
     from cntas_cobrar
    where (cod_relacion = :new.cod_relacion ) and
          (tipo_doc     = :new.tipo_doc     ) and
          (nro_doc      = :new.nro_doc      ) ;


   IF :new.flab_tabor = '1'      THEN /*Cuentas x Cobrar*/

      select importe_doc,Nvl(saldo_sol,0),Nvl(saldo_dol,0),cod_moneda
        into ln_monto_total,ln_saldo_sol,ln_saldo_dol,lc_cod_moneda
        from cntas_cobrar
       where (( origen       = :new.origen_ref   ) AND
              ( cod_relacion = :new.proveedor_ref ) AND
              ( tipo_doc     = :new.tipo_ref     ) AND
              ( nro_doc      = :new.nro_ref      ));



      ln_imp_dol_old := ln_saldo_dol ;
      ln_imp_sol_old := ln_saldo_sol ;


       --hallar t.cambio old
       select tasa_cambio into ln_tcambio_old from tt_fin_tasa_cambio
       where (cod_relacion = :new.cod_relacion) and
             (tipo_doc     = :new.tipo_doc    ) and
             (nro_doc      = :new.nro_doc     ) ;

       if lc_cod_moneda = lc_soles then
          ln_saldo_sol := ((ln_saldo_sol + Nvl(:old.importe,0)) - Nvl(:new.importe,0))  ;
          ln_saldo_dol := (ln_saldo_dol  + Round(Nvl(:old.importe,0) / ln_tcambio_old,2) ) - Round(Nvl(:new.importe,0) / ln_tcambio,2) ;

          if ln_saldo_sol = 0 then --pagado totalmente
             lc_flag_estado := '3' ;
          elsif ln_monto_total = ln_saldo_sol then --generado
             lc_flag_estado := '1';
          elsif ln_saldo_sol > 0 then    --pagado parcialmente
             lc_flag_estado := '2';
          end if ;

       elsif lc_cod_moneda = lc_dolares then
          ln_saldo_sol_old := 0.00 ;
          ln_saldo_dol_old := 0.00 ;

          --monto anterior a transaci?n x diferencia en cambio
          usp_fin_monto_asiento_x_doc(lc_origen,ln_ano,ln_mes,ln_nro_libro,ln_nro_asiento,:new.cod_relacion,:new.tipo_ref,:new.nro_ref,ln_saldo_sol_old,ln_saldo_dol_old);

          ln_saldo_sol_new := ln_saldo_sol_old ;

          ln_saldo_sol_old := Nvl(ln_saldo_sol_old,0) + Nvl(ln_imp_sol_old,0) ;
          ln_saldo_sol_new := Nvl(ln_saldo_sol_new,0) + Nvl(ln_imp_sol_old,0) ;
          ln_saldo_dol_old := Nvl(ln_saldo_dol_old,0) + Nvl(ln_imp_dol_old,0) ;

          ln_saldo_sol_old := Round(ln_saldo_dol_old * ln_tcambio_old,2) - ln_saldo_sol_old ;
          ln_saldo_sol_new := Round(ln_saldo_dol_old * ln_tcambio,2) - ln_saldo_sol_new    ;

          --TERMINA CALCULO DE DIFERENCIA EN CAMBIO


          ln_saldo_dol := ((ln_saldo_dol + Nvl(:old.importe,0)) - Nvl(:new.importe,0))  ;
          ln_saldo_sol := (ln_saldo_sol  + (Round(Nvl(:old.importe,0) * ln_tcambio_old,2 ) - ln_saldo_sol_old) ) - Round(Nvl(:new.importe,0) * ln_tcambio,2) ;

          --aumento monto por diferencia en cambio en columna de soles
          ln_saldo_sol := ln_saldo_sol + ln_saldo_sol_new ;

          if ln_saldo_dol = 0 then --pagado totalmente
             lc_flag_estado := '3' ;
          elsif ln_monto_total = ln_saldo_dol then --generado
             lc_flag_estado := '1';
          elsif ln_saldo_dol > 0 then    --pagado parcialmente
             lc_flag_estado := '2';
          end if ;

       end if ;

       /**/
       /*************************************************************************************
        REPLICACION (replicar informacion)
       **************************************************************************************/

       UPDATE cntas_cobrar
          SET flag_estado = lc_flag_estado ,
              saldo_sol   = ln_saldo_sol,
              saldo_dol   = ln_saldo_dol,
              flag_replicacion = '1'
        WHERE (( origen       = :new.origen_ref   ) AND
               ( cod_relacion = :new.proveedor_ref ) AND
               ( tipo_doc     = :new.tipo_ref     ) AND
               ( nro_doc      = :new.nro_ref      ));

   ELSIF :new.flab_tabor = '3' THEN
      select importe_doc,Nvl(saldo_sol,0),Nvl(saldo_dol,0),cod_moneda
        into ln_monto_total,ln_saldo_sol,ln_saldo_dol,lc_cod_moneda
        from cntas_pagar
       where (( origen       = :new.origen_ref   ) AND
              ( cod_relacion = :new.proveedor_ref ) AND
              ( tipo_doc     = :new.tipo_ref     ) AND
              ( nro_doc      = :new.nro_ref      ));



      ln_imp_dol_old := ln_saldo_dol ;
      ln_imp_sol_old := ln_saldo_sol ;


       --hallar t.cambio old
       select tasa_cambio into ln_tcambio_old from tt_fin_tasa_cambio
       where (cod_relacion = :new.cod_relacion) and
             (tipo_doc     = :new.tipo_doc    ) and
             (nro_doc      = :new.nro_doc     ) ;

       if lc_cod_moneda = lc_soles then
          ln_saldo_sol := ((ln_saldo_sol + Nvl(:old.importe,0)) - Nvl(:new.importe,0))  ;
          ln_saldo_dol := (ln_saldo_dol  + Round(Nvl(:old.importe,0) / ln_tcambio_old,2) ) - Round(Nvl(:new.importe,0) / ln_tcambio,2) ;



          if ln_saldo_sol = 0 then --pagado totalmente
             lc_flag_estado := '3' ;
          elsif ln_monto_total = ln_saldo_sol then --generado
             lc_flag_estado := '1';
          elsif ln_saldo_sol > 0 then    --pagado parcialmente
             lc_flag_estado := '2';
          end if ;

       elsif lc_cod_moneda = lc_dolares then
          ln_saldo_sol_old := 0.00 ;
          ln_saldo_dol_old := 0.00 ;

          --monto anterior a transaci?n x diferencia en cambio
          usp_fin_monto_asiento_x_doc(lc_origen,ln_ano,ln_mes,ln_nro_libro,ln_nro_asiento,:new.cod_relacion,:new.tipo_ref,:new.nro_ref,ln_saldo_sol_old,ln_saldo_dol_old);

          ln_saldo_sol_new := ln_saldo_sol_old ;

          ln_saldo_sol_old := Nvl(ln_saldo_sol_old,0) + Nvl(ln_imp_sol_old,0) ;
          ln_saldo_sol_new := Nvl(ln_saldo_sol_new,0) + Nvl(ln_imp_sol_old,0) ;
          ln_saldo_dol_old := Nvl(ln_saldo_dol_old,0) + Nvl(ln_imp_dol_old,0) ;

          ln_saldo_sol_old := Round(ln_saldo_dol_old * ln_tcambio_old,2) - ln_saldo_sol_old ;
          ln_saldo_sol_new := Round(ln_saldo_dol_old * ln_tcambio,2) - ln_saldo_sol_new    ;

          --TERMINA CALCULO DE DIFERENCIA EN CAMBIO


          ln_saldo_dol := ((ln_saldo_dol + Nvl(:old.importe,0)) - Nvl(:new.importe,0))  ;
          ln_saldo_sol := (ln_saldo_sol  + (Round(Nvl(:old.importe,0) * ln_tcambio_old,2 ) - ln_saldo_sol_old) ) - Round(Nvl(:new.importe,0) * ln_tcambio,2) ;

          --aumento monto por diferencia en cambio en columna de soles
          ln_saldo_sol := ln_saldo_sol + ln_saldo_sol_new ;

          if ln_saldo_dol = 0 then --pagado totalmente
             lc_flag_estado := '3' ;
          elsif ln_monto_total = ln_saldo_dol then --generado
             lc_flag_estado := '1';
          elsif ln_saldo_dol > 0 then    --pagado parcialmente
             lc_flag_estado := '2';
          end if ;

       end if ;

       /**/
       /*************************************************************************************
        REPLICACION (replicar informacion)
       **************************************************************************************/

       UPDATE cntas_pagar
          SET flag_estado = lc_flag_estado , saldo_sol = ln_saldo_sol,saldo_dol = ln_saldo_dol,
              flag_replicacion = '1'
        WHERE (( origen       = :new.origen_ref   ) AND
               ( cod_relacion = :new.proveedor_ref ) AND
               ( tipo_doc     = :new.tipo_ref     ) AND
               ( nro_doc      = :new.nro_ref      ));


   END IF ;


ELSIF :new.tipo_mov = 'P' AND :new.tipo_doc  = lc_letra_pagar THEN /*Actualiza Letra X Pagar Canje Renovacion*/
   select tasa_cambio,origen,ano,mes,nro_libro,nro_asiento
     into ln_tcambio,lc_origen,ln_ano,ln_mes,ln_nro_libro,ln_nro_asiento
     from cntas_pagar
    where (cod_relacion = :new.cod_relacion ) and
          (tipo_doc     = :new.tipo_doc     ) and
          (nro_doc      = :new.nro_doc      ) ;


   IF :new.flab_tabor = '3'      THEN /*Cuentas x Pagar*/

      select importe_doc,Nvl(saldo_sol,0),Nvl(saldo_dol,0),cod_moneda
        into ln_monto_total,ln_saldo_sol,ln_saldo_dol,lc_cod_moneda
        from cntas_pagar
       where origen       = :new.origen_ref
         AND cod_relacion = :new.proveedor_ref
         AND tipo_doc     = :new.tipo_ref
         AND nro_doc      = :new.nro_ref;



      ln_imp_dol_old := ln_saldo_dol ;
      ln_imp_sol_old := ln_saldo_sol ;


       --hallar t.cambio old
       select tasa_cambio into ln_tcambio_old from tt_fin_tasa_cambio
       where (cod_relacion = :new.cod_relacion) and
             (tipo_doc     = :new.tipo_doc    ) and
             (nro_doc      = :new.nro_doc     ) ;

       if lc_cod_moneda = lc_soles then
          ln_saldo_sol := ((ln_saldo_sol + Nvl(:old.importe,0)) - Nvl(:new.importe,0))  ;
          ln_saldo_dol := (ln_saldo_dol  + Round(Nvl(:old.importe,0) / ln_tcambio_old,2) ) - Round(Nvl(:new.importe,0) / ln_tcambio,2) ;

          ln_saldo_sol := abs(ln_saldo_sol);
          ln_saldo_dol := abs(ln_saldo_dol);

          if ln_saldo_sol = 0 then --pagado totalmente
             lc_flag_estado := '3' ;
          elsif ln_monto_total = ln_saldo_sol then --generado
             lc_flag_estado := '1';
          elsif ln_saldo_sol > 0 then    --pagado parcialmente
             lc_flag_estado := '2';
          end if ;

       elsif lc_cod_moneda = lc_dolares then
          ln_saldo_sol_old := 0.00 ;
          ln_saldo_dol_old := 0.00 ;

          --monto anterior a transaci?n x diferencia en cambio
          usp_fin_monto_asiento_x_doc(lc_origen,ln_ano,ln_mes,ln_nro_libro,ln_nro_asiento,:new.cod_relacion,:new.tipo_ref,:new.nro_ref,ln_saldo_sol_old,ln_saldo_dol_old);

          ln_saldo_sol_new := ln_saldo_sol_old ;

          ln_saldo_sol_old := Nvl(ln_saldo_sol_old,0) + Nvl(ln_imp_sol_old,0) ;
          ln_saldo_sol_new := Nvl(ln_saldo_sol_new,0) + Nvl(ln_imp_sol_old,0) ;
          ln_saldo_dol_old := Nvl(ln_saldo_dol_old,0) + Nvl(ln_imp_dol_old,0) ;

          ln_saldo_sol_old := Round(ln_saldo_dol_old * ln_tcambio_old,2) - ln_saldo_sol_old ;
          ln_saldo_sol_new := Round(ln_saldo_dol_old * ln_tcambio,2) - ln_saldo_sol_new    ;

          --TERMINA CALCULO DE DIFERENCIA EN CAMBIO
          ln_saldo_dol := ((ln_saldo_dol + Nvl(:old.importe,0)) - Nvl(:new.importe,0))  ;
          ln_saldo_sol := (ln_saldo_sol  + (Round(Nvl(:old.importe,0) * ln_tcambio_old,2 ) - ln_saldo_sol_old) ) - Round(Nvl(:new.importe,0) * ln_tcambio,2) ;

          --aumento monto por diferencia en cambio en columna de soles
          ln_saldo_sol := ln_saldo_sol + ln_saldo_sol_new ;

          ln_saldo_sol := abs(ln_saldo_sol);
          ln_saldo_dol := abs(ln_saldo_dol);


          if ln_saldo_dol = 0 then --pagado totalmente
             lc_flag_estado := '3' ;
          elsif ln_monto_total = ln_saldo_dol then --generado
             lc_flag_estado := '1';
          elsif ln_saldo_dol > 0 then    --pagado parcialmente
             lc_flag_estado := '2';
          end if ;

       end if ;

       /**/
       /*************************************************************************************
        REPLICACION (replicar informacion)
       **************************************************************************************/

       if lc_flag_estado is null then
          RAISE_APPLICATION_ERROR(-20000, 'Flag de estado para documento esta nulo, por favor revisar!'
                                      || chr(13) || 'Cod. Relacion: ' || :new.cod_relacion
                                      || chr(13) || 'Tipo DOC: ' || :new.tipo_doc
                                      || chr(13) || 'Nro DOC: ' || :new.nro_doc
                                      || chr(13) || 'Saldo dol: ' || to_char(ln_saldo_dol)
                                      || chr(13) || 'Saldo dol: ' || to_char(ln_saldo_dol)
                                      || chr(13) || 'Saldo sol: ' || to_char(ln_saldo_sol)
                                      || chr(13) || 'Importe Doc: ' || to_char(ln_monto_total)
                                      || chr(13) || 'Moneda: ' || lc_cod_moneda
                                      || chr(13) || 'Tabor: ' ||  :new.flab_tabor
                                      );

       end if;

       UPDATE cntas_pagar
          SET flag_estado = lc_flag_estado , saldo_sol = ln_saldo_sol,saldo_dol = ln_saldo_dol,
              flag_replicacion = '1'
        WHERE (( origen       = :new.origen_ref   ) AND
               ( cod_relacion = :new.proveedor_ref ) AND
               ( tipo_doc     = :new.tipo_ref     ) AND
               ( nro_doc      = :new.nro_ref      ));

   END IF ;

/* Cuentas por Pagar */
ELSIF :new.tipo_mov = 'P' AND :new.tipo_ref = lc_doc_oc THEN  /* Orden de Compra */
   /*Actualizacion de Monto de Orden de Comnpra*/
   /*************************************************************************************
     REPLICACION (replicar informacion)
    **************************************************************************************/

      UPDATE orden_compra
         SET monto_facturado = (Nvl(monto_facturado,0) - :old.importe ) + :new.importe,
             flag_replicacion = '1'
       WHERE ((cod_origen = :new.origen_ref )  AND
              (nro_oc     = :new.nro_ref    )) ;

ELSIF :new.tipo_mov = 'P' AND :new.tipo_ref = lc_doc_os THEN  /* Orden de Servicio */
      /*Actualizacion de Monto de Orden de Servicio*/
      /*************************************************************************************
       REPLICACION (replicar informacion)
      **************************************************************************************/
      UPDATE orden_servicio
         SET monto_facturado  = (Nvl(monto_facturado,0) - :old.importe) + :new.importe,
             flag_replicacion = '1'
       WHERE ((cod_origen = :new.origen_ref )  AND
              (nro_os     = :new.nro_ref    )) ;


       SELECT monto_total ,monto_facturado
         INTO ln_monto_total , ln_monto_fact
         FROM orden_servicio
        WHERE ((cod_origen = :new.origen_ref )  AND
               (nro_os     = :new.nro_ref    )) ;

       --estado del documento
       lc_flag_estado := '1' ;

       IF ln_monto_fact >=  ln_monto_total THEN
          lc_flag_estado := '2' ;          /*Facturado Total  */
       ELSIF (ln_monto_fact < ln_monto_total or ln_monto_fact = 0) THEN
          lc_flag_estado := '1' ;
       END IF ;

      /*************************************************************************************
       REPLICACION (replicar informacion)
      **************************************************************************************/

       UPDATE orden_servicio
          SET flag_estado = lc_flag_estado,flag_replicacion = '1'
        WHERE ((cod_origen = :new.origen_ref )  AND
               (nro_os     = :new.nro_ref    )) ;

END IF ;

end TUA_FIN_DOC_REFERENCIAS;
/

prompt
prompt Creating trigger TUA_FIN_RETENCION_IGV_CRT
prompt ==========================================
prompt
CREATE OR REPLACE TRIGGER CANTABRIA.TUA_FIN_RETENCION_IGV_CRT
  after update on retencion_igv_crt
  for each row
declare
  -- local variables here
  lc_doc_cri      doc_tipo.tipo_doc%type            ;

begin

--PARAMETROS
select f.doc_ret_igv_crt into lc_doc_cri from finparam f where (reckey = '1') ;

IF :new.flag_estado = '0' THEN
   delete from doc_pendientes_cta_cte
   where ((cod_relacion = :new.proveedor       ) and
          (tipo_doc     = lc_doc_cri           ) and
          (nro_doc      = :new.nro_certificado )) ;
END IF ;

end TUA_FIN_RETENCION_IGV_CRT;
/

prompt
prompt Creating trigger TUA_FIN_SOLICITUD_GIRO
prompt =======================================
prompt
CREATE OR REPLACE TRIGGER CANTABRIA.tua_fin_solicitud_giro
  after update on solicitud_giro
  for each row
declare
  -- local variables here
  ln_mes         Number (2)             ;
  ln_ano         Number (4)             ;
  lc_doc_sg      doc_tipo.tipo_doc%type ;
  lc_flag_ctrl   Char   (1)             ;
  ln_factor      doc_pendientes_cta_cte.factor%type      ;
  lc_flag_debhab doc_pendientes_cta_cte.flag_debhab%type ;
  lc_soles       moneda.cod_moneda%type                  ;
  lc_dolares     moneda.cod_moneda%type                  ;
  lc_cta_ctbl_gan cntbl_cnta.cnta_ctbl%type;
  lc_cta_ctbl_per cntbl_cnta.cnta_ctbl%type;
  lc_cnta_debe    cntbl_cnta.cnta_ctbl%type;
  ln_count        number ;
  lc_cnta_ctbl    cntbl_cnta.cnta_ctbl%type;
  lc_cnta_haber   cntbl_cnta.cnta_ctbl%type;
begin

--recuperar tipo og
select doc_sol_giro into lc_doc_sg from finparam where (reckey = '1') ;

--
select cod_soles,cod_dolares into lc_soles,lc_dolares from logparam where (reckey ='1') ;

--factor de documento
select Nvl(factor,0) into ln_factor from doc_tipo where (tipo_doc = lc_doc_sg) ;

if ln_factor = 0 THEN
   RAISE_APPLICATION_ERROR( -20000,'Factor de Documento '||lc_doc_sg|| 'es igual a 0 debera Colocar alguna valor 1 o -1 ' ) ;
end if ;


IF :new.flag_estado = '2' AND :old.flag_estado = '1' THEN

   ln_ano := to_char(:new.fecha_emision,'yyyy') ;
   ln_mes := to_char(:new.fecha_emision,'mm') ;

   /*verifico partida presupuestal*/
   USP_FIN_VERIF_PRESUP_PARTIDA(ln_ano,:new.cencos,:new.cnta_prsp,lc_flag_ctrl);

   IF lc_flag_ctrl <> '0' THEN
      --Valida Afectacion presupuestalmente
      usp_pto_afecta_ejecucion(ln_mes         ,ln_ano        , :new.cencos,
                               :new.cnta_prsp ,:new.saldo_dol );
   END IF;

    /************************************************************************
      REPLICACION
    *************************************************************************/
    /* Insercion A Presupuesto Ejecutado */
    Insert Into presupuesto_ejec
    (cod_origen ,ano         ,cencos      ,
     cnta_prsp  ,fecha       ,descripcion ,
     importe    ,origen_ref  ,tipo_doc_ref,
     nro_doc_ref,cod_rel_ref ,flag_replicacion,
     cod_usr)
    Values
    (:new.origen        ,ln_ano             ,:new.cencos ,
     :new.cnta_prsp     ,:new.fecha_emision ,substr(:new.descripcion,1,100) ,
     :new.saldo_dol * -1,:new.origen        ,lc_doc_sg   ,
     :new.nro_solicitud ,:new.cod_relacion  ,'0'         ,
     :new.aprobacion ) ;

    /*doc pendientes cta cte*/
    if ln_factor = 1 then
      lc_flag_debhab := 'D' ;
    elsif ln_factor = -1 then
      lc_flag_debhab := 'H' ;
    end if ;

    /************************************************************************
      REPLICACION
    *************************************************************************/
    Insert Into doc_pendientes_cta_cte
    (cod_relacion ,tipo_doc  ,nro_doc    ,
     flag_tabla   ,cnta_ctbl ,cod_moneda ,
     flag_debhab  ,sldo_sol  ,saldo_dol  ,
     fecha_doc    ,factor    ,flag_replicacion,
     fecha_vencimiento)
    Values
    (:new.cod_relacion  ,lc_doc_sg      ,:new.nro_solicitud ,
     '6'                ,NULL           ,:new.cod_moneda    ,
     lc_flag_debhab     ,ABS(:new.saldo_sol) ,ABS(:new.saldo_dol)     ,
     :new.fecha_emision ,ln_factor           ,'0'                     ,
     :new.fecha_emision);



ELSIF :old.flag_estado = '2' AND :new.flag_estado = '1' THEN
    --eliminar afectacion presupuestal
    delete from presupuesto_ejec
    where (origen_ref   = :new.origen        ) and
          (tipo_doc_ref = lc_doc_sg          ) and
          (nro_doc_ref  = :new.nro_solicitud ) and
          (cod_rel_ref  = :new.cod_relacion  ) ;

   --eliminar de cta cte
   delete from doc_pendientes_cta_cte
   where (cod_relacion = :new.cod_relacion  ) and
         (tipo_doc     = lc_doc_sg          ) and
         (nro_doc      = :new.nro_solicitud ) ;

ELSIF :new.flag_estado = '2' AND :old.flag_estado = '3' THEN
   if ln_factor = 1 then
      lc_flag_debhab := 'D' ;
   elsif ln_factor = -1 then
      lc_flag_debhab := 'H' ;
   end if ;


      if :new.saldo_sol < 0 or :new.saldo_dol < 0 then --ajuste por conversion
           if :new.cod_moneda = lc_soles then
              if :new.saldo_sol <= 0 then
                 if ln_factor = -1 then
                    ln_factor := 1 ;
                    lc_flag_debhab := 'D' ;
                 else
                    ln_factor := -1 ;
                    lc_flag_debhab := 'H' ;
                 end if ;

              end if;
           else
              if :new.saldo_dol <= 0 then
                 if ln_factor = -1 then
                    ln_factor := 1 ;
                    lc_flag_debhab := 'D' ;
                 else
                    ln_factor := -1 ;
                    lc_flag_debhab := 'H' ;
                 end if ;
             end if;
           end if;

      end if ;

       /****************************************************
        REPLICACION
       *****************************************************/
       update doc_pendientes_cta_cte
          set sldo_sol  = ABS(:new.saldo_sol),
              saldo_dol = ABS(:new.saldo_dol),
              flag_replicacion = '0'         ,
              fecha_vencimiento = :new.fecha_emision
        where ((cod_relacion = :new.cod_relacion  ) and
               (tipo_doc     = lc_doc_sg          ) and
               (nro_doc      = :new.nro_solicitud )) ;

       IF SQL%NOTFOUND THEN
          /****************************************************
            REPLICACION
          *****************************************************/
          Insert Into doc_pendientes_cta_cte
          (cod_relacion ,tipo_doc  ,nro_doc    ,
           flag_tabla   ,cnta_ctbl ,cod_moneda ,
           flag_debhab  ,sldo_sol  ,saldo_dol  ,
           fecha_doc    ,factor    ,flag_replicacion,
           fecha_vencimiento)
          Values
          (:new.cod_relacion  ,lc_doc_sg      ,:new.nro_solicitud ,
           '6'                ,NULL           ,:new.cod_moneda    ,
           lc_flag_debhab     ,ABS(:new.saldo_sol) ,ABS(:new.saldo_dol)     ,
           :new.fecha_emision ,ln_factor      ,'0' ,
           :new.fecha_emision);
       END IF ;


ELSIF :new.flag_estado = '3' OR :new.flag_estado = '4' OR :new.flag_estado = '5' THEN

   if ln_factor = 1 then
      lc_flag_debhab := 'D' ;
   elsif ln_factor = -1 then
      lc_flag_debhab := 'H' ;
   end if ;




    IF :new.saldo_sol <> 0 OR :new.saldo_dol <> 0 THEN

       /**************************************************
        REPLICACION
       **************************************************/
       update doc_pendientes_cta_cte
          set sldo_sol  = ABS(:new.saldo_sol) ,
              saldo_dol = ABS(:new.saldo_dol) ,
              flag_replicacion = '0'          ,
              fecha_vencimiento = :new.fecha_emision
        where ((cod_relacion = :new.cod_relacion  ) and
               (tipo_doc     = lc_doc_sg          ) and
               (nro_doc      = :new.nro_solicitud )) ;

       IF SQL%NOTFOUND THEN

          IF :new.flag_estado = '5' THEN
             --BUSCAR EN ASIENTO CONTABLE
             --revertir devolucion

                --parametros
                select cnta_ctbl_liq_haber,cnta_ctbl_liq_debe,cnta_ctbl_dc_ganancia,cnta_ctbl_dc_perdida
                  into lc_cnta_haber,lc_cnta_debe,lc_cta_ctbl_gan,lc_cta_ctbl_per
                  from finparam where reckey = '1' ;
                --


                 select Count(*) into ln_count from cntbl_asiento_det cad
                  where (cad.cod_relacion = :new.cod_relacion     ) and
                        (cad.tipo_docref1 = lc_doc_sg             ) and
                        (cad.nro_docref1  = :new.nro_solicitud    ) and
                        (cad.cnta_ctbl    = lc_cnta_debe          ) and
                        (cad.origen||trim(to_char(cad.ano))||trim(to_char(cad.mes))||trim(to_char(cad.nro_libro))||trim(to_char(cad.nro_asiento)))=(:new.cnt_origen||trim(to_char(:new.ano))||trim(to_char(:new.mes))||trim(to_char(:new.nro_libro))||trim(to_char(:new.nro_asiento)));





                if ln_count > 0 then

                   lc_flag_debhab := 'D' ;
                   lc_cnta_ctbl   := lc_cnta_debe ;
                   ln_factor      := 1   ;


                else--revertir diferencia en cambio
                    select Count(*) into ln_count from cntbl_asiento_det cad
                     where (cad.cod_relacion = :new.cod_relacion     ) and
                           (cad.tipo_docref1 = lc_doc_sg             ) and
                           (cad.nro_docref1  = :new.nro_solicitud    ) and
                           (cad.cnta_ctbl    = lc_cnta_haber         ) and
                           (cad.origen||trim(to_char(cad.ano))||trim(to_char(cad.mes))||trim(to_char(cad.nro_libro))||trim(to_char(cad.nro_asiento)))=(:new.cnt_origen||trim(to_char(:new.ano))||trim(to_char(:new.mes))||trim(to_char(:new.nro_libro))||trim(to_char(:new.nro_asiento)));


                    if ln_count > 0 then
                       lc_flag_debhab := 'H' ;
                       lc_cnta_ctbl   := lc_cnta_haber ;
                       ln_factor      := -1  ;

                    else
                       select Count(*) into ln_count from cntbl_asiento_det cad
                        where (cad.cod_relacion = :new.cod_relacion     ) and
                              (cad.tipo_docref1 = lc_doc_sg             ) and
                              (cad.nro_docref1  = :new.nro_solicitud    ) and
                              (cad.cnta_ctbl    = lc_cta_ctbl_gan       ) and
                              (cad.origen||trim(to_char(cad.ano))||trim(to_char(cad.mes))||trim(to_char(cad.nro_libro))||trim(to_char(cad.nro_asiento)))=(:new.cnt_origen||trim(to_char(:new.ano))||trim(to_char(:new.mes))||trim(to_char(:new.nro_libro))||trim(to_char(:new.nro_asiento)));

                       if ln_count > 0 then
                          lc_flag_debhab := 'H' ;
                          lc_cnta_ctbl   := lc_cta_ctbl_gan ;
                          ln_factor      := -1   ;
                       else
                          select Count(*) into ln_count from cntbl_asiento_det cad
                           where (cad.cod_relacion = :new.cod_relacion     ) and
                                 (cad.tipo_docref1 = lc_doc_sg             ) and
                                 (cad.nro_docref1  = :new.nro_solicitud    ) and
                                 (cad.cnta_ctbl    = lc_cta_ctbl_per       ) and
                                 (cad.origen||trim(to_char(cad.ano))||trim(to_char(cad.mes))||trim(to_char(cad.nro_libro))||trim(to_char(cad.nro_asiento)))=(:new.cnt_origen||trim(to_char(:new.ano))||trim(to_char(:new.mes))||trim(to_char(:new.nro_libro))||trim(to_char(:new.nro_asiento)));



                          if ln_count > 0 then
                             lc_flag_debhab := 'D' ;
                             lc_cnta_ctbl   := lc_cta_ctbl_per ;
                             ln_factor      := 1   ;
                          end if ;
                      end if;
                    end if ;
                end if;


           END IF ;
          /**************************************************
            REPLICACION
           **************************************************/
          Insert Into doc_pendientes_cta_cte
          (cod_relacion ,tipo_doc  ,nro_doc    ,
           flag_tabla   ,cnta_ctbl ,cod_moneda ,
           flag_debhab  ,sldo_sol  ,saldo_dol  ,
           fecha_doc    ,factor    ,flag_replicacion,
           fecha_vencimiento)
          Values
          (:new.cod_relacion  ,lc_doc_sg      ,:new.nro_solicitud ,
           '6'                ,lc_cnta_ctbl   ,:new.cod_moneda    ,
           lc_flag_debhab     ,ABS(:new.saldo_sol) ,ABS(:new.saldo_dol),
           :new.fecha_emision ,ln_factor      ,'0' ,
           :new.fecha_emision);
       END IF ;


   ELSE --NO EXISTE SALDO
      DELETE FROM DOC_PENDIENTES_CTA_CTE
      WHERE ((cod_relacion = :new.cod_relacion  ) AND
             (tipo_doc     = lc_doc_sg          ) AND
             (nro_doc      = :new.nro_solicitud )) ;
   END IF;

END IF ;


---estado de orden de giro
--if :new.flag_estado <> '5' and :new.nro_asiento is not null then
--   :new.flag_estado := '5' ;
--end if ;


 end tua_fin_solicitud_giro;
/

prompt
prompt Creating trigger TUA_FIN_SOLICITUD_GIRO_LIQ_DET
prompt ===============================================
prompt
CREATE OR REPLACE TRIGGER CANTABRIA.TUA_FIN_SOLICITUD_GIRO_LIQ_DET
  after update on solicitud_giro_liq_det
  for each row
declare
  -- local variables here

lc_sol_giro      doc_tipo.tipo_doc%type ;
lc_soles         moneda.cod_moneda%type ;
lc_dolares       moneda.cod_moneda%type ;
ln_monto_total   cntas_pagar.importe_doc%type ;
ln_saldo_sol     cntas_pagar.importe_doc%type ;
ln_saldo_dol     cntas_pagar.importe_doc%type ;
lc_flag_estado   cntas_pagar.flag_estado%type ;
ln_count         Number                       ;
lc_flag_ctrl_reg cntas_pagar.flag_control_reg%type ;

begin

  If (dbms_reputil.from_remote=true or dbms_snapshot.i_am_a_refresh=true) then
     return;
  end if;

--parametros
select doc_sol_giro into lc_sol_giro from finparam where reckey = '1' ;

select cod_soles,cod_dolares into lc_soles,lc_dolares from logparam where reckey = '1' ;


IF :new.tipo_doc = lc_sol_giro THEN --SOLICITUD GIRO
   select importe_doc,Nvl(saldo_sol,0),Nvl(saldo_dol,0)
     into ln_monto_total,ln_saldo_sol,ln_saldo_dol
     from solicitud_giro sg
    WHERE ((cod_relacion  = :new.proveedor  ) AND
           (nro_solicitud = :new.nro_doc   )) ;


   if :new.cod_moneda = lc_soles then
      ln_saldo_sol := ((ln_saldo_sol + Nvl(:old.importe,0)) - Nvl(:new.importe,0))  ;
      ln_saldo_dol := (ln_saldo_dol  + Round(Nvl(:old.importe,0) / :old.tasa_cambio,2) ) - Round(Nvl(:new.importe,0) / :new.tasa_cambio,2) ;


   elsif :new.cod_moneda = lc_dolares then
      ln_saldo_dol := ((ln_saldo_dol + Nvl(:old.importe,0)) - Nvl(:new.importe,0))  ;
      ln_saldo_sol := (ln_saldo_sol  + (Round(Nvl(:old.importe,0) * :old.tasa_cambio,2 ) ) ) - Round(Nvl(:new.importe,0) * :new.tasa_cambio,2) ;

   end if ;

   /**/
   /************************************************************************
    REPLICACION
    ************************************************************************/
   UPDATE solicitud_giro
      SET saldo_sol = ln_saldo_sol,saldo_dol = ln_saldo_dol,flag_estado = '3',flag_replicacion = '0'
    WHERE ((cod_relacion  = :new.proveedor  ) AND
           (nro_solicitud = :new.nro_doc   )) ;



ELSE
   --verificacion de  doc cuenta corriente
   --VERIFICAR SI ES TIPO CUENTA CORRIENTE
   select count(*) into ln_count from doc_grupo_relacion dg where (dg.grupo    = 'C2'          ) and
                                                                  (dg.tipo_doc = :new.tipo_doc );

   IF ln_count > 0 AND :new.flag_provisionado = 'D' THEN --NO AFECTARA DOC_PENDIENTES_CTA_CTE
      select cp.flag_control_reg into lc_flag_ctrl_reg
        from cntas_pagar cp
       where (cp.cod_relacion = :new.proveedor ) and
             (cp.tipo_doc     = :new.tipo_doc  ) and
             (cp.nro_doc      = :new.nro_doc   ) ;

      IF lc_flag_ctrl_reg = '1' THEN --invertira condicion de documento
         --no se actualiza documento
         RETURN ;
      END IF ;

   END IF ;
   ---

   select importe_doc,Nvl(saldo_sol,0),Nvl(saldo_dol,0)
     into ln_monto_total,ln_saldo_sol,ln_saldo_dol
     from cntas_pagar
    where (( cod_relacion = :new.proveedor ) AND
           ( tipo_doc     = :new.tipo_doc  ) AND
           ( nro_doc      = :new.nro_doc   ));

   if :new.cod_moneda = lc_soles then
      ln_saldo_sol := ((ln_saldo_sol + Nvl(:old.importe,0)) - Nvl(:new.importe,0))  ;
      ln_saldo_dol := (ln_saldo_dol  + Round(Nvl(:old.importe,0) / :old.tasa_cambio,2) ) - Round(Nvl(:new.importe,0) / :new.tasa_cambio,2) ;

      if ln_saldo_sol = 0 then --pagado totalmente
         lc_flag_estado := '3' ;
      elsif ln_monto_total = ln_saldo_sol then --generado
         lc_flag_estado := '1';
      elsif ln_saldo_sol > 0 then    --pagado parcialmente
         lc_flag_estado := '2';
      end if ;

   elsif :new.cod_moneda = lc_dolares then

      ln_saldo_dol := (ln_saldo_dol + Nvl(:old.importe,0)) - Nvl(:new.importe,0)  ;
      ln_saldo_sol := (ln_saldo_sol +  (Round(Nvl(:old.importe,0) * :old.tasa_cambio,2 )) - Round(Nvl(:new.importe,0) * :new.tasa_cambio,2)) ;

      if ln_saldo_dol = 0 then --pagado totalmente
         lc_flag_estado := '3' ;
      elsif ln_monto_total = ln_saldo_dol then --generado
         lc_flag_estado := '1';
      elsif ln_saldo_dol > 0 then    --pagado parcialmente
         lc_flag_estado := '2';
      end if ;

    end if ;

     /**/
     /************************************************************************
       REPLICACION
     ************************************************************************/
     UPDATE cntas_pagar
        SET flag_estado = lc_flag_estado , saldo_sol = ln_saldo_sol,saldo_dol = ln_saldo_dol,flag_replicacion = '0'
      WHERE (( cod_relacion = :new.proveedor ) AND
             ( tipo_doc     = :new.tipo_doc  ) AND
             ( nro_doc      = :new.nro_doc   ));

     -- Actualiza control documentario
     IF ln_saldo_sol=0 OR ln_saldo_dol=0 THEN
        ln_count := usf_fin_cierra_control_doc(:new.proveedor, :new.tipo_doc, :new.nro_doc);
     END IF ;

END IF ;

end TUA_FIN_SOLICITUD_GIRO_LIQ_DET;
/

