CREATE OR REPLACE TRIGGER CANTABRIA.TUA_LABOR
  after update on labor
  for each row
declare
  -- local variables here
begin
  IF :new.flag_estado='0' THEN
     UPDATE operaciones o
        SET o.flag_estado='2'
      WHERE o.cod_labor = :new.cod_labor
        AND o.flag_estado in ('3');
  END IF ;
end TUA_LABOR;
