prompt
prompt Creating trigger TUA_MTT_PD_OT_DET
prompt ==================================
prompt
CREATE OR REPLACE TRIGGER CANTABRIA.TUA_MTT_PD_OT_DET
  after update on pd_ot_det
  for each row

DECLARE
  -- local variables here

 Cursor c_oper_new is
   SELECT flag_estado,cant_real
     FROM operaciones
    WHERE (tipo_orden = (select doc_ot from prod_param where reckey = '1' )  ) AND
          (nro_orden  = :new.nro_orden )
   ORDER BY nro_operacion ;

  lc_flag_estado_old Char (1) ; -- estado de la ot old
  lc_flag_estado_new Char (1) ; -- estado de la ot new
  lc_doc_ot          doc_tipo.tipo_doc%type    ;
  ldc_cant_real_old  pd_ot_det.cant_labor%type ;
  ln_count           number ;
  lb_flag_proy       boolean ;
  lb_flag            boolean ;
  ln_flag0           number ;
  ln_flag1           number ;
  ln_flag2           number ;
  ln_flag3           number ;
  ls_flag_externo_o  ejecutor.flag_externo%type ;
  ls_flag_externo_n  ejecutor.flag_externo%type ;


BEGIN
 -- Edgar Morante Miercoles 10Jul2002, replicacion
  If (dbms_reputil.from_remote=true or dbms_snapshot.i_am_a_refresh=true) then
     return;
  end if;

lb_flag_proy := false ;
lb_flag      := false ;

-- Actualizando horometraje o kilimetraje de una maquina
IF ( (:old.cod_maquina <> :new.cod_maquina) AND
     (:old.ind_act_maq <> :new.ind_act_maq) )  THEN

    -- Actualiza antiguos datos
    UPDATE maquina m
       SET m.ind_act_acumulada = NVL(m.ind_act_acumulada,0) - :old.ind_act_maq
     WHERE m.cod_maquina = :old.cod_maquina ;

    -- Actualiza nuevos datos
    UPDATE maquina m
       SET m.ind_act_acumulada = NVL(m.ind_act_acumulada,0) + :new.ind_act_maq
     WHERE m.cod_maquina = :new.cod_maquina ;

END IF ;

 --solamente ingresa cuando cambio los siguientes campos
--1.- oper_sec
--2.- flag_terminado
--3.- cant_labor
--4.- cant_avance
--5.- cod_maquina
--6.- ind_act_maq

IF (:old.oper_sec <> :new.oper_sec) OR
   (:old.flag_terminado <> :new.flag_terminado) OR
   (Nvl(:old.cant_labor,0) <> Nvl(:new.cant_labor,0)) OR
   (Nvl(:old.cant_avance,0) <> Nvl(:new.cant_avance,0)) OR
   (:old.cod_maquina <> :new.cod_maquina) OR
   (:old.ind_act_maq <> :new.ind_act_maq) THEN


   IF :new.flag_terminado = '1' THEN --si operacion es cerrada
      --Fin de Operacion
      UPDATE operaciones
         SET cant_real     = ( Nvl(cant_real,0)  - (NVL(:old.cant_labor,0) - NVL(:old.horas_inciden,0) )
                                                 + ( NVL(:new.cant_labor,0) - NVL(:new.horas_inciden,0) )),  --acumula cantidad de labor de operacion
             avance_actual = (Nvl(avance_actual,0) - NVL(:old.cant_avance,0) ) + NVL(:new.cant_avance,0), --cantidad
             flag_estado  = '2',                                                                          -- operacion terminada
             flag_replicacion = '0',
             fec_fin      = :new.hora_fin                                              --fecha final de la operacion
       WHERE oper_sec = :new.oper_sec ;

   ELSE

      IF :old.flag_terminado = '1' THEN
         --ABRE OPERACION
         UPDATE operaciones
         SET cant_real     = ( Nvl(cant_real,0)  - (NVL(:old.cant_labor,0) - NVL(:old.horas_inciden,0) )
                                                 + ( NVL(:new.cant_labor,0) - NVL(:new.horas_inciden,0) )),  --acumula cantidad de labor de operacion                avance_actual = (Nvl(avance_actual,0) - NVL(:old.cant_avance,0) ) + NVL(:new.cant_avance,0), --cantidad
                flag_estado   = '1'                                                           , --operacion activa
                flag_replicacion = '0' ,
                fec_fin      = null                                                             --fecha final no termina
          WHERE oper_sec = :new.oper_sec ;

      ELSE
         -- NO SE TOCA ESTADO ACTUAL DE LA OPERACION
         --ABRE OPERACION
         UPDATE operaciones
         SET cant_real     = ( Nvl(cant_real,0)  - (NVL(:old.cant_labor,0) - NVL(:old.horas_inciden,0) )
                                                 + ( NVL(:new.cant_labor,0) - NVL(:new.horas_inciden,0) )),  --acumula cantidad de labor de operacion                avance_actual = (Nvl(avance_actual,0) - NVL(:old.cant_avance,0) ) + NVL(:new.cant_avance,0), --cantidad
                flag_replicacion = '0'
          WHERE oper_sec = :new.oper_sec ;
      END IF ;
   END IF ;


    --ENCONTRAR ESTADO DE LA OT
    --estados de la ot
    --0 = anulado ,1 = activo
    --2 = cerrado ,3 = proyectado
    --

   /*actualiza maquina*/
   IF :old.cod_maquina is not null OR :new.cod_maquina is not null THEN
      IF (:new.cod_maquina = :old.cod_maquina) THEN

         if (:old.ind_act_maq <> Nvl(:new.ind_act_maq,0)) then

             UPDATE maquina m
                SET m.flag_replicacion = '0',
                    m.ind_act_acumulada = (Nvl(m.ind_act_acumulada,0) - Nvl(:old.ind_act_maq,0) ) + :new.ind_act_maq
              WHERE m.cod_maquina = :new.cod_maquina;

          end if;

      ELSE
         --maquina antigua
         IF :old.cod_maquina is not null THEN
            UPDATE maquina m
               SET m.flag_replicacion  = '0',
                   m.ind_act_acumulada = Nvl(m.ind_act_acumulada,0) - Nvl(:old.ind_act_maq,0)
             WHERE m.cod_maquina = :old.cod_maquina ;
        END IF ;

        --nueva maquina
        IF :new.cod_maquina is not null THEN
           UPDATE maquina m
              SET m.flag_replicacion = '0',
                  m.ind_act_acumulada = Nvl(m.ind_act_acumulada,0) + Nvl(:new.ind_act_maq,0)
            WHERE m.cod_maquina = :new.cod_maquina ;
        END IF ;
     END IF ;
   END IF;


   SELECT count(decode(flag_estado,'0',1,0)),
          count(decode(flag_estado,'1',1,0)),
          count(decode(flag_estado,'2',1,0)),
          count(decode(flag_estado,'3',1,0))
     INTO ln_flag0, ln_flag1, ln_flag2, ln_flag3
     FROM operaciones o
    WHERE (tipo_orden = (select doc_ot from prod_param where reckey = '1' )  ) AND
         (nro_orden  = :new.nro_orden ) ;

   IF ln_flag0>0 AND ln_flag1=0 AND ln_flag2=0 AND ln_flag3=0 THEN
     lc_flag_estado_new:='0' ;
   ELSIF ln_flag2>0 AND ln_flag1=0 AND ln_flag3=0 THEN
     lc_flag_estado_new:='2' ;
   ELSIF ln_flag3>0 AND ln_flag1=0 THEN
     lc_flag_estado_new:='3' ;
   ELSE
     lc_flag_estado_new:='1' ;
   END IF ;


   /**Actualiza Estado de Orden de Trabajo**/
   /*
   For rc_oper in c_oper_new Loop
       IF rc_oper.flag_estado = '2' THEN --Cerrada
          if lb_flag_proy then
             lc_flag_estado_new := '1' ; --se activa automaticamente la ot y sale del bucle
             EXIT;
          else
             lc_flag_estado_new := '2' ; --hasta este punto ot se encontraria cerrada
             lb_flag := TRUE ; --FLAG PARA CONTROLAR ESTADO DE LA OT
          end if ;
       ELSIF rc_oper.flag_estado = '1' THEN --Activa
          lc_flag_estado_new := '1' ; --se activa automaticamente la ot y sale del bucle
          EXIT;
       ELSIF rc_oper.flag_estado = '3' THEN --Planeado
          if lb_flag then
             lc_flag_estado_new := '1' ; --se activa automaticamente la ot y sale del bucle
             EXIT;
          else
             lc_flag_estado_new := '3' ; --proyectado sigue busqueda
             lb_flag_proy := TRUE ; --FLAG PARA CONTROLAR ESTADO DE LA OT
          end if ;
       ELSIF rc_oper.flag_estado = '0' THEN --Anulado
          lc_flag_estado_new := '1' ;
       END IF;
    End Loop ;
    */
    -- Verificando si ejecutor es externo?
    SELECT flag_externo
      INTO ls_flag_externo_o
      FROM ejecutor e
     WHERE e.cod_ejecutor=:old.cod_ejecutor ;

    SELECT flag_externo
      INTO ls_flag_externo_n
      FROM ejecutor e
     WHERE e.cod_ejecutor=:new.cod_ejecutor ;

   IF ls_flag_externo_n = ls_flag_externo_o THEN
       -- Actualiza si el ejecutor no es un tercero
       IF ( ls_flag_externo_n = '0' ) AND
          ( :new.cant_labor <> :old.cant_labor OR :new.costo_labor <>:old.costo_labor) THEN
           UPDATE orden_trabajo ot
              SET ot.flag_estado = lc_flag_estado_new,
                  ot.costo_ejecutado = NVL(ot.costo_ejecutado,0)
                                     + NVL(:new.cant_labor,0)*NVL(:new.costo_labor,0)
                                     - NVL(:old.cant_labor,0)*NVL(:old.costo_labor,0),
                  ot.flag_replicacion = '0'
            WHERE (nro_orden = :new.nro_orden );
       ELSE
       -- No actualiza, porque la OS sera la que actualiza
           UPDATE orden_trabajo ot
              SET ot.flag_estado = lc_flag_estado_new,
                  ot.flag_replicacion = '0'
            WHERE (nro_orden = :new.nro_orden );
       END IF ;
   ELSE
       -- Si era anteriormente un EXTERNO y ahora es NO EXTERNO
       IF ls_flag_externo_o = '1' AND
          ( :new.cant_labor <> :old.cant_labor OR :new.costo_labor <>:old.costo_labor) THEN
             UPDATE orden_trabajo ot
                SET ot.flag_estado = lc_flag_estado_new,
                    ot.costo_ejecutado = NVL(ot.costo_ejecutado,0)
                                       + NVL(:new.cant_labor,0)*NVL(:new.costo_labor,0),
                    ot.flag_replicacion = '0'
              WHERE (nro_orden = :new.nro_orden );
       END IF ;
   END IF ;


   /*verifica si existe ot en correlativo*/
   SELECT count(*)
     INTO ln_count
     FROM campo_ciclo
    WHERE nro_orden = :new.nro_orden  ;

   IF ln_count > 0  THEN
      IF lc_flag_estado_new = '1' THEN --activa
         update campo_ciclo
            set flag_estado = '1', --abierto
                flag_replicacion = '0'
          where nro_orden = :new.nro_orden;
      ELSIF lc_flag_estado_new = '2' THEN --cerrada
         update campo_ciclo
            set flag_estado = '0', --cerrrado
                flag_replicacion = '0'
          where nro_orden = :new.nro_orden ;
      ELSIF lc_flag_estado_new = '3' THEN --planeada
         update campo_ciclo
            set flag_estado = '2',  --en proyecto
                flag_replicacion = '0'
          where nro_orden = :new.nro_orden ;
      END IF ;
   END IF ;

END IF ;

END TUA_MTT_PD_OT_DET;
/

prompt
prompt Creating trigger TUA_OPE_ORDEN_TRABAJO
prompt ======================================
prompt
CREATE OR REPLACE TRIGGER CANTABRIA.TUA_OPE_ORDEN_TRABAJO
  after update on orden_trabajo
  for each row

DECLARE

ld_ult_fec  DATE;

BEGIN
-- Edgar Morante Miercoles 10Jul2002, replicacion
 IF (dbms_reputil.from_remote=true or dbms_snapshot.i_am_a_refresh=true) THEN
    RETURN;
 END IF;

 IF :NEW.flag_estado IS NULL THEN
    RAISE_APPLICATION_ERROR(-20000, 'La OT no puede tener flag_estado nulo');
 END IF;

 --modificacion realizado 20/01/2004 arojas
 IF :new.flag_estado = '0' THEN --anulado orden de trabajo
    IF Not(:old.nro_solicitud is null) OR Trim(:old.nro_solicitud) <> '' THEN
       UPDATE solicitud_ot
          SET flag_estado ='1',
              flag_replicacion = '0'
        WHERE (nro_solicitud = :old.nro_solicitud );
    END IF ;
 END IF ;

 -- Actualizar Programa Ciclico de Mantenimiento
 IF :new.MNT_UND_ACT_REAL <> :old.MNT_UND_ACT_REAL OR
    :new.flag_estado      <> :old.flag_estado      then

    if :new.PROG_MNT is null then return; end if;

    if :new.flag_estado <> '2' then return; end if;

    --Obtengo la ultima fecha de las operaciones
    select max(fec_fin)
      into ld_ult_fec
      from operaciones
     where nro_orden = :new.nro_orden;

    if ld_ult_fec is null then ld_ult_fec := :new.fec_inicio; end if;

    if NVL(:new.MNT_UND_ACT_REAL,0) <> 0 then
       update mt_prog_ciclo_mantto
          set ULTIMO_MNT = NVL(:new.MNT_UND_ACT_REAL,0),
              FECHA_ULTIMO_MNT = ld_ult_fec,
              flag_replicacion = '0'
        where PROG_MNT = :new.PROG_MNT;
    end if;

 end if;

/* IF :new.FEC_INICIO <> :old.FEC_INICIO AND :new.FEC_INICIO IS NOT NULL then

     IF :new.MNT_UND_ACT_REAL <> :old.MNT_UND_ACT_REAL then

        if (:new.PROG_MNT is not null or trim(:new.PROG_MNT)  <> '') and
           :new.flag_estado <> '0' then

           if NVL(:new.MNT_UND_ACT_REAL,0) <> 0 then
              update mt_prog_ciclo_mantto
                 set ULTIMO_MNT = NVL(:new.MNT_UND_ACT_REAL,0),
                     FECHA_ULTIMO_MNT = :new.FEC_INICIO,
                     flag_replicacion = '0'
               where PROG_MNT = :new.PROG_MNT;
           end if;
        end if;

     end if;

 end if;
*/
END TUA_OPE_ORDEN_TRABAJO;
/

