  -- local variables here
  ln_tasa_cambio calendario.vta_dol_prom%type ;

begin

   --RECUPERO tasa de cambio de acuerdo a cabecera
   select c.vta_dol_prom into ln_tasa_cambio
     from calendario c
    where to_char(c.fecha,'yyyymmdd') = to_char(:old.fecha,'yyyymmdd') ;


   Insert Into tt_ope_pd (nro_parte , tasa_cambio)
   values (:new.nro_parte,ln_tasa_cambio) ;


end tua_ope_pd_ot;
