prompt
prompt Creating trigger TUA_OPE_PD_OT_ASISTENCIA
prompt =========================================
prompt
CREATE OR REPLACE TRIGGER CANTABRIA.TUA_OPE_PD_OT_ASISTENCIA
  after update on pd_ot_asistencia
  for each row
declare
  -- local variables here
  lc_und_lb       labor.und%type               ;
  lc_flag_maq_mo  labor.flag_maq_mo%type       ;
  lc_und_hr       labor.und%type               ;
  ln_cant_lab     pd_ot_det.cant_labor%type    ;
  ln_costo_labor  pd_ot_det.costo_labor%type   ;
  ln_dol_prom     calendario.vta_dol_prom%type ;
  ln_dol_prom_old calendario.vta_dol_prom%type ;
  ln_costo_unit_lab      Number (13,4)         ;
  ln_costo_x_trab_x_item Number (13,2)         ;

begin


--datos de labor
select lb.und ,lb.flag_maq_mo into lc_und_lb ,lc_flag_maq_mo from pd_ot_det pod,labor lb
 where (pod.cod_labor = lb.cod_labor  ) and (pod.nro_parte = :new.no_parte ) and
       (pod.nro_item  = :new.nro_item ) ;

--parametros de und
select pp.und_hr into lc_und_hr from prod_param pp where pp.reckey = '1' ;


IF (lc_flag_maq_mo = 'O' and lc_und_lb = lc_und_hr) THEN
    select tasa_cambio into ln_dol_prom_old
          from tt_ope_pd
         where (nro_parte = :old.no_parte) ;


   select nvl(c.vta_dol_prom,0.000) into ln_dol_prom
     from calendario c
    where trunc(c.fecha) = (select trunc(pd.fecha)
                                           from pd_ot pd
                                          where pd.nro_parte = :new.no_parte) ;

   if ln_dol_prom = 0 or ln_dol_prom_old = 0 then
      raise_application_error (-20000,'No Existe Tasa de Cambio para fecha de Parte Diario Verifique !');
   end if ;

   ln_costo_x_trab_x_item := (Nvl(:new.nro_horas,0) * Nvl(:new.costo_horas,0)) *
Nvl(:new.factor,0) ;


   --convertir a dolares sueldo de trabajador
   if ln_costo_x_trab_x_item > 0 then --convertir a dolares
      ln_costo_x_trab_x_item := Round(ln_costo_x_trab_x_item / ln_dol_prom,2) ;
   end if ;



   --RECUPERO CANTIDAD Y LABOR DE PD_OT_DET
   select Nvl(pdo.cant_labor,0),Nvl(pdo.costo_labor,0) into ln_cant_lab,ln_costo_labor
from pd_ot_det pdo
    where (pdo.nro_parte = :new.no_parte ) and
          (pdo.nro_item  = :new.nro_item ) ;





   --calculo de costo unitario antes de agregar trabajador modificado
   ln_costo_labor := ROUND((ln_costo_labor * ((ln_cant_lab - :new.nro_horas ) +
:old.nro_horas)) -  (( (Nvl(:old.nro_horas,0) * Nvl(:old.costo_horas,0)) *
Nvl(:old.factor,0) / ln_dol_prom_old )),2);
   --calculo para tomar en cuenta modificaciones de trabajador y se halla costo unitario

   ln_costo_unit_lab := Round((ln_costo_labor + ln_costo_x_trab_x_item) / ln_cant_lab ,4)
;

    --actualiza parte diario de ot (detalle)
    update pd_ot_det pdo
       set pdo.costo_labor =  ln_costo_unit_lab
     where (pdo.nro_parte = :new.no_parte ) and
           (pdo.nro_item  = :new.nro_item ) ;


END IF ;





end TUA_OPE_PD_OT_ASISTENCIA;
/

prompt
prompt Creating trigger TUA_OPERACIONES
prompt ================================
prompt
CREATE OR REPLACE TRIGGER CANTABRIA.TUA_OPERACIONES
  after update on operaciones
  for each row

declare
  -- local variables here
  ld_fec_proyec         operaciones.fec_inicio%type ;
  ld_fec_estimada       date ;
  ld_fec_inicio         date ;
  ld_fecha_fin_estimada date ;
  ls_doc_ot             logparam.doc_ot%type ;
  ls_doc_oc             logparam.doc_oc%TYPE;

  CURSOR c_amp_ot (as_oper_sec IN operaciones.oper_sec%TYPE) IS
    SELECT amp.cod_origen, amp.nro_mov
      FROM articulo_mov_proy amp
     WHERE amp.flag_estado IN ('1', '3')
       AND amp.oper_sec = as_oper_sec
       AND amp.tipo_doc = ls_doc_ot;
BEGIN
  -- Edgar Morante Miercoles 10Jul2002, replicacion
  IF (dbms_reputil.from_remote=true or dbms_snapshot.i_am_a_refresh=true) then
     return;
  END IF;
  -- Documento de orden de trabajo
  SELECT l.doc_ot , doc_oc
    INTO ls_doc_ot, ls_doc_oc
    FROM logparam l WHERE reckey='1' ;

  IF :old.fec_inicio <> :new.fec_inicio THEN
     ld_fec_proyec := :new.fec_inicio ;
  ELSE
     ld_fec_proyec := :old.fec_inicio ;
  END IF ;

  IF (:old.fec_inicio <> :new.fec_inicio) THEN
     UPDATE articulo_mov_proy amp
        SET fec_proyect = ld_fec_proyec,
            flag_replicacion = '0'
      WHERE oper_sec = :new.oper_sec AND
            tipo_doc = ls_doc_ot AND
            flag_estado in ('1','3') AND
            NVL(amp.cant_proyect,0) > NVL(amp.cant_procesada,0) ;
     -- Chequear estos casos
     -- fec_proyect <= ld_fec_proyec AND
  END IF ;

  IF :old.flag_estado <> :new.flag_estado THEN
     IF :new.flag_estado = '2' THEN
        -- Si estoy cerrando la operacion debo liberar todos los items de la OT
        FOR lc_reg IN c_amp_ot(:NEW.oper_sec) LOOP

            UPDATE articulo_mov_proy amp
               SET amp.Org_Amp_Ref = NULL,
                   amp.nro_amp_ref = NULL
             WHERE amp.org_Amp_Ref = lc_reg.cod_origen
               AND amp.nro_amp_ref = lc_reg.nro_mov
               AND amp.tipo_doc    = ls_doc_oc;

            UPDATE articulo_mov_proy amp
               SET amp.nro_aprob  = NULL,
                   amp.cant_reservado = 0,
                   amp.flag_estado = '2'
             WHERE amp.cod_origen  = lc_reg.cod_origen
               AND amp.nro_mov     = lc_reg.nro_mov;
        END LOOP;

     ELSIF :new.flag_estado = '1' THEN
        UPDATE articulo_mov_proy amp
           SET flag_estado = '1',
               flag_replicacion = '0'
         WHERE amp.oper_sec = :new.oper_sec AND
               amp.tipo_doc = ls_doc_ot and
               amp.flag_estado in ('2','3') and
               NVL(amp.cant_proyect,0) > NVL(amp.cant_procesada,0) and
               NVL(amp.cant_procesada,0) > 0;
     END IF ;

  END IF ;

  -- Actualizando datos de orden de trabajo
  IF ( ( :old.fec_inicio_est <> :new.fec_inicio_est) OR
       ( :old.fec_inicio <> :new.fec_inicio) OR
       ( :old.cant_proyect <> :new.cant_proyect ) OR
       ( :old.costo_unit <> :new.costo_unit ) ) THEN

       -- Capturando datos
       SELECT fec_estimada, fec_inicio, fecha_fin_estimada
         INTO ld_fec_estimada, ld_fec_inicio, ld_fecha_fin_estimada
         FROM orden_trabajo ot
        WHERE ot.nro_orden = :new.nro_orden ;

       IF :new.fec_inicio_est < ld_fec_estimada THEN
          ld_fec_estimada := :new.fec_inicio_est ;
       END IF ;
       IF :new.fec_inicio < ld_fec_inicio THEN
          ld_fec_inicio := :new.fec_inicio ;
       END IF ;
       IF :new.fec_inicio > ld_fecha_fin_estimada THEN
          ld_fecha_fin_estimada := :new.fec_inicio ;
       END IF ;

       UPDATE orden_trabajo ot
          SET ot.fec_estimada = ld_fec_estimada,
              ot.fec_inicio = ld_fec_inicio,
              ot.fecha_fin_estimada = ld_fecha_fin_estimada,
              ot.costo_estimado = NVL(ot.costo_estimado,0) +
              ( NVL(:new.cant_proyect,0) * NVL(:new.costo_unit,0) -
                NVL(:old.cant_proyect,0) * NVL(:old.costo_unit,0) )
         WHERE ot.nro_orden = :new.nro_orden ;

  END IF ;

END TUA_OPERACIONES;
/

prompt
prompt Creating trigger TUA_ORDEN_COMPRA
prompt =================================
prompt
CREATE OR REPLACE TRIGGER CANTABRIA.TUA_ORDEN_COMPRA
  after update on orden_compra
  for each row
declare
  -- local variables here
  ln_count    number;
  ls_doc_oc   logparam.doc_sc%type;
begin
  -- Edgar Morante Miercoles 10Jul2002, replicacion
  IF (dbms_reputil.from_remote=true or dbms_snapshot.i_am_a_refresh=true) THEN
    RETURN;
  END IF;

  -- Busca tipo documento de orden compra
  Select l.doc_oc
    into ls_doc_oc
    from logparam l
    where reckey = '1';

  -- Si anula, verificar que no tenga adelantos
  if :new.flag_estado = '0' and :new.flag_estado <> :old.flag_estado then
     Select count(cod_origen)
       into ln_count
       from solicitud_adelantos_oc
      where cod_origen = :new.cod_origen
        and nro_oc = :new.nro_oc;

     if ln_count > 0 then
        Raise_application_error(-20000, 'Orden de compra tiene adelantos, no
           podra anularse');
     end if;
  end if;
end TUA_ORDEN_COMPRA;
/

prompt
prompt Creating trigger TUA_PD_OT_INCIDENCIAS
prompt ======================================
prompt
CREATE OR REPLACE TRIGGER CANTABRIA.TUA_PD_OT_INCIDENCIAS
  after update on pd_ot_incidencias
  for each row

declare
   -- local variables here
  ln_horas_o number(4,2);          --horas de incidencias old
  ln_horas_n number(4,2);          --horas de incidencias new
  ln_cant_labor number(4,2);       --horas trabajo de pd_ot_det
  ln_horas_inciden number(4,2);    --horas de Incidencia de pd_ot_det
  ls_flag  char(1);                --flag de estado de operaciones
  ls_opersec         operaciones.oper_sec%type ;

begin

 ln_horas_o := ( :old.fecha_fin - :old.fecha_inicio ) * 24;
 ln_horas_n := ( :new.fecha_fin - :new.fecha_inicio ) * 24;

select o.flag_estado, pod.cant_labor, pod.horas_inciden
  into ls_flag, ln_cant_labor, ln_horas_inciden
  from operaciones o,pd_ot_det pod
 where pod.nro_parte = :old.nro_parte and pod.nro_item = :old.nro_item
   and pod.oper_sec = o.oper_sec;

 --comprobacion de de las horas inciden no pueden ser mayores a
 --horas de trabajo

   ln_horas_inciden := nvl(ln_horas_inciden,0);

   if ln_horas_inciden <> 0 then
      ln_horas_inciden := ln_horas_inciden - ln_horas_o;
   end if;

   ln_horas_inciden := ln_horas_inciden + ln_horas_n;

 if ln_cant_labor < ln_horas_inciden then

    RAISE_APPLICATION_ERROR( -20000, 'Horas de Incidencias no pueden ser mayores a horas de Labor ') ;
    return;

 end if;

 --revisando el flag de estado de operaciones
 if ls_flag = '1' then

   update pd_ot_det
      set horas_inciden = ln_horas_inciden
    where nro_parte = :old.nro_parte and nro_item = :old.nro_item ;

 else

   RAISE_APPLICATION_ERROR( -20000, 'OperSec no esta Activo, No podra modificar las incidencias hasta que active el OperSec') ;
   return;

 end if;


end TUA_PD_OT_INCIDENCIAS;
/

prompt
prompt Creating trigger TUA_PRESUP_INGRESOS_UND
prompt ========================================
prompt
CREATE OR REPLACE TRIGGER CANTABRIA.TUA_PRESUP_INGRESOS_UND
  after update on presup_ingresos_und
  for each row
declare
  -- local variables here
begin
  -- Edgar Morante Miercoles 10Jul2002, replicacion
  If (dbms_reputil.from_remote=true or dbms_snapshot.i_am_a_refresh=true) then
     return;
  end if;

/*  -- Busca ratio segun codigo
\*****************************************************
**** REPLICACION
*****************************************************\
  Update presupuesto_partida p
     set proy_ene = NVL(proy_ene,0) - (NVL( :old.proy_ene,0) * :old.pu_proy_ene) +
            (NVL( :new.proy_ene,0) * :new.pu_proy_ene),
         proy_feb = NVL(proy_feb,0) - (NVL( :old.proy_feb,0) * :old.pu_proy_feb) +
            (NVL( :new.proy_feb,0) * :new.pu_proy_feb),
         proy_mar = NVL(proy_mar,0) - (NVL( :old.proy_mar,0) * :old.pu_proy_mar) +
            (NVL( :new.proy_mar,0) * :new.pu_proy_mar),
         proy_abr = NVL(proy_abr,0) - (NVL( :old.proy_abr,0) * :old.pu_proy_abr) +
            (NVL( :new.proy_abr,0) * :new.pu_proy_abr),
         proy_may = NVL(proy_may,0) - (NVL( :old.proy_may,0) * :old.pu_proy_may) +
            (NVL( :new.proy_may,0) * :new.pu_proy_may),
         proy_jun = NVL(proy_jun,0) - (NVL( :old.proy_jun,0) * :old.pu_proy_jun) +
            (NVL( :new.proy_jun,0) * :new.pu_proy_jun),
         proy_jul = NVL(proy_jul,0) - (NVL( :old.proy_jul,0) * :old.pu_proy_jul) +
            (NVL( :new.proy_jul,0) * :new.pu_proy_jul),
         proy_ago = NVL(proy_ago,0) - (NVL( :old.proy_ago,0) * :old.pu_proy_ago) +
            (NVL( :new.proy_ago,0) * :new.pu_proy_ago),
         proy_set = NVL(proy_set,0) - (NVL( :old.proy_set,0) * :old.pu_proy_set) +
            (NVL( :new.proy_set,0) * :new.pu_proy_set),
         proy_oct = NVL(proy_oct,0) - (NVL( :old.proy_oct,0) * :old.pu_proy_oct) +
            (NVL( :new.proy_oct,0) * :new.pu_proy_oct),
         proy_nov = NVL(proy_nov,0) - (NVL( :old.proy_nov,0) * :old.pu_proy_nov) +
            (NVL( :new.proy_nov,0) * :new.pu_proy_nov),
         proy_dic = NVL(proy_dic,0) - (NVL( :old.proy_dic,0) * :old.pu_proy_dic) +
            (NVL( :new.proy_dic,0) * :new.pu_proy_dic),
         flag_replicacion = '0'
     where p.cencos = :new.cencos
       and p.cnta_prsp = :new.cnta_prsp
       and p.ano = :new.ano;
\*****************************************************\
*/
end TUA_PRESUP_INGRESOS_UND;
/

