prompt
prompt Creating trigger TUA_RH_CNTA_CRRTE
prompt ==================================
prompt
CREATE OR REPLACE TRIGGER CANTABRIA.TUA_RH_CNTA_CRRTE
  after update on cnta_crrte
  for each row
declare
  -- local variables here
  ln_existe  integer;
  ln_tipo_cambio calendario.vnt_dol_libre%type ;
  ld_fecha date ;
  lc_flag_cb     cntas_pagar.flag_caja_bancos%type ;
  lc_flag_cr     cntas_pagar.flag_control_reg%type ;
  lc_flag_estado cntas_pagar.flag_estado%type      ;
  ln_count   number ;
begin
    /***************************************************************************
         Actualiza el saldo de cuentas por cobrar y pagar
   ****************************************************************************/

select count (*) into ln_existe from Cntas_cobrar where tipo_doc = :new.tipo_doc and nro_doc  = :new.nro_doc ;


--buscar cuenta corriente detalle
select count(*) into ln_count from cnta_crrte_detalle ccd
 where (ccd.cod_trabajador = :new.cod_trabajador) and
       (ccd.tipo_doc       = :new.tipo_doc      ) and
       (ccd.nro_doc        = :new.nro_doc       );

if ln_count > 0 then
--busco tipo de cambio

select Max(ccd.fec_dscto) into ld_fecha from cnta_crrte_detalle ccd
 where (ccd.cod_trabajador = :new.cod_trabajador) and
       (ccd.tipo_doc       = :new.tipo_doc      ) and
       (ccd.nro_doc        = :new.nro_doc       );

 ln_tipo_cambio := usf_fin_tasa_cambio(ld_fecha) ;--buscar cuenta corriente detalle

  If  ln_existe = 1 Then

      select cc.flag_caja_bancos,cc.flag_control_reg, cc.flag_estado
        into lc_flag_cb,lc_flag_cr,lc_flag_estado
        from Cntas_cobrar cc
        where ((cc.tipo_doc     = :new.tipo_doc       ) and
               (cc.nro_doc      = :new.nro_doc        )) ;


      if (lc_flag_cb = '1' and lc_flag_cr = '1' ) or (lc_flag_cr = '0' and lc_flag_estado <> '0') then
         update Cntas_cobrar cc
            set   saldo_sol    = :new.sldo_prestamo  , saldo_dol = Round(:new.sldo_prestamo / ln_tipo_cambio,2)
          where ((tipo_doc     = :new.tipo_doc       ) and
                 (nro_doc      = :new.nro_doc        )) ;
      else
         raise_application_error(-20000,'Documento tiene que estar cobrado');
      end if ;

   Else
       --verificar que este pagado
       select count(*)
         into ln_count
         from cntas_pagar cp
        where cp.tipo_doc     = :new.tipo_doc
          and cp.cod_relacion = :new.cod_trabajador
          and cp.nro_doc      = :new.nro_doc;

       if ln_count = 0 then
          
          RAISE_APPLICATION_ERROR(-20000, 'Documento no existe en cuentas x pagar'
                                   || chr(13) || 'Tipo Doc: ' || :new.tipo_doc
                                   || chr(13) || 'Nro Doc: ' || :new.nro_doc
                                   || chr(13) || 'C.Relacion :'|| :new.cod_trabajador);

                                   
          return;
       end if ;
       
       if ln_count > 1 then
          
          RAISE_APPLICATION_ERROR(-20000, 'Documento tiene mas de registro en cuentas x pagar'
                                   || chr(13) || 'Tipo Doc: ' || :new.tipo_doc
                                   || chr(13) || 'Nro Doc: ' || :new.nro_doc
                                   || chr(13) || 'C.Relacion :'|| :new.cod_trabajador);

                                   
          return;
       end if ;

       
       select cp.flag_caja_bancos,cp.flag_control_reg,cp.flag_estado
         into lc_flag_cb,lc_flag_cr,lc_flag_estado
         from cntas_pagar cp
        where cp.tipo_doc     = :new.tipo_doc
          and cp.cod_relacion = :new.cod_trabajador
          and cp.nro_doc      = :new.nro_doc             ;

       if (lc_flag_cb = '1' and lc_flag_cr = '1' ) or (lc_flag_cr = '0' and lc_flag_estado <> '0') then
          update Cntas_pagar
             set   saldo_sol = :new.sldo_prestamo  ,
                   saldo_dol = Round(:new.sldo_prestamo / ln_tipo_cambio,2)
           where tipo_doc     = :new.tipo_doc
             and cod_relacion = :new.cod_trabajador
             and nro_doc      = :new.nro_doc        ;
       else
          raise_application_error(-20000,'Documento tiene que estar pagado'
                                   || chr(13) || 'Tipo Doc: ' || :new.tipo_doc
                                   || chr(13) || 'Nro Doc: ' || :new.nro_doc
                                   || chr(13) || 'C.Relacion :'|| :new.cod_trabajador );

       end if;

    End  If;
end if ;
end TUA_RH_CNTA_CRRTE;
/

prompt
prompt Creating trigger TUB_ALM_ARTICULO
prompt =================================
prompt
CREATE OR REPLACE TRIGGER CANTABRIA.tub_alm_articulo
  before update on articulo
  for each row
declare
  -- local variables here
  ln_count number;

begin
  if :new.flag_inventariable is null then :new.flag_inventariable := '0'; end if;
  if :new.costo_ult_compra   is null then :new.costo_ult_compra   := 0;   end if;
  if :new.SLDO_TOTAL         is null then :new.SLDO_TOTAL         := 0;   end if;
  if :new.SLDO_POR_LLEGAR    is null then :new.SLDO_POR_LLEGAR    := 0;   end if;
  if :new.SLDO_SOLICITADO    is null then :new.SLDO_SOLICITADO    := 0;   end if;
  if :new.sldo_reservado     is null then :new.sldo_reservado     := 0;   end if;
  if :new.SLDO_CONSIGNACION  is null then :new.SLDO_CONSIGNACION  := 0;   end if;
  if :new.SLDO_TOTAL_UND2    is null then :new.SLDO_TOTAL_UND2    := 0;   end if;

  if :new.flag_inventariable <> :old.flag_inventariable then
     if :new.flag_inventariable = '0' then
        :new.SLDO_TOTAL        := 0;
        :new.SLDO_POR_LLEGAR   := 0;
        :new.SLDO_SOLICITADO   := 0;
        :new.SLDO_CONSIGNACION := 0;
        :new.SLDO_TOTAL_UND2   := 0;
        :new.SLDO_RESERVADO    := 0;
     elsif :new.flag_inventariable = '1' then
        :new.SLDO_TOTAL        := usf_alm_saldo_total(:new.cod_art);
        :new.SLDO_POR_LLEGAR   := usf_alm_saldo_xllegar(:new.cod_art);
        :new.SLDO_SOLICITADO   := usf_alm_saldo_solic(:new.cod_art);
        :new.SLDO_CONSIGNACION := usf_alm_saldo_consig(:new.cod_art);
        :new.SLDO_TOTAL_UND2   := usf_alm_saldo_total_und2(:new.cod_art);
        :new.SLDO_RESERVADO    := usf_alm_saldo_reservado(:new.cod_art);
     end if;
  end if;

  /*
  If :new.costo_ult_compra <> :old.costo_ult_compra then
     If :new.costo_ult_compra = 0 and :new.flag_inventariable = '1' then
        -- Si el precio de ultima compra es cero entonces lo reemplazo con el anterior,
        -- si ambos precios, el nuevo y el viejo, son cero, entonces lanzo un mensaje
        -- de error
        if :old.costo_ult_compra > 0 then
           :new.costo_ult_compra := :old.costo_ult_compra;
        else
           RAISE_APPLICATION_ERROR(-20000, 'Error en TUB_ALM_ARTICULO: El precio de ultima compra del Articulo ' || trim(:new.cod_art) || ' no puede ser cero');
        end if;
     end if;
  end if;
  */
  --=======================================================================
  -- actualizar el precio del articulo, solo si el nro de ultima oc es nulo
  --=======================================================================
  select count(*)
    into ln_count
    from tt_alm_trigger;

  if :old.costo_ult_compra <> :new.costo_ult_compra and :new.nro_ultima_oc is null and ln_count = 0 then
      update articulo_almacen aa
         set aa.costo_ult_compra = :new.costo_ult_compra
       where aa.cod_art = :new.cod_art
         and aa.nro_ult_oc is null;
  end if;

  --====================================================================
  -- Debo Validar que el saldo reservado no sea mayor que el saldo total
  --====================================================================
  if :new.sldo_reservado > :new.sldo_total then
     RAISE_APPLICATION_ERROR(-20000, 'No saldo reservado no puede ser mayor que el saldo total'
                     || chr(13) || 'Cod Art: ' || :new.cod_art
                     || chr(13) || 'Saldo Reservado: ' || :new.sldo_reservado
                     || chr(13) || 'Saldo Total: ' || :new.sldo_total);
  end if;

end tub_alm_articulo;
/

