prompt
CREATE OR REPLACE TRIGGER CANTABRIA.TUB_ALM_VALE_MOV
  before update on vale_mov
  for each row
declare
-- local variables here
  ls_cierre               vale_mov.flag_estado%type ;

begin

--  ==============================
--  ** Articulo Saldo Mensual **
--  ==============================
    -- Verificando si puede generar asiento via proceso
    ls_cierre := USF_CNT_CIERRE_CNTBL( to_number(to_char(:new.fec_registro,'yyyy')),
                                       to_number(to_char(:new.fec_registro,'mm')), 'A') ;


