prompt
prompt Creating trigger TUB_RESERVACION_DET
prompt ====================================
prompt
CREATE OR REPLACE TRIGGER CANTABRIA.TUB_RESERVACION_DET
  BEFORE update on reservacion_det
  for each row

DECLARE
  -- Presupuesto_partida
  ls_trigger_amp          tt_trigers.trigger_amp%TYPE := '0';
  ls_estado               articulo_mov_proy.flag_estado%TYPE;
  ln_cant_reservado       articulo_mov_proy.cant_reservado%TYPE;
  ln_cant_libre_ot        NUMBER;
  ln_count                NUMBER;

BEGIN

  -- verifico si existe un registro en la tabla tt_triggers, y que este activo el flag de trigger_amp
  -- de esta manera se que el registro que se esta insertando proviene de una insercion del
  -- trigger de ARTICULO_MOV_PROY y por lo tanto este trigger se va a encargar de actualizar el
  -- saldo reservado.

  SELECT COUNT(*)
    INTO ln_count
    FROM tt_trigers;

  IF ln_count > 0 THEN
     SELECT NVL(trigger_amp, '0')
       INTO ls_trigger_amp
       FROM tt_trigers;
  END IF;

  IF ls_trigger_amp = '1' THEN RETURN; END IF;

  IF :NEW.cantidad < 0 THEN
     raise_application_error(-20000, 'La cantidad reservada de la reservacion no puede ser negativa'
                          || chr(13) || 'Nro_reservacion: ' || :NEW.nro_reservacion
                          || chr(13) || 'Item: ' || to_char(:NEW.nro_item));
  END IF;

  IF :NEW.cant_procesada < 0 THEN
     raise_application_error(-20000, 'La cantidad retirada de la Reservacion no puede ser negativa'
                          || chr(13) || 'Nro_reservacion: ' || :NEW.nro_reservacion
                          || chr(13) || 'Item: ' || to_char(:NEW.nro_item));
  END IF;

  -- Validando si existe registro
  IF ( :new.org_amp_ref <> :old.org_amp_ref or
       :new.nro_amp_ref <> :old.nro_amp_ref) THEN

     RAISE_APPLICATION_ERROR( -20000, 'No Puede cambiar la referencia a la OT' ) ;

  END IF ;

  -- Verificando si AMP sigue activo
  -- Obtengo la cantidad Libre del Requerimiento de la OT, porque es lo maximo
  -- que se puede reservar
  SELECT cant_reservado, flag_estado,
         usf_alm_cant_libre_ot(amp.cod_origen, amp.nro_mov)
    INTO ln_cant_reservado, ls_estado, ln_cant_libre_ot
    FROM articulo_mov_proy amp
   WHERE amp.cod_origen    = :NEW.org_amp_ref
     AND amp.nro_mov       = :NEW.nro_amp_ref FOR UPDATE;

/*  IF ls_estado = '0' THEN
     RAISE_APPLICATION_ERROR(-20000, 'Requerimiento ' || :NEW.org_amp_ref
          || to_char(:NEW.nro_amp_ref) || ' esta anulado, por favor verifique ');
  END IF; */

/*  IF ls_estado = '3' THEN
     RAISE_APPLICATION_ERROR(-20000, 'Requerimiento ' || :NEW.org_amp_ref
          || to_char(:NEW.nro_amp_ref) || ' esta planeado, por favor verifique ');
  END IF;*/

  -- Solo proceso si el flag de estado del AMP es '1', de lo contrario no hago nada
  IF ls_estado = '1' THEN
      -- Verifico si esta vencida el requerimiento simplemente lo cierro
      IF trunc(:NEW.fec_vencimiento) < trunc(SYSDATE) AND :new.flag_estado = '1' THEN
         :NEW.flag_estado := '5';  -- Vencido
      END IF;

      -- Si la cant procesada es mayor o igual a la cantidad reservada entonces
      -- Cierro el item
      IF :NEW.cant_procesada >= :NEW.cantidad AND :new.flag_estado = '1' THEN
         :NEW.flag_estado := '2';  -- Cerrado
      END IF;

      -- Si estoy cambiando la cantidad procesada o la cantidad reservada, y la cantidad procesada
      -- es menor a la cantidad reservada, y ademas si el item esta cerrado entonces lo aperturo,
      -- solo para esos casos nada mas.

      IF NVL(:NEW.cant_procesada, 0) <> NVL(:OLD.cant_procesada,0) OR
          NVL(:new.cantidad, 0)       <> NVL(:old.cantidad, 0)      THEN
         IF :NEW.flag_estado IN ('3', '4') THEN
            raise_application_error(-20000, 'No puede cambiar el item porque el requerimiento esta liberado'
                                  || chr(13) || 'Requerimiento: ' || :NEW.org_amp_ref || to_char(:NEW.nro_amp_ref));
         ELSIF :NEW.flag_estado = '5' THEN
            raise_application_error(-20000, 'No puede cambiar el item porque el requerimiento esta vencido'
                                  || chr(13) || 'Requerimiento: ' || :NEW.org_amp_ref || to_char(:NEW.nro_amp_ref));
         ELSIF :NEW.flag_estado = '2' AND NVL(:NEW.cant_procesada, 0) < NVL(:NEW.cantidad,0) THEN
            :NEW.flag_estado := '1';
         END IF;
      END IF;

      -- Hago los updates respectivos
      IF :NEW.flag_estado           <> :OLD.flag_estado            or
         NVL(:new.cant_procesada,0) <> NVL(:old.cant_procesada, 0) or
         NVL(:new.cantidad,0)       <> NVL(:old.cantidad,0 )       THEN

         IF :OLD.flag_estado = '1' THEN
            -- Verifico que la cantidad no se haga negativa
            IF ln_cant_reservado - (:old.cantidad - :OLD.cant_procesada) < 0 THEN
               raise_application_error(-20000, 'Cantidad reservada en requerimiento se hace negativo '
                  || chr(13) || 'Reservacion N?: ' || to_char(:OLD.nro_reservacion)
                  || chr(13) || 'Requerimiento ' || :OLD.org_amp_ref || to_char(:OLD.nro_amp_ref)
                  || chr(13) || 'Reservado en AMP_OT: ' || to_char(ln_cant_reservado)
                  || chr(13) || 'Cantidad: ' || to_char(:old.cantidad - :OLD.cant_procesada));
            END IF;

            -- Se disminuye la cantidad reservada
            ln_cant_reservado := ln_cant_reservado - (:old.cantidad - :OLD.cant_procesada);

            UPDATE articulo_mov_proy amp
               SET amp.cant_reservado = ln_cant_reservado
             WHERE amp.cod_origen = :OLD.org_amp_ref
               AND amp.nro_mov    = :OLD.nro_amp_ref ;
         END IF ;

         IF :NEW.flag_estado = '1' THEN

            -- Se disminuye la cantidad reservada
            ln_cant_reservado := ln_cant_reservado + (:NEW.cantidad - :NEW.cant_procesada);

            UPDATE articulo_mov_proy amp
               SET amp.cant_reservado = ln_cant_reservado
             WHERE amp.cod_origen = :NEW.org_amp_ref
               AND amp.nro_mov    = :NEW.nro_amp_ref ;

         END IF ;

      END IF;
END IF ;

END TUB_RESERVACION_DET ;
/

